/**
 * Note: Real Firebase keys should be handled via environment variables.
 * For this implementation, we simulate the storage with a LocalStorage-based fallback 
 * if process.env.API_KEY or Firebase initialization fails, ensuring the app 
 * is "Offline-first" as requested.
 */
import { initializeApp } from 'firebase/app';
import { getFirestore, enableIndexedDbPersistence } from 'firebase/firestore';
import { getAuth, signInAnonymously } from 'firebase/auth';
import { getStorage } from 'firebase/storage';

const firebaseConfig = {
  apiKey: "MOCK_API_KEY",
  authDomain: "mock-trip-planner.firebaseapp.com",
  projectId: "mock-trip-planner",
  storageBucket: "mock-trip-planner.appspot.com",
  messagingSenderId: "123456789",
  appId: "1:123456789:web:abcdef"
};

let db: any;
let auth: any;
let storage: any;

try {
  const app = initializeApp(firebaseConfig);
  db = getFirestore(app);
  auth = getAuth(app);
  storage = getStorage(app);

  // Enable offline persistence
  enableIndexedDbPersistence(db).catch((err) => {
    if (err.code === 'failed-precondition') {
      console.warn('Multiple tabs open, persistence can only be enabled in one tab at a time.');
    } else if (err.code === 'unimplemented') {
      console.warn('The current browser does not support all of the features required to enable persistence');
    }
  });

  signInAnonymously(auth).catch(err => console.error("Auth failed", err));
} catch (e) {
  console.warn("Firebase initialization failed. Falling back to local state mode.", e);
}

export { db, auth, storage };

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import { 
  Calendar, 
  Ticket, 
  Wallet, 
  Camera, 
  CheckSquare, 
  Users, 
  MapPin,
  Clock,
  Plus
} from 'lucide-react';
import { MOCK_MEMBERS, MOCK_TRIP_CONFIG } from './constants';
import Schedule from './modules/Schedule';
import Bookings from './modules/Bookings';
import Expense from './modules/Expense';
import Journal from './modules/Journal';
import Planning from './modules/Planning';
import Members from './modules/Members';

type Tab = 'schedule' | 'bookings' | 'expense' | 'journal' | 'planning' | 'members';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('schedule');
  const [currentUser, setCurrentUser] = useState(MOCK_MEMBERS[0]);
  const [tripConfig, setTripConfig] = useState(MOCK_TRIP_CONFIG);

  // Sync state to local storage for PWA offline experience
  useEffect(() => {
    const savedTab = localStorage.getItem('activeTab') as Tab;
    if (savedTab) setActiveTab(savedTab);

    const savedUser = localStorage.getItem('currentUser');
    if (savedUser) setCurrentUser(JSON.parse(savedUser));
  }, []);

  useEffect(() => {
    localStorage.setItem('activeTab', activeTab);
  }, [activeTab]);

  const handleSwitchUser = (user: any) => {
    setCurrentUser(user);
    localStorage.setItem('currentUser', JSON.stringify(user));
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'schedule': return <Schedule config={tripConfig} />;
      case 'bookings': return <Bookings />;
      case 'expense': return <Expense currentUser={currentUser} members={MOCK_MEMBERS} />;
      case 'journal': return <Journal currentUser={currentUser} />;
      case 'planning': return <Planning members={MOCK_MEMBERS} />;
      case 'members': return <Members currentUser={currentUser} members={MOCK_MEMBERS} onSwitch={handleSwitchUser} />;
      default: return <Schedule config={tripConfig} />;
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto bg-cream shadow-2xl relative overflow-hidden">
      {/* Header */}
      <header className="p-4 pt-6 flex justify-between items-center bg-paper/80 backdrop-blur-md sticky top-0 z-50 border-b border-accent">
        <div>
          <h1 className="text-xl font-bold text-navy flex items-center gap-2">
            <span className="text-stitch">🏝️</span> {tripConfig.tripName}
          </h1>
          <p className="text-xs text-navy/60 font-medium tracking-wide">STITCH x DONALD ADVENTURE</p>
        </div>
        <div 
          className="w-10 h-10 rounded-full border-2 border-donald sticker-shadow overflow-hidden cursor-pointer"
          onClick={() => setActiveTab('members')}
        >
          <img src={currentUser.avatar} alt={currentUser.name} className="w-full h-full object-cover" />
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto pb-24 px-4 pt-4">
        {renderContent()}
      </main>

      {/* Floating Action Button - Context Aware */}
      {['schedule', 'bookings', 'expense', 'journal', 'planning'].includes(activeTab) && (
        <button 
          className="fixed bottom-24 right-6 w-14 h-14 bg-donald text-navy rounded-full sticker-shadow flex items-center justify-center active:scale-95 transition-transform z-40 border-2 border-paper"
          onClick={() => console.log('Add new item for', activeTab)}
        >
          <Plus size={32} />
        </button>
      )}

      {/* Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-paper border-t border-accent px-2 py-3 flex justify-around items-center z-50 rounded-t-3xl shadow-[0_-4px_10px_rgba(0,0,0,0.05)]">
        <NavButton active={activeTab === 'schedule'} onClick={() => setActiveTab('schedule')} icon={<Calendar size={22} />} label="Schedule" />
        <NavButton active={activeTab === 'bookings'} onClick={() => setActiveTab('bookings')} icon={<Ticket size={22} />} label="Bookings" />
        <NavButton active={activeTab === 'expense'} onClick={() => setActiveTab('expense')} icon={<Wallet size={22} />} label="Expense" />
        <NavButton active={activeTab === 'journal'} onClick={() => setActiveTab('journal')} icon={<Camera size={22} />} label="Journal" />
        <NavButton active={activeTab === 'planning'} onClick={() => setActiveTab('planning')} icon={<CheckSquare size={22} />} label="Plan" />
        <NavButton active={activeTab === 'members'} onClick={() => setActiveTab('members')} icon={<Users size={22} />} label="Mems" />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center gap-1 transition-all duration-200 ${active ? 'text-stitch scale-110' : 'text-navy/40'}`}
  >
    <div className={`p-1 rounded-xl ${active ? 'bg-stitch/10' : ''}`}>
      {icon}
    </div>
    <span className="text-[10px] font-bold uppercase tracking-tighter">{label}</span>
  </button>
);

export default App;

import React, { useState, useEffect } from 'react';
import { MapPin, Clock, CloudRain, Sun, Thermometer } from 'lucide-react';
import { TripConfig, ScheduleItem } from '../types';
import { COLORS } from '../constants';

const Schedule: React.FC<{ config: TripConfig }> = ({ config }) => {
  const [selectedDay, setSelectedDay] = useState(0);
  const [countdown, setCountdown] = useState(0);

  useEffect(() => {
    const start = new Date(config.startDate).getTime();
    const now = new Date().getTime();
    const diff = Math.ceil((start - now) / (1000 * 60 * 60 * 24));
    setCountdown(diff > 0 ? diff : 0);
  }, [config.startDate]);

  const days = Array.from({ length: config.duration }, (_, i) => {
    const d = new Date(config.startDate);
    d.setDate(d.getDate() + i);
    return {
      index: i,
      date: d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
      weekday: d.toLocaleDateString('en-US', { weekday: 'short' })
    };
  });

  const mockItems: ScheduleItem[] = [
    { id: '1', dayIndex: 0, time: '10:00', title: 'Arrival at Narita', location: 'NRT Terminal 1', category: 'Transport' },
    { id: '2', dayIndex: 0, time: '13:30', title: 'Lunch at Ichiran', location: 'Shinjuku', category: 'Food' },
    { id: '3', dayIndex: 0, time: '15:00', title: 'Hotel Check-in', location: 'Shinjuku Prince Hotel', category: 'Stay' },
    { id: '4', dayIndex: 1, time: '09:00', title: 'DisneySea!', location: 'Urayasu', category: 'Attraction' },
  ].filter(item => item.dayIndex === selectedDay);

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Countdown Card */}
      <div className="bg-stitch text-white p-6 rounded-2xl-sticker sticker-shadow flex justify-between items-center relative overflow-hidden">
        <div className="z-10">
          <p className="text-sm font-bold opacity-80 uppercase tracking-widest">Adventure Begins In</p>
          <h2 className="text-4xl font-black">{countdown} Days</h2>
        </div>
        <div className="text-6xl opacity-20 absolute -right-2 -bottom-2 transform rotate-12 z-0">🏝️</div>
      </div>

      {/* Horizontal Date Picker */}
      <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide snap-x">
        {days.map((day) => (
          <button
            key={day.index}
            onClick={() => setSelectedDay(day.index)}
            className={`flex-shrink-0 w-20 py-4 rounded-xl-sticker border-2 transition-all snap-center ${
              selectedDay === day.index 
              ? 'bg-donald border-paper sticker-shadow scale-105' 
              : 'bg-paper border-accent opacity-60'
            }`}
          >
            <p className="text-[10px] font-bold uppercase opacity-60">{day.weekday}</p>
            <p className="text-lg font-black">{day.date.split(' ')[1]}</p>
            <p className="text-[10px] font-bold">{day.date.split(' ')[0]}</p>
          </button>
        ))}
      </div>

      {/* Weather Card (Mock) */}
      <div className="bg-white p-4 rounded-xl-sticker sticker-shadow border border-accent flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-stitch/10 rounded-full flex items-center justify-center text-stitch">
            <Sun size={28} />
          </div>
          <div>
            <p className="text-xs font-bold text-navy/40">TODAY'S WEATHER</p>
            <p className="font-bold">Sunny & Clear</p>
          </div>
        </div>
        <div className="text-right">
          <p className="text-2xl font-black text-stitch">24°C</p>
          <p className="text-[10px] font-bold opacity-40">H: 26° L: 18°</p>
        </div>
      </div>

      {/* Itinerary List */}
      <div className="space-y-4">
        {mockItems.length > 0 ? mockItems.map((item) => (
          <div key={item.id} className="relative pl-6 border-l-2 border-dashed border-accent pb-2">
            <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-paper border-2 border-stitch" />
            <div className="bg-paper p-4 rounded-xl-sticker sticker-shadow border border-accent active:scale-[0.98] transition-all cursor-pointer">
              <div className="flex justify-between items-start mb-2">
                <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-wider text-white`} style={{ backgroundColor: COLORS[item.category.toLowerCase() as keyof typeof COLORS] || COLORS.stitch }}>
                  {item.category}
                </span>
                <div className="flex items-center gap-1 text-navy/40 font-bold text-xs">
                  <Clock size={14} />
                  {item.time}
                </div>
              </div>
              <h3 className="font-bold text-lg leading-tight mb-1">{item.title}</h3>
              <div className="flex items-center gap-1 text-navy/60 text-xs">
                <MapPin size={12} />
                {item.location}
              </div>
            </div>
          </div>
        )) : (
          <div className="py-12 text-center opacity-40">
            <p className="text-4xl mb-2">🎈</p>
            <p className="font-bold">Nothing planned yet!</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Schedule;

import React, { useState } from 'react';
