const Expense: React.FC<{ currentUser: TripMember; members: TripMember[] }> = ({ currentUser, members }) => {
  const [expenses, setExpenses] = useState<ExpenseType[]>([
    { id: '1', amount: 3500, currency: 'JPY', category: 'Food', paidBy: '1', splitWith: ['1', '2', '3', '4'], date: '2024-10-12' },
    { id: '2', amount: 12000, currency: 'JPY', category: 'Transport', paidBy: '2', splitWith: ['1', '2', '3', '4'], date: '2024-10-12' },
  ]);

  const totalSpentJPY = expenses.reduce((acc, exp) => acc + (exp.amount * CURRENCY_RATES[exp.currency]), 0);
  const perPerson = totalSpentJPY / members.length;

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Dashboard Card */}
      <div className="bg-donald p-6 rounded-2xl-sticker sticker-shadow border-2 border-paper">
