        <div className="grid grid-cols-2 gap-4 pt-4 border-t border-navy/10">
          <div>
            <p className="text-[10px] font-black text-navy/40 uppercase">Per Person</p>
            <p className="text-lg font-black text-navy">¥{perPerson.toLocaleString()}</p>
          </div>
          <div className="text-right">
            <p className="text-[10px] font-black text-navy/40 uppercase">Your Share</p>
            <p className="text-lg font-black text-stitch">¥{perPerson.toLocaleString()}</p>
          </div>
        </div>
      </div>

      {/* Currency Shortcuts */}
      <div className="flex gap-2">
        <div className="flex-1 bg-paper p-3 rounded-xl-sticker sticker-shadow border border-accent flex justify-between items-center">
          <span className="text-[10px] font-black opacity-40">100 HKD</span>
          <span className="font-bold">¥1,900</span>
        </div>
        <div className="flex-1 bg-paper p-3 rounded-xl-sticker sticker-shadow border border-accent flex justify-between items-center">
          <span className="text-[10px] font-black opacity-40">1 AUD</span>
          <span className="font-bold">¥95</span>
        </div>
      </div>

      {/* Recent Activity */}
      <div className="space-y-4">
        <h3 className="text-lg font-black px-1 flex items-center justify-between">
          Recent Expenses
          <span className="text-[10px] text-stitch font-bold cursor-pointer">View History</span>
        </h3>

        {expenses.map((exp) => {
          const payer = members.find(m => m.id === exp.paidBy);
          return (
            <div key={exp.id} className="bg-white p-4 rounded-xl-sticker sticker-shadow border border-accent flex items-center gap-4">
