      <div className="space-y-3">
        {filteredItems.map((item) => {
          const assignee = members.find(m => m.id === item.assignedTo);
          return (
            <div 
              key={item.id} 
              onClick={() => toggleComplete(item.id)}
              className={`bg-white p-4 rounded-xl-sticker sticker-shadow border flex items-center gap-4 active:scale-[0.98] transition-all cursor-pointer ${
                item.completed ? 'opacity-50 grayscale border-accent' : 'border-accent'
              }`}
            >
              <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-colors ${
                item.completed ? 'bg-stitch border-stitch' : 'border-accent'
              }`}>
                {item.completed && <Check size={16} className="text-white" />}
              </div>
              <div className="flex-1">
                <p className={`font-bold ${item.completed ? 'line-through' : ''}`}>{item.title}</p>
                <div className="flex items-center gap-1 text-[10px] font-bold text-navy/40 mt-0.5">
                  <User size={10} />
                  {item.assignedTo === 'All' ? 'Everyone' : assignee?.name}
                </div>
              </div>
              <button className="text-navy/20 hover:text-red-400 p-2">
                <Trash2 size={16} />
              </button>
            </div>
          );
        })}

        <button className="w-full py-4 rounded-xl-sticker border-2 border-dashed border-accent text-navy/40 font-black flex items-center justify-center gap-2 hover:bg-white transition-colors">
          <Plus size={20} />
          ADD NEW {activeTab.toUpperCase()}
        </button>
      </div>

      <div className="bg-stitch/10 p-5 rounded-2xl-sticker border border-stitch/20">
        <h4 className="text-sm font-black text-stitch mb-3 uppercase tracking-widest">Progress</h4>
        <div className="flex items-center gap-3">
          <div className="h-3 flex-1 bg-white rounded-full overflow-hidden border border-stitch/20">
            <div 
              className="h-full bg-stitch transition-all duration-1000" 
              style={{ width: `${(filteredItems.filter(i => i.completed).length / (filteredItems.length || 1)) * 100}%` }} 
            />
          </div>
          <span className="text-xs font-black text-stitch">
            {filteredItems.filter(i => i.completed).length}/{filteredItems.length}
          </span>
        </div>
      </div>
    </div>
  );
};

