import React, { useState, useEffect, useMemo } from 'react';
import { 
  MapPin, 
  Clock, 
  Sun, 
  Settings, 
  Plus, 
  X, 
  ChevronRight, 
  Info,
  RefreshCw,
  Navigation
} from 'lucide-react';
import { TripConfig, ScheduleItem, Category } from '../types';
import { COLORS } from '../constants';
import { GoogleGenAI } from "@google/genai";

interface WeatherData {
  temp: string;
  condition: string;
  humidity: string;
  source: string;
}

const Schedule: React.FC<{ config: TripConfig }> = ({ config: initialConfig }) => {
  const [config, setConfig] = useState<TripConfig>(() => {
    const saved = localStorage.getItem('tripConfig');
    return saved ? JSON.parse(saved) : initialConfig;
  });

  const [itinerary, setItinerary] = useState<ScheduleItem[]>(() => {
    const saved = localStorage.getItem('itinerary');
    return saved ? JSON.parse(saved) : [
      { id: '1', dayIndex: 0, time: '10:00', title: 'Arrival at Narita', location: 'NRT Terminal 1', category: 'Transport' as Category },
      { id: '2', dayIndex: 0, time: '13:30', title: 'Lunch at Ichiran', location: 'Shinjuku', category: 'Food' as Category },
      { id: '3', dayIndex: 0, time: '15:00', title: 'Hotel Check-in', location: 'Shinjuku Prince Hotel', category: 'Stay' as Category },
      { id: '4', dayIndex: 1, time: '09:00', title: 'DisneySea!', location: 'Urayasu', category: 'Attraction' as Category },
    ];
  });

  const [selectedDay, setSelectedDay] = useState(0);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [loadingWeather, setLoadingWeather] = useState(false);

  // Persistence
  useEffect(() => {
    localStorage.setItem('tripConfig', JSON.stringify(config));
  }, [config]);

  useEffect(() => {
    localStorage.setItem('itinerary', JSON.stringify(itinerary));
  }, [itinerary]);

  const countdown = useMemo(() => {
    const start = new Date(config.startDate).getTime();
    const now = new Date().getTime();
    const diff = Math.ceil((start - now) / (1000 * 60 * 60 * 24));
    return diff > 0 ? diff : 0;
  }, [config.startDate]);

  const days = useMemo(() => {
    return Array.from({ length: config.duration }, (_, i) => {
      const d = new Date(config.startDate);
      d.setDate(d.getDate() + i);
      return {
        index: i,
        date: d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        weekday: d.toLocaleDateString('en-US', { weekday: 'short' })
      };
    });
  }, [config.startDate, config.duration]);

  const fetchWeather = async () => {
    setLoadingWeather(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Provide the current real-time weather for ${config.region}. Return ONLY JSON with: temp (celsius string), condition (1-3 words), humidity (percentage string).`,
        config: { 
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json"
        }
      });

      const data = JSON.parse(response.text || '{}');
      setWeather({
        temp: data.temp || "22°C",
        condition: data.condition || "Partly Cloudy",
        humidity: data.humidity || "45%",
        source: "Live Grounding"
      });
    } catch (e) {
      console.error("Weather fetch failed", e);
      setWeather({ temp: "22°C", condition: "Sunny", humidity: "40%", source: "Mocked" });
    } finally {
      setLoadingWeather(false);
    }
  };

  useEffect(() => {
    fetchWeather();
  }, [config.region]);

  const dayItems = itinerary
    .filter(item => item.dayIndex === selectedDay)
    .sort((a, b) => a.time.localeCompare(b.time));

  const handleAddItem = (newItem: Omit<ScheduleItem, 'id' | 'dayIndex'>) => {
    const item: ScheduleItem = {
      ...newItem,
      id: Date.now().toString(),
      dayIndex: selectedDay
    };
    setItinerary([...itinerary, item]);
    setIsAddModalOpen(false);
  };

  return (
    <div className="space-y-6 pb-20 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Header Info */}
      <div className="flex justify-between items-end px-1">
        <div>
          <h2 className="text-sm font-black text-navy/40 uppercase tracking-[0.2em] mb-1">{config.region}</h2>
          <p className="text-2xl font-black text-navy">{days[selectedDay]?.date}, {days[selectedDay]?.weekday}</p>
        </div>
        <button 
          onClick={() => setIsSettingsOpen(true)}
          className="w-10 h-10 bg-white rounded-full sticker-shadow border border-accent flex items-center justify-center text-navy active:scale-90 transition-transform"
        >
          <Settings size={20} />
        </button>
      </div>

      {/* Countdown & Weather */}
      <div className="grid grid-cols-5 gap-3">
        <div className="col-span-3 bg-stitch text-white p-5 rounded-2xl-sticker sticker-shadow relative overflow-hidden flex flex-col justify-center">
          <p className="text-[10px] font-black uppercase tracking-widest opacity-70">Countdown</p>
          <h2 className="text-3xl font-black">{countdown} Days</h2>
          <div className="text-5xl opacity-10 absolute -right-2 -bottom-2 transform rotate-12">🧳</div>
        </div>

        <div className="col-span-2 bg-white p-4 rounded-2xl-sticker sticker-shadow border border-accent flex flex-col items-center justify-center relative">
          {loadingWeather ? (
            <RefreshCw size={24} className="animate-spin text-stitch" />
          ) : (
            <>
              <Sun className="text-donald mb-1" size={24} />
              <p className="text-lg font-black text-navy leading-none">{weather?.temp}</p>
              <p className="text-[8px] font-bold text-navy/40 uppercase mt-1 text-center">{weather?.condition}</p>
            </>
          )}
          <button 
            onClick={fetchWeather}
            className="absolute top-1 right-1 p-1 text-navy/20 hover:text-stitch transition-colors"
          >
            <RefreshCw size={10} />
          </button>
        </div>
      </div>

      {/* Day Picker */}
      <div className="flex gap-2 overflow-x-auto pb-4 scrollbar-hide snap-x -mx-4 px-4">
        {days.map((day) => (
          <button
            key={day.index}
            onClick={() => setSelectedDay(day.index)}
            className={`flex-shrink-0 w-16 h-20 rounded-xl-sticker border-2 transition-all flex flex-col items-center justify-center snap-center ${
              selectedDay === day.index 
              ? 'bg-donald border-white sticker-shadow scale-105 z-10' 
              : 'bg-paper border-accent opacity-50'
            }`}
          >
            <p className="text-[10px] font-black opacity-40 leading-none mb-1">{day.weekday}</p>
            <p className="text-xl font-black leading-none">{day.date.split(' ')[1]}</p>
          </button>
        ))}
      </div>

      {/* Itinerary List */}
      <div className="space-y-6">
        {dayItems.length > 0 ? dayItems.map((item, idx) => (
          <div key={item.id} className="relative">
            {/* Travel Line */}
            {idx < dayItems.length - 1 && (
              <div className="absolute left-[2.45rem] top-16 bottom-0 w-0.5 border-l-2 border-dashed border-accent z-0" />
            )}

            <div className="flex gap-4 relative z-10">
              <div className="flex flex-col items-center pt-1">
                <div className="w-12 h-12 bg-white rounded-full border-2 border-accent flex items-center justify-center sticker-shadow flex-shrink-0">
                  <span className="text-xs font-black text-navy">{item.time}</span>
                </div>
              </div>

              <div className="flex-1">
                <div className="bg-paper p-4 rounded-xl-sticker sticker-shadow border border-accent active:scale-[0.98] transition-all">
                  <div className="flex justify-between items-start mb-2">
                    <span 
                      className="px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-wider text-white" 
                      style={{ backgroundColor: COLORS[item.category.toLowerCase() as keyof typeof COLORS] || COLORS.stitch }}
                    >
                      {item.category}
                    </span>
                    <button className="text-navy/20">
                      <ChevronRight size={14} />
                    </button>
                  </div>
                  <h3 className="font-bold text-navy leading-tight mb-2">{item.title}</h3>
                  <div className="flex items-center justify-between text-[10px] font-bold">
                    <div className="flex items-center gap-1 text-navy/40 truncate mr-2">
                      <MapPin size={10} className="flex-shrink-0" />
                      {item.location}
                    </div>
                    <a 
                      href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(item.location)}`}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="text-stitch flex items-center gap-1 whitespace-nowrap bg-stitch/5 px-2 py-1 rounded-md"
                    >
                      <Navigation size={10} />
                      MAP
                    </a>
                  </div>
                  {item.notes && (
                    <p className="mt-3 pt-3 border-t border-accent text-[10px] text-navy/60 italic leading-relaxed">
                      "{item.notes}"
                    </p>
                  )}
                </div>

                {/* Distance Badge (Mocked spacing) */}
                {idx < dayItems.length - 1 && (
                  <div className="my-4 flex justify-center">
                    <div className="bg-cream border border-accent px-3 py-1 rounded-full flex items-center gap-2">
                       <Clock size={10} className="text-navy/40" />
                       <span className="text-[9px] font-black text-navy/40 uppercase">15m travel • 1.2km</span>
                    </div>
                  </div>
                )}
              </div>
            </div>
          </div>
        )) : (
          <div className="py-20 text-center opacity-30 flex flex-col items-center">
            <div className="w-20 h-20 bg-accent/20 rounded-full flex items-center justify-center mb-4">
               <Info size={40} />
            </div>
            <p className="font-black text-lg">No plans for today!</p>
            <p className="text-sm font-bold mt-1">Tap the + to add a stop</p>
          </div>
        )}
      </div>

      {/* Settings Modal */}
      {isSettingsOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-navy/40 backdrop-blur-sm" onClick={() => setIsSettingsOpen(false)} />
          <div className="bg-paper w-full max-w-sm rounded-2xl-sticker p-6 sticker-shadow border-2 border-accent relative z-10 animate-in zoom-in-95 duration-200">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-black text-navy">Trip Settings</h3>
              <button onClick={() => setIsSettingsOpen(false)} className="text-navy/40"><X size={24} /></button>
            </div>
            <div className="space-y-4">
              <div>
                <label className="text-[10px] font-black uppercase text-navy/40 block mb-1">Destination Region</label>
                <input 
                  type="text" 
                  value={config.region} 
                  onChange={(e) => setConfig({...config, region: e.target.value})}
                  className="w-full p-3 bg-cream border border-accent rounded-xl font-bold text-navy focus:outline-none focus:ring-2 focus:ring-stitch"
                  placeholder="e.g. Kyoto, Japan"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] font-black uppercase text-navy/40 block mb-1">Start Date</label>
                  <input 
                    type="date" 
                    value={config.startDate} 
                    onChange={(e) => setConfig({...config, startDate: e.target.value})}
                    className="w-full p-3 bg-cream border border-accent rounded-xl font-bold text-navy text-xs"
                  />
                </div>
                <div>
                  <label className="text-[10px] font-black uppercase text-navy/40 block mb-1">Duration (Days)</label>
                  <input 
                    type="number" 
                    min="1"
                    max="30"
                    value={config.duration} 
                    onChange={(e) => setConfig({...config, duration: parseInt(e.target.value) || 1})}
                    className="w-full p-3 bg-cream border border-accent rounded-xl font-bold text-navy"
                  />
                </div>
              </div>
            </div>
            <button 
              onClick={() => setIsSettingsOpen(false)}
              className="w-full mt-8 py-4 bg-stitch text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-transform"
            >
              SAVE CHANGES
            </button>
          </div>
        </div>
      )}

      {/* Add Item Modal */}
      {isAddModalOpen && (
        <AddItemModal 
          onClose={() => setIsAddModalOpen(false)} 
          onAdd={handleAddItem}
        />
      )}

      {/* FAB Override for this module */}
      <button 
        className="fixed bottom-24 right-6 w-14 h-14 bg-donald text-navy rounded-full sticker-shadow flex items-center justify-center active:scale-95 transition-transform z-[55] border-2 border-paper"
        onClick={() => setIsAddModalOpen(true)}
      >
        <Plus size={32} />
      </button>
    </div>
  );
};

