                        <p className="text-xs font-bold">{booking.details.checkIn}</p>
                      </div>
                      <div>
                        <p className="text-[8px] font-black opacity-30 uppercase">Check-out</p>
                        <p className="text-xs font-bold">{booking.details.checkOut}</p>
                      </div>
                    </div>
                  </div>
                )}

                <div className="mt-2 flex justify-between items-center pt-3 border-t border-accent/20">
                  <div className="flex gap-3">
                     {booking.details.time && (
                       <div className="flex items-center gap-1 text-[10px] font-bold text-navy/40">
                         <Clock size={10} /> {booking.details.time}
                       </div>
                     )}
                     {booking.details.seat && (
                       <div className="text-[10px] font-bold text-navy/40 uppercase">Seat: {booking.details.seat}</div>
                     )}
                  </div>
                  {booking.cost > 0 && (
                    <span className="text-sm font-black text-stitch">¥{booking.cost.toLocaleString()}</span>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      ) : (
        <div className="py-20 text-center opacity-30 flex flex-col items-center border-2 border-dashed border-accent rounded-2xl">
          <TicketIcon size={48} className="mb-4" />
          <p className="font-black text-lg">No Bookings Yet</p>
          <p className="text-sm font-bold">Store your flight, hotel, and vouchers here!</p>
        </div>
      )}

      {isModalOpen && (
        <BookingFormModal 
          initialData={editingBooking} 
          onClose={() => setIsModalOpen(false)} 
          onSave={handleSave} 
        />
      )}
    </div>
  );
};

const BookingFormModal: React.FC<{ initialData: Booking | null; onClose: () => void; onSave: (b: Booking) => void }> = ({ initialData, onClose, onSave }) => {
  const [formData, setFormData] = useState<Partial<Booking>>(initialData || {
    type: 'Hotel',
    title: '',
    cost: 0,
    imageUrl: '',
    details: {}
  });

  const [imagePreview, setImagePreview] = useState<string>(initialData?.imageUrl || '');

  const types: Booking['type'][] = ['Flight', 'Hotel', 'Car', 'Restaurant', 'Ticket'];

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setImagePreview(base64);
        setFormData({ ...formData, imageUrl: base64 });
      };
      reader.readAsDataURL(file);
    }
  };

  const updateDetail = (key: string, value: any) => {
    setFormData({
      ...formData,
      details: { ...formData.details, [key]: value }
    });
  };

  return (
    <div className="fixed inset-0 z-[70] flex flex-col bg-cream animate-in slide-in-from-bottom duration-300">
      <div className="p-4 flex justify-between items-center border-b border-accent bg-paper">
        <button onClick={onClose} className="text-navy/40 p-2"><X size={24} /></button>
        <h3 className="text-lg font-black text-navy uppercase tracking-widest">{initialData ? 'Edit Booking' : 'Add Booking'}</h3>
        <button 
          onClick={() => onSave(formData as Booking)} 
          className="text-stitch font-black p-2"
          disabled={!formData.title}
        >
          DONE
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-5">
        {/* Image Upload Area */}
        <div 
          className="w-full aspect-video bg-white rounded-2xl-sticker sticker-shadow border-2 border-dashed border-accent flex flex-col items-center justify-center relative overflow-hidden group cursor-pointer"
          onClick={() => document.getElementById('imageInput')?.click()}
        >
          {imagePreview ? (
            <img src={imagePreview} alt="Preview" className="w-full h-full object-cover" />
          ) : (
            <div className="flex flex-col items-center text-navy/20">
              <Camera size={40} />
              <p className="text-xs font-black mt-2 uppercase">Upload Voucher / Photo</p>
            </div>
          )}
          <input id="imageInput" type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
          {imagePreview && (
            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity">
              <span className="text-white text-xs font-black uppercase">Change Photo</span>
            </div>
          )}
        </div>

        <div className="bg-paper p-4 rounded-xl border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">Booking Type</label>
          <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
            {types.map(t => (
              <button
                key={t}
                onClick={() => setFormData({ ...formData, type: t })}
                className={`flex-shrink-0 px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${
                  formData.type === t ? 'bg-stitch text-white sticker-shadow' : 'bg-accent/20 text-navy/40 border border-accent/30'
                }`}
              >
                {t}
              </button>
            ))}
          </div>
        </div>

        <div className="bg-paper p-4 rounded-xl border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">Booking Title</label>
          <input 
            type="text" 
            value={formData.title} 
            onChange={e => setFormData({ ...formData, title: e.target.value })} 
            placeholder="e.g. Pacific Air CX504" 
            className="w-full text-lg font-black bg-transparent border-none p-0 focus:ring-0 text-navy" 
          />
        </div>

        {/* Dynamic Details based on Type */}
        {formData.type === 'Flight' && (
          <div className="grid grid-cols-2 gap-4">
            <div className="bg-paper p-4 rounded-xl border border-accent sticker-shadow">
              <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">From</label>
              <input type="text" value={formData.details.from || ''} onChange={e => updateDetail('from', e.target.value.toUpperCase())} placeholder="HKG" className="w-full font-black bg-transparent border-none p-0 focus:ring-0" />
            </div>
            <div className="bg-paper p-4 rounded-xl border border-accent sticker-shadow">
              <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">To</label>
              <input type="text" value={formData.details.to || ''} onChange={e => updateDetail('to', e.target.value.toUpperCase())} placeholder="NRT" className="w-full font-black bg-transparent border-none p-0 focus:ring-0" />
            </div>
          </div>
        )}

        {formData.type === 'Hotel' && (
          <div className="space-y-4">
            <div className="bg-paper p-4 rounded-xl border border-accent sticker-shadow">
              <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">Address</label>
              <input type="text" value={formData.details.address || ''} onChange={e => updateDetail('address', e.target.value)} placeholder="Hotel Address" className="w-full font-bold bg-transparent border-none p-0 focus:ring-0" />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="bg-paper p-4 rounded-xl border border-accent sticker-shadow">
                <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">Check-in</label>
                <input type="text" value={formData.details.checkIn || ''} onChange={e => updateDetail('checkIn', e.target.value)} placeholder="Oct 12" className="w-full font-black bg-transparent border-none p-0 focus:ring-0" />
              </div>
              <div className="bg-paper p-4 rounded-xl border border-accent sticker-shadow">
                <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">Check-out</label>
                <input type="text" value={formData.details.checkOut || ''} onChange={e => updateDetail('checkOut', e.target.value)} placeholder="Oct 17" className="w-full font-black bg-transparent border-none p-0 focus:ring-0" />
              </div>
            </div>
          </div>
        )}

        <div className="grid grid-cols-2 gap-4">
          <div className="bg-paper p-4 rounded-xl border border-accent sticker-shadow">
            <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">Date</label>
            <input type="text" value={formData.details.date || ''} onChange={e => updateDetail('date', e.target.value)} placeholder="Oct 12" className="w-full font-black bg-transparent border-none p-0 focus:ring-0" />
          </div>
          <div className="bg-paper p-4 rounded-xl border border-accent sticker-shadow">
            <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">Total Cost (¥)</label>
            <input 
              type="number" 
              value={formData.cost} 
              onChange={e => setFormData({ ...formData, cost: parseInt(e.target.value) || 0 })} 
              className="w-full font-black bg-transparent border-none p-0 focus:ring-0" 
            />
          </div>
        </div>

        <div className="bg-paper p-4 rounded-xl border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">Specific Details (Seat/Gate/Notes)</label>
          <div className="flex gap-4">
            <input type="text" value={formData.details.seat || ''} onChange={e => updateDetail('seat', e.target.value)} placeholder="Seat: 24A" className="w-1/2 font-bold bg-transparent border-none p-0 focus:ring-0" />
            <input type="text" value={formData.details.time || ''} onChange={e => updateDetail('time', e.target.value)} placeholder="Time: 09:15" className="w-1/2 font-bold bg-transparent border-none p-0 focus:ring-0" />
          </div>
        </div>
      </div>
    </div>
  );
};

export default Bookings;

export type Category = 'Attraction' | 'Food' | 'Transport' | 'Stay' | 'Other';

export interface TripMember {
  id: string;
  name: string;
  avatar: string;
}

export interface ScheduleItem {
  id: string;
  dayIndex: number;
  time: string;
  title: string;
  location: string;
  category: Category;
  notes?: string;
  photo?: string;
  distanceInfo?: string; // e.g. "2.4km, 15 min walk"
}

export interface Booking {
  id: string;
  type: 'Flight' | 'Hotel' | 'Car' | 'Restaurant' | 'Amusement' | 'Ticket';
  title: string;
  details: any;
  cost: number;
  imageUrl?: string;
}

export interface Expense {
  id: string;
  amount: number;
