      },
      {
        id: '2',
        type: 'Hotel',
        title: 'Grand Stay Tokyo',
        cost: 45000,
        imageUrl: 'https://picsum.photos/seed/hotel/600/400',
        details: { address: 'Shinjuku, Tokyo', checkIn: '12 OCT', checkOut: '17 OCT', room: 'Deluxe Twin' }
      },
      {
        id: '3',
        type: 'Amusement',
        title: 'DisneySea 1-Day Pass',
