               </div>
            </div>
            <div className="mt-4 pt-4 border-t border-white/30 flex justify-between items-center">
               <div className="w-1/2 h-4 bg-navy/10 rounded flex items-center justify-around">
                  {Array.from({length: 12}).map((_, i) => <div key={i} className="w-0.5 h-3 bg-navy/20" />)}
               </div>
               {booking.cost > 0 && <span className="text-sm font-black text-navy">¥{booking.cost.toLocaleString()}</span>}
            </div>
          </div>
        );

      default:
        return (
          <div className="bg-paper p-5 rounded-xl-sticker sticker-shadow border border-accent group">
            <div className="flex justify-between mb-2">
               <div className="flex items-center gap-2">
                 <TicketIcon size={16} className="text-stitch" />
                 <span className="text-[10px] font-black uppercase tracking-widest opacity-40">{booking.type}</span>
               </div>
               <div className="flex gap-2">
                  <button onClick={() => { setEditingBooking(booking); setIsModalOpen(true); }} className="p-1 text-navy/20 hover:text-stitch transition-colors"><Edit2 size={14} /></button>
                  <button onClick={() => handleDelete(booking.id)} className="p-1 text-navy/20 hover:text-red-400 transition-colors"><Trash2 size={14} /></button>
               </div>
            </div>
            <h3 className="text-lg font-black text-navy">{booking.title}</h3>
            {booking.cost > 0 && <p className="text-xs font-black text-stitch mt-2">¥{booking.cost.toLocaleString()}</p>}
          </div>
        );
    }
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500">
      <div className="flex justify-between items-center px-1">
        <h2 className="text-2xl font-black text-navy">Vouchers & Tickets</h2>
        <button 
          onClick={() => { setEditingBooking(null); setIsModalOpen(true); }}
          className="w-12 h-12 bg-donald rounded-full sticker-shadow border-2 border-white flex items-center justify-center text-navy active:scale-90 transition-transform shadow-lg"
        >
          <Plus size={28} />
        </button>
      </div>

      {bookings.length > 0 ? (
        <div className="space-y-6">
          {bookings.map((booking) => (
            <div key={booking.id}>
              {renderBookingCard(booking)}
            </div>
          ))}
        </div>
      ) : (
        <div className="py-20 text-center opacity-30 flex flex-col items-center border-2 border-dashed border-accent rounded-2xl">
          <TicketIcon size={48} className="mb-4" />
          <p className="font-black text-lg">Empty Pocket</p>
          <p className="text-sm font-bold">Add your travel tickets here!</p>
        </div>
      )}

      {isModalOpen && (
        <BookingFormModal 
          initialData={editingBooking} 
          onClose={() => setIsModalOpen(false)} 
          onSave={handleSave} 
        />
      )}
    </div>
  );
};

const BookingFormModal: React.FC<{ initialData: Booking | null; onClose: () => void; onSave: (b: Booking) => void }> = ({ initialData, onClose, onSave }) => {
  const [formData, setFormData] = useState<Partial<Booking>>(initialData || {
    type: 'Hotel',
    title: '',
    cost: 0,
    imageUrl: '',
    details: {}
  });

  const [imagePreview, setImagePreview] = useState<string>(initialData?.imageUrl || '');

  const types: Booking['type'][] = ['Flight', 'Hotel', 'Car', 'Restaurant', 'Amusement', 'Ticket'];

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setImagePreview(base64);
        setFormData({ ...formData, imageUrl: base64 });
      };
      reader.readAsDataURL(file);
    }
  };

  const updateDetail = (key: string, value: any) => {
    setFormData({
      ...formData,
      details: { ...formData.details, [key]: value }
    });
  };

  return (
    <div className="fixed inset-0 z-[70] flex flex-col bg-cream animate-in slide-in-from-bottom duration-300">
      <div className="p-4 flex justify-between items-center border-b border-accent bg-paper">
        <button onClick={onClose} className="text-navy/40 p-2"><X size={24} /></button>
        <h3 className="text-lg font-black text-navy uppercase tracking-widest">{initialData ? 'Edit Entry' : 'New Ticket'}</h3>
        <button onClick={() => onSave(formData as Booking)} className="text-stitch font-black p-2" disabled={!formData.title}>DONE</button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-5 pb-10">
        <div 
          className="w-full aspect-video bg-white rounded-2xl-sticker sticker-shadow border-2 border-dashed border-accent flex flex-col items-center justify-center relative overflow-hidden cursor-pointer"
          onClick={() => document.getElementById('imageInput')?.click()}
        >
          {imagePreview ? (
            <img src={imagePreview} alt="Preview" className="w-full h-full object-cover" />
          ) : (
            <div className="flex flex-col items-center text-navy/20">
              <Camera size={40} />
              <p className="text-xs font-black mt-2 uppercase">Voucher Snapshot</p>
            </div>
          )}
          <input id="imageInput" type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
        </div>

        <div className="bg-paper p-4 rounded-xl border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/40 mb-2 block">Category</label>
          <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
            {types.map(t => (
              <button
                key={t}
                onClick={() => setFormData({ ...formData, type: t })}
                className={`flex-shrink-0 px-4 py-2 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${
                  formData.type === t ? 'bg-navy text-white sticker-shadow' : 'bg-accent/20 text-navy/40'
                }`}
              >
                {t}
              </button>
            ))}
          </div>
        </div>

        <div className="bg-paper p-4 rounded-xl border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">Title</label>
          <input type="text" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} placeholder="e.g. DisneySea Entry" className="w-full text-lg font-black bg-transparent border-none p-0 focus:ring-0 text-navy" />
        </div>

        {/* Dynamic Fields */}
        {formData.type === 'Flight' && (
          <div className="space-y-4">
             <div className="grid grid-cols-2 gap-4">
                <input type="text" value={formData.details.from || ''} onChange={e => updateDetail('from', e.target.value.toUpperCase())} placeholder="FROM: HKG" className="p-4 bg-paper rounded-xl border border-accent font-black text-center" />
                <input type="text" value={formData.details.to || ''} onChange={e => updateDetail('to', e.target.value.toUpperCase())} placeholder="TO: NRT" className="p-4 bg-paper rounded-xl border border-accent font-black text-center" />
             </div>
             <div className="grid grid-cols-2 gap-4">
                <input type="text" value={formData.details.date || ''} onChange={e => updateDetail('date', e.target.value)} placeholder="DATE" className="p-4 bg-paper rounded-xl border border-accent font-bold" />
                <input type="text" value={formData.details.time || ''} onChange={e => updateDetail('time', e.target.value)} placeholder="TIME" className="p-4 bg-paper rounded-xl border border-accent font-bold" />
             </div>
             <div className="grid grid-cols-2 gap-4">
                <input type="text" value={formData.details.seat || ''} onChange={e => updateDetail('seat', e.target.value)} placeholder="SEAT" className="p-4 bg-paper rounded-xl border border-accent font-bold" />
                <input type="text" value={formData.details.gate || ''} onChange={e => updateDetail('gate', e.target.value)} placeholder="GATE" className="p-4 bg-paper rounded-xl border border-accent font-bold" />
             </div>
          </div>
        )}

        {formData.type === 'Hotel' && (
          <div className="space-y-4">
             <input type="text" value={formData.details.address || ''} onChange={e => updateDetail('address', e.target.value)} placeholder="ADDRESS" className="w-full p-4 bg-paper rounded-xl border border-accent font-bold" />
             <div className="grid grid-cols-2 gap-4">
                <input type="text" value={formData.details.checkIn || ''} onChange={e => updateDetail('checkIn', e.target.value)} placeholder="CHECK IN" className="p-4 bg-paper rounded-xl border border-accent font-bold" />
                <input type="text" value={formData.details.checkOut || ''} onChange={e => updateDetail('checkOut', e.target.value)} placeholder="CHECK OUT" className="p-4 bg-paper rounded-xl border border-accent font-bold" />
             </div>
          </div>
        )}

        {formData.type === 'Restaurant' && (
          <div className="grid grid-cols-2 gap-4">
             <input type="text" value={formData.details.date || ''} onChange={e => updateDetail('date', e.target.value)} placeholder="DATE" className="p-4 bg-paper rounded-xl border border-accent font-bold" />
             <input type="text" value={formData.details.time || ''} onChange={e => updateDetail('time', e.target.value)} placeholder="TIME" className="p-4 bg-paper rounded-xl border border-accent font-bold" />
             <input type="number" value={formData.details.pax || ''} onChange={e => updateDetail('pax', e.target.value)} placeholder="PAX" className="p-4 bg-paper rounded-xl border border-accent font-bold" />
          </div>
        )}

        <div className="bg-paper p-4 rounded-xl border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">Cost (¥)</label>
          <input type="number" value={formData.cost} onChange={e => setFormData({ ...formData, cost: parseInt(e.target.value) || 0 })} className="w-full font-black bg-transparent border-none p-0 focus:ring-0" />
        </div>
      </div>
    </div>
  );
};

