import React, { useState, useEffect } from 'react';
import { TripMember, Expense as ExpenseType } from '../types';
import { CURRENCY_RATES } from '../constants';
import { 
  TrendingDown, 
  CreditCard, 
  Plus, 
  Trash2, 
  Edit2, 
  X, 
  Check, 
  Users,
  ArrowRight,
  Calculator
} from 'lucide-react';

const Expense: React.FC<{ currentUser: TripMember; members: TripMember[] }> = ({ currentUser, members }) => {
  const [expenses, setExpenses] = useState<ExpenseType[]>(() => {
    const saved = localStorage.getItem('expenses');
    return saved ? JSON.parse(saved) : [
      { id: '1', amount: 3500, currency: 'JPY', category: 'Dinner', paidBy: '1', splitWith: ['1', '2', '3', '4'], date: new Date().toISOString().split('T')[0] },
      { id: '2', amount: 12000, currency: 'JPY', category: 'Trains', paidBy: '2', splitWith: ['1', '2', '3', '4'], date: new Date().toISOString().split('T')[0] },
    ];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettlementOpen, setIsSettlementOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<ExpenseType | null>(null);

  useEffect(() => {
    localStorage.setItem('expenses', JSON.stringify(expenses));
  }, [expenses]);

  const handleDelete = (id: string) => {
    if (confirm('Delete this expense?')) {
      setExpenses(expenses.filter(e => e.id !== id));
    }
  };

  const handleSave = (expense: ExpenseType) => {
    if (editingExpense) {
      setExpenses(expenses.map(e => e.id === expense.id ? expense : e));
    } else {
      setExpenses([{ ...expense, id: Date.now().toString() }, ...expenses]);
    }
    setIsModalOpen(false);
    setEditingExpense(null);
  };

  const totalSpentJPY = expenses.reduce((acc, exp) => acc + (exp.amount * CURRENCY_RATES[exp.currency]), 0);

  // Settlement Calculation logic
  const calculateBalances = () => {
    const balances: Record<string, number> = {};
    members.forEach(m => balances[m.id] = 0);

    expenses.forEach(exp => {
      const amountJPY = exp.amount * CURRENCY_RATES[exp.currency];
      const share = amountJPY / exp.splitWith.length;

      // Payer gets back the full amount
      balances[exp.paidBy] += amountJPY;

      // Everyone splitting owes their share
      exp.splitWith.forEach(id => {
        balances[id] -= share;
      });
    });

    return balances;
  };

  const balances = calculateBalances();

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500">
      {/* Dashboard Card */}
      <div className="bg-donald p-6 rounded-2xl-sticker sticker-shadow border-2 border-paper relative overflow-hidden">
        <div className="absolute top-0 right-0 w-24 h-24 bg-paper/10 rounded-full -mr-10 -mt-10 blur-2xl" />
        <p className="text-navy/60 text-[10px] font-black uppercase tracking-[0.2em] mb-1">Total Trip Spending</p>
        <h2 className="text-4xl font-black text-navy mb-6">¥{totalSpentJPY.toLocaleString()}</h2>

        <div className="flex gap-3">
          <button 
            onClick={() => { setEditingExpense(null); setIsModalOpen(true); }}
            className="flex-1 bg-navy text-white py-3 rounded-xl-sticker font-black text-xs flex items-center justify-center gap-2 sticker-shadow active:scale-95 transition-all"
          >
            <Plus size={16} /> ADD EXPENSE
          </button>
          <button 
            onClick={() => setIsSettlementOpen(true)}
            className="flex-1 bg-paper text-navy py-3 rounded-xl-sticker font-black text-xs flex items-center justify-center gap-2 sticker-shadow active:scale-95 transition-all"
          >
            <Calculator size={16} /> SETTLEMENT
          </button>
        </div>
      </div>

      {/* Quick Converter */}
      <div className="grid grid-cols-2 gap-3">
        <div className="bg-paper p-3 rounded-xl-sticker sticker-shadow border border-accent flex justify-between items-center">
          <span className="text-[8px] font-black opacity-30 uppercase">100 HKD</span>
          <span className="font-bold text-xs">¥1,900</span>
        </div>
        <div className="bg-paper p-3 rounded-xl-sticker sticker-shadow border border-accent flex justify-between items-center">
          <span className="text-[8px] font-black opacity-30 uppercase">1 AUD</span>
          <span className="font-bold text-xs">¥95</span>
        </div>
      </div>

      {/* History List */}
      <div className="space-y-4">
        <h3 className="text-lg font-black px-1 text-navy uppercase tracking-widest">History</h3>
        {expenses.length > 0 ? expenses.map((exp) => {
          const payer = members.find(m => m.id === exp.paidBy);
          return (
            <div key={exp.id} className="bg-white p-4 rounded-xl-sticker sticker-shadow border border-accent flex items-center gap-4 group animate-in slide-in-from-bottom-2 duration-300">
              <div className="w-10 h-10 rounded-full border-2 border-accent overflow-hidden flex-shrink-0 bg-cream">
                <img src={payer?.avatar} alt={payer?.name} className="w-full h-full object-cover" />
              </div>
              <div className="flex-1 min-w-0">
                <h4 className="font-black text-navy truncate">{exp.category}</h4>
                <div className="flex items-center gap-1 text-[9px] font-bold text-navy/30 uppercase">
                  <span>{payer?.name} Paid</span>
                  <ArrowRight size={8} />
                  <span>{exp.splitWith.length} Shared</span>
                </div>
              </div>
              <div className="text-right flex flex-col items-end gap-1">
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => { setEditingExpense(exp); setIsModalOpen(true); }} className="text-navy/20 hover:text-stitch p-1"><Edit2 size={14} /></button>
                  <button onClick={() => handleDelete(exp.id)} className="text-navy/20 hover:text-red-400 p-1"><Trash2 size={14} /></button>
                </div>
                <p className="font-black text-navy leading-none">
                  {exp.currency} {exp.amount.toLocaleString()}
                </p>
                {exp.currency !== 'JPY' && (
                  <p className="text-[8px] font-bold text-stitch leading-none">
                    ≈ ¥{(exp.amount * CURRENCY_RATES[exp.currency]).toLocaleString()}
                  </p>
                )}
              </div>
            </div>
          );
        }) : (
          <div className="py-12 text-center opacity-20 border-2 border-dashed border-accent rounded-2xl">
            <CreditCard size={48} className="mx-auto mb-2" />
            <p className="font-black">No expenses yet</p>
          </div>
        )}
      </div>

      {/* Settlement Summary Preview */}
      <div className="bg-white p-5 rounded-2xl-sticker sticker-shadow border border-accent">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
            <TrendingDown size={18} className="text-red-400" />
            <h4 className="text-xs font-black uppercase tracking-widest text-navy">Balances</h4>
          </div>
          <button onClick={() => setIsSettlementOpen(true)} className="text-[10px] font-black text-stitch uppercase underline">Detailed Calculation</button>
        </div>
        <div className="space-y-2">
          {members.map(m => (
            <div key={m.id} className="flex justify-between items-center">
              <span className="text-xs font-bold text-navy/60">{m.name}</span>
              <span className={`text-xs font-black ${balances[m.id] >= 0 ? 'text-green-500' : 'text-red-400'}`}>
                {balances[m.id] >= 0 ? '+' : ''}¥{Math.round(balances[m.id]).toLocaleString()}
              </span>
            </div>
          ))}
        </div>
      </div>

      {/* Add/Edit Modal */}
      {isModalOpen && (
        <ExpenseModal 
          expense={editingExpense} 
          members={members} 
          onClose={() => setIsModalOpen(false)} 
          onSave={handleSave} 
        />
      )}

      {/* Settlement Detail Modal */}
      {isSettlementOpen && (
        <SettlementModal 
          members={members} 
          balances={balances} 
          onClose={() => setIsSettlementOpen(false)} 
        />
      )}
    </div>
  );
};

const ExpenseModal: React.FC<{ 
