                  <span className="text-xs font-black text-navy">{m.name}</span>
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

const SettlementModal: React.FC<{ 
  members: TripMember[]; 
  balances: Record<string, number>; 
  onClose: () => void 
}> = ({ members, balances, onClose }) => {

  const getDebts = () => {
    const list = members.map(m => ({ id: m.id, name: m.name, bal: balances[m.id] }));
    const payers = list.filter(m => m.bal > 1).sort((a, b) => b.bal - a.bal);
    const owers = list.filter(m => m.bal < -1).sort((a, b) => a.bal - b.bal);
    const debts: Array<{ from: string; to: string; amount: number }> = [];

    let pIdx = 0, oIdx = 0;
    while (pIdx < payers.length && oIdx < owers.length) {
      const payer = payers[pIdx];
      const ower = owers[oIdx];
      const amount = Math.min(payer.bal, Math.abs(ower.bal));

      debts.push({ from: ower.name, to: payer.name, amount });

      payer.bal -= amount;
      ower.bal += amount;

      if (payer.bal < 1) pIdx++;
      if (ower.bal > -1) oIdx++;
    }
    return debts;
  };

  const debts = getDebts();

  return (
    <div className="fixed inset-0 z-[120] flex items-center justify-center p-4 bg-navy/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="bg-paper w-full max-w-sm rounded-[2rem] sticker-shadow border-4 border-accent p-8 animate-in zoom-in-95 max-h-[90vh] overflow-y-auto">
        <div className="flex justify-between items-center mb-8">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-stitch/10 rounded-xl text-stitch"><Calculator size={24} /></div>
            <div>
              <h3 className="text-2xl font-black text-navy leading-none">Settlement</h3>
              <p className="text-[10px] font-bold text-navy/30 uppercase mt-1 tracking-widest">Balance Breakdown</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
        </div>

        <div className="space-y-8">
          {/* Member Status */}
          <div className="space-y-4">
            <p className="text-[10px] font-black uppercase text-navy/30 tracking-[0.2em] border-b border-accent/30 pb-1">Current Balances</p>
            {members.map(m => (
              <div key={m.id} className="flex justify-between items-center">
                <div className="flex items-center gap-4">
                  <img src={m.avatar} alt={m.name} className="w-10 h-10 rounded-full object-cover border-2 border-accent" />
                  <span className="text-sm font-black text-navy">{m.name}</span>
                </div>
                <div className="text-right">
                  <p className={`text-base font-black ${balances[m.id] >= 0 ? 'text-green-500' : 'text-red-400'}`}>
                    ¥{Math.round(Math.abs(balances[m.id])).toLocaleString()}
                  </p>
                  <p className="text-[8px] font-black uppercase opacity-40">
                    {balances[m.id] >= 0 ? 'Receivable (應收)' : 'Payable (應付)'}
                  </p>
                </div>
              </div>
            ))}
          </div>

          {/* Solution */}
          <div className="bg-stitch/5 p-6 rounded-3xl border-2 border-dashed border-stitch/30">
            <p className="text-[10px] font-black uppercase text-stitch tracking-[0.2em] mb-4">Clearing the Debts</p>
            {debts.length > 0 ? (
              <div className="space-y-3">
                {debts.map((d, i) => (
                  <div key={i} className="flex items-center justify-between text-xs bg-white p-4 rounded-2xl border border-stitch/20 sticker-shadow-sm">
                    <span className="font-black text-red-400 text-center w-16">{d.from}</span>
                    <div className="flex flex-col items-center flex-1 px-3">
                      <span className="text-xs font-black text-navy mb-1">¥{Math.round(d.amount).toLocaleString()}</span>
                      <div className="w-full h-0.5 bg-accent/50 relative rounded-full overflow-hidden">
                        <div className="absolute top-0 left-0 h-full w-full bg-stitch/30 animate-pulse" />
                      </div>
                    </div>
                    <span className="font-black text-green-500 text-center w-16">{d.to}</span>
                  </div>
                ))}
              </div>
            ) : (
              <div className="text-center py-6">
                <p className="text-3xl mb-2">🎉</p>
                <p className="text-xs font-black text-navy/40">Everyone is fully square!</p>
              </div>
            )}
          </div>
        </div>

        <button 
          onClick={onClose}
          className="w-full mt-10 py-5 bg-stitch text-white font-black rounded-2xl-sticker sticker-shadow active:scale-95 transition-all uppercase tracking-widest text-sm"
        >
          Got It, Thanks!
        </button>
      </div>
    </div>
  );
};

