                  <Share2 size={12} /> SHARE
                </button>
                {isAuthor && (
                  <button onClick={() => { onEdit(); setShowMenu(false); }} className="w-full px-4 py-2 text-left text-xs font-black text-navy hover:bg-cream flex items-center gap-2">
