const JournalModal: React.FC<{ 
  currentUser: TripMember;
  members: TripMember[];
  initialData: JournalPost | null; 
  onClose: () => void; 
  onSave: (p: JournalPost) => void 
}> = ({ currentUser, members, initialData, onClose, onSave }) => {
  const [content, setContent] = useState(initialData?.content || '');
  const [imagePreview, setImagePreview] = useState<string>(initialData?.imageUrl || '');
  const [selectedAuthorId, setSelectedAuthorId] = useState<string>(initialData?.authorId || currentUser.id);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleDone = () => {
    const post: JournalPost = {
      id: initialData?.id || Date.now().toString(),
      authorId: selectedAuthorId,
      content: content,
      imageUrl: imagePreview,
      date: initialData?.date || new Date().toLocaleString('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: 'numeric', hour12: true })
    };
    onSave(post);
  };

  return (
    <div className="fixed inset-0 z-[70] flex flex-col bg-cream animate-in slide-in-from-bottom duration-300">
      <div className="p-4 flex justify-between items-center border-b border-accent bg-paper">
        <button onClick={onClose} className="text-navy/40 p-2 active:scale-90"><X size={24} /></button>
        <h3 className="text-lg font-black text-navy uppercase tracking-widest">{initialData ? 'Edit Entry' : 'New Journal'}</h3>
        <button 
          onClick={handleDone} 
          className="text-stitch font-black p-2 active:scale-90 disabled:opacity-30"
          disabled={!content.trim()}
        >
          <Send size={24} />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {/* Post Composition */}
        <div className="bg-paper p-5 rounded-3xl-sticker border border-accent sticker-shadow flex flex-col min-h-[180px]">
          <textarea 
            autoFocus
            value={content}
            onChange={(e) => setContent(e.target.value)}
            placeholder="Record a memory... #JapanTrip"
            className="flex-1 w-full bg-transparent border-none focus:ring-0 p-0 text-navy placeholder:text-navy/20 text-lg leading-relaxed resize-none"
          />
        </div>

        {/* Member Selection - Included in Edit/New View */}
        <div className="space-y-3">
          <div className="flex items-center gap-2 px-1">
             <UserCircle2 size={14} className="text-navy/30" />
             <label className="text-[10px] font-black uppercase text-navy/30 tracking-widest">Post as</label>
          </div>
          <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
            {members.map((member) => (
              <button
                key={member.id}
                onClick={() => setSelectedAuthorId(member.id)}
                className={`flex-shrink-0 flex items-center gap-2 px-4 py-2 rounded-full transition-all border-2 ${
                  selectedAuthorId === member.id 
                    ? 'bg-navy border-navy text-white sticker-shadow scale-105' 
                    : 'bg-white border-accent text-navy opacity-60'
                }`}
              >
                <div className="relative">
                  <img src={member.avatar} alt={member.name} className="w-6 h-6 rounded-full object-cover border border-white/20" />
                  {selectedAuthorId === member.id && (
                    <div className="absolute -top-1 -right-1 bg-stitch rounded-full p-0.5 border border-white">
                      <Check size={8} className="text-white" />
                    </div>
                  )}
                </div>
                <span className="text-[10px] font-black uppercase tracking-tight">{member.name}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Photo Upload */}
        <div 
          className="w-full aspect-[4/3] bg-white rounded-3xl-sticker border-2 border-dashed border-accent flex flex-col items-center justify-center sticker-shadow relative overflow-hidden group transition-all active:scale-95"
          onClick={() => document.getElementById('imageInput')?.click()}
        >
          {imagePreview ? (
            <>
              <img src={imagePreview} alt="Preview" className="w-full h-full object-cover" />
              <div className="absolute inset-0 bg-black/20 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                 <Camera className="text-white" size={32} />
              </div>
              <button 
                onClick={(e) => { e.stopPropagation(); setImagePreview(''); }}
                className="absolute top-2 right-2 w-8 h-8 bg-white/80 backdrop-blur-sm rounded-full flex items-center justify-center text-red-500 shadow-lg"
              >
                <X size={16} />
              </button>
            </>
          ) : (
            <div className="flex flex-col items-center text-navy/20">
              <Camera size={48} />
              <p className="text-xs font-black mt-2 uppercase tracking-widest">Snap or Upload</p>
            </div>
          )}
          <input id="imageInput" type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
        </div>
      </div>

      <div className="p-8 bg-paper border-t border-accent flex flex-col items-center justify-center gap-1">
         <p className="text-[10px] font-black text-navy/20 uppercase tracking-[0.4em]">Stitch & Donald Adventure</p>
         <div className="w-12 h-1 bg-accent/30 rounded-full" />
      </div>
    </div>
  );
};

export default Journal;

import React, { useState, useEffect } from 'react';
import { TripMember, Expense as ExpenseType } from '../types';
import { 
  TrendingDown, 
  CreditCard, 
  Plus, 
  Trash2, 
  Edit2, 
  X, 
  Check, 
  Users,
  ArrowRight,
  Calculator,
  RefreshCw,
  Search,
  ArrowRightLeft,
  Calendar
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

const Expense: React.FC<{ currentUser: TripMember; members: TripMember[] }> = ({ currentUser, members }) => {
  const [expenses, setExpenses] = useState<ExpenseType[]>(() => {
    const saved = localStorage.getItem('expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [rates, setRates] = useState<Record<string, number>>({ JPY: 1, HKD: 19.2, AUD: 96.5 });
  const [loadingRates, setLoadingRates] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettlementOpen, setIsSettlementOpen] = useState(false);
  const [isCalcOpen, setIsCalcOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<ExpenseType | null>(null);

  // Sync to local storage
  useEffect(() => {
    localStorage.setItem('expenses', JSON.stringify(expenses));
  }, [expenses]);

  const fetchLiveRates = async () => {
    setLoadingRates(true);
    try {
      // Initialize GoogleGenAI with API key from environment variable
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: "What are the current mid-market exchange rates for 1 HKD to JPY and 1 AUD to JPY according to recent Wise or Google Finance data? Return ONLY JSON: {HKD: number, AUD: number}",
        config: { 
          tools: [{ googleSearch: {} }], 
          responseMimeType: "application/json" 
        }
      });
      // Access response.text as a property
      const data = JSON.parse(response.text || '{}');
      if (data.HKD && data.AUD) {
        setRates({ JPY: 1, HKD: data.HKD, AUD: data.AUD });
      }
    } catch (e) {
      console.error("Failed to fetch live rates", e);
    } finally {
      setLoadingRates(false);
    }
  };

  useEffect(() => { fetchLiveRates(); }, []);

  const totalSpentJPY = expenses.reduce((acc, exp) => acc + (exp.amount * (rates[exp.currency] || 1)), 0);

  const handleDelete = (id: string) => {
    if (confirm('Delete this expense?')) {
      setExpenses(expenses.filter(e => e.id !== id));
    }
  };

  const handleSave = (expense: ExpenseType) => {
    if (editingExpense) {
      setExpenses(expenses.map(e => e.id === expense.id ? expense : e));
    } else {
      setExpenses([{ ...expense, id: Date.now().toString() }, ...expenses]);
    }
    setIsModalOpen(false);
    setEditingExpense(null);
  };

  // Settlement Calculation
  const calculateBalances = () => {
    const balances: Record<string, number> = {};
    members.forEach(m => balances[m.id] = 0);

    expenses.forEach(exp => {
      const amountJPY = exp.amount * (rates[exp.currency] || 1);
      const share = amountJPY / exp.splitWith.length;
      balances[exp.paidBy] += amountJPY;
      exp.splitWith.forEach(id => {
        balances[id] -= share;
      });
    });
    return balances;
  };

  const balances = calculateBalances();

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500">
      {/* Dashboard Card */}
      <div className="bg-donald p-6 rounded-2xl-sticker sticker-shadow border-2 border-paper relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-paper/20 rounded-full -mr-16 -mt-16 blur-2xl" />
        <div className="flex justify-between items-start relative z-10">
          <div>
            <p className="text-navy/60 text-[10px] font-black uppercase tracking-[0.2em] mb-1">Trip Total Cost</p>
            <h2 className="text-4xl font-black text-navy">¥{Math.round(totalSpentJPY).toLocaleString()}</h2>
          </div>
          <button 
            onClick={fetchLiveRates}
            className={`p-2 bg-paper/40 rounded-full text-navy transition-all ${loadingRates ? 'animate-spin' : 'active:scale-90'}`}
          >
            <RefreshCw size={18} />
          </button>
        </div>

        <div className="mt-8 flex gap-3 relative z-10">
          <button 
            onClick={() => { setEditingExpense(null); setIsModalOpen(true); }}
            className="flex-1 bg-navy text-white py-4 rounded-xl-sticker font-black text-xs flex items-center justify-center gap-2 sticker-shadow active:scale-95 transition-all"
          >
            <Plus size={18} /> ADD
          </button>
          <button 
            onClick={() => setIsCalcOpen(true)}
            className="w-14 bg-paper text-navy py-4 rounded-xl-sticker font-black text-xs flex items-center justify-center sticker-shadow active:scale-95 transition-all"
          >
            <Calculator size={20} />
          </button>
        </div>
      </div>

      {/* Live Rates & Settlement Entry */}
      <div className="grid grid-cols-2 gap-3">
        <div className="bg-paper p-4 rounded-xl-sticker sticker-shadow border border-accent">
          <p className="text-[8px] font-black text-navy/30 uppercase tracking-widest mb-2">Live Exchange (Wise)</p>
          <div className="space-y-1">
            <div className="flex justify-between items-center text-xs font-bold text-navy">
              <span>1 HKD</span>
              <span className="text-stitch">¥{rates.HKD.toFixed(1)}</span>
            </div>
            <div className="flex justify-between items-center text-xs font-bold text-navy">
              <span>1 AUD</span>
              <span className="text-stitch">¥{rates.AUD.toFixed(1)}</span>
            </div>
          </div>
        </div>
        <button 
          onClick={() => setIsSettlementOpen(true)}
          className="bg-white p-4 rounded-xl-sticker sticker-shadow border border-accent flex flex-col justify-center items-center gap-1 active:scale-95 transition-all group"
        >
          <TrendingDown size={18} className="text-red-400 group-hover:scale-110 transition-transform" />
          <span className="text-[10px] font-black text-navy uppercase">Settlement</span>
        </button>
      </div>

      {/* History List */}
      <div className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <h3 className="text-lg font-black text-navy uppercase tracking-widest">History</h3>
          <span className="text-[10px] font-bold text-navy/30">{expenses.length} Records</span>
        </div>
        {expenses.length > 0 ? expenses.map((exp) => {
          const payer = members.find(m => m.id === exp.paidBy);
          return (
            <div key={exp.id} className="bg-white p-4 rounded-xl-sticker sticker-shadow border border-accent flex items-center gap-4 group animate-in slide-in-from-bottom-2 duration-300">
              <div className="w-12 h-12 rounded-full border-2 border-accent overflow-hidden flex-shrink-0 bg-cream">
                <img src={payer?.avatar} alt={payer?.name} className="w-full h-full object-cover" />
              </div>
              <div className="flex-1 min-w-0">
                <h4 className="font-black text-navy text-sm truncate">{exp.category}</h4>
                <div className="flex items-center gap-1 text-[9px] font-bold text-navy/30 uppercase mt-0.5">
                  <span className="text-stitch">{payer?.name}</span>
                  <span className="opacity-50">for</span>
                  <span>{exp.splitWith.length} Members</span>
                </div>
              </div>
              <div className="text-right flex flex-col items-end gap-1">
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => { setEditingExpense(exp); setIsModalOpen(true); }} className="text-navy/20 hover:text-stitch p-1"><Edit2 size={14} /></button>
                  <button onClick={() => handleDelete(exp.id)} className="text-navy/20 hover:text-red-400 p-1"><Trash2 size={14} /></button>
                </div>
                <p className="font-black text-navy leading-none">
                  {exp.currency} {exp.amount.toLocaleString()}
                </p>
                {exp.currency !== 'JPY' && (
                  <p className="text-[9px] font-bold text-stitch/60 leading-none">
                    ≈ ¥{Math.round(exp.amount * rates[exp.currency]).toLocaleString()}
                  </p>
                )}
              </div>
            </div>
          );
        }) : (
          <div className="py-20 text-center opacity-20 border-2 border-dashed border-accent rounded-3xl bg-paper/50">
            <CreditCard size={48} className="mx-auto mb-3" />
            <p className="font-black">No Expenses Recorded</p>
          </div>
        )}
      </div>

      {/* Calculator Tool */}
      {isCalcOpen && (
        <CalculatorTool 
          rates={rates} 
          onClose={() => setIsCalcOpen(false)} 
        />
      )}

      {/* Add/Edit Modal */}
      {isModalOpen && (
        <ExpenseModal 
          expense={editingExpense} 
          members={members} 
          rates={rates}
          onClose={() => setIsModalOpen(false)} 
          onSave={handleSave} 
        />
      )}

      {/* Settlement Detail Modal */}
      {isSettlementOpen && (
        <SettlementModal 
          members={members} 
          balances={balances} 
          onClose={() => setIsSettlementOpen(false)} 
        />
      )}
    </div>
  );
};

const CalculatorTool: React.FC<{ rates: Record<string, number>; onClose: () => void }> = ({ rates, onClose }) => {
  const [val, setVal] = useState('');
  const [cur, setCur] = useState<'HKD' | 'AUD'>('HKD');

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-navy/20 backdrop-blur-sm animate-in fade-in duration-300" onClick={onClose}>
      <div className="bg-paper w-full max-w-xs rounded-3xl-sticker p-6 sticker-shadow border-4 border-donald animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
        <div className="flex justify-between items-center mb-6">
          <div className="flex items-center gap-2">
            <ArrowRightLeft className="text-stitch" />
            <h3 className="text-lg font-black text-navy uppercase">Shopper Calc</h3>
          </div>
          <button onClick={onClose} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
        </div>

        <div className="space-y-6">
          <div className="flex bg-accent/20 p-1 rounded-xl">
            <button onClick={() => setCur('HKD')} className={`flex-1 py-2 rounded-lg text-[10px] font-black ${cur === 'HKD' ? 'bg-white text-navy sticker-shadow' : 'text-navy/40'}`}>HKD</button>
            <button onClick={() => setCur('AUD')} className={`flex-1 py-2 rounded-lg text-[10px] font-black ${cur === 'AUD' ? 'bg-white text-navy sticker-shadow' : 'text-navy/40'}`}>AUD</button>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black uppercase text-navy/30">Enter Foreign Price</label>
            <input 
              autoFocus
              type="number" 
              value={val}
              onChange={e => setVal(e.target.value)}
              placeholder="0.00"
              className="w-full text-4xl font-black text-navy border-b-4 border-accent focus:border-donald bg-transparent p-2 focus:ring-0 text-center"
            />
          </div>

          <div className="py-4 text-center">
            <p className="text-[10px] font-black uppercase text-navy/30 mb-1">Equals approximately</p>
            <h4 className="text-4xl font-black text-stitch">
              ¥ {val ? Math.round(parseFloat(val) * rates[cur]).toLocaleString() : '0'}
            </h4>
          </div>
        </div>

        <button 
          onClick={onClose}
          className="w-full mt-6 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all"
        >
          CLOSE
        </button>
      </div>
    </div>
  );
};

const ExpenseModal: React.FC<{ 
  expense: ExpenseType | null; 
  members: TripMember[]; 
  rates: Record<string, number>;
  onClose: () => void; 
  onSave: (e: ExpenseType) => void 
}> = ({ expense, members, rates, onClose, onSave }) => {
  const [formData, setFormData] = useState<Partial<ExpenseType>>(expense || {
    amount: 0,
    currency: 'JPY',
    category: '',
    paidBy: members[0].id,
    splitWith: members.map(m => m.id),
    date: new Date().toISOString().split('T')[0]
  });

  const toggleSplit = (id: string) => {
    const current = formData.splitWith || [];
    if (current.includes(id)) {
      setFormData({ ...formData, splitWith: current.filter(cid => cid !== id) });
    } else {
      setFormData({ ...formData, splitWith: [...current, id] });
    }
  };

  return (
    <div className="fixed inset-0 z-[110] flex flex-col bg-cream animate-in slide-in-from-bottom duration-300">
      <div className="p-4 flex justify-between items-center border-b border-accent bg-paper">
        <button onClick={onClose} className="text-navy/40 p-2"><X size={24} /></button>
        <h3 className="text-lg font-black text-navy uppercase tracking-widest">{expense ? 'Edit Record' : 'Add Expense'}</h3>
        <button 
          onClick={() => onSave(formData as ExpenseType)} 
          className="text-stitch font-black p-2 disabled:opacity-30"
          disabled={!formData.category || !formData.amount || formData.splitWith?.length === 0}
        >
          DONE
        </button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-20">
        {/* Amount Input */}
        <div className="bg-paper p-8 rounded-3xl-sticker sticker-shadow border border-accent text-center relative overflow-hidden">
          <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-stitch via-donald to-stitch opacity-50" />
          <label className="text-[10px] font-black uppercase text-navy/30 mb-3 block">Expense Amount</label>
          <div className="flex items-center justify-center gap-2">
            <select 
              value={formData.currency} 
              onChange={e => setFormData({...formData, currency: e.target.value as any})}
              className="text-2xl font-black text-stitch bg-transparent border-none focus:ring-0 cursor-pointer"
            >
              <option value="JPY">JPY ¥</option>
              <option value="HKD">HKD $</option>
              <option value="AUD">AUD $</option>
            </select>
            <input 
              type="number" 
              value={formData.amount || ''} 
              onChange={e => setFormData({...formData, amount: parseFloat(e.target.value) || 0})}
              placeholder="0"
              className="w-full text-5xl font-black text-navy bg-transparent border-none focus:ring-0 text-center"
              autoFocus
            />
          </div>
          {formData.currency !== 'JPY' && (
             <p className="mt-4 text-xs font-bold text-navy/40">
               ≈ JPY {Math.round((formData.amount || 0) * (rates[formData.currency || 'JPY'])).toLocaleString()}
             </p>
          )}
        </div>

        {/* Basic Info */}
        <div className="bg-paper p-5 rounded-2xl-sticker border border-accent sticker-shadow space-y-5">
          <div className="flex items-center gap-3">
            <Search size={18} className="text-navy/20" />
            <div className="flex-1 border-b border-accent pb-1">
              <label className="text-[10px] font-black uppercase text-navy/30 block mb-0.5">What was it for?</label>
              <input 
                type="text" 
                value={formData.category} 
                onChange={e => setFormData({...formData, category: e.target.value})}
                placeholder="Sushi, Souvenirs, Taxi..."
                className="w-full font-black text-navy border-none focus:ring-0 p-0 text-lg placeholder:text-navy/10"
              />
            </div>
          </div>
          <div className="flex items-center gap-3">
            <Calendar size={18} className="text-navy/20" />
            <div className="flex-1">
              <label className="text-[10px] font-black uppercase text-navy/30 block mb-0.5">Date</label>
              <input 
                type="date" 
                value={formData.date} 
                onChange={e => setFormData({...formData, date: e.target.value})}
                className="w-full font-black text-navy border-none focus:ring-0 p-0 text-lg"
              />
            </div>
          </div>
        </div>

        {/* Paid By Selection */}
        <div className="bg-paper p-5 rounded-2xl-sticker border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/30 mb-4 block">Paid By</label>
          <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide">
            {members.map(m => (
              <button
                key={m.id}
                onClick={() => setFormData({ ...formData, paidBy: m.id })}
                className={`flex-shrink-0 flex flex-col items-center gap-2 p-2 rounded-2xl transition-all border-2 ${
                  formData.paidBy === m.id ? 'bg-navy/5 border-navy' : 'border-transparent opacity-40'
                }`}
              >
                <img src={m.avatar} className="w-10 h-10 rounded-full object-cover" alt={m.name} />
                <span className="text-[10px] font-black uppercase">{m.name}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Split With Selection */}
        <div className="bg-paper p-5 rounded-2xl-sticker border border-accent sticker-shadow">
          <div className="flex justify-between items-center mb-4">
            <label className="text-[10px] font-black uppercase text-navy/30">Split With</label>
            <button 
              onClick={() => setFormData({ ...formData, splitWith: members.map(m => m.id) })}
              className="text-[9px] font-black text-stitch uppercase"
            >
              Select All
            </button>
          </div>
          <div className="grid grid-cols-2 gap-3">
            {members.map(m => {
              const isSelected = formData.splitWith?.includes(m.id);
              return (
                <button
                  key={m.id}
                  onClick={() => toggleSplit(m.id)}
                  className={`flex items-center gap-3 p-3 rounded-xl border-2 transition-all ${
                    isSelected ? 'bg-stitch border-stitch text-white' : 'bg-cream border-accent text-navy/40'
                  }`}
                >
                  <div className={`w-4 h-4 rounded border flex items-center justify-center ${isSelected ? 'bg-white border-white' : 'border-navy/10'}`}>
                    {isSelected && <Check size={12} className="text-stitch" />}
                  </div>
                  <span className="text-xs font-black uppercase">{m.name}</span>
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

