export default Expense;

import React, { useState, useEffect } from 'react';
import { TripMember, Expense as ExpenseType } from '../types';
import { 
  TrendingDown, 
  CreditCard, 
  Plus, 
  Trash2, 
  Edit2, 
  X, 
  Check, 
  Calculator, 
  RefreshCw, 
  Search, 
  ArrowRightLeft, 
  Calendar,
  Settings2,
  TrendingUp,
  DollarSign
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

const Expense: React.FC<{ currentUser: TripMember; members: TripMember[] }> = ({ currentUser, members }) => {
  const [expenses, setExpenses] = useState<ExpenseType[]>(() => {
    const saved = localStorage.getItem('expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [rates, setRates] = useState<Record<string, number>>({ JPY: 1, HKD: 19.2, AUD: 96.5 });
  const [loadingRates, setLoadingRates] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettlementOpen, setIsSettlementOpen] = useState(false);
  const [isCalcOpen, setIsCalcOpen] = useState(false);
  const [isCurrencySettingsOpen, setIsCurrencySettingsOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<ExpenseType | null>(null);

  useEffect(() => {
    localStorage.setItem('expenses', JSON.stringify(expenses));
  }, [expenses]);

  const fetchLiveRates = async () => {
    setLoadingRates(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: "Current exchange rates: 1 HKD to JPY and 1 AUD to JPY. Return ONLY JSON: {HKD: number, AUD: number}",
        config: { tools: [{ googleSearch: {} }], responseMimeType: "application/json" }
      });
      const data = JSON.parse(response.text || '{}');
      if (data.HKD && data.AUD) {
        setRates({ JPY: 1, HKD: data.HKD, AUD: data.AUD });
      }
    } catch (e) {
      console.error("Rates fetch failed", e);
    } finally {
      setLoadingRates(false);
    }
  };

  const calculateBalances = () => {
    const balances: Record<string, number> = {};
    members.forEach(m => balances[m.id] = 0);
    expenses.forEach(exp => {
      const amountJPY = exp.amount * (rates[exp.currency] || 1);
      const share = amountJPY / exp.splitWith.length;
      balances[exp.paidBy] += amountJPY;
      exp.splitWith.forEach(id => {
        balances[id] -= share;
      });
    });
    return balances;
  };

  const balances = calculateBalances();
  const myBalance = balances[currentUser.id] || 0;
  const totalSpentJPY = expenses.reduce((acc, exp) => acc + (exp.amount * (rates[exp.currency] || 1)), 0);

  const handleSave = (expense: ExpenseType) => {
    if (editingExpense) {
      setExpenses(expenses.map(e => e.id === expense.id ? expense : e));
    } else {
      setExpenses([{ ...expense, id: Date.now().toString() }, ...expenses]);
    }
    setIsModalOpen(false);
    setEditingExpense(null);
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500">
      {/* Dashboard Card */}
      <div className="bg-navy p-6 rounded-3xl-sticker sticker-shadow relative overflow-hidden text-white">
        <div className="absolute -right-4 -top-4 w-24 h-24 bg-stitch/20 rounded-full blur-2xl" />
        <div className="relative z-10">
          <p className="text-[10px] font-black uppercase tracking-[0.2em] opacity-40 mb-1">Trip Total Cost</p>
          <h2 className="text-4xl font-black mb-6">¥{Math.round(totalSpentJPY).toLocaleString()}</h2>

          <div className="flex gap-2">
            <button 
              onClick={() => { setEditingExpense(null); setIsModalOpen(true); }}
              className="flex-1 bg-donald text-navy py-3 rounded-xl-sticker font-black text-[10px] uppercase tracking-wider flex items-center justify-center gap-2 active:scale-95 transition-all"
            >
              <Plus size={14} /> Add Record
            </button>
            <button 
              onClick={() => setIsCalcOpen(true)}
              className="w-12 h-12 bg-white/10 rounded-xl-sticker flex items-center justify-center active:scale-90"
            >
              <Calculator size={18} />
            </button>
          </div>
        </div>
      </div>

      {/* Personal Status Card */}
      <div className={`p-5 rounded-2xl-sticker sticker-shadow border-2 transition-colors ${myBalance >= 0 ? 'bg-white border-stitch' : 'bg-white border-red-200'}`}>
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-3">
             <div className={`w-10 h-10 rounded-full flex items-center justify-center ${myBalance >= 0 ? 'bg-stitch/10 text-stitch' : 'bg-red-50 text-red-400'}`}>
               {myBalance >= 0 ? <TrendingUp size={20} /> : <TrendingDown size={20} />}
             </div>
             <div>
                <p className="text-[10px] font-black text-navy/30 uppercase tracking-widest">My Balance</p>
                <h3 className={`text-lg font-black ${myBalance >= 0 ? 'text-stitch' : 'text-red-400'}`}>
                  {myBalance >= 0 ? '應收' : '應付'} ¥{Math.abs(Math.round(myBalance)).toLocaleString()}
                </h3>
             </div>
          </div>
          <button 
            onClick={() => setIsSettlementOpen(true)}
            className="px-4 py-2 bg-cream text-navy/40 text-[9px] font-black rounded-full uppercase tracking-tighter border border-accent active:bg-accent"
          >
            All Members
          </button>
        </div>
      </div>

      {/* Quick Settings & Currency Info */}
      <div className="flex gap-3">
        <div className="flex-1 bg-white p-4 rounded-xl-sticker sticker-shadow border border-accent flex items-center justify-between">
           <div className="flex items-center gap-3">
              <RefreshCw 
                size={14} 
                className={`text-stitch ${loadingRates ? 'animate-spin' : 'cursor-pointer'}`} 
                onClick={fetchLiveRates}
              />
              <div>
                 <p className="text-[8px] font-black text-navy/30 uppercase">Rate JPY</p>
                 <p className="text-[10px] font-black text-navy">HKD: {rates.HKD.toFixed(1)} / AUD: {rates.AUD.toFixed(1)}</p>
              </div>
           </div>
           <Settings2 size={16} className="text-navy/20 cursor-pointer" onClick={() => setIsCurrencySettingsOpen(true)} />
        </div>
      </div>

      {/* History */}
      <div className="space-y-4">
        <h3 className="text-sm font-black text-navy uppercase tracking-[0.2em] px-1">Expense History</h3>
        {expenses.length > 0 ? expenses.map((exp) => {
          const payer = members.find(m => m.id === exp.paidBy);
          return (
            <div key={exp.id} className="bg-paper p-4 rounded-xl-sticker sticker-shadow border border-accent flex items-center gap-4 group">
              <div className="w-10 h-10 rounded-full border-2 border-accent overflow-hidden bg-cream flex-shrink-0">
                <img src={payer?.avatar} alt={payer?.name} className="w-full h-full object-cover" />
              </div>
              <div className="flex-1 min-w-0">
                <h4 className="font-black text-navy text-xs truncate">{exp.category}</h4>
                <p className="text-[9px] font-bold text-navy/30 uppercase">{exp.date} • Paid by {payer?.name}</p>
              </div>
              <div className="text-right">
                <p className="font-black text-navy text-sm">
                  {exp.currency} {exp.amount.toLocaleString()}
                </p>
                {exp.currency !== 'JPY' && (
                  <p className="text-[9px] font-bold text-stitch opacity-60">≈ ¥{Math.round(exp.amount * rates[exp.currency]).toLocaleString()}</p>
                )}
                <div className="flex gap-2 justify-end mt-1 opacity-0 group-hover:opacity-100 transition-opacity">
                   <button onClick={() => { setEditingExpense(exp); setIsModalOpen(true); }} className="text-navy/20 hover:text-stitch"><Edit2 size={12} /></button>
                   <button onClick={() => setExpenses(expenses.filter(e => e.id !== exp.id))} className="text-navy/20 hover:text-red-400"><Trash2 size={12} /></button>
                </div>
              </div>
            </div>
          );
        }) : (
          <div className="py-20 text-center opacity-20 border-2 border-dashed border-accent rounded-3xl">
            <CreditCard size={48} className="mx-auto mb-2" />
            <p className="font-black uppercase text-xs tracking-widest">No Expenses</p>
          </div>
        )}
      </div>

      {/* Settlement Modal */}
      {isSettlementOpen && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 bg-navy/20 backdrop-blur-sm" onClick={() => setIsSettlementOpen(false)}>
          <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-stitch animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-black text-navy uppercase tracking-widest">Group Settlement</h3>
              <button onClick={() => setIsSettlementOpen(false)} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
            </div>
            <div className="space-y-3 max-h-[50vh] overflow-y-auto pr-1">
              {members.map(m => {
                const bal = balances[m.id] || 0;
                return (
                  <div key={m.id} className="flex items-center justify-between p-4 bg-cream rounded-2xl border border-accent">
                    <div className="flex items-center gap-3">
                      <img src={m.avatar} className="w-10 h-10 rounded-full object-cover border-2 border-white" alt={m.name} />
                      <div>
                        <p className="font-black text-navy text-xs">{m.name}</p>
                        <p className={`text-[9px] font-black uppercase ${bal >= 0 ? 'text-stitch' : 'text-red-400'}`}>
                          {bal >= 0 ? '應收 Receivable' : '應付 Payable'}
                        </p>
                      </div>
                    </div>
                    <p className={`font-black text-base ${bal >= 0 ? 'text-stitch' : 'text-red-400'}`}>
                      ¥{Math.abs(Math.round(bal)).toLocaleString()}
                    </p>
                  </div>
                );
              })}
            </div>
            <button 
              onClick={() => setIsSettlementOpen(false)}
              className="w-full mt-6 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all uppercase text-xs tracking-widest"
            >
              Close Summary
            </button>
          </div>
        </div>
      )}

      {/* Currency Settings Modal */}
      {isCurrencySettingsOpen && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 bg-navy/20 backdrop-blur-sm" onClick={() => setIsCurrencySettingsOpen(false)}>
           <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-donald animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-black text-navy uppercase tracking-widest">Currency Settings</h3>
                <button onClick={() => setIsCurrencySettingsOpen(false)} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
              </div>
              <div className="space-y-4">
                 <div className="p-4 bg-cream rounded-xl border border-accent">
                    <label className="text-[10px] font-black uppercase text-navy/30 mb-2 block">Base Currency</label>
                    <p className="text-sm font-black text-navy">Japanese Yen (JPY) - Default</p>
                 </div>
                 <div className="space-y-2">
                    <label className="text-[10px] font-black uppercase text-navy/30 block px-1">Active Exchange Rates</label>
                    <div className="flex items-center justify-between p-3 bg-white border border-accent rounded-xl">
                       <span className="font-black text-xs">1 HKD =</span>
                       <input 
                         type="number" 
                         value={rates.HKD} 
                         onChange={e => setRates({...rates, HKD: parseFloat(e.target.value) || 0})}
                         className="w-20 text-right font-black text-stitch bg-transparent border-none focus:ring-0"
                       />
                       <span className="text-[10px] font-black text-navy/20">JPY</span>
                    </div>
                    <div className="flex items-center justify-between p-3 bg-white border border-accent rounded-xl">
                       <span className="font-black text-xs">1 AUD =</span>
                       <input 
                         type="number" 
                         value={rates.AUD} 
                         onChange={e => setRates({...rates, AUD: parseFloat(e.target.value) || 0})}
                         className="w-20 text-right font-black text-stitch bg-transparent border-none focus:ring-0"
                       />
                       <span className="text-[10px] font-black text-navy/20">JPY</span>
                    </div>
                 </div>
                 <button 
                  onClick={fetchLiveRates}
                  className="w-full py-3 bg-stitch/10 text-stitch font-black rounded-xl border border-stitch/20 flex items-center justify-center gap-2 active:scale-95 transition-all"
                 >
                   <RefreshCw size={14} className={loadingRates ? 'animate-spin' : ''} />
                   REFRESH LIVE RATES
                 </button>
              </div>
              <button 
                onClick={() => setIsCurrencySettingsOpen(false)}
                className="w-full mt-8 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all uppercase text-xs"
              >
                Save Settings
              </button>
           </div>
        </div>
      )}

      {/* Calc & Modal remains similar to previous implementations but using handleSave */}
      {isCalcOpen && <CalculatorTool rates={rates} onClose={() => setIsCalcOpen(false)} />}
      {isModalOpen && (
        <ExpenseModal 
          expense={editingExpense} 
          members={members} 
          rates={rates}
          onClose={() => setIsModalOpen(false)} 
          onSave={handleSave} 
        />
      )}
    </div>
  );
};

const CalculatorTool: React.FC<{ rates: Record<string, number>; onClose: () => void }> = ({ rates, onClose }) => {
  const [val, setVal] = useState('');
  const [cur, setCur] = useState<'HKD' | 'AUD'>('HKD');
  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-navy/20 backdrop-blur-sm" onClick={onClose}>
      <div className="bg-paper w-full max-w-xs rounded-3xl-sticker p-6 sticker-shadow border-4 border-donald" onClick={e => e.stopPropagation()}>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-black text-navy uppercase tracking-widest">Price Calc</h3>
          <button onClick={onClose} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
        </div>
        <div className="space-y-6">
          <div className="flex bg-accent/20 p-1 rounded-xl">
            {(['HKD', 'AUD'] as const).map(c => (
              <button key={c} onClick={() => setCur(c)} className={`flex-1 py-2 rounded-lg text-[10px] font-black ${cur === c ? 'bg-white text-navy sticker-shadow' : 'text-navy/40'}`}>{c}</button>
            ))}
          </div>
          <input 
            autoFocus type="number" value={val} onChange={e => setVal(e.target.value)} placeholder="0.00"
            className="w-full text-4xl font-black text-navy border-b-4 border-accent focus:border-donald bg-transparent p-2 focus:ring-0 text-center"
          />
          <div className="text-center">
            <p className="text-[10px] font-black uppercase text-navy/30 mb-1">Approximately</p>
            <h4 className="text-4xl font-black text-stitch">¥ {val ? Math.round(parseFloat(val) * rates[cur]).toLocaleString() : '0'}</h4>
          </div>
        </div>
        <button onClick={onClose} className="w-full mt-6 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all">CLOSE</button>
      </div>
    </div>
  );
};

const ExpenseModal: React.FC<{ 
  expense: ExpenseType | null; 
  members: TripMember[]; 
  rates: Record<string, number>;
  onClose: () => void; 
  onSave: (e: ExpenseType) => void 
}> = ({ expense, members, rates, onClose, onSave }) => {
  const [formData, setFormData] = useState<Partial<ExpenseType>>(expense || {
    amount: 0, currency: 'JPY', category: '', paidBy: members[0].id, splitWith: members.map(m => m.id), date: new Date().toISOString().split('T')[0]
  });

  const toggleSplit = (id: string) => {
    const current = formData.splitWith || [];
    setFormData({ ...formData, splitWith: current.includes(id) ? current.filter(cid => cid !== id) : [...current, id] });
  };

  return (
    <div className="fixed inset-0 z-[110] flex flex-col bg-cream animate-in slide-in-from-bottom duration-300">
      <div className="p-4 flex justify-between items-center border-b border-accent bg-paper">
        <button onClick={onClose} className="text-navy/40 p-2"><X size={24} /></button>
        <h3 className="text-lg font-black text-navy uppercase tracking-widest">{expense ? 'Edit Record' : 'Add Expense'}</h3>
        <button 
          onClick={() => onSave(formData as ExpenseType)} 
          className="text-stitch font-black p-2 disabled:opacity-30"
          disabled={!formData.category || !formData.amount || formData.splitWith?.length === 0}
        >DONE</button>
      </div>
      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        <div className="bg-paper p-8 rounded-3xl-sticker sticker-shadow border border-accent text-center relative overflow-hidden">
          <label className="text-[10px] font-black uppercase text-navy/30 mb-3 block">Amount</label>
          <div className="flex items-center justify-center gap-2">
            <select 
              value={formData.currency} 
              onChange={e => setFormData({...formData, currency: e.target.value as any})}
              className="text-2xl font-black text-stitch bg-transparent border-none focus:ring-0"
            >
              <option value="JPY">¥</option><option value="HKD">$ HKD</option><option value="AUD">$ AUD</option>
            </select>
            <input 
              type="number" value={formData.amount || ''} onChange={e => setFormData({...formData, amount: parseFloat(e.target.value) || 0})}
              placeholder="0" className="w-full text-5xl font-black text-navy bg-transparent border-none focus:ring-0 text-center" autoFocus
            />
          </div>
        </div>

        <div className="bg-paper p-5 rounded-2xl-sticker border border-accent sticker-shadow space-y-5">
          <input 
            type="text" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})}
            placeholder="What was it for?" className="w-full font-black text-navy border-b-2 border-accent/20 focus:border-stitch p-2 text-lg focus:ring-0"
          />
          <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full font-black text-navy bg-transparent border-none focus:ring-0" />
        </div>

        <div className="bg-paper p-5 rounded-2xl-sticker border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/30 mb-4 block">Paid By</label>
          <div className="flex gap-3 overflow-x-auto pb-2 scrollbar-hide">
            {members.map(m => (
              <button
                key={m.id} onClick={() => setFormData({ ...formData, paidBy: m.id })}
                className={`flex-shrink-0 flex flex-col items-center gap-2 p-2 rounded-2xl transition-all border-2 ${formData.paidBy === m.id ? 'bg-navy/5 border-navy' : 'border-transparent opacity-40'}`}
              >
                <img src={m.avatar} className="w-10 h-10 rounded-full object-cover" alt={m.name} />
                <span className="text-[10px] font-black uppercase">{m.name}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="bg-paper p-5 rounded-2xl-sticker border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/30 mb-4 block">Split With</label>
          <div className="grid grid-cols-2 gap-3">
            {members.map(m => {
              const isSelected = formData.splitWith?.includes(m.id);
              return (
                <button
                  key={m.id} onClick={() => toggleSplit(m.id)}
                  className={`flex items-center gap-3 p-3 rounded-xl border-2 transition-all ${isSelected ? 'bg-stitch border-stitch text-white' : 'bg-cream border-accent text-navy/40'}`}
                >
                  <div className={`w-4 h-4 rounded border flex items-center justify-center ${isSelected ? 'bg-white border-white' : 'border-navy/10'}`}>
                    {isSelected && <Check size={12} className="text-stitch" />}
                  </div>
                  <span className="text-xs font-black uppercase">{m.name}</span>
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Expense;

import React, { useState, useEffect } from 'react';
import { TripMember, Expense as ExpenseType } from '../types';
import { 
  TrendingDown, 
  CreditCard, 
  Plus, 
  Trash2, 
  Edit2, 
  X, 
  Check, 
  Calculator, 
  RefreshCw, 
  Search, 
  ArrowRightLeft, 
  Calendar,
  Settings2,
  TrendingUp,
  CircleDollarSign,
  User
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

const Expense: React.FC<{ currentUser: TripMember; members: TripMember[] }> = ({ currentUser, members }) => {
  const [expenses, setExpenses] = useState<ExpenseType[]>(() => {
    const saved = localStorage.getItem('expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [rates, setRates] = useState<Record<string, number>>({ JPY: 1, HKD: 19.2, AUD: 96.5 });
  const [baseCurrency, setBaseCurrency] = useState<'JPY' | 'HKD' | 'AUD'>(() => {
    return (localStorage.getItem('baseCurrency') as any) || 'JPY';
  });
  const [loadingRates, setLoadingRates] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettlementOpen, setIsSettlementOpen] = useState(false);
  const [isCalcOpen, setIsCalcOpen] = useState(false);
  const [isCurrencySettingsOpen, setIsCurrencySettingsOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<ExpenseType | null>(null);

  useEffect(() => {
    localStorage.setItem('expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('baseCurrency', baseCurrency);
  }, [baseCurrency]);

  const fetchLiveRates = async () => {
    setLoadingRates(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: "Current exchange rates: 1 HKD to JPY and 1 AUD to JPY. Return ONLY JSON: {HKD: number, AUD: number}",
        config: { tools: [{ googleSearch: {} }], responseMimeType: "application/json" }
      });
      const data = JSON.parse(response.text || '{}');
      if (data.HKD && data.AUD) {
        setRates({ JPY: 1, HKD: data.HKD, AUD: data.AUD });
      }
    } catch (e) {
      console.error("Rates fetch failed", e);
    } finally {
      setLoadingRates(false);
    }
  };

  const calculateBalances = () => {
    const balances: Record<string, number> = {};
    members.forEach(m => balances[m.id] = 0);
    expenses.forEach(exp => {
      const amountJPY = exp.amount * (rates[exp.currency] || 1);
      const share = amountJPY / exp.splitWith.length;
      balances[exp.paidBy] += amountJPY;
      exp.splitWith.forEach(id => {
        balances[id] -= share;
      });
    });
    return balances;
  };

  const balances = calculateBalances();
  const myBalanceJPY = balances[currentUser.id] || 0;
  const totalSpentJPY = expenses.reduce((acc, exp) => acc + (exp.amount * (rates[exp.currency] || 1)), 0);

  // Convert JPY to Base Currency for display
  const convertFromJPY = (amount: number) => {
    if (baseCurrency === 'JPY') return amount;
    return amount / rates[baseCurrency];
  };

  const handleSave = (expense: ExpenseType) => {
    if (editingExpense) {
      setExpenses(expenses.map(e => e.id === expense.id ? expense : e));
    } else {
      setExpenses([{ ...expense, id: Date.now().toString() }, ...expenses]);
    }
    setIsModalOpen(false);
    setEditingExpense(null);
  };

  const getCurrencySymbol = (cur: string) => {
    if (cur === 'JPY') return '¥';
    return '$';
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500">
      {/* Softer Dashboard Card */}
      <div className="bg-stitch/10 p-6 rounded-3xl-sticker sticker-shadow relative overflow-hidden border-2 border-stitch/20">
        <div className="absolute -right-6 -bottom-6 text-9xl opacity-[0.05] pointer-events-none transform -rotate-12">💰</div>
        <div className="relative z-10">
          <div className="flex justify-between items-start mb-1">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-navy/40">Trip Total ({baseCurrency})</p>
             <button onClick={() => setIsCurrencySettingsOpen(true)} className="text-navy/20 active:scale-90"><Settings2 size={16} /></button>
          </div>
          <h2 className="text-4xl font-black text-navy">
            {getCurrencySymbol(baseCurrency)}{Math.round(convertFromJPY(totalSpentJPY)).toLocaleString()}
          </h2>

          <div className="mt-8 flex gap-3">
            <button 
              onClick={() => { setEditingExpense(null); setIsModalOpen(true); }}
              className="flex-1 bg-stitch text-white py-3.5 rounded-2xl-sticker font-black text-[11px] uppercase tracking-wider flex items-center justify-center gap-2 sticker-shadow active:scale-95 transition-all"
            >
              <Plus size={16} /> New Expense
            </button>
            <button 
              onClick={() => setIsSettlementOpen(true)}
              className="px-6 bg-donald text-navy py-3.5 rounded-2xl-sticker font-black text-[11px] uppercase tracking-wider sticker-shadow active:scale-95 transition-all"
            >
              Settlement
            </button>
          </div>
        </div>
      </div>

      {/* Personal Status - Softer Colors */}
      <div className={`p-5 rounded-2xl-sticker sticker-shadow border-2 transition-colors bg-white ${myBalanceJPY >= 0 ? 'border-stitch/30' : 'border-red-100'}`}>
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-3">
             <div className={`w-11 h-11 rounded-full flex items-center justify-center ${myBalanceJPY >= 0 ? 'bg-stitch/10 text-stitch' : 'bg-red-50 text-red-300'}`}>
               {myBalanceJPY >= 0 ? <TrendingUp size={22} /> : <TrendingDown size={22} />}
             </div>
             <div>
                <p className="text-[9px] font-black text-navy/30 uppercase tracking-widest">My Balance</p>
                <h3 className={`text-lg font-black ${myBalanceJPY >= 0 ? 'text-stitch' : 'text-red-300'}`}>
                  {myBalanceJPY >= 0 ? '應收 Receivable' : '應付 Payable'} 
                  <span className="ml-1 text-sm">{getCurrencySymbol(baseCurrency)}{Math.abs(Math.round(convertFromJPY(myBalanceJPY))).toLocaleString()}</span>
                </h3>
             </div>
          </div>
          <button 
            onClick={() => setIsCalcOpen(true)}
            className="w-10 h-10 bg-cream rounded-full flex items-center justify-center text-navy/20 active:bg-accent transition-colors"
          >
            <Calculator size={18} />
          </button>
        </div>
      </div>

      {/* History - Showing "Paid By" Clearly */}
      <div className="space-y-4">
        <div className="flex justify-between items-center px-1">
           <h3 className="text-[11px] font-black text-navy/40 uppercase tracking-[0.2em]">Expense History</h3>
           <div className="flex items-center gap-2 text-[9px] font-bold text-navy/20">
              <RefreshCw size={10} className={loadingRates ? 'animate-spin' : ''} onClick={fetchLiveRates} />
              UPDATE RATES
           </div>
        </div>

        {expenses.length > 0 ? expenses.map((exp) => {
          const payer = members.find(m => m.id === exp.paidBy);
          return (
            <div key={exp.id} className="bg-white p-4 rounded-xl-sticker sticker-shadow border border-accent flex items-center gap-4 group animate-in fade-in slide-in-from-bottom-2">
              {/* Payer Avatar Focus */}
              <div className="relative">
                <div className="w-12 h-12 rounded-full border-2 border-accent overflow-hidden bg-cream flex-shrink-0">
                  <img src={payer?.avatar} alt={payer?.name} className="w-full h-full object-cover" />
                </div>
                <div className="absolute -bottom-1 -right-1 bg-white rounded-full p-1 border border-accent shadow-sm">
                   <CircleDollarSign size={10} className="text-stitch" />
                </div>
              </div>

              <div className="flex-1 min-w-0">
                <h4 className="font-black text-navy text-sm truncate">{exp.category}</h4>
                <div className="flex items-center gap-1.5 mt-1">
                   <span className="text-[9px] font-black text-stitch uppercase tracking-tight">{payer?.name} PAID</span>
                   <span className="w-1 h-1 bg-navy/10 rounded-full" />
                   <span className="text-[9px] font-bold text-navy/20 uppercase">{exp.date}</span>
                </div>
              </div>

              <div className="text-right">
                <p className="font-black text-navy text-sm">
                  {exp.currency} {exp.amount.toLocaleString()}
                </p>
                {exp.currency !== baseCurrency && (
                  <p className="text-[9px] font-bold text-navy/20">
                    ≈ {baseCurrency} {Math.round(convertFromJPY(exp.amount * rates[exp.currency])).toLocaleString()}
                  </p>
                )}
                <div className="flex gap-2 justify-end mt-1.5 opacity-0 group-hover:opacity-100 transition-opacity">
                   <button onClick={() => { setEditingExpense(exp); setIsModalOpen(true); }} className="p-1 text-navy/20 hover:text-stitch"><Edit2 size={12} /></button>
                   <button onClick={() => setExpenses(expenses.filter(e => e.id !== exp.id))} className="p-1 text-navy/20 hover:text-red-400"><Trash2 size={12} /></button>
                </div>
              </div>
            </div>
          );
        }) : (
          <div className="py-20 text-center opacity-20 border-2 border-dashed border-accent rounded-3xl bg-paper/50">
            <CreditCard size={48} className="mx-auto mb-2" />
            <p className="font-black uppercase text-[10px] tracking-widest">Adventure is free (almost)</p>
          </div>
        )}
      </div>

      {/* Settlement Modal */}
      {isSettlementOpen && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 bg-navy/10 backdrop-blur-sm" onClick={() => setIsSettlementOpen(false)}>
          <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-stitch animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-6">
              <div>
                <h3 className="text-lg font-black text-navy uppercase tracking-widest leading-none">Settlement</h3>
                <p className="text-[9px] font-bold text-navy/30 uppercase mt-1">Total in {baseCurrency}</p>
              </div>
              <button onClick={() => setIsSettlementOpen(false)} className="p-2 bg-cream rounded-full text-navy/40 active:scale-90"><X size={20} /></button>
            </div>

            <div className="space-y-3 max-h-[50vh] overflow-y-auto pr-1">
              {members.map(m => {
                const balJPY = balances[m.id] || 0;
                const balBase = convertFromJPY(balJPY);
                return (
                  <div key={m.id} className="flex items-center justify-between p-4 bg-cream rounded-2xl border border-accent">
                    <div className="flex items-center gap-3">
                      <img src={m.avatar} className="w-10 h-10 rounded-full object-cover border-2 border-white shadow-sm" alt={m.name} />
                      <div>
                        <p className="font-black text-navy text-xs">{m.name}</p>
                        <p className={`text-[8px] font-black uppercase tracking-tighter ${balJPY >= 0 ? 'text-stitch' : 'text-red-300'}`}>
                          {balJPY >= 0 ? '收 Receivable' : '付 Payable'}
                        </p>
                      </div>
                    </div>
                    <p className={`font-black text-base ${balJPY >= 0 ? 'text-stitch' : 'text-red-300'}`}>
                      {getCurrencySymbol(baseCurrency)}{Math.abs(Math.round(balBase)).toLocaleString()}
                    </p>
                  </div>
                );
              })}
            </div>

            <div className="mt-6 p-4 bg-stitch/5 rounded-2xl border border-stitch/10">
               <p className="text-[9px] font-bold text-navy/40 text-center leading-relaxed">
                 Calculated using current market rates.<br/>Please settle manually via cash or transfer.
               </p>
            </div>

            <button 
              onClick={() => setIsSettlementOpen(false)}
              className="w-full mt-6 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all uppercase text-[10px] tracking-widest"
            >
              Confirm Summary
            </button>
          </div>
        </div>
      )}

      {/* Currency & Base Settings Modal */}
      {isCurrencySettingsOpen && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 bg-navy/10 backdrop-blur-sm" onClick={() => setIsCurrencySettingsOpen(false)}>
           <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-donald animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-black text-navy uppercase tracking-widest">Settings</h3>
                <button onClick={() => setIsCurrencySettingsOpen(false)} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
              </div>

              <div className="space-y-6">
                 {/* Base Currency Selection */}
                 <div>
                    <label className="text-[10px] font-black uppercase text-navy/30 mb-3 block px-1">Display Currency</label>
                    <div className="flex gap-2">
                       {(['JPY', 'HKD', 'AUD'] as const).map(cur => (
                         <button 
                           key={cur}
                           onClick={() => setBaseCurrency(cur)}
                           className={`flex-1 py-3 rounded-xl border-2 font-black text-xs transition-all ${baseCurrency === cur ? 'bg-navy text-white border-navy sticker-shadow' : 'bg-white text-navy/40 border-accent'}`}
                         >
                           {cur}
                         </button>
                       ))}
                    </div>
                 </div>

                 {/* Rate Adjustment */}
                 <div className="space-y-3">
                    <div className="flex justify-between items-center px-1">
                       <label className="text-[10px] font-black uppercase text-navy/30">Exchange Rates (vs JPY)</label>
                       <button onClick={fetchLiveRates} className="text-[9px] font-black text-stitch flex items-center gap-1 active:scale-90">
                         <RefreshCw size={10} className={loadingRates ? 'animate-spin' : ''} /> SYNC LIVE
                       </button>
                    </div>
                    <div className="space-y-2">
                       {['HKD', 'AUD'].map(cur => (
                         <div key={cur} className="flex items-center justify-between p-3.5 bg-cream rounded-xl border border-accent">
                            <span className="font-black text-navy text-xs">1 {cur} =</span>
                            <div className="flex items-center gap-2">
                               <input 
                                 type="number" 
                                 value={rates[cur]} 
                                 onChange={e => setRates({...rates, [cur]: parseFloat(e.target.value) || 0})}
                                 className="w-16 text-right font-black text-stitch bg-transparent border-none focus:ring-0 p-0"
                               />
                               <span className="text-[10px] font-black text-navy/20">JPY</span>
                            </div>
                         </div>
                       ))}
                    </div>
                 </div>
              </div>

              <button 
                onClick={() => setIsCurrencySettingsOpen(false)}
                className="w-full mt-8 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all uppercase text-[10px]"
              >
                Apply Changes
              </button>
           </div>
        </div>
      )}

      {/* Calc & Modal remains similar */}
      {isCalcOpen && <CalculatorTool rates={rates} onClose={() => setIsCalcOpen(false)} />}
      {isModalOpen && (
        <ExpenseModal 
          expense={editingExpense} 
          members={members} 
          rates={rates}
          onClose={() => setIsModalOpen(false)} 
          onSave={handleSave} 
        />
      )}
    </div>
  );
};

const CalculatorTool: React.FC<{ rates: Record<string, number>; onClose: () => void }> = ({ rates, onClose }) => {
  const [val, setVal] = useState('');
  const [cur, setCur] = useState<'HKD' | 'AUD'>('HKD');
  return (
    <div className="fixed inset-0 z-[130] flex items-center justify-center p-6 bg-navy/10 backdrop-blur-sm" onClick={onClose}>
      <div className="bg-paper w-full max-w-xs rounded-3xl-sticker p-6 sticker-shadow border-4 border-donald" onClick={e => e.stopPropagation()}>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-black text-navy uppercase tracking-widest">Convert</h3>
          <button onClick={onClose} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
        </div>
        <div className="space-y-6">
          <div className="flex bg-accent/20 p-1 rounded-xl">
            {(['HKD', 'AUD'] as const).map(c => (
              <button key={c} onClick={() => setCur(c)} className={`flex-1 py-2 rounded-lg text-[10px] font-black ${cur === c ? 'bg-white text-navy sticker-shadow' : 'text-navy/40'}`}>{c}</button>
            ))}
          </div>
          <input 
            autoFocus type="number" value={val} onChange={e => setVal(e.target.value)} placeholder="0.00"
            className="w-full text-4xl font-black text-navy border-b-4 border-accent focus:border-donald bg-transparent p-2 focus:ring-0 text-center"
          />
          <div className="text-center py-4 bg-stitch/5 rounded-2xl">
            <p className="text-[9px] font-black uppercase text-navy/20 mb-1">Equals Approx.</p>
            <h4 className="text-4xl font-black text-stitch">¥ {val ? Math.round(parseFloat(val) * rates[cur]).toLocaleString() : '0'}</h4>
          </div>
        </div>
        <button onClick={onClose} className="w-full mt-6 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all">Done</button>
      </div>
    </div>
  );
};

const ExpenseModal: React.FC<{ 
  expense: ExpenseType | null; 
  members: TripMember[]; 
  rates: Record<string, number>;
  onClose: () => void; 
  onSave: (e: ExpenseType) => void 
}> = ({ expense, members, rates, onClose, onSave }) => {
  const [formData, setFormData] = useState<Partial<ExpenseType>>(expense || {
    amount: 0, currency: 'JPY', category: '', paidBy: members[0].id, splitWith: members.map(m => m.id), date: new Date().toISOString().split('T')[0]
  });

  const toggleSplit = (id: string) => {
    const current = formData.splitWith || [];
    setFormData({ ...formData, splitWith: current.includes(id) ? current.filter(cid => cid !== id) : [...current, id] });
  };

  return (
    <div className="fixed inset-0 z-[150] flex flex-col bg-cream animate-in slide-in-from-bottom duration-300">
      <div className="p-4 flex justify-between items-center border-b border-accent bg-paper">
        <button onClick={onClose} className="text-navy/40 p-2 active:scale-90"><X size={24} /></button>
        <h3 className="text-lg font-black text-navy uppercase tracking-widest leading-none">{expense ? 'Edit' : 'New Record'}</h3>
        <button 
          onClick={() => onSave(formData as ExpenseType)} 
          className="text-stitch font-black p-2 disabled:opacity-30"
          disabled={!formData.category || !formData.amount || formData.splitWith?.length === 0}
        >SAVE</button>
      </div>
      <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-20">
        <div className="bg-paper p-8 rounded-3xl-sticker sticker-shadow border border-accent text-center relative">
          <div className="flex items-center justify-center gap-2">
            <select 
              value={formData.currency} 
              onChange={e => setFormData({...formData, currency: e.target.value as any})}
              className="text-xl font-black text-stitch bg-transparent border-none focus:ring-0 p-0 w-min"
            >
              <option value="JPY">¥ JPY</option><option value="HKD">$ HKD</option><option value="AUD">$ AUD</option>
            </select>
            <input 
              type="number" value={formData.amount || ''} onChange={e => setFormData({...formData, amount: parseFloat(e.target.value) || 0})}
              placeholder="0" className="w-full text-5xl font-black text-navy bg-transparent border-none focus:ring-0 text-center" autoFocus
            />
          </div>
        </div>

        <div className="bg-paper p-5 rounded-2xl-sticker border border-accent sticker-shadow space-y-5">
          <div className="flex items-center gap-3 border-b border-accent pb-2">
             <Search size={18} className="text-navy/20" />
             <input 
               type="text" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})}
               placeholder="What was it for?" className="w-full font-black text-navy border-none focus:ring-0 p-0 text-lg placeholder:text-navy/10"
             />
          </div>
          <div className="flex items-center gap-3">
             <Calendar size={18} className="text-navy/20" />
             <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full font-black text-navy bg-transparent border-none focus:ring-0 p-0" />
          </div>
        </div>

        <div className="bg-paper p-5 rounded-2xl-sticker border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/30 mb-4 block">Paid By</label>
