import React, { useState, useEffect, useMemo } from 'react';
import { TripMember, Expense as ExpenseType } from '../types';
import { 
  TrendingDown, 
  CreditCard, 
  Plus, 
  Trash2, 
  Edit2, 
  X, 
  Check, 
  Calculator, 
  RefreshCw, 
  Search, 
  ArrowRightLeft, 
  Calendar,
  Settings2,
  TrendingUp,
  CircleDollarSign,
  ArrowRight
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

const Expense: React.FC<{ currentUser: TripMember; members: TripMember[] }> = ({ currentUser, members }) => {
  const [expenses, setExpenses] = useState<ExpenseType[]>(() => {
    const saved = localStorage.getItem('expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [rates, setRates] = useState<Record<string, number>>({ JPY: 1, HKD: 19.2, AUD: 96.5 });
  const [baseCurrency, setBaseCurrency] = useState<'JPY' | 'HKD' | 'AUD'>(() => {
    return (localStorage.getItem('baseCurrency') as any) || 'JPY';
  });
  const [loadingRates, setLoadingRates] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettlementOpen, setIsSettlementOpen] = useState(false);
  const [isCalcOpen, setIsCalcOpen] = useState(false);
  const [isCurrencySettingsOpen, setIsCurrencySettingsOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<ExpenseType | null>(null);

  useEffect(() => {
    localStorage.setItem('expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('baseCurrency', baseCurrency);
  }, [baseCurrency]);

  const fetchLiveRates = async () => {
    setLoadingRates(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: "Current exchange rates: 1 HKD to JPY and 1 AUD to JPY. Return ONLY JSON: {HKD: number, AUD: number}",
        config: { tools: [{ googleSearch: {} }], responseMimeType: "application/json" }
      });
      const data = JSON.parse(response.text || '{}');
      if (data.HKD && data.AUD) {
        setRates({ JPY: 1, HKD: data.HKD, AUD: data.AUD });
      }
    } catch (e) {
      console.error("Rates fetch failed", e);
    } finally {
      setLoadingRates(false);
    }
  };

  // Memoized balance calculation for performance and reactivity to currentUser prop
  const balances = useMemo(() => {
    const bal: Record<string, number> = {};
    members.forEach(m => bal[m.id] = 0);
    expenses.forEach(exp => {
      const amountJPY = exp.amount * (rates[exp.currency] || 1);
      const share = amountJPY / exp.splitWith.length;
      bal[exp.paidBy] += amountJPY;
      exp.splitWith.forEach(id => {
        if (bal[id] !== undefined) bal[id] -= share;
      });
    });
    return bal;
  }, [expenses, members, rates]);

  // Debt simplification algorithm (Who pays whom)
  const settlementSuggestions = useMemo(() => {
    const people = Object.entries(balances).map(([id, balance]) => ({ id, balance }));
    const debtors = people.filter(p => p.balance < -0.01).sort((a, b) => a.balance - b.balance);
    const creditors = people.filter(p => p.balance > 0.01).sort((a, b) => b.balance - a.balance);

    const transactions: Array<{ from: string; to: string; amount: number }> = [];
    let dIdx = 0, cIdx = 0;

    while (dIdx < debtors.length && cIdx < creditors.length) {
      const amount = Math.min(Math.abs(debtors[dIdx].balance), creditors[cIdx].balance);
      transactions.push({ from: debtors[dIdx].id, to: creditors[cIdx].id, amount });

      debtors[dIdx].balance += amount;
      creditors[cIdx].balance -= amount;

      if (Math.abs(debtors[dIdx].balance) < 0.01) dIdx++;
      if (Math.abs(creditors[cIdx].balance) < 0.01) cIdx++;
    }
    return transactions;
  }, [balances]);

  const myBalanceJPY = balances[currentUser.id] || 0;
  const totalSpentJPY = expenses.reduce((acc, exp) => acc + (exp.amount * (rates[exp.currency] || 1)), 0);

  const convertFromJPY = (amount: number) => {
    if (baseCurrency === 'JPY') return amount;
    return amount / rates[baseCurrency];
  };

  const handleSave = (expense: ExpenseType) => {
    if (editingExpense) {
      setExpenses(expenses.map(e => e.id === expense.id ? expense : e));
    } else {
      setExpenses([{ ...expense, id: Date.now().toString() }, ...expenses]);
    }
    setIsModalOpen(false);
    setEditingExpense(null);
  };

  const getCurrencySymbol = (cur: string) => {
    if (cur === 'JPY') return '¥';
    return '$';
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500">
      {/* Dashboard - Soft Gradient Stationery Look */}
      <div className="bg-white p-6 rounded-3xl-sticker sticker-shadow relative overflow-hidden border border-accent/50">
        <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none">
          <CircleDollarSign size={80} className="text-stitch" />
        </div>
        <div className="relative z-10">
          <div className="flex justify-between items-center mb-1">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-navy/30">Total Trip Spending</p>
             <button onClick={() => setIsCurrencySettingsOpen(true)} className="p-2 text-navy/20 hover:text-stitch transition-colors"><Settings2 size={16} /></button>
          </div>
          <h2 className="text-4xl font-black text-navy">
            <span className="text-xl mr-1 opacity-40">{getCurrencySymbol(baseCurrency)}</span>
            {Math.round(convertFromJPY(totalSpentJPY)).toLocaleString()}
          </h2>

          <div className="mt-8 flex gap-3">
            <button 
              onClick={() => { setEditingExpense(null); setIsModalOpen(true); }}
              className="flex-1 bg-stitch text-white py-3.5 rounded-2xl-sticker font-black text-[11px] uppercase tracking-widest flex items-center justify-center gap-2 sticker-shadow active:scale-95 transition-all"
            >
              <Plus size={16} /> New Receipt
            </button>
            <button 
              onClick={() => setIsSettlementOpen(true)}
              className="px-6 bg-donald/90 text-navy py-3.5 rounded-2xl-sticker font-black text-[11px] uppercase tracking-widest sticker-shadow active:scale-95 transition-all"
            >
              Settlement
            </button>
          </div>
        </div>
      </div>

      {/* Reactive Personal Status Card */}
      <div className={`p-5 rounded-2xl-sticker sticker-shadow border transition-all duration-300 bg-white ${myBalanceJPY >= 0 ? 'border-stitch/40' : 'border-red-100'}`}>
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-4">
             <div className={`w-12 h-12 rounded-full flex items-center justify-center transition-colors ${myBalanceJPY >= 0 ? 'bg-stitch/5 text-stitch' : 'bg-red-50 text-red-300'}`}>
               {myBalanceJPY >= 0 ? <TrendingUp size={24} /> : <TrendingDown size={24} />}
             </div>
             <div>
                <p className="text-[9px] font-black text-navy/20 uppercase tracking-[0.2em]">Balance for {currentUser.name}</p>
                <h3 className={`text-xl font-black ${myBalanceJPY >= 0 ? 'text-stitch' : 'text-red-300'}`}>
                  {myBalanceJPY >= 0 ? 'To Receive' : 'To Pay'} 
                  <span className="ml-2 font-black">{getCurrencySymbol(baseCurrency)}{Math.abs(Math.round(convertFromJPY(myBalanceJPY))).toLocaleString()}</span>
                </h3>
             </div>
          </div>
          <button 
            onClick={() => setIsCalcOpen(true)}
            className="w-10 h-10 bg-cream rounded-full flex items-center justify-center text-navy/20 active:scale-90"
          >
            <Calculator size={18} />
          </button>
        </div>
      </div>

      {/* History - Stationery List */}
      <div className="space-y-4 pt-2">
        <h3 className="text-[11px] font-black text-navy/30 uppercase tracking-[0.3em] px-1 flex items-center gap-2">
           <ArrowRightLeft size={12} /> Transaction Log
        </h3>

        {expenses.length > 0 ? expenses.map((exp) => {
          const payer = members.find(m => m.id === exp.paidBy);
          return (
            <div key={exp.id} className="bg-white p-4 rounded-xl-sticker sticker-shadow border border-accent/40 flex items-center gap-4 group transition-all hover:border-stitch/30">
              <div className="relative flex-shrink-0">
                <img src={payer?.avatar} alt={payer?.name} className="w-12 h-12 rounded-full object-cover border-2 border-accent" />
                <div className="absolute -bottom-1 -right-1 bg-white rounded-full p-0.5 border border-accent shadow-sm">
                   <CircleDollarSign size={10} className="text-stitch" />
                </div>
              </div>

              <div className="flex-1 min-w-0">
                <h4 className="font-black text-navy text-sm truncate">{exp.category}</h4>
                <p className="text-[9px] font-bold text-navy/20 uppercase mt-0.5">
                  <span className="text-stitch/60">{payer?.name}</span> paid on {exp.date}
                </p>
              </div>

              <div className="text-right">
                <p className="font-black text-navy text-sm">
                  {exp.currency} {exp.amount.toLocaleString()}
                </p>
                {exp.currency !== baseCurrency && (
                  <p className="text-[9px] font-bold text-navy/20">
                    ≈ {baseCurrency} {Math.round(convertFromJPY(exp.amount * rates[exp.currency])).toLocaleString()}
                  </p>
                )}
                <div className="flex gap-2 justify-end mt-1.5 opacity-0 group-hover:opacity-100 transition-opacity">
                   <button onClick={() => { setEditingExpense(exp); setIsModalOpen(true); }} className="text-navy/20 hover:text-stitch"><Edit2 size={12} /></button>
                   <button onClick={() => setExpenses(expenses.filter(e => e.id !== exp.id))} className="text-navy/20 hover:text-red-400"><Trash2 size={12} /></button>
                </div>
              </div>
            </div>
          );
        }) : (
          <div className="py-24 text-center opacity-20 border-2 border-dashed border-accent rounded-3xl bg-paper/30">
            <CreditCard size={48} className="mx-auto mb-3" />
            <p className="font-black uppercase text-[10px] tracking-widest">No spending recorded yet</p>
          </div>
        )}
      </div>

      {/* Settlement Modal - Detailed Debts */}
      {isSettlementOpen && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 bg-navy/10 backdrop-blur-sm" onClick={() => setIsSettlementOpen(false)}>
          <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-stitch animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-6">
              <div>
                <h3 className="text-lg font-black text-navy uppercase tracking-widest">Settlement</h3>
                <p className="text-[9px] font-bold text-navy/30 uppercase mt-1">Suggested Repayments</p>
              </div>
              <button onClick={() => setIsSettlementOpen(false)} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
            </div>

            <div className="space-y-4 max-h-[60vh] overflow-y-auto pr-1">
              {/* Transactions List */}
              {settlementSuggestions.length > 0 ? (
                <div className="space-y-2">
                  <p className="text-[9px] font-black text-stitch uppercase tracking-widest px-1 mb-2">Repayment Plan</p>
                  {settlementSuggestions.map((tx, idx) => {
                    const from = members.find(m => m.id === tx.from);
                    const to = members.find(m => m.id === tx.to);
                    return (
                      <div key={idx} className="bg-cream p-4 rounded-2xl border border-accent/40 flex items-center justify-between">
                        <div className="flex items-center gap-2">
                          <img src={from?.avatar} className="w-8 h-8 rounded-full border border-white" />
                          <ArrowRight size={14} className="text-navy/20" />
                          <img src={to?.avatar} className="w-8 h-8 rounded-full border border-white" />
                        </div>
                        <div className="text-right">
                          <p className="text-[9px] font-black text-navy/30 uppercase">{from?.name} ➜ {to?.name}</p>
                          <p className="font-black text-stitch text-sm">
                            {getCurrencySymbol(baseCurrency)}{Math.round(convertFromJPY(tx.amount)).toLocaleString()}
                          </p>
                        </div>
                      </div>
                    );
                  })}
                </div>
              ) : (
                <div className="text-center py-10 opacity-30">
                  <Check size={40} className="mx-auto mb-2 text-stitch" />
                  <p className="font-black uppercase text-xs">All Settled!</p>
                </div>
              )}

              {/* Individual Balances Summary */}
              <div className="pt-4 border-t border-accent/50">
                <p className="text-[9px] font-black text-navy/30 uppercase tracking-widest px-1 mb-3">Individual Balances</p>
                <div className="space-y-2">
                  {members.map(m => {
                    const bal = convertFromJPY(balances[m.id] || 0);
                    return (
                      <div key={m.id} className="flex items-center justify-between px-2">
                        <span className="text-xs font-black text-navy/60">{m.name}</span>
                        <span className={`text-xs font-black ${bal >= 0 ? 'text-stitch' : 'text-red-300'}`}>
                          {bal >= 0 ? '+' : ''}{Math.round(bal).toLocaleString()}
                        </span>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>

            <button 
              onClick={() => setIsSettlementOpen(false)}
              className="w-full mt-8 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all uppercase text-[10px] tracking-[0.2em]"
            >
              Close Summary
            </button>
          </div>
        </div>
      )}

      {/* Currency & Base Settings Modal */}
      {isCurrencySettingsOpen && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 bg-navy/10 backdrop-blur-sm" onClick={() => setIsCurrencySettingsOpen(false)}>
           <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-donald animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-black text-navy uppercase tracking-widest">Settings</h3>
                <button onClick={() => setIsCurrencySettingsOpen(false)} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
              </div>

              <div className="space-y-6">
                 <div>
                    <label className="text-[10px] font-black uppercase text-navy/30 mb-3 block px-1">App Base Currency</label>
                    <div className="flex gap-2">
                       {(['JPY', 'HKD', 'AUD'] as const).map(cur => (
                         <button 
                           key={cur}
                           onClick={() => setBaseCurrency(cur)}
                           className={`flex-1 py-3 rounded-xl border-2 font-black text-xs transition-all ${baseCurrency === cur ? 'bg-navy text-white border-navy sticker-shadow' : 'bg-white text-navy/40 border-accent'}`}
                         >
                           {cur}
                         </button>
                       ))}
                    </div>
                 </div>

                 <div className="space-y-3">
                    <div className="flex justify-between items-center px-1">
                       <label className="text-[10px] font-black uppercase text-navy/30">Rates (vs JPY)</label>
                       <button onClick={fetchLiveRates} className="text-[9px] font-black text-stitch flex items-center gap-1 active:scale-90 transition-transform">
                         <RefreshCw size={10} className={loadingRates ? 'animate-spin' : ''} /> SYNC LIVE
                       </button>
                    </div>
                    <div className="space-y-2">
                       {['HKD', 'AUD'].map(cur => (
                         <div key={cur} className="flex items-center justify-between p-3.5 bg-cream rounded-xl border border-accent">
                            <span className="font-black text-navy text-xs">1 {cur} =</span>
                            <div className="flex items-center gap-2">
                               <input 
                                 type="number" 
                                 value={rates[cur]} 
                                 onChange={e => setRates({...rates, [cur]: parseFloat(e.target.value) || 0})}
                                 className="w-16 text-right font-black text-stitch bg-transparent border-none focus:ring-0 p-0"
                               />
                               <span className="text-[10px] font-black text-navy/20 uppercase">JPY</span>
                            </div>
                         </div>
                       ))}
                    </div>
                 </div>
              </div>

              <button 
                onClick={() => setIsCurrencySettingsOpen(false)}
                className="w-full mt-8 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all uppercase text-[10px] tracking-widest"
              >
                Apply Changes
              </button>
           </div>
        </div>
      )}

      {isCalcOpen && <CalculatorTool rates={rates} onClose={() => setIsCalcOpen(false)} />}
      {isModalOpen && (
        <ExpenseModal 
          expense={editingExpense} 
          members={members} 
          rates={rates}
          onClose={() => setIsModalOpen(false)} 
          onSave={handleSave} 
        />
      )}
    </div>
  );
};

const CalculatorTool: React.FC<{ rates: Record<string, number>; onClose: () => void }> = ({ rates, onClose }) => {
  const [val, setVal] = useState('');
  const [cur, setCur] = useState<'HKD' | 'AUD'>('HKD');
  return (
    <div className="fixed inset-0 z-[130] flex items-center justify-center p-6 bg-navy/10 backdrop-blur-sm" onClick={onClose}>
      <div className="bg-paper w-full max-w-xs rounded-3xl-sticker p-6 sticker-shadow border-4 border-donald" onClick={e => e.stopPropagation()}>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-black text-navy uppercase tracking-widest">Converter</h3>
          <button onClick={onClose} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
        </div>
        <div className="space-y-6">
          <div className="flex bg-accent/20 p-1 rounded-xl">
            {(['HKD', 'AUD'] as const).map(c => (
              <button key={c} onClick={() => setCur(c)} className={`flex-1 py-2 rounded-lg text-[10px] font-black transition-all ${cur === c ? 'bg-white text-navy sticker-shadow' : 'text-navy/40'}`}>{c}</button>
            ))}
          </div>
          <input 
            autoFocus type="number" value={val} onChange={e => setVal(e.target.value)} placeholder="0.00"
            className="w-full text-4xl font-black text-navy border-b-4 border-accent focus:border-donald bg-transparent p-2 focus:ring-0 text-center"
          />
          <div className="text-center py-6 bg-stitch/5 rounded-2xl border border-stitch/10">
            <p className="text-[9px] font-black uppercase text-navy/20 mb-1">Equals Approx.</p>
            <h4 className="text-4xl font-black text-stitch">¥ {val ? Math.round(parseFloat(val) * rates[cur]).toLocaleString() : '0'}</h4>
          </div>
        </div>
        <button onClick={onClose} className="w-full mt-6 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all uppercase text-[10px]">Close</button>
      </div>
    </div>
  );
};

const ExpenseModal: React.FC<{ 
  expense: ExpenseType | null; 
  members: TripMember[]; 
  rates: Record<string, number>;
  onClose: () => void; 
  onSave: (e: ExpenseType) => void 
}> = ({ expense, members, rates, onClose, onSave }) => {
  const [formData, setFormData] = useState<Partial<ExpenseType>>(expense || {
    amount: 0, currency: 'JPY', category: '', paidBy: members[0].id, splitWith: members.map(m => m.id), date: new Date().toISOString().split('T')[0]
  });

  const toggleSplit = (id: string) => {
    const current = formData.splitWith || [];
    setFormData({ ...formData, splitWith: current.includes(id) ? current.filter(cid => cid !== id) : [...current, id] });
  };

  return (
    <div className="fixed inset-0 z-[150] flex flex-col bg-cream animate-in slide-in-from-bottom duration-300">
      <div className="p-4 flex justify-between items-center border-b border-accent bg-paper">
        <button onClick={onClose} className="text-navy/40 p-2 active:scale-90"><X size={24} /></button>
        <h3 className="text-lg font-black text-navy uppercase tracking-widest">{expense ? 'Edit' : 'New Spending'}</h3>
        <button 
          onClick={() => onSave(formData as ExpenseType)} 
          className="text-stitch font-black p-2 disabled:opacity-30"
          disabled={!formData.category || !formData.amount || formData.splitWith?.length === 0}
        >SAVE</button>
      </div>
      <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-24">
        <div className="bg-paper p-8 rounded-3xl-sticker sticker-shadow border border-accent text-center relative">
          <div className="flex items-center justify-center gap-2">
            <select 
              value={formData.currency} 
              onChange={e => setFormData({...formData, currency: e.target.value as any})}
              className="text-xl font-black text-stitch bg-transparent border-none focus:ring-0 p-0 w-min"
            >
              <option value="JPY">¥ JPY</option><option value="HKD">$ HKD</option><option value="AUD">$ AUD</option>
            </select>
            <input 
              type="number" value={formData.amount || ''} onChange={e => setFormData({...formData, amount: parseFloat(e.target.value) || 0})}
              placeholder="0" className="w-full text-5xl font-black text-navy bg-transparent border-none focus:ring-0 text-center" autoFocus
            />
          </div>
        </div>

        <div className="bg-paper p-5 rounded-2xl-sticker border border-accent sticker-shadow space-y-5">
          <div className="flex items-center gap-3 border-b border-accent/20 pb-3">
             <Search size={18} className="text-navy/20" />
             <input 
               type="text" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})}
               placeholder="What was it for?" className="w-full font-black text-navy border-none focus:ring-0 p-0 text-lg placeholder:text-navy/10"
             />
          </div>
          <div className="flex items-center gap-3">
             <Calendar size={18} className="text-navy/20" />
             <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full font-black text-navy bg-transparent border-none focus:ring-0 p-0" />
          </div>
        </div>

        <div className="bg-paper p-5 rounded-2xl-sticker border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/30 mb-4 block tracking-widest">Paid By</label>
          <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-hide">
            {members.map(m => (
              <button
                key={m.id} onClick={() => setFormData({ ...formData, paidBy: m.id })}
                className={`flex-shrink-0 flex flex-col items-center gap-2 transition-all ${formData.paidBy === m.id ? 'opacity-100 scale-110' : 'opacity-30'}`}
              >
                <img src={m.avatar} className={`w-12 h-12 rounded-full object-cover border-2 p-0.5 ${formData.paidBy === m.id ? 'border-stitch shadow-md' : 'border-transparent'}`} alt={m.name} />
                <span className="text-[9px] font-black uppercase">{m.name}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="bg-paper p-5 rounded-2xl-sticker border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/30 mb-4 block tracking-widest">Split With</label>
          <div className="grid grid-cols-2 gap-3">
            {members.map(m => {
              const isSelected = formData.splitWith?.includes(m.id);
              return (
                <button
                  key={m.id} onClick={() => toggleSplit(m.id)}
                  className={`flex items-center gap-3 p-3 rounded-xl border-2 transition-all ${isSelected ? 'bg-stitch/5 border-stitch text-navy' : 'bg-white border-accent/50 text-navy/30'}`}
                >
                  <div className={`w-4 h-4 rounded border flex items-center justify-center transition-colors ${isSelected ? 'bg-stitch border-stitch' : 'border-navy/10'}`}>
                    {isSelected && <Check size={12} className="text-white" />}
                  </div>
                  <span className="text-[11px] font-black uppercase tracking-tight">{m.name}</span>
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Expense;

import React, { useState, useEffect } from 'react';
import { TripMember, PlanningItem } from '../types';
import { Plus, Trash2, Check, User, X, Users } from 'lucide-react';

const Planning: React.FC<{ members: TripMember[] }> = ({ members }) => {
  const [activeTab, setActiveTab] = useState<'Packing' | 'Shopping'>('Packing');
  const [items, setItems] = useState<PlanningItem[]>(() => {
    const saved = localStorage.getItem('planning_items');
    return saved ? JSON.parse(saved) : [
      { id: '1', type: 'Packing', title: 'Passport', assignedTo: 'All', completed: true },
      { id: '2', type: 'Packing', title: 'Japan Rail Pass', assignedTo: 'All', completed: false },
      { id: '3', type: 'Packing', title: 'Camera Batteries', assignedTo: members[0]?.id || 'All', completed: false },
    ];
  });

  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [newItemTitle, setNewItemTitle] = useState('');
  const [newItemAssignee, setNewItemAssignee] = useState('All');

  useEffect(() => {
    localStorage.setItem('planning_items', JSON.stringify(items));
  }, [items]);

  const filteredItems = items.filter(item => item.type === activeTab);

  const toggleComplete = (id: string) => {
    setItems(items.map(item => item.id === id ? { ...item, completed: !item.completed } : item));
  };

  const deleteItem = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    setItems(items.filter(item => item.id !== id));
  };

  const handleAddItem = () => {
    if (!newItemTitle.trim()) return;
    const newItem: PlanningItem = {
      id: Date.now().toString(),
      type: activeTab,
      title: newItemTitle,
      assignedTo: newItemAssignee,
      completed: false
    };
    setItems([...items, newItem]);
    setNewItemTitle('');
    setIsAddModalOpen(false);
  };

  return (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">
      <div className="flex bg-accent/20 p-1.5 rounded-2xl border border-accent/40">
        {(['Packing', 'Shopping'] as const).map((tab) => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 py-3 rounded-xl font-black text-xs tracking-widest transition-all ${
              activeTab === tab ? 'bg-white text-navy sticker-shadow scale-[1.02]' : 'text-navy/30 hover:text-navy/50'
            }`}
          >
            {tab.toUpperCase()}
          </button>
        ))}
      </div>

      <div className="space-y-3">
        {filteredItems.length > 0 ? filteredItems.map((item) => {
          const assignee = members.find(m => m.id === item.assignedTo);
          return (
            <div 
              key={item.id} 
              onClick={() => toggleComplete(item.id)}
              className={`bg-white p-4 rounded-xl-sticker sticker-shadow border transition-all cursor-pointer group flex items-center gap-4 ${
                item.completed ? 'opacity-40 grayscale border-accent' : 'border-accent/40 hover:border-stitch/30'
              }`}
            >
              <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-all ${
                item.completed ? 'bg-stitch border-stitch' : 'border-accent'
              }`}>
                {item.completed && <Check size={16} className="text-white" />}
              </div>
              <div className="flex-1 min-w-0">
                <p className={`font-black text-sm text-navy truncate ${item.completed ? 'line-through decoration-navy/20' : ''}`}>
                  {item.title}
                </p>
                <div className="flex items-center gap-1.5 text-[9px] font-black text-navy/30 mt-1 uppercase tracking-tighter">
                  {item.assignedTo === 'All' ? (
                    <><Users size={10} className="text-stitch/50" /> Everyone</>
                  ) : (
                    <><img src={assignee?.avatar} className="w-3 h-3 rounded-full" /> {assignee?.name}</>
                  )}
                </div>
              </div>
              <button 
                onClick={(e) => deleteItem(e, item.id)}
                className="text-navy/10 hover:text-red-400 p-2 opacity-0 group-hover:opacity-100 transition-opacity"
              >
                <Trash2 size={16} />
              </button>
            </div>
          );
        }) : (
          <div className="py-20 text-center opacity-20 border-2 border-dashed border-accent rounded-3xl bg-paper/50">
             <p className="font-black uppercase text-[10px] tracking-widest">List is clear!</p>
          </div>
        )}

        <button 
          onClick={() => setIsAddModalOpen(true)}
          className="w-full py-5 rounded-xl-sticker border-2 border-dashed border-accent text-navy/30 font-black flex items-center justify-center gap-3 hover:bg-white transition-all active:scale-95 group"
        >
          <div className="p-1.5 bg-accent/20 rounded-full group-hover:bg-stitch/10 group-hover:text-stitch transition-colors">
            <Plus size={20} />
          </div>
          ADD {activeTab.toUpperCase()} ITEM
        </button>
      </div>

      <div className="bg-white p-5 rounded-3xl-sticker border border-accent/40 sticker-shadow relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-[0.03] pointer-events-none transform rotate-12">✅</div>
        <h4 className="text-[10px] font-black text-navy/30 mb-4 uppercase tracking-[0.3em] flex items-center gap-2">
          <Check size={12} className="text-stitch" /> Checklist Progress
        </h4>
        <div className="flex items-center gap-4">
          <div className="h-2.5 flex-1 bg-cream rounded-full overflow-hidden border border-accent/20">
            <div 
              className="h-full bg-stitch transition-all duration-1000 shadow-[0_0_8px_rgba(110,193,228,0.4)]" 
              style={{ width: `${(filteredItems.filter(i => i.completed).length / (filteredItems.length || 1)) * 100}%` }} 
            />
          </div>
          <span className="text-[10px] font-black text-stitch tabular-nums">
            {filteredItems.filter(i => i.completed).length}/{filteredItems.length}
          </span>
        </div>
      </div>

      {/* Add Item Modal */}
      {isAddModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-navy/10 backdrop-blur-sm" onClick={() => setIsAddModalOpen(false)}>
          <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-stitch animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-black text-navy uppercase tracking-widest">Add {activeTab}</h3>
              <button onClick={() => setIsAddModalOpen(false)} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
            </div>

            <div className="space-y-6">
              <div className="bg-cream p-4 rounded-2xl border border-accent">
                <label className="text-[10px] font-black uppercase text-navy/30 mb-1 block tracking-widest">Item Title</label>
                <input 
                  autoFocus
                  type="text" 
                  value={newItemTitle}
                  onChange={(e) => setNewItemTitle(e.target.value)}
                  placeholder="e.g. Suntan Lotion"
                  className="w-full bg-transparent border-none p-0 font-black text-navy text-lg focus:ring-0 placeholder:text-navy/10"
                />
              </div>

              <div>
                <label className="text-[10px] font-black uppercase text-navy/30 mb-3 block px-1 tracking-widest">Assign To</label>
                <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                  <button 
                    onClick={() => setNewItemAssignee('All')}
                    className={`flex-shrink-0 px-4 py-2 rounded-full font-black text-[10px] border-2 uppercase tracking-tighter transition-all ${newItemAssignee === 'All' ? 'bg-navy border-navy text-white' : 'bg-white border-accent text-navy/30'}`}
                  >
                    Everyone
                  </button>
                  {members.map(m => (
                    <button 
                      key={m.id}
                      onClick={() => setNewItemAssignee(m.id)}
                      className={`flex-shrink-0 flex items-center gap-2 px-3 py-1.5 rounded-full font-black text-[10px] border-2 uppercase transition-all ${newItemAssignee === m.id ? 'bg-stitch border-stitch text-white' : 'bg-white border-accent text-navy/30'}`}
                    >
                      <img src={m.avatar} className="w-4 h-4 rounded-full" />
                      {m.name}
                    </button>
                  ))}
                </div>
              </div>

              <button 
                onClick={handleAddItem}
                disabled={!newItemTitle.trim()}
                className="w-full py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all disabled:opacity-30 disabled:pointer-events-none uppercase text-xs tracking-widest"
              >
                ADD TO LIST
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Planning;

import React, { useState, useEffect, useMemo } from 'react';
import { TripMember, Expense as ExpenseType } from '../types';
import { 
  TrendingDown, 
  CreditCard, 
  Plus, 
  Trash2, 
  Edit2, 
  X, 
  Check, 
  Calculator, 
  RefreshCw, 
  Search, 
  ArrowRightLeft, 
  Calendar,
  Settings2,
  TrendingUp,
  CircleDollarSign,
  ArrowRight,
  ChevronDown
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

const Expense: React.FC<{ currentUser: TripMember; members: TripMember[] }> = ({ currentUser, members }) => {
  const [expenses, setExpenses] = useState<ExpenseType[]>(() => {
    const saved = localStorage.getItem('expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [rates, setRates] = useState<Record<string, number>>({ JPY: 1, HKD: 19.2, AUD: 96.5 });
  const [baseCurrency, setBaseCurrency] = useState<'JPY' | 'HKD' | 'AUD'>(() => {
    return (localStorage.getItem('baseCurrency') as any) || 'JPY';
  });
  const [loadingRates, setLoadingRates] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettlementOpen, setIsSettlementOpen] = useState(false);
  const [isCalcOpen, setIsCalcOpen] = useState(false);
  const [isCurrencySettingsOpen, setIsCurrencySettingsOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<ExpenseType | null>(null);

  useEffect(() => {
    localStorage.setItem('expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('baseCurrency', baseCurrency);
  }, [baseCurrency]);

  const fetchLiveRates = async () => {
    setLoadingRates(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: "Current exchange rates: 1 HKD to JPY and 1 AUD to JPY. Return ONLY JSON: {HKD: number, AUD: number}",
        config: { tools: [{ googleSearch: {} }], responseMimeType: "application/json" }
      });
      const data = JSON.parse(response.text || '{}');
      if (data.HKD && data.AUD) {
        setRates({ JPY: 1, HKD: data.HKD, AUD: data.AUD });
      }
    } catch (e) {
      console.error("Rates fetch failed", e);
    } finally {
      setLoadingRates(false);
    }
  };

  // Memoized balance calculation
  const balances = useMemo(() => {
    const bal: Record<string, number> = {};
    members.forEach(m => bal[m.id] = 0);
    expenses.forEach(exp => {
      const amountJPY = exp.amount * (rates[exp.currency] || 1);
      const share = amountJPY / (exp.splitWith.length || 1);
      bal[exp.paidBy] += amountJPY;
      exp.splitWith.forEach(id => {
        if (bal[id] !== undefined) bal[id] -= share;
      });
    });
    return bal;
  }, [expenses, members, rates]);

  // Debt simplification (Who pays whom)
  const settlementSuggestions = useMemo(() => {
    const people = Object.entries(balances).map(([id, balance]) => ({ id, balance }));
    const debtors = people.filter(p => p.balance < -0.01).sort((a, b) => a.balance - b.balance);
    const creditors = people.filter(p => p.balance > 0.01).sort((a, b) => b.balance - a.balance);

    const transactions: Array<{ from: string; to: string; amount: number }> = [];
    let dIdx = 0, cIdx = 0;

    const debtorsCopy = debtors.map(d => ({ ...d }));
    const creditorsCopy = creditors.map(c => ({ ...c }));

    while (dIdx < debtorsCopy.length && cIdx < creditorsCopy.length) {
      const amount = Math.min(Math.abs(debtorsCopy[dIdx].balance), creditorsCopy[cIdx].balance);
      transactions.push({ from: debtorsCopy[dIdx].id, to: creditorsCopy[cIdx].id, amount });

      debtorsCopy[dIdx].balance += amount;
      creditorsCopy[cIdx].balance -= amount;

      if (Math.abs(debtorsCopy[dIdx].balance) < 0.01) dIdx++;
      if (Math.abs(creditorsCopy[cIdx].balance) < 0.01) cIdx++;
    }
    return transactions;
  }, [balances]);

  const myBalanceJPY = balances[currentUser.id] || 0;
  const totalSpentJPY = expenses.reduce((acc, exp) => acc + (exp.amount * (rates[exp.currency] || 1)), 0);

  const convertFromJPY = (amount: number, target: string) => {
    if (target === 'JPY') return amount;
    return amount / (rates[target as keyof typeof rates] || 1);
  };

  const handleSave = (expense: ExpenseType) => {
    if (editingExpense) {
      setExpenses(expenses.map(e => e.id === expense.id ? expense : e));
    } else {
      setExpenses([{ ...expense, id: Date.now().toString() }, ...expenses]);
    }
    setIsModalOpen(false);
    setEditingExpense(null);
  };

  const getCurrencySymbol = (cur: string) => {
    if (cur === 'JPY') return '¥';
    return '$';
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500">
      {/* Softer Dashboard Header */}
      <div className="bg-white/80 backdrop-blur-sm p-6 rounded-3xl-sticker sticker-shadow border border-stitch/20 relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-donald/10 rounded-full blur-3xl pointer-events-none" />
        <div className="relative z-10">
          <div className="flex justify-between items-center mb-1">
             <div className="flex items-center gap-1">
               <p className="text-[10px] font-black uppercase tracking-[0.2em] text-navy/30">Total Trip Cost</p>
               <ChevronDown size={10} className="text-navy/20" />
             </div>
             <div className="flex gap-2">
                {(['JPY', 'HKD', 'AUD'] as const).map(cur => (
                  <button 
                    key={cur}
                    onClick={() => setBaseCurrency(cur)}
                    className={`text-[9px] font-black px-2 py-1 rounded-md transition-all ${baseCurrency === cur ? 'bg-navy text-white' : 'text-navy/20 hover:text-navy/40'}`}
                  >
                    {cur}
                  </button>
                ))}
             </div>
          </div>
          <h2 className="text-4xl font-black text-navy flex items-baseline gap-1">
            <span className="text-xl opacity-30 font-bold">{getCurrencySymbol(baseCurrency)}</span>
            {Math.round(convertFromJPY(totalSpentJPY, baseCurrency)).toLocaleString()}
          </h2>

          <div className="mt-8 flex gap-3">
            <button 
              onClick={() => { setEditingExpense(null); setIsModalOpen(true); }}
              className="flex-1 bg-stitch text-white py-4 rounded-2xl-sticker font-black text-[11px] uppercase tracking-widest flex items-center justify-center gap-2 sticker-shadow active:scale-95 transition-all"
            >
              <Plus size={16} /> Add Record
            </button>
            <button 
              onClick={() => setIsSettlementOpen(true)}
              className="px-6 bg-donald/40 text-navy py-4 rounded-2xl-sticker font-black text-[11px] uppercase tracking-widest border border-donald/50 sticker-shadow active:scale-95 transition-all"
            >
              Settlement
            </button>
          </div>
        </div>
      </div>

      {/* Dynamic Personal Balance Card */}
      <div className={`p-5 rounded-2xl-sticker sticker-shadow border-2 transition-all duration-300 bg-white ${myBalanceJPY >= 0 ? 'border-stitch/10 bg-stitch/5' : 'border-red-50 bg-red-50/30'}`}>
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-4">
             <div className={`w-12 h-12 rounded-full flex items-center justify-center transition-colors shadow-sm ${myBalanceJPY >= 0 ? 'bg-white text-stitch' : 'bg-white text-red-300'}`}>
               {myBalanceJPY >= 0 ? <TrendingUp size={24} /> : <TrendingDown size={24} />}
             </div>
             <div>
                <p className="text-[9px] font-black text-navy/20 uppercase tracking-[0.2em]">Balance for {currentUser.name}</p>
                <h3 className={`text-xl font-black ${myBalanceJPY >= 0 ? 'text-stitch' : 'text-red-300'}`}>
                  {myBalanceJPY >= 0 ? 'To Receive' : 'To Pay'} 
                  <span className="ml-2 font-black">
                    {getCurrencySymbol(baseCurrency)}{Math.abs(Math.round(convertFromJPY(myBalanceJPY, baseCurrency))).toLocaleString()}
                  </span>
                </h3>
             </div>
          </div>
          <button 
            onClick={() => setIsCalcOpen(true)}
            className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-navy/20 active:scale-90 sticker-shadow border border-accent/30"
          >
            <Calculator size={18} />
          </button>
        </div>
      </div>

      {/* History List */}
      <div className="space-y-4 pt-2">
        <div className="flex justify-between items-center px-1">
           <h3 className="text-[11px] font-black text-navy/20 uppercase tracking-[0.3em] flex items-center gap-2">
              <ArrowRightLeft size={12} /> Log Book
           </h3>
           <button onClick={() => setIsCurrencySettingsOpen(true)} className="text-navy/20 hover:text-stitch transition-colors">
              <Settings2 size={14} />
           </button>
        </div>

        {expenses.length > 0 ? expenses.map((exp) => {
          const payer = members.find(m => m.id === exp.paidBy);
          return (
            <div key={exp.id} className="bg-white p-4 rounded-xl-sticker sticker-shadow border border-accent/30 flex items-center gap-4 group hover:border-stitch/40 transition-all animate-in slide-in-from-bottom-2">
              <div className="relative flex-shrink-0">
                <img src={payer?.avatar} alt={payer?.name} className="w-12 h-12 rounded-full object-cover border-2 border-accent shadow-inner" />
                <div className="absolute -bottom-1 -right-1 bg-white rounded-full p-1 border border-accent shadow-sm">
                   <CircleDollarSign size={8} className="text-stitch" />
                </div>
              </div>

              <div className="flex-1 min-w-0">
                <h4 className="font-black text-navy text-sm truncate">{exp.category}</h4>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-[9px] font-black text-stitch/70 uppercase">{payer?.name} PAID</span>
                  <span className="w-1 h-1 bg-navy/10 rounded-full" />
                  <span className="text-[9px] font-bold text-navy/20 uppercase tracking-tighter">{exp.date}</span>
                </div>
              </div>

              <div className="text-right">
                <p className="font-black text-navy text-sm">
                  {exp.currency} {exp.amount.toLocaleString()}
                </p>
                {exp.currency !== baseCurrency && (
                  <p className="text-[9px] font-bold text-navy/10">
                    ≈ {baseCurrency} {Math.round(convertFromJPY(exp.amount * (rates[exp.currency as keyof typeof rates] || 1), baseCurrency)).toLocaleString()}
                  </p>
                )}
                <div className="flex gap-2 justify-end mt-1.5 opacity-0 group-hover:opacity-100 transition-opacity">
                   <button onClick={() => { setEditingExpense(exp); setIsModalOpen(true); }} className="p-1 text-navy/10 hover:text-stitch"><Edit2 size={12} /></button>
                   <button onClick={() => setExpenses(expenses.filter(e => e.id !== exp.id))} className="p-1 text-navy/10 hover:text-red-400"><Trash2 size={12} /></button>
                </div>
              </div>
            </div>
          );
        }) : (
          <div className="py-24 text-center opacity-10 border-2 border-dashed border-accent rounded-3xl bg-paper/50">
            <CreditCard size={48} className="mx-auto mb-3" />
            <p className="font-black uppercase text-[10px] tracking-widest italic">Spending is caring</p>
          </div>
        )}
      </div>

      {/* Settlement Modal */}
      {isSettlementOpen && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 bg-navy/5 backdrop-blur-sm" onClick={() => setIsSettlementOpen(false)}>
          <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-stitch/30 animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-6">
              <div>
                <h3 className="text-lg font-black text-navy uppercase tracking-widest leading-none">Settlement</h3>
                <p className="text-[9px] font-bold text-navy/20 uppercase mt-2">Recommended Transfers ({baseCurrency})</p>
              </div>
              <button onClick={() => setIsSettlementOpen(false)} className="p-2 bg-cream rounded-full text-navy/20 active:scale-90 transition-transform"><X size={20} /></button>
            </div>

            <div className="space-y-4 max-h-[60vh] overflow-y-auto pr-1">
              {settlementSuggestions.length > 0 ? (
                <div className="space-y-2">
                  {settlementSuggestions.map((tx, idx) => {
                    const from = members.find(m => m.id === tx.from);
                    const to = members.find(m => m.id === tx.to);
                    return (
                      <div key={idx} className="bg-cream p-4 rounded-2xl border border-accent/20 flex items-center justify-between">
                        <div className="flex items-center gap-3">
                          <div className="flex -space-x-2">
                            <img src={from?.avatar} className="w-8 h-8 rounded-full border-2 border-white shadow-sm" />
                            <img src={to?.avatar} className="w-8 h-8 rounded-full border-2 border-white shadow-sm" />
                          </div>
                          <div>
                            <p className="text-[9px] font-black text-navy/40 uppercase leading-none mb-1">{from?.name} ➜ {to?.name}</p>
                            <p className="font-black text-stitch text-sm">
                              {getCurrencySymbol(baseCurrency)}{Math.round(convertFromJPY(tx.amount, baseCurrency)).toLocaleString()}
                            </p>
                          </div>
                        </div>
                        <ArrowRight size={16} className="text-navy/10" />
                      </div>
                    );
                  })}
                </div>
              ) : (
                <div className="text-center py-12 bg-stitch/5 rounded-3xl border border-stitch/10">
                  <Check size={40} className="mx-auto mb-3 text-stitch opacity-40" />
                  <p className="font-black uppercase text-xs text-navy/40 tracking-widest">Perfectly Balanced</p>
                </div>
              )}

              <div className="pt-6 border-t border-accent/40">
                <p className="text-[9px] font-black text-navy/20 uppercase tracking-widest px-1 mb-3">Individual Balances</p>
                <div className="grid grid-cols-2 gap-2">
                  {members.map(m => {
                    const bal = convertFromJPY(balances[m.id] || 0, baseCurrency);
                    return (
                      <div key={m.id} className="bg-white border border-accent/20 p-2 rounded-xl flex items-center justify-between">
                        <span className="text-[10px] font-black text-navy/40 truncate pr-1">{m.name}</span>
                        <span className={`text-[10px] font-black ${bal >= 0 ? 'text-stitch' : 'text-red-300'}`}>
                          {bal > 0 ? '+' : ''}{Math.round(bal).toLocaleString()}
                        </span>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>

            <button 
              onClick={() => setIsSettlementOpen(false)}
              className="w-full mt-8 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all uppercase text-[11px] tracking-[0.2em]"
            >
              Close
            </button>
          </div>
        </div>
      )}

      {/* Calculator Modal */}
      {isCalcOpen && <CalculatorTool rates={rates} onClose={() => setIsCalcOpen(false)} />}

      {/* Settings Modal */}
      {isCurrencySettingsOpen && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 bg-navy/5 backdrop-blur-sm" onClick={() => setIsCurrencySettingsOpen(false)}>
           <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-donald/30 animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-black text-navy uppercase tracking-widest">Money Settings</h3>
                <button onClick={() => setIsCurrencySettingsOpen(false)} className="p-2 bg-cream rounded-full text-navy/20 active:scale-90"><X size={20} /></button>
              </div>

              <div className="space-y-6">
                 <div>
                    <label className="text-[10px] font-black uppercase text-navy/20 mb-3 block px-1 tracking-widest">Base Currency</label>
                    <div className="flex gap-2">
                       {(['JPY', 'HKD', 'AUD'] as const).map(cur => (
                         <button 
                           key={cur}
                           onClick={() => setBaseCurrency(cur)}
                           className={`flex-1 py-3 rounded-xl border-2 font-black text-xs transition-all ${baseCurrency === cur ? 'bg-navy text-white border-navy sticker-shadow scale-105' : 'bg-white text-navy/20 border-accent/50 hover:bg-cream'}`}
                         >
                           {cur}
                         </button>
                       ))}
                    </div>
                 </div>

                 <div className="space-y-3">
                    <div className="flex justify-between items-center px-1">
                       <label className="text-[10px] font-black uppercase text-navy/20 tracking-widest">Live Rates (vs JPY)</label>
                       <button onClick={fetchLiveRates} className="text-[9px] font-black text-stitch flex items-center gap-1 active:scale-90 transition-transform">
                         <RefreshCw size={10} className={loadingRates ? 'animate-spin' : ''} /> SYNC
                       </button>
                    </div>
                    <div className="space-y-2">
                       {['HKD', 'AUD'].map(cur => (
                         <div key={cur} className="flex items-center justify-between p-4 bg-cream/40 rounded-xl border border-accent/40">
                            <span className="font-black text-navy/40 text-xs uppercase">1 {cur} =</span>
                            <div className="flex items-center gap-2">
                               <input 
                                 type="number" 
                                 value={rates[cur]} 
                                 onChange={e => setRates({...rates, [cur]: parseFloat(e.target.value) || 0})}
                                 className="w-16 text-right font-black text-stitch bg-transparent border-none focus:ring-0 p-0"
                               />
                               <span className="text-[10px] font-black text-navy/10 uppercase">JPY</span>
                            </div>
                         </div>
                       ))}
                    </div>
                 </div>
              </div>

              <button 
                onClick={() => setIsCurrencySettingsOpen(false)}
                className="w-full mt-8 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all uppercase text-[11px] tracking-widest"
              >
                Apply Changes
              </button>
           </div>
        </div>
      )}

      {/* Entry Modal */}
      {isModalOpen && (
        <ExpenseModal 
          expense={editingExpense} 
          members={members} 
          rates={rates}
          onClose={() => setIsModalOpen(false)} 
          onSave={handleSave} 
        />
      )}
    </div>
  );
};

const CalculatorTool: React.FC<{ rates: Record<string, number>; onClose: () => void }> = ({ rates, onClose }) => {
  const [val, setVal] = useState('');
  const [cur, setCur] = useState<'HKD' | 'AUD'>('HKD');
  return (
    <div className="fixed inset-0 z-[130] flex items-center justify-center p-6 bg-navy/5 backdrop-blur-sm" onClick={onClose}>
      <div className="bg-paper w-full max-w-xs rounded-3xl-sticker p-6 sticker-shadow border-4 border-donald/30 animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-black text-navy uppercase tracking-widest leading-none">Price Check</h3>
          <button onClick={onClose} className="p-2 bg-cream rounded-full text-navy/20 active:scale-90"><X size={20} /></button>
        </div>
        <div className="space-y-6">
          <div className="flex bg-accent/10 p-1.5 rounded-2xl border border-accent/20">
            {(['HKD', 'AUD'] as const).map(c => (
              <button key={c} onClick={() => setCur(c)} className={`flex-1 py-2.5 rounded-xl text-[10px] font-black transition-all ${cur === c ? 'bg-white text-navy sticker-shadow scale-105 shadow-sm' : 'text-navy/20 hover:text-navy/40'}`}>{c}</button>
            ))}
          </div>
          <input 
            autoFocus type="number" value={val} onChange={e => setVal(e.target.value)} placeholder="0.00"
            className="w-full text-4xl font-black text-navy border-b-4 border-accent/20 focus:border-donald/50 bg-transparent p-4 focus:ring-0 text-center placeholder:text-navy/5"
          />
          <div className="text-center py-6 bg-stitch/5 rounded-3xl border border-stitch/10">
            <p className="text-[9px] font-black uppercase text-navy/20 mb-2 tracking-[0.2em]">Approximately</p>
            <h4 className="text-4xl font-black text-stitch">¥ {val ? Math.round(parseFloat(val) * rates[cur]).toLocaleString() : '0'}</h4>
          </div>
        </div>
        <button onClick={onClose} className="w-full mt-6 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all uppercase text-[11px] tracking-widest">Done</button>
      </div>
    </div>
  );
};

const ExpenseModal: React.FC<{ 
  expense: ExpenseType | null; 
  members: TripMember[]; 
  rates: Record<string, number>;
  onClose: () => void; 
  onSave: (e: ExpenseType) => void 
}> = ({ expense, members, rates, onClose, onSave }) => {
  const [formData, setFormData] = useState<Partial<ExpenseType>>(expense || {
    amount: 0, currency: 'JPY', category: '', paidBy: members[0].id, splitWith: members.map(m => m.id), date: new Date().toISOString().split('T')[0]
  });

  const toggleSplit = (id: string) => {
    const current = formData.splitWith || [];
    setFormData({ ...formData, splitWith: current.includes(id) ? current.filter(cid => cid !== id) : [...current, id] });
  };

  return (
    <div className="fixed inset-0 z-[150] flex flex-col bg-cream/95 backdrop-blur-md animate-in slide-in-from-bottom duration-300">
      <div className="p-4 flex justify-between items-center border-b border-accent/40 bg-white/80">
        <button onClick={onClose} className="text-navy/20 p-2 active:scale-90"><X size={24} /></button>
        <h3 className="text-lg font-black text-navy uppercase tracking-[0.2em] leading-none">{expense ? 'Edit Spending' : 'New Spending'}</h3>
        <button 
          onClick={() => onSave(formData as ExpenseType)} 
          className="text-stitch font-black p-2 disabled:opacity-30 active:scale-90 transition-transform"
          disabled={!formData.category || !formData.amount || formData.splitWith?.length === 0}
        >SAVE</button>
      </div>
      <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-24">
        <div className="bg-white p-8 rounded-3xl-sticker sticker-shadow border border-accent/30 text-center relative shadow-inner">
          <div className="flex items-center justify-center gap-2">
            <select 
              value={formData.currency} 
              onChange={e => setFormData({...formData, currency: e.target.value as any})}
              className="text-xl font-black text-stitch bg-transparent border-none focus:ring-0 p-0 w-min cursor-pointer hover:scale-105 transition-transform"
            >
              <option value="JPY">¥ JPY</option><option value="HKD">$ HKD</option><option value="AUD">$ AUD</option>
            </select>
            <input 
              type="number" value={formData.amount || ''} onChange={e => setFormData({...formData, amount: parseFloat(e.target.value) || 0})}
              placeholder="0" className="w-full text-5xl font-black text-navy bg-transparent border-none focus:ring-0 text-center placeholder:text-navy/5" autoFocus
            />
          </div>
        </div>

        <div className="bg-white p-5 rounded-2xl-sticker border border-accent/30 sticker-shadow space-y-6 shadow-inner">
          <div className="flex items-center gap-4 border-b border-accent/10 pb-4">
             <div className="p-2 bg-cream rounded-lg text-navy/20"><Search size={18} /></div>
             <input 
               type="text" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})}
               placeholder="Description (e.g. Sushi)" className="w-full font-black text-navy border-none focus:ring-0 p-0 text-lg placeholder:text-navy/5"
             />
          </div>
          <div className="flex items-center gap-4">
             <div className="p-2 bg-cream rounded-lg text-navy/20"><Calendar size={18} /></div>
             <input type="date" value={formData.date} onChange={e => setFormData({...formData, date: e.target.value})} className="w-full font-black text-navy bg-transparent border-none focus:ring-0 p-0 text-sm" />
          </div>
        </div>

        <div className="bg-white p-5 rounded-2xl-sticker border border-accent/30 sticker-shadow shadow-inner">
          <label className="text-[10px] font-black uppercase text-navy/20 mb-4 block tracking-widest">Paid By</label>
          <div className="flex gap-4 overflow-x-auto pb-2 scrollbar-hide">
            {members.map(m => (
              <button
                key={m.id} onClick={() => setFormData({ ...formData, paidBy: m.id })}
                className={`flex-shrink-0 flex flex-col items-center gap-2 transition-all ${formData.paidBy === m.id ? 'opacity-100 scale-110' : 'opacity-20'}`}
              >
                <img src={m.avatar} className={`w-14 h-14 rounded-full object-cover border-4 p-0.5 transition-all ${formData.paidBy === m.id ? 'border-stitch shadow-md' : 'border-transparent'}`} alt={m.name} />
                <span className="text-[9px] font-black uppercase tracking-widest">{m.name}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="bg-white p-5 rounded-2xl-sticker border border-accent/30 sticker-shadow shadow-inner">
          <label className="text-[10px] font-black uppercase text-navy/20 mb-4 block tracking-widest">Split With</label>
          <div className="grid grid-cols-2 gap-3">
            {members.map(m => {
              const isSelected = formData.splitWith?.includes(m.id);
              return (
                <button
                  key={m.id} onClick={() => toggleSplit(m.id)}
                  className={`flex items-center gap-3 p-4 rounded-xl-sticker border-2 transition-all ${isSelected ? 'bg-stitch/5 border-stitch text-navy' : 'bg-white border-accent/40 text-navy/10'}`}
                >
                  <div className={`w-5 h-5 rounded-lg border-2 flex items-center justify-center transition-colors ${isSelected ? 'bg-stitch border-stitch' : 'border-navy/10'}`}>
                    {isSelected && <Check size={14} className="text-white" strokeWidth={4} />}
                  </div>
                  <span className="text-[11px] font-black uppercase tracking-widest">{m.name}</span>
                </button>
              );
            })}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Expense;

import React, { useState, useEffect } from 'react';
import { 
  Calendar, 
  Ticket, 
  Wallet, 
  Camera, 
  CheckSquare, 
  Users
} from 'lucide-react';
import { MOCK_MEMBERS, MOCK_TRIP_CONFIG } from './constants';
import { TripMember } from './types';
import Schedule from './modules/Schedule';
import Bookings from './modules/Bookings';
import Expense from './modules/Expense';
import Journal from './modules/Journal';
import Planning from './modules/Planning';
import Members from './modules/Members';

type Tab = 'schedule' | 'bookings' | 'expense' | 'journal' | 'planning' | 'members';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('schedule');
  const [members, setMembers] = useState<TripMember[]>(() => {
    const saved = localStorage.getItem('trip_members');
    return saved ? JSON.parse(saved) : MOCK_MEMBERS;
  });
  const [currentUser, setCurrentUser] = useState<TripMember>(() => {
    const savedUser = localStorage.getItem('currentUser');
    if (savedUser) {
      const parsed = JSON.parse(savedUser);
      const exists = members.find(m => m.id === parsed.id);
      return exists || members[0];
    }
    return members[0];
  });
  const [tripConfig, setTripConfig] = useState(MOCK_TRIP_CONFIG);

  useEffect(() => {
    const savedTab = localStorage.getItem('activeTab') as Tab;
    if (savedTab) setActiveTab(savedTab);
  }, []);

  useEffect(() => {
    localStorage.setItem('activeTab', activeTab);
  }, [activeTab]);

  useEffect(() => {
    localStorage.setItem('trip_members', JSON.stringify(members));
  }, [members]);

  useEffect(() => {
    localStorage.setItem('currentUser', JSON.stringify(currentUser));
  }, [currentUser]);

  const handleSwitchUser = (user: TripMember) => {
    setCurrentUser(user);
  };

  const handleAddMember = (name: string, avatar: string) => {
    const newMember: TripMember = {
      id: Date.now().toString(),
      name,
      avatar
    };
    setMembers([...members, newMember]);
  };

  const handleDeleteMember = (id: string) => {
    if (id === currentUser.id) {
      alert("Ohana! 你不能刪除目前正在使用的成員。請先切換身分。");
      return;
    }
    if (confirm("確定要移除這位成員嗎？這不會刪除已記錄的支出，但會影響未來的分帳顯示。")) {
      setMembers(members.filter(m => m.id !== id));
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'schedule': return <Schedule config={tripConfig} />;
      case 'bookings': return <Bookings />;
      case 'expense': return <Expense currentUser={currentUser} members={members} />;
      case 'journal': return <Journal currentUser={currentUser} members={members} />;
      case 'planning': return <Planning members={members} />;
      case 'members': return (
        <Members 
          currentUser={currentUser} 
          members={members} 
          onSwitch={handleSwitchUser} 
          onAdd={handleAddMember}
          onDelete={handleDeleteMember}
        />
      );
      default: return <Schedule config={tripConfig} />;
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto bg-cream shadow-2xl relative overflow-hidden">
      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto pb-24 px-4 pt-6">
        {renderContent()}
      </main>

      {/* Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-paper border-t border-accent px-2 py-3 flex justify-around items-center z-50 rounded-t-3xl shadow-[0_-4px_10px_rgba(0,0,0,0.05)]">
        <NavButton active={activeTab === 'schedule'} onClick={() => setActiveTab('schedule')} icon={<Calendar size={22} />} label="行程" />
        <NavButton active={activeTab === 'bookings'} onClick={() => setActiveTab('bookings')} icon={<Ticket size={22} />} label="預訂" />
        <NavButton active={activeTab === 'expense'} onClick={() => setActiveTab('expense')} icon={<Wallet size={22} />} label="記帳" />
        <NavButton active={activeTab === 'journal'} onClick={() => setActiveTab('journal')} icon={<Camera size={22} />} label="日誌" />
        <NavButton active={activeTab === 'planning'} onClick={() => setActiveTab('planning')} icon={<CheckSquare size={22} />} label="清單" />
        <NavButton active={activeTab === 'members'} onClick={() => setActiveTab('members')} icon={<Users size={22} />} label="成員" />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center gap-1 transition-all duration-200 ${active ? 'text-stitch scale-110' : 'text-navy/40'}`}
  >
    <div className={`p-1 rounded-xl ${active ? 'bg-stitch/10' : ''}`}>
      {icon}
    </div>
    <span className="text-[10px] font-bold uppercase tracking-tighter">{label}</span>
  </button>
);

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { TripMember, Expense as ExpenseType } from '../types';
import { 
  TrendingDown, 
  CreditCard, 
  Plus, 
  Trash2, 
  Edit2, 
  X, 
  Check, 
  Calculator, 
  RefreshCw, 
  Search, 
  ArrowRightLeft, 
  Calendar,
  Settings2,
  TrendingUp,
  CircleDollarSign,
  ArrowRight,
  ChevronDown
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

const Expense: React.FC<{ currentUser: TripMember; members: TripMember[] }> = ({ currentUser, members }) => {
  const [expenses, setExpenses] = useState<ExpenseType[]>(() => {
    const saved = localStorage.getItem('expenses');
    return saved ? JSON.parse(saved) : [];
  });

  const [rates, setRates] = useState<Record<string, number>>({ JPY: 1, HKD: 19.2, AUD: 96.5 });
  const [baseCurrency, setBaseCurrency] = useState<'JPY' | 'HKD' | 'AUD'>(() => {
    return (localStorage.getItem('baseCurrency') as any) || 'JPY';
  });
  const [loadingRates, setLoadingRates] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettlementOpen, setIsSettlementOpen] = useState(false);
  const [isCalcOpen, setIsCalcOpen] = useState(false);
  const [isCurrencySettingsOpen, setIsCurrencySettingsOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<ExpenseType | null>(null);

  useEffect(() => {
    localStorage.setItem('expenses', JSON.stringify(expenses));
  }, [expenses]);

  useEffect(() => {
    localStorage.setItem('baseCurrency', baseCurrency);
  }, [baseCurrency]);

  const fetchLiveRates = async () => {
    setLoadingRates(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: "Current exchange rates: 1 HKD to JPY and 1 AUD to JPY. Return ONLY JSON: {HKD: number, AUD: number}",
        config: { tools: [{ googleSearch: {} }], responseMimeType: "application/json" }
      });
      const data = JSON.parse(response.text || '{}');
      if (data.HKD && data.AUD) {
        setRates({ JPY: 1, HKD: data.HKD, AUD: data.AUD });
      }
    } catch (e) {
      console.error("Rates fetch failed", e);
    } finally {
      setLoadingRates(false);
    }
  };

  const balances = useMemo(() => {
    const bal: Record<string, number> = {};
    members.forEach(m => bal[m.id] = 0);
    expenses.forEach(exp => {
      const amountJPY = exp.amount * (rates[exp.currency as keyof typeof rates] || 1);
      const share = amountJPY / (exp.splitWith.length || 1);
      if (bal[exp.paidBy] !== undefined) bal[exp.paidBy] += amountJPY;
      exp.splitWith.forEach(id => {
        if (bal[id] !== undefined) bal[id] -= share;
      });
    });
    return bal;
  }, [expenses, members, rates]);

  const settlementSuggestions = useMemo(() => {
    const people = Object.entries(balances).map(([id, balance]) => ({ id, balance }));
    const debtors = people.filter(p => p.balance < -0.01).sort((a, b) => a.balance - b.balance);
    const creditors = people.filter(p => p.balance > 0.01).sort((a, b) => b.balance - a.balance);

    const transactions: Array<{ from: string; to: string; amount: number }> = [];
    const dCopy = debtors.map(d => ({ ...d }));
    const cCopy = creditors.map(c => ({ ...c }));

    let dIdx = 0, cIdx = 0;
    while (dIdx < dCopy.length && cIdx < cCopy.length) {
      const amount = Math.min(Math.abs(dCopy[dIdx].balance), cCopy[cIdx].balance);
      transactions.push({ from: dCopy[dIdx].id, to: cCopy[cIdx].id, amount });

      dCopy[dIdx].balance += amount;
      cCopy[cIdx].balance -= amount;

      if (Math.abs(dCopy[dIdx].balance) < 0.01) dIdx++;
      if (Math.abs(cCopy[cIdx].balance) < 0.01) cIdx++;
    }
    return transactions;
  }, [balances]);

  const myBalanceJPY = balances[currentUser.id] || 0;
  const totalSpentJPY = expenses.reduce((acc, exp) => acc + (exp.amount * (rates[exp.currency as keyof typeof rates] || 1)), 0);

  const convertFromJPY = (amount: number, target: string) => {
    if (target === 'JPY') return amount;
    return amount / (rates[target as keyof typeof rates] || 1);
  };

  const handleSave = (expense: ExpenseType) => {
    if (editingExpense) {
      setExpenses(expenses.map(e => e.id === expense.id ? expense : e));
    } else {
      setExpenses([{ ...expense, id: Date.now().toString() }, ...expenses]);
    }
    setIsModalOpen(false);
    setEditingExpense(null);
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500">
      <div className="bg-white/80 backdrop-blur-sm p-6 rounded-3xl-sticker sticker-shadow border border-stitch/20 relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-donald/10 rounded-full blur-3xl pointer-events-none" />
        <div className="relative z-10">
          <div className="flex justify-between items-center mb-1">
             <div className="flex items-center gap-1">
               <p className="text-[10px] font-black uppercase tracking-[0.2em] text-navy/30">總支出總額</p>
             </div>
             <div className="flex gap-2">
                {(['JPY', 'HKD', 'AUD'] as const).map(cur => (
                  <button 
                    key={cur}
                    onClick={() => setBaseCurrency(cur)}
                    className={`text-[9px] font-black px-2 py-1 rounded-md transition-all ${baseCurrency === cur ? 'bg-navy text-white' : 'text-navy/20 hover:text-navy/40'}`}
                  >
                    {cur}
                  </button>
                ))}
             </div>
          </div>
          <h2 className="text-4xl font-black text-navy flex items-baseline gap-1">
            <span className="text-xl opacity-30 font-bold">{baseCurrency === 'JPY' ? '¥' : '$'}</span>
            {Math.round(convertFromJPY(totalSpentJPY, baseCurrency)).toLocaleString()}
          </h2>

          <div className="mt-8 flex gap-3">
            <button 
              onClick={() => { setEditingExpense(null); setIsModalOpen(true); }}
              className="flex-1 bg-stitch text-white py-4 rounded-2xl-sticker font-black text-[11px] uppercase tracking-widest flex items-center justify-center gap-2 sticker-shadow active:scale-95 transition-all"
            >
              <Plus size={16} /> 新增支出
            </button>
            <button 
              onClick={() => setIsSettlementOpen(true)}
              className="px-6 bg-donald/40 text-navy py-4 rounded-2xl-sticker font-black text-[11px] uppercase tracking-widest border border-donald/50 sticker-shadow active:scale-95 transition-all"
            >
              結算
            </button>
          </div>
        </div>
      </div>

      <div className={`p-5 rounded-2xl-sticker sticker-shadow border-2 transition-all duration-300 bg-white ${myBalanceJPY >= 0 ? 'border-stitch/10 bg-stitch/5' : 'border-red-50 bg-red-50/30'}`}>
        <div className="flex justify-between items-center">
          <div className="flex items-center gap-4">
             <div className={`w-12 h-12 rounded-full flex items-center justify-center transition-colors shadow-sm ${myBalanceJPY >= 0 ? 'bg-white text-stitch' : 'bg-white text-red-300'}`}>
               {myBalanceJPY >= 0 ? <TrendingUp size={24} /> : <TrendingDown size={24} />}
             </div>
             <div>
                <p className="text-[9px] font-black text-navy/20 uppercase tracking-[0.2em]">{currentUser.name} 的收支平衡</p>
                <h3 className={`text-xl font-black ${myBalanceJPY >= 0 ? 'text-stitch' : 'text-red-300'}`}>
                  {myBalanceJPY >= 0 ? '應收' : '應付'} 
                  <span className="ml-2 font-black">
                    {baseCurrency === 'JPY' ? '¥' : '$'}{Math.abs(Math.round(convertFromJPY(myBalanceJPY, baseCurrency))).toLocaleString()}
                  </span>
                </h3>
             </div>
          </div>
          <button onClick={() => setIsCalcOpen(true)} className="w-10 h-10 bg-white rounded-full flex items-center justify-center text-navy/20 active:scale-90 sticker-shadow border border-accent/30">
            <Calculator size={18} />
          </button>
        </div>
      </div>

      <div className="space-y-4 pt-2">
        <div className="flex justify-between items-center px-1">
           <h3 className="text-[11px] font-black text-navy/20 uppercase tracking-[0.3em] flex items-center gap-2">
              <ArrowRightLeft size={12} /> 歷史紀錄
           </h3>
           <button onClick={() => setIsCurrencySettingsOpen(true)} className="text-navy/20 hover:text-stitch transition-colors">
              <Settings2 size={14} />
           </button>
        </div>

        {expenses.length > 0 ? expenses.map((exp) => {
          const payer = members.find(m => m.id === exp.paidBy);
          return (
            <div key={exp.id} className="bg-white p-4 rounded-xl-sticker sticker-shadow border border-accent/30 flex items-center gap-4 group hover:border-stitch/40 transition-all">
              <div className="relative flex-shrink-0">
                <img src={payer?.avatar} alt={payer?.name} className="w-12 h-12 rounded-full object-cover border-2 border-accent shadow-inner" />
                <div className="absolute -bottom-1 -right-1 bg-white rounded-full p-1 border border-accent shadow-sm">
                   <CircleDollarSign size={8} className="text-stitch" />
                </div>
              </div>
              <div className="flex-1 min-w-0">
                <h4 className="font-black text-navy text-sm truncate">{exp.category}</h4>
                <div className="flex items-center gap-2 mt-1">
                  <span className="text-[9px] font-black text-stitch/70 uppercase">{payer?.name} 付款</span>
                  <span className="w-1 h-1 bg-navy/10 rounded-full" />
                  <span className="text-[9px] font-bold text-navy/20 uppercase">{exp.date}</span>
                </div>
              </div>
              <div className="text-right">
                <p className="font-black text-navy text-sm">
                  {exp.currency} {exp.amount.toLocaleString()}
                </p>
                {exp.currency !== baseCurrency && (
                  <p className="text-[9px] font-bold text-navy/10">
                    ≈ {baseCurrency} {Math.round(convertFromJPY(exp.amount * (rates[exp.currency as keyof typeof rates] || 1), baseCurrency)).toLocaleString()}
                  </p>
                )}
                <div className="flex gap-2 justify-end mt-1.5 opacity-0 group-hover:opacity-100">
                   <button onClick={() => { setEditingExpense(exp); setIsModalOpen(true); }} className="p-1 text-navy/10 hover:text-stitch"><Edit2 size={12} /></button>
                   <button onClick={() => setExpenses(expenses.filter(e => e.id !== exp.id))} className="p-1 text-navy/10 hover:text-red-400"><Trash2 size={12} /></button>
                </div>
              </div>
            </div>
          );
        }) : (
          <div className="py-24 text-center opacity-10 border-2 border-dashed border-accent rounded-3xl">
            <CreditCard size={48} className="mx-auto mb-3" />
            <p className="font-black uppercase text-[10px] tracking-widest italic">尚未有支出紀錄</p>
          </div>
        )}
      </div>

      {isSettlementOpen && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 bg-navy/5 backdrop-blur-sm" onClick={() => setIsSettlementOpen(false)}>
          <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-stitch/30 animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-6">
              <div>
                <h3 className="text-lg font-black text-navy uppercase tracking-widest">Ohana 結算</h3>
                <p className="text-[9px] font-bold text-navy/20 uppercase mt-2">建議還款路徑 ({baseCurrency})</p>
              </div>
              <button onClick={() => setIsSettlementOpen(false)} className="p-2 bg-cream rounded-full text-navy/20 active:scale-90"><X size={20} /></button>
            </div>
            <div className="space-y-4 max-h-[60vh] overflow-y-auto pr-1">
              {settlementSuggestions.length > 0 ? settlementSuggestions.map((tx, idx) => {
                const from = members.find(m => m.id === tx.from);
                const to = members.find(m => m.id === tx.to);
                return (
                  <div key={idx} className="bg-cream p-4 rounded-2xl border border-accent/20 flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <div className="flex -space-x-2">
                        <img src={from?.avatar} className="w-8 h-8 rounded-full border-2 border-white shadow-sm" />
                        <img src={to?.avatar} className="w-8 h-8 rounded-full border-2 border-white shadow-sm" />
                      </div>
                      <div>
                        <p className="text-[9px] font-black text-navy/40 uppercase mb-1">{from?.name} ➜ {to?.name}</p>
                        <p className="font-black text-stitch text-sm">
                          {baseCurrency === 'JPY' ? '¥' : '$'}{Math.round(convertFromJPY(tx.amount, baseCurrency)).toLocaleString()}
                        </p>
                      </div>
                    </div>
                    <ArrowRight size={16} className="text-navy/10" />
                  </div>
                );
              }) : (
                <div className="text-center py-12 opacity-40">
                  <Check size={40} className="mx-auto mb-3 text-stitch" />
                  <p className="font-black uppercase text-xs tracking-widest">帳目已清！</p>
                </div>
              )}
            </div>
            <button onClick={() => setIsSettlementOpen(false)} className="w-full mt-8 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow uppercase text-[11px] tracking-[0.2em]">關閉</button>
          </div>
        </div>
      )}

      {isCalcOpen && <CalculatorTool rates={rates} onClose={() => setIsCalcOpen(false)} />}
      {isCurrencySettingsOpen && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center p-6 bg-navy/5 backdrop-blur-sm" onClick={() => setIsCurrencySettingsOpen(false)}>
           <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-donald/30 animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-black text-navy uppercase tracking-widest">幣別與匯率</h3>
                <button onClick={() => setIsCurrencySettingsOpen(false)} className="p-2 bg-cream rounded-full text-navy/20"><X size={20} /></button>
              </div>
              <div className="space-y-6">
                 <div>
                    <label className="text-[10px] font-black uppercase text-navy/20 mb-3 block px-1">基準幣別</label>
                    <div className="flex gap-2">
                       {(['JPY', 'HKD', 'AUD'] as const).map(cur => (
                         <button 
                           key={cur}
                           onClick={() => setBaseCurrency(cur)}
                           className={`flex-1 py-3 rounded-xl border-2 font-black text-xs transition-all ${baseCurrency === cur ? 'bg-navy text-white border-navy sticker-shadow scale-105' : 'bg-white text-navy/20 border-accent/50'}`}
                         >
                           {cur}
                         </button>
                       ))}
                    </div>
                 </div>
                 <div className="space-y-3">
                    <div className="flex justify-between items-center px-1">
                       <label className="text-[10px] font-black uppercase text-navy/20">匯率 (vs JPY)</label>
                       <button onClick={fetchLiveRates} className="text-[9px] font-black text-stitch flex items-center gap-1 active:scale-90">
                         <RefreshCw size={10} className={loadingRates ? 'animate-spin' : ''} /> 更新
                       </button>
                    </div>
                    {['HKD', 'AUD'].map(cur => (
                      <div key={cur} className="flex items-center justify-between p-4 bg-cream/40 rounded-xl border border-accent/40">
                         <span className="font-black text-navy/40 text-xs uppercase">1 {cur} =</span>
                         <div className="flex items-center gap-2">
                            <input 
                              type="number" 
                              value={rates[cur as keyof typeof rates]} 
                              onChange={e => setRates({...rates, [cur]: parseFloat(e.target.value) || 0})}
                              className="w-16 text-right font-black text-stitch bg-transparent border-none focus:ring-0 p-0"
                            />
                            <span className="text-[10px] font-black text-navy/10">JPY</span>
                         </div>
                      </div>
                    ))}
                 </div>
              </div>
              <button onClick={() => setIsCurrencySettingsOpen(false)} className="w-full mt-8 py-4 bg-navy text-white font-black rounded-xl-sticker sticker-shadow uppercase text-[11px] tracking-widest">套用</button>
           </div>
        </div>
      )}

      {isModalOpen && (
        <ExpenseModal 
          expense={editingExpense} 
          members={members} 
          rates={rates}
          onClose={() => setIsModalOpen(false)} 
          onSave={handleSave} 
        />
      )}
    </div>
  );
};

