import React, { useState, useEffect } from 'react';
import { 
  Calendar, 
  Ticket, 
  Wallet, 
  Camera, 
  CheckSquare, 
  Users,
  CloudCheck
} from 'lucide-react';
import { MOCK_MEMBERS, MOCK_TRIP_CONFIG } from './constants';
import { TripMember } from './types';
import Schedule from './modules/Schedule';
import Bookings from './modules/Bookings';
import Expense from './modules/Expense';
import Journal from './modules/Journal';
import Planning from './modules/Planning';

type Tab = 'schedule' | 'bookings' | 'expense' | 'journal' | 'planning';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('schedule');
  const [lastSync, setLastSync] = useState<string>(new Date().toLocaleTimeString());
  const [members, setMembers] = useState<TripMember[]>(() => {
    const saved = localStorage.getItem('trip_members');
    return saved ? JSON.parse(saved) : MOCK_MEMBERS;
  });
  const [currentUser, setCurrentUser] = useState<TripMember>(() => {
    const savedUser = localStorage.getItem('currentUser');
    if (savedUser) {
      const parsed = JSON.parse(savedUser);
      const exists = members.find(m => m.id === parsed.id);
      return exists || members[0];
    }
    return members[0];
  });
  const [tripConfig, setTripConfig] = useState(MOCK_TRIP_CONFIG);

  useEffect(() => {
    const savedTab = localStorage.getItem('activeTab') as Tab;
    // Prevent loading 'members' tab if it was saved previously
    if (savedTab && savedTab !== 'members' as any) setActiveTab(savedTab);
  }, []);

  useEffect(() => {
    localStorage.setItem('activeTab', activeTab);
  }, [activeTab]);

  useEffect(() => {
    localStorage.setItem('trip_members', JSON.stringify(members));
    setLastSync(new Date().toLocaleTimeString());
  }, [members]);

  useEffect(() => {
    localStorage.setItem('currentUser', JSON.stringify(currentUser));
  }, [currentUser]);

  const handleSwitchUser = (user: TripMember) => {
    setCurrentUser(user);
  };

  const handleAddMember = (name: string, avatar: string) => {
    const newMember: TripMember = { id: Date.now().toString(), name, avatar };
    setMembers([...members, newMember]);
  };

  const handleDeleteMember = (id: string) => {
    if (id === currentUser.id) {
      alert("Ohana! 你不能刪除目前正在使用的身分。");
      return;
    }
    if (confirm("確定要移除這位成員嗎？這會影響分帳計算。")) {
      setMembers(members.filter(m => m.id !== id));
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'schedule': return (
        <Schedule 
          config={tripConfig} 
          members={members}
          currentUser={currentUser}
          onAddMember={handleAddMember}
          onDeleteMember={handleDeleteMember}
          onSwitchUser={handleSwitchUser}
        />
      );
      case 'bookings': return <Bookings />;
      case 'expense': return <Expense currentUser={currentUser} members={members} />;
      case 'journal': return <Journal currentUser={currentUser} members={members} />;
      case 'planning': return <Planning members={members} />;
      default: return (
        <Schedule 
          config={tripConfig} 
          members={members}
          currentUser={currentUser}
          onAddMember={handleAddMember}
          onDeleteMember={handleDeleteMember}
          onSwitchUser={handleSwitchUser}
        />
      );
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto bg-cream shadow-2xl relative overflow-hidden">
      {/* Top Sync Bar (Aesthetic) */}
      <div className="absolute top-0 left-0 right-0 z-[60] px-4 py-1 flex justify-center items-center gap-1.5 pointer-events-none">
        <div className="bg-navy/10 backdrop-blur-md px-3 py-1 rounded-full flex items-center gap-1">
          <div className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse" />
          <span className="text-[8px] font-black text-navy/40 uppercase tracking-widest">
            Ohana Sync: {lastSync}
          </span>
        </div>
      </div>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto pb-24 px-4 pt-10">
        {renderContent()}
      </main>

      {/* Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-paper/90 backdrop-blur-lg border-t border-accent px-2 py-3 flex justify-around items-center z-50 rounded-t-3xl shadow-[0_-4px_10px_rgba(0,0,0,0.05)] safe-bottom">
        <NavButton active={activeTab === 'schedule'} onClick={() => setActiveTab('schedule')} icon={<Calendar size={22} />} label="行程" />
        <NavButton active={activeTab === 'bookings'} onClick={() => setActiveTab('bookings')} icon={<Ticket size={22} />} label="票券" />
        <NavButton active={activeTab === 'expense'} onClick={() => setActiveTab('expense')} icon={<Wallet size={22} />} label="記帳" />
        <NavButton active={activeTab === 'journal'} onClick={() => setActiveTab('journal')} icon={<Camera size={22} />} label="日誌" />
        <NavButton active={activeTab === 'planning'} onClick={() => setActiveTab('planning')} icon={<CheckSquare size={22} />} label="清單" />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center gap-1 transition-all duration-300 ${active ? 'text-stitch scale-110' : 'text-navy/30'}`}
  >
    <div className={`p-1.5 rounded-xl transition-colors ${active ? 'bg-stitch/10' : 'bg-transparent'}`}>
      {icon}
    </div>
    <span className={`text-[10px] font-bold uppercase tracking-tighter ${active ? 'opacity-100' : 'opacity-60'}`}>{label}</span>
  </button>
);

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  MapPin, 
  Settings, 
  Plus, 
  X, 
  ChevronRight, 
  Navigation,
  GripVertical,
  Trash2,
  ArrowRight,
  Sparkles,
  Lightbulb,
  CornerRightDown,
  LayoutGrid,
  Users,
  Check,
  UserCircle2
} from 'lucide-react';
import { TripConfig, ScheduleItem, Category, TripMember } from '../types';
import { COLORS } from '../constants';

interface ScheduleProps {
  config: TripConfig;
  members: TripMember[];
  currentUser: TripMember;
  onAddMember: (name: string, avatar: string) => void;
  onDeleteMember: (id: string) => void;
  onSwitchUser: (member: TripMember) => void;
}

const Schedule: React.FC<ScheduleProps> = ({ 
  config: initialConfig, 
  members, 
  currentUser, 
  onAddMember, 
  onDeleteMember, 
  onSwitchUser
}) => {
  const [config, setConfig] = useState<TripConfig>(() => {
    const saved = localStorage.getItem('tripConfig');
    return saved ? JSON.parse(saved) : initialConfig;
  });

  // Main Itinerary State
  const [itinerary, setItinerary] = useState<ScheduleItem[]>(() => {
    const saved = localStorage.getItem('itinerary');
    return saved ? JSON.parse(saved) : [
      { id: '1', dayIndex: 0, time: '10:00', title: 'Arrival', location: 'NRT Terminal 1', category: 'Transport' as Category, distanceInfo: '0km, 0m' },
      { id: '2', dayIndex: 0, time: '13:30', title: 'Lunch', location: 'Ichiran Shinjuku', category: 'Food' as Category, distanceInfo: '65km, 1h 20m' },
    ];
  });

  // Inspiration Pool State
  const [pool, setPool] = useState<ScheduleItem[]>(() => {
    const saved = localStorage.getItem('inspiration_pool');
    return saved ? JSON.parse(saved) : [
      { id: 'p1', dayIndex: -1, time: '--:--', title: 'Idea', location: 'TeamLab Planets', category: 'Attraction' as Category, distanceInfo: '' },
      { id: 'p2', dayIndex: -1, time: '--:--', title: 'Idea', location: 'Shibuya Sky', category: 'Attraction' as Category, distanceInfo: '' },
    ];
  });

  const [selectedDay, setSelectedDay] = useState(0);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [addItemTarget, setAddItemTarget] = useState<'schedule' | 'pool'>('schedule');

  // Member Management State in Settings
  const [newMemberName, setNewMemberName] = useState('');

  // Drag & Drop State
  const [draggedData, setDraggedData] = useState<{ item: ScheduleItem, source: 'pool' | 'schedule' } | null>(null);
  const [dragOverDay, setDragOverDay] = useState<number | null>(null);
  const [isPoolDragOver, setIsPoolDragOver] = useState(false);

  const [swipeId, setSwipeId] = useState<string | null>(null);
  const touchStartPos = useRef<number | null>(null);

  useEffect(() => {
    localStorage.setItem('tripConfig', JSON.stringify(config));
  }, [config]);

  useEffect(() => {
    localStorage.setItem('itinerary', JSON.stringify(itinerary));
  }, [itinerary]);

  useEffect(() => {
    localStorage.setItem('inspiration_pool', JSON.stringify(pool));
  }, [pool]);

  const countdown = useMemo(() => {
    const start = new Date(config.startDate).getTime();
    const now = new Date().getTime();
    const diff = Math.ceil((start - now) / (1000 * 60 * 60 * 24));
    return diff > 0 ? diff : 0;
  }, [config.startDate]);

  const days = useMemo(() => {
    return Array.from({ length: config.duration }, (_, i) => {
      const d = new Date(config.startDate);
      d.setDate(d.getDate() + i);
      return {
        index: i,
        date: d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        weekday: d.toLocaleDateString('en-US', { weekday: 'short' })
      };
    });
  }, [config.startDate, config.duration]);

  const currentDayItems = useMemo(() => 
    itinerary.filter(item => item.dayIndex === selectedDay),
  [itinerary, selectedDay]);

  // --- Drag & Drop Logic ---

  const handleDragStart = (e: React.DragEvent, item: ScheduleItem, source: 'pool' | 'schedule') => {
    setDraggedData({ item, source });
    e.dataTransfer.effectAllowed = 'move';
    if (e.currentTarget instanceof HTMLElement) {
       e.currentTarget.style.opacity = '0.5';
    }
  };

  const handleDragEnd = (e: React.DragEvent) => {
    if (e.currentTarget instanceof HTMLElement) {
       e.currentTarget.style.opacity = '1';
    }
    setDraggedData(null);
    setDragOverDay(null);
    setIsPoolDragOver(false);
  };

  const handleDropOnDayButton = (dayIndex: number) => {
    if (!draggedData) return;
    const { item, source } = draggedData;

    if (source === 'pool') {
      setPool(prev => prev.filter(i => i.id !== item.id));
    } else {
      setItinerary(prev => prev.filter(i => i.id !== item.id));
    }

    const newItem = { ...item, dayIndex: dayIndex };
    setItinerary(prev => [...prev, newItem]);
    setSelectedDay(dayIndex);
  };

  const handleDropOnPool = () => {
    if (!draggedData) return;
    const { item, source } = draggedData;

    if (source === 'schedule') {
      setItinerary(prev => prev.filter(i => i.id !== item.id));
      setPool(prev => [...prev, { ...item, dayIndex: -1 }]);
    }
  };

  const handleDropOnScheduleList = (targetIndex: number) => {
    if (!draggedData) return;
    const { item, source } = draggedData;

    let newList = [...itinerary];
    if (source === 'schedule') {
      newList = newList.filter(i => i.id !== item.id);
    } else {
      setPool(prev => prev.filter(i => i.id !== item.id));
    }

    const currentItems = newList.filter(i => i.dayIndex === selectedDay);
    const newItem = { ...item, dayIndex: selectedDay };
    const otherDaysItems = newList.filter(i => i.dayIndex !== selectedDay);

    if (targetIndex === -1) {
       currentItems.push(newItem);
    } else {
       currentItems.splice(targetIndex, 0, newItem);
    }

    setItinerary([...otherDaysItems, ...currentItems]);
  };

  // --- Touch / Swipe Logic ---

  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartPos.current = e.touches[0].clientX;
  };

  const handleTouchMove = (e: React.TouchEvent, id: string) => {
    if (touchStartPos.current === null) return;
    const delta = e.touches[0].clientX - touchStartPos.current;
    if (delta > 50) setSwipeId(id);
    if (delta < -50) setSwipeId(null);
  };

  // --- CRUD ---

  const deleteItem = (id: string, from: 'pool' | 'schedule') => {
    if (from === 'pool') setPool(pool.filter(i => i.id !== id));
    else setItinerary(itinerary.filter(i => i.id !== id));
    setSwipeId(null);
  };

  const handleAddItem = (newItem: Omit<ScheduleItem, 'id' | 'dayIndex'>) => {
    const item: ScheduleItem = { 
      ...newItem, 
      id: Date.now().toString(), 
      dayIndex: addItemTarget === 'schedule' ? selectedDay : -1 
    };

    if (addItemTarget === 'schedule') {
      setItinerary([...itinerary, item]);
    } else {
      setPool([...pool, item]);
    }
    setIsAddModalOpen(false);
  };

  // --- Member Logic in Settings ---

  const handleAddMemberSubmit = () => {
    if (newMemberName.trim()) {
      const randomId = Math.floor(Math.random() * 1000);
      const avatar = `https://picsum.photos/seed/${newMemberName}${randomId}/200`;
      onAddMember(newMemberName.trim(), avatar);
      setNewMemberName('');
    }
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500">
      {/* Countdown Card */}
      <div className="bg-stitch text-white p-6 rounded-2xl-sticker sticker-shadow flex justify-between items-center relative overflow-hidden border-2 border-white/20">
        <div className="z-10">
          <p className="text-[10px] font-black opacity-70 uppercase tracking-[0.3em] mb-1">Adventure Starts In</p>
          <h2 className="text-4xl font-black drop-shadow-sm">{countdown} Days</h2>
        </div>
        <div className="text-6xl opacity-20 absolute -right-2 -bottom-2 transform rotate-12 z-0">🏝️</div>
      </div>

      {/* Inspiration Pool Area */}
      <div 
        className={`transition-all duration-300 ${isPoolDragOver ? 'scale-[1.02]' : ''}`}
        onDragOver={(e) => { e.preventDefault(); setIsPoolDragOver(true); }}
        onDragLeave={() => setIsPoolDragOver(false)}
        onDrop={(e) => {
           e.preventDefault();
           setIsPoolDragOver(false);
           handleDropOnPool();
        }}
      >
        <div className="flex justify-between items-center px-1 mb-2">
           <h3 className="text-sm font-black text-navy flex items-center gap-2">
             <Sparkles size={16} className="text-donald" />
             Inspiration Pool
           </h3>
           <button 
              onClick={() => { setAddItemTarget('pool'); setIsAddModalOpen(true); }}
              className="text-[10px] font-black bg-white px-2 py-1 rounded-full text-navy/40 border border-accent hover:text-stitch active:scale-95"
           >
             + ADD IDEA
           </button>
        </div>

        <div className={`
           min-h-[100px] p-4 rounded-2xl-sticker border-2 border-dashed flex gap-3 overflow-x-auto snap-x scrollbar-hide items-center
           ${isPoolDragOver ? 'bg-stitch/10 border-stitch' : 'bg-white border-accent'}
        `}>
          {pool.length > 0 ? pool.map((item) => (
            <div 
              key={item.id}
              draggable
              onDragStart={(e) => handleDragStart(e, item, 'pool')}
              onDragEnd={handleDragEnd}
              className="flex-shrink-0 w-40 snap-center cursor-grab active:cursor-grabbing group"
            >
              <div className="bg-paper p-3 rounded-xl-sticker sticker-shadow border border-accent relative hover:-translate-y-1 transition-transform duration-300 active:scale-105 active:shadow-xl">
                 <div className="flex justify-between items-start mb-2">
                    <span 
                      className="px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-wider text-white"
                      style={{ backgroundColor: COLORS[item.category.toLowerCase() as keyof typeof COLORS] || COLORS.stitch }}
                    >
                      {item.category}
                    </span>
                    <button onClick={() => deleteItem(item.id, 'pool')} className="text-navy/10 hover:text-red-400"><X size={12} /></button>
                 </div>
                 <h4 className="font-black text-navy text-sm leading-tight mb-1 truncate">{item.location}</h4>
                 <p className="text-[9px] font-bold text-navy/30 truncate">{item.notes || 'No notes'}</p>
                 <div className="absolute -bottom-2 -right-2 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                    <CornerRightDown size={16} className="text-stitch" />
                 </div>
              </div>
            </div>
          )) : (
            <div className="w-full text-center text-navy/20 flex flex-col items-center justify-center py-2">
               <Lightbulb size={24} className="mb-1" />
               <p className="text-[10px] font-black uppercase tracking-widest">Drag items here to save for later</p>
            </div>
          )}
        </div>
      </div>

      {/* Date Picker (Drop Zones) */}
      <div className="flex gap-2 overflow-x-auto pb-4 scrollbar-hide snap-x -mx-4 px-4">
        {days.map((day) => (
          <button
            key={day.index}
            onClick={() => setSelectedDay(day.index)}
            onDragOver={(e) => { e.preventDefault(); setDragOverDay(day.index); }}
            onDragLeave={() => setDragOverDay(null)}
            onDrop={(e) => { e.preventDefault(); handleDropOnDayButton(day.index); }}
            className={`flex-shrink-0 w-16 py-3 rounded-xl-sticker border-2 transition-all flex flex-col items-center snap-center relative ${
              selectedDay === day.index 
                ? 'bg-donald border-white text-navy sticker-shadow scale-105 z-10' 
                : dragOverDay === day.index
                   ? 'bg-stitch text-white border-stitch scale-110 shadow-lg z-20'
                   : 'bg-paper border-accent opacity-50 text-navy'
            }`}
          >
            <p className="text-[10px] font-black uppercase leading-none mb-1 opacity-60">{day.weekday}</p>
            <p className="text-xl font-black leading-none">{day.date.split(' ')[1]}</p>
            {dragOverDay === day.index && (
               <div className="absolute -top-2 -right-2 bg-red-400 text-white rounded-full p-1 animate-bounce">
                  <ArrowRight size={10} className="transform rotate-90" />
               </div>
            )}
          </button>
        ))}
      </div>

      {/* Itinerary List */}
      <div 
        className="space-y-6 min-h-[300px]"
        onDragOver={(e) => e.preventDefault()}
        onDrop={(e) => {
           if (e.target === e.currentTarget) {
              handleDropOnScheduleList(-1);
           }
        }}
      >
        {currentDayItems.length > 0 ? currentDayItems.map((item, idx) => {
          const prevItem = idx > 0 ? currentDayItems[idx - 1] : null;
          return (
            <div 
              key={item.id} 
              className="relative group transition-all"
              onDragOver={(e) => e.preventDefault()}
              onDrop={(e) => {
                 e.stopPropagation();
                 handleDropOnScheduleList(idx);
              }}
            >
              {prevItem && (
                <div className="flex justify-center -my-3 mb-4 relative z-0">
                  <a 
                    href={`https://www.google.com/maps/dir/?api=1&origin=${encodeURIComponent(prevItem.location)}&destination=${encodeURIComponent(item.location)}`}
                    target="_blank"
                    className="flex items-center gap-2 px-4 py-2 bg-cream border border-accent rounded-full text-[10px] font-black text-navy/60 hover:bg-stitch hover:text-white transition-all sticker-shadow active:scale-95"
                  >
                    <Navigation size={12} className="text-stitch group-hover:text-white" />
                    <span>{item.distanceInfo || 'Distance + Time'}</span>
                    <ArrowRight size={12} />
                  </a>
                </div>
              )}

              <div 
                className="flex items-start gap-3 relative"
                draggable
                onDragStart={(e) => handleDragStart(e, item, 'schedule')}
                onDragEnd={handleDragEnd}
                onTouchStart={handleTouchStart}
                onTouchMove={(e) => handleTouchMove(e, item.id)}
              >
                <div className="mt-6 text-navy/10 cursor-grab active:cursor-grabbing group-hover:text-navy/30 transition-colors">
                  <GripVertical size={20} />
                </div>

                <div className="flex-1 relative overflow-hidden rounded-xl-sticker">
                  <div className={`absolute inset-0 bg-red-500 flex items-center px-6 transition-opacity ${swipeId === item.id ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
                    <button onClick={() => deleteItem(item.id, 'schedule')} className="text-white flex items-center gap-2 font-black">
                      <Trash2 size={20} /> DELETE
                    </button>
                  </div>

                  <div className={`bg-paper p-5 rounded-xl-sticker sticker-shadow border border-accent transition-all duration-300 active:scale-[1.02] active:shadow-xl ${swipeId === item.id ? 'translate-x-32' : 'translate-x-0'}`}>
                    <div className="flex justify-between items-center mb-4">
                      <div className="flex items-center gap-3">
                        <div className="text-2xl font-black text-navy tracking-tight">
                          {item.time}
                        </div>
                        <span 
                          className="px-2.5 py-1 rounded-full text-[8px] font-black uppercase tracking-wider text-white shadow-sm" 
                          style={{ backgroundColor: COLORS[item.category.toLowerCase() as keyof typeof COLORS] || COLORS.stitch }}
                        >
                          {item.category}
                        </span>
                      </div>
                      <button onClick={() => setSwipeId(swipeId === item.id ? null : item.id)} className="text-navy/20 active:scale-125 transition-transform"><ChevronRight size={18} /></button>
                    </div>

                    <div className="flex items-start justify-between gap-4">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-1">
                          <MapPin size={16} className="text-stitch flex-shrink-0" />
                          <h3 className="text-xl font-black text-navy leading-tight truncate">
                            {item.location}
                          </h3>
                        </div>
                      </div>
                      <a 
                        href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(item.location)}`}
                        target="_blank"
                        className="p-3 bg-stitch/5 text-stitch rounded-xl active:scale-90 transition-transform flex-shrink-0"
                      >
                        <Navigation size={18} />
                      </a>
                    </div>

                    {item.notes && (
                      <div className="mt-4 pt-4 border-t border-accent/50 text-[10px] text-navy/70 italic leading-relaxed whitespace-pre-wrap">
                        {item.notes}
                      </div>
                    )}
                  </div>
                </div>
              </div>
            </div>
          );
        }) : (
          <div className="py-20 text-center opacity-30 flex flex-col items-center bg-paper/50 rounded-2xl border-2 border-dashed border-accent">
            <LayoutGrid size={40} className="mb-2" />
            <p className="font-black text-lg">Day {selectedDay + 1} is open</p>
            <p className="text-sm font-bold">Drag ideas here or tap +</p>
          </div>
        )}
      </div>

      {/* Floating Action Buttons */}
      <div className="fixed bottom-24 right-6 flex flex-col gap-3 z-50">
        <button 
          onClick={() => setIsSettingsOpen(true)}
          className="w-12 h-12 bg-white text-navy rounded-full sticker-shadow border border-accent flex items-center justify-center active:scale-90 transition-transform"
        >
          <Settings size={20} />
        </button>
        <button 
          onClick={() => { setAddItemTarget('schedule'); setIsAddModalOpen(true); }}
          className="w-14 h-14 bg-donald text-navy rounded-full sticker-shadow border-2 border-paper flex items-center justify-center active:scale-95 transition-transform shadow-lg"
        >
          <Plus size={32} />
        </button>
      </div>

      {/* Settings Modal (Including Member Management) */}
      {isSettingsOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-navy/20 backdrop-blur-sm" onClick={() => setIsSettingsOpen(false)}>
          <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-stitch/20 relative animate-in zoom-in-95 flex flex-col max-h-[85vh]" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-6">
               <h3 className="text-xl font-black text-navy uppercase tracking-wider">Trip Settings</h3>
               <button onClick={() => setIsSettingsOpen(false)} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
            </div>

            <div className="overflow-y-auto pr-2 space-y-6 flex-1">
               {/* General Section */}
               <div className="space-y-4">
                 <div className="flex items-center gap-2 mb-2">
                    <Settings size={16} className="text-stitch" />
                    <h4 className="text-[10px] font-black uppercase text-navy/40 tracking-[0.2em]">General</h4>
                 </div>
                 <div>
                   <label className="text-[10px] font-black uppercase text-navy/40 block mb-1">Region</label>
                   <input type="text" value={config.region} onChange={e => setConfig({...config, region: e.target.value})} className="w-full p-3 bg-cream rounded-xl font-bold border border-accent" />
                 </div>
                 <div className="grid grid-cols-2 gap-4">
                   <div>
                     <label className="text-[10px] font-black uppercase text-navy/40 block mb-1">Start Date</label>
                     <input type="date" value={config.startDate} onChange={e => setConfig({...config, startDate: e.target.value})} className="w-full p-3 bg-cream rounded-xl font-bold border border-accent text-xs" />
                   </div>
                   <div>
                     <label className="text-[10px] font-black uppercase text-navy/40 block mb-1">Days</label>
                     <input type="number" value={config.duration} onChange={e => setConfig({...config, duration: parseInt(e.target.value) || 1})} className="w-full p-3 bg-cream rounded-xl font-bold border border-accent" />
                   </div>
                 </div>
               </div>

               {/* Members Section */}
               <div className="space-y-4 pt-4 border-t border-accent/40">
                 <div className="flex items-center gap-2 mb-2">
                    <Users size={16} className="text-donald" />
                    <h4 className="text-[10px] font-black uppercase text-navy/40 tracking-[0.2em]">Ohana Members</h4>
                 </div>

                 <div className="space-y-2">
                    {members.map(member => (
                       <div key={member.id} className="flex items-center justify-between p-3 bg-cream rounded-xl border border-accent/50 group">
                          <div className="flex items-center gap-3">
                             <div className="relative">
                               <img src={member.avatar} className="w-10 h-10 rounded-full border-2 border-white shadow-sm" />
                               {currentUser.id === member.id && <div className="absolute -bottom-1 -right-1 bg-stitch text-white rounded-full p-0.5 border-2 border-white"><Check size={8} /></div>}
                             </div>
                             <div>
                                <p className="font-black text-sm text-navy">{member.name}</p>
                                {currentUser.id === member.id ? (
                                   <p className="text-[8px] font-bold text-stitch uppercase tracking-wider">Active User</p>
                                ) : (
                                   <button onClick={() => onSwitchUser(member)} className="text-[8px] font-bold text-navy/30 hover:text-navy uppercase tracking-wider underline">Switch to this</button>
                                )}
                             </div>
                          </div>
                          {currentUser.id !== member.id && (
                             <button onClick={() => onDeleteMember(member.id)} className="p-2 text-navy/10 hover:text-red-400 active:scale-90"><Trash2 size={16} /></button>
                          )}
                       </div>
                    ))}
                 </div>

                 <div className="flex gap-2">
                    <input 
                       type="text" 
                       value={newMemberName} 
                       onChange={e => setNewMemberName(e.target.value)} 
                       placeholder="New member name..." 
                       className="flex-1 p-3 bg-white border border-accent rounded-xl text-sm font-bold"
                    />
                    <button 
                       onClick={handleAddMemberSubmit} 
                       disabled={!newMemberName.trim()}
                       className="px-4 bg-navy text-white rounded-xl font-black disabled:opacity-50"
                    >
                       <Plus size={20} />
                    </button>
                 </div>
               </div>
            </div>

            <button onClick={() => setIsSettingsOpen(false)} className="w-full mt-6 py-4 bg-stitch text-white font-black rounded-xl-sticker sticker-shadow uppercase text-xs tracking-widest">
               Close Settings
            </button>
          </div>
        </div>
      )}

      {/* Add Stop Modal */}
      {isAddModalOpen && <AddItemModal target={addItemTarget} onClose={() => setIsAddModalOpen(false)} onAdd={handleAddItem} />}
    </div>
  );
};

