  referenceNo?: string; // e.g. Booking Reference / PNR
  bookedBy?: string; // Member ID who booked this
  details: any;
  cost: number;
  imageUrl?: string;
}

export interface Expense {
  id: string;
  amount: number;
  currency: 'JPY' | 'HKD' | 'AUD';
