  id: string;
  authorId: string;
  content: string;
  imageUrl?: string;
  date: string;
}

export interface PlanningItem {
  id: string;
  type: 'Packing' | 'Shopping';
  title: string;
  assignedTo: string; // 'All' or Member ID
  completed: boolean;
}

export interface TripConfig {
  startDate: string;
  duration: number;
  tripName: string;
  region: string;
}

