import React, { useState, useEffect } from 'react';
import { 
  Calendar, 
  Ticket, 
  Wallet, 
  Camera, 
  CheckSquare, 
  Users,
  CloudCheck
} from 'lucide-react';
import { MOCK_MEMBERS, MOCK_TRIP_CONFIG } from './constants';
import { TripMember } from './types';
import Schedule from './modules/Schedule';
import Bookings from './modules/Bookings';
import Expense from './modules/Expense';
import Journal from './modules/Journal';
import Planning from './modules/Planning';

type Tab = 'schedule' | 'bookings' | 'expense' | 'journal' | 'planning';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('schedule');
  const [highlightId, setHighlightId] = useState<string | null>(null);
  const [lastSync, setLastSync] = useState<string>(new Date().toLocaleTimeString());
  const [members, setMembers] = useState<TripMember[]>(() => {
    const saved = localStorage.getItem('trip_members');
    return saved ? JSON.parse(saved) : MOCK_MEMBERS;
  });
  const [currentUser, setCurrentUser] = useState<TripMember>(() => {
    const savedUser = localStorage.getItem('currentUser');
    if (savedUser) {
      const parsed = JSON.parse(savedUser);
      const exists = members.find(m => m.id === parsed.id);
      return exists || members[0];
    }
    return members[0];
  });
  const [tripConfig, setTripConfig] = useState(MOCK_TRIP_CONFIG);

  useEffect(() => {
    const savedTab = localStorage.getItem('activeTab') as Tab;
    // Prevent loading 'members' tab if it was saved previously
    if (savedTab && savedTab !== 'members' as any) setActiveTab(savedTab);
  }, []);

  useEffect(() => {
    localStorage.setItem('activeTab', activeTab);
  }, [activeTab]);

  useEffect(() => {
    localStorage.setItem('trip_members', JSON.stringify(members));
    setLastSync(new Date().toLocaleTimeString());
  }, [members]);

  useEffect(() => {
    localStorage.setItem('currentUser', JSON.stringify(currentUser));
  }, [currentUser]);

  const handleSwitchUser = (user: TripMember) => {
    setCurrentUser(user);
  };

  const handleAddMember = (name: string, avatar: string) => {
    const newMember: TripMember = { id: Date.now().toString(), name, avatar };
    setMembers([...members, newMember]);
  };

  const handleDeleteMember = (id: string) => {
    if (id === currentUser.id) {
      alert("Ohana! 你不能刪除目前正在使用的身分。");
      return;
    }
    if (confirm("確定要移除這位成員嗎？這會影響分帳計算。")) {
      setMembers(members.filter(m => m.id !== id));
    }
  };

  const handleNavigate = (tab: Tab, id?: string) => {
    setActiveTab(tab);
    if (id) {
      setHighlightId(id);
      // Clear highlight after a delay to allow re-highlighting if needed, 
      // but strictly Bookings will handle it via useEffect on prop change.
      // Keeping it simple for now.
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'schedule': return (
        <Schedule 
          config={tripConfig} 
          members={members}
          currentUser={currentUser}
          onAddMember={handleAddMember}
          onDeleteMember={handleDeleteMember}
          onSwitchUser={handleSwitchUser}
          onNavigate={handleNavigate}
        />
      );
      case 'bookings': return (
        <Bookings 
          members={members} 
          currentUser={currentUser} 
          onNavigate={handleNavigate}
          highlightId={highlightId}
        />
      );
      case 'expense': return <Expense currentUser={currentUser} members={members} />;
      case 'journal': return <Journal currentUser={currentUser} members={members} />;
      case 'planning': return <Planning members={members} />;
      default: return (
        <Schedule 
          config={tripConfig} 
          members={members}
          currentUser={currentUser}
          onAddMember={handleAddMember}
          onDeleteMember={handleDeleteMember}
          onSwitchUser={handleSwitchUser}
          onNavigate={handleNavigate}
        />
      );
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto bg-cream shadow-2xl relative overflow-hidden">
      {/* Top Sync Bar (Aesthetic) */}
      <div className="absolute top-0 left-0 right-0 z-[60] px-4 py-1 flex justify-center items-center gap-1.5 pointer-events-none">
        <div className="bg-navy/10 backdrop-blur-md px-3 py-1 rounded-full flex items-center gap-1">
          <div className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse" />
          <span className="text-[8px] font-black text-navy/40 uppercase tracking-widest">
            Ohana Sync: {lastSync}
          </span>
        </div>
      </div>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto pb-24 px-4 pt-10">
        {renderContent()}
      </main>

      {/* Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-paper/90 backdrop-blur-lg border-t border-accent px-2 py-3 flex justify-around items-center z-50 rounded-t-3xl shadow-[0_-4px_10px_rgba(0,0,0,0.05)] safe-bottom">
        <NavButton active={activeTab === 'schedule'} onClick={() => handleNavigate('schedule')} icon={<Calendar size={22} />} label="行程" />
        <NavButton active={activeTab === 'bookings'} onClick={() => handleNavigate('bookings')} icon={<Ticket size={22} />} label="票券" />
        <NavButton active={activeTab === 'expense'} onClick={() => handleNavigate('expense')} icon={<Wallet size={22} />} label="記帳" />
        <NavButton active={activeTab === 'journal'} onClick={() => handleNavigate('journal')} icon={<Camera size={22} />} label="日誌" />
        <NavButton active={activeTab === 'planning'} onClick={() => handleNavigate('planning')} icon={<CheckSquare size={22} />} label="清單" />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center gap-1 transition-all duration-300 ${active ? 'text-stitch scale-110' : 'text-navy/30'}`}
  >
    <div className={`p-1.5 rounded-xl transition-colors ${active ? 'bg-stitch/10' : 'bg-transparent'}`}>
      {icon}
    </div>
    <span className={`text-[10px] font-bold uppercase tracking-tighter ${active ? 'opacity-100' : 'opacity-60'}`}>{label}</span>
  </button>
);

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  MapPin, 
  Settings, 
  Plus, 
  X, 
  GripVertical,
  Trash2,
  Sparkles,
  Lightbulb,
  LayoutGrid,
  MoreHorizontal,
  CalendarDays,
  ArrowRight,
  Navigation,
  Ticket as TicketIcon
} from 'lucide-react';
import { TripConfig, ScheduleItem, Category, TripMember, Booking } from '../types';
import { COLORS } from '../constants';

interface ScheduleProps {
  config: TripConfig;
  members: TripMember[];
  currentUser: TripMember;
  onAddMember: (name: string, avatar: string) => void;
  onDeleteMember: (id: string) => void;
  onSwitchUser: (member: TripMember) => void;
  onNavigate: (tab: any, id?: string) => void;
}

const Schedule: React.FC<ScheduleProps> = ({ 
  config: initialConfig, 
  members, 
  currentUser, 
  onAddMember, 
  onDeleteMember, 
  onSwitchUser,
  onNavigate
}) => {
  const [config, setConfig] = useState<TripConfig>(() => {
    const saved = localStorage.getItem('tripConfig');
    return saved ? JSON.parse(saved) : initialConfig;
  });

  const [itinerary, setItinerary] = useState<ScheduleItem[]>(() => {
    const saved = localStorage.getItem('itinerary');
    return saved ? JSON.parse(saved) : [
      { id: '1', dayIndex: 0, time: '10:00', title: 'Arrival', location: 'NRT Terminal 1', category: 'Transport' as Category },
      { id: '2', dayIndex: 0, time: '13:30', title: 'Lunch', location: 'Ichiran Shinjuku', category: 'Food' as Category },
    ];
  });

  const [pool, setPool] = useState<ScheduleItem[]>(() => {
    const saved = localStorage.getItem('inspiration_pool');
    return saved ? JSON.parse(saved) : [
      { id: 'p1', dayIndex: -1, time: '--:--', title: 'Idea', location: 'TeamLab Planets', category: 'Attraction' as Category },
      { id: 'p2', dayIndex: -1, time: '--:--', title: 'Idea', location: 'Shibuya Sky', category: 'Attraction' as Category },
    ];
  });

  // State to hold bookings for linking
  const [bookings, setBookings] = useState<Booking[]>([]);

  const [selectedDay, setSelectedDay] = useState(0);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<'add' | 'edit'>('add');
  const [editingItem, setEditingItem] = useState<ScheduleItem | null>(null);
  const [addItemTarget, setAddItemTarget] = useState<'schedule' | 'pool'>('schedule');

  // New state for "Move to Day" modal
  const [movingItem, setMovingItem] = useState<ScheduleItem | null>(null);

  const [newMemberName, setNewMemberName] = useState('');
  const [draggedData, setDraggedData] = useState<{ item: ScheduleItem, source: 'pool' | 'schedule' } | null>(null);
  const [dragOverDay, setDragOverDay] = useState<number | null>(null);
  const [isPoolDragOver, setIsPoolDragOver] = useState(false);
  const [swipeId, setSwipeId] = useState<string | null>(null);

  useEffect(() => { localStorage.setItem('tripConfig', JSON.stringify(config)); }, [config]);
  useEffect(() => { localStorage.setItem('itinerary', JSON.stringify(itinerary)); }, [itinerary]);
  useEffect(() => { localStorage.setItem('inspiration_pool', JSON.stringify(pool)); }, [pool]);

  // Load bookings to check for links
  useEffect(() => {
    const savedBookings = localStorage.getItem('bookings');
    if (savedBookings) {
      setBookings(JSON.parse(savedBookings));
    }
  }, [isAddModalOpen, selectedDay]); // Refresh when modals close or day changes just in case

  const countdown = useMemo(() => {
    const start = new Date(config.startDate).getTime();
    const now = new Date().getTime();
    const diff = Math.ceil((start - now) / (1000 * 60 * 60 * 24));
    return diff > 0 ? diff : 0;
  }, [config.startDate]);

  const days = useMemo(() => {
    return Array.from({ length: config.duration }, (_, i) => {
      const d = new Date(config.startDate);
      d.setDate(d.getDate() + i);
      return {
        index: i,
        date: d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        weekday: d.toLocaleDateString('en-US', { weekday: 'short' })
      };
    });
  }, [config.startDate, config.duration]);

  const currentDayItems = useMemo(() => 
    itinerary.filter(item => item.dayIndex === selectedDay).sort((a, b) => a.time.localeCompare(b.time)),
  [itinerary, selectedDay]);

  // Drag & Drop
  const handleDragStart = (e: React.DragEvent, item: ScheduleItem, source: 'pool' | 'schedule') => {
    setDraggedData({ item, source });
    e.dataTransfer.effectAllowed = 'move';
    if (e.currentTarget instanceof HTMLElement) e.currentTarget.style.opacity = '0.5';
  };
  const handleDragEnd = (e: React.DragEvent) => {
    if (e.currentTarget instanceof HTMLElement) e.currentTarget.style.opacity = '1';
    setDraggedData(null);
    setDragOverDay(null);
    setIsPoolDragOver(false);
  };
  const handleDropOnDayButton = (dayIndex: number) => {
    if (!draggedData) return;
    const { item, source } = draggedData;
    if (source === 'pool') setPool(prev => prev.filter(i => i.id !== item.id));
    else setItinerary(prev => prev.filter(i => i.id !== item.id));
    setItinerary(prev => [...prev, { ...item, dayIndex: dayIndex }]);
    setSelectedDay(dayIndex);
  };
  const handleDropOnPool = () => {
    if (!draggedData) return;
    const { item, source } = draggedData;
    if (source === 'schedule') {
      setItinerary(prev => prev.filter(i => i.id !== item.id));
      setPool(prev => [...prev, { ...item, dayIndex: -1 }]);
    }
  };
  const handleDropOnScheduleList = (targetIndex: number) => {
    if (!draggedData) return;
    const { item, source } = draggedData;
    let newList = [...itinerary];
    if (source === 'schedule') newList = newList.filter(i => i.id !== item.id);
    else setPool(prev => prev.filter(i => i.id !== item.id));
    const currentItems = newList.filter(i => i.dayIndex === selectedDay);
    const newItem = { ...item, dayIndex: selectedDay };
    const otherDaysItems = newList.filter(i => i.dayIndex !== selectedDay);
    if (targetIndex === -1) currentItems.push(newItem);
    else currentItems.splice(targetIndex, 0, newItem);
    setItinerary([...otherDaysItems, ...currentItems]);
  };

  // CRUD & Move
  const deleteItem = (id: string, from: 'pool' | 'schedule') => {
    if (from === 'pool') setPool(pool.filter(i => i.id !== id));
    else setItinerary(itinerary.filter(i => i.id !== id));
    setSwipeId(null);
  };

  const moveItemToDay = (item: ScheduleItem, targetDayIndex: number) => {
    // Remove from current list
    if (item.dayIndex === -1) {
       setPool(pool.filter(i => i.id !== item.id));
    } else {
       setItinerary(itinerary.filter(i => i.id !== item.id));
    }
    // Add to new day
    const updatedItem = { ...item, dayIndex: targetDayIndex };
    setItinerary(prev => [...prev, updatedItem]);
    setMovingItem(null);
    setSelectedDay(targetDayIndex);
  };

  const openAddModal = (target: 'pool' | 'schedule') => {
    setAddItemTarget(target);
    setModalMode('add');
    setEditingItem(null);
    setIsAddModalOpen(true);
  };

  const openEditModal = (item: ScheduleItem, target: 'pool' | 'schedule') => {
    setAddItemTarget(target);
    setModalMode('edit');
    setEditingItem(item);
    setIsAddModalOpen(true);
    setSwipeId(null);
  };

  const handleSaveItem = (itemData: any) => {
    // Check if dayIndex changed during edit (for schedule items)
    const targetDayIndex = itemData.dayIndex !== undefined ? itemData.dayIndex : (addItemTarget === 'schedule' ? selectedDay : -1);

    if (modalMode === 'add') {
      const newItem: ScheduleItem = { 
        ...itemData, 
        id: Date.now().toString(), 
        dayIndex: targetDayIndex
      };
      if (targetDayIndex === -1) setPool([...pool, newItem]);
      else setItinerary([...itinerary, newItem]);
    } else if (editingItem) {
      const updatedItem = { ...editingItem, ...itemData, dayIndex: targetDayIndex };

      // Handle moving between pool and schedule or changing days
      const oldDayIndex = editingItem.dayIndex;

      if (oldDayIndex !== targetDayIndex) {
         // Remove from old location
         if (oldDayIndex === -1) setPool(prev => prev.filter(i => i.id !== editingItem.id));
         else setItinerary(prev => prev.filter(i => i.id !== editingItem.id));

         // Add to new location
         if (targetDayIndex === -1) setPool(prev => [...prev, updatedItem]);
         else setItinerary(prev => [...prev, updatedItem]);
      } else {
         // Just update in place
         if (targetDayIndex === -1) setPool(pool.map(i => i.id === updatedItem.id ? updatedItem : i));
         else setItinerary(itinerary.map(i => i.id === updatedItem.id ? updatedItem : i));
      }
    }
    setIsAddModalOpen(false);
  };

  const handleAddMemberSubmit = () => {
    if (newMemberName.trim()) {
      const randomId = Math.floor(Math.random() * 1000);
      onAddMember(newMemberName.trim(), `https://picsum.photos/seed/${newMemberName}${randomId}/200`);
      setNewMemberName('');
    }
  };

  const handleOpenMaps = (e: React.MouseEvent, location: string) => {
    e.stopPropagation();
    const query = encodeURIComponent(location);
    window.open(`https://www.google.com/maps/search/?api=1&query=${query}`, '_blank');
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500">
      {/* Countdown Card */}
      <div className="bg-stitch text-white p-6 rounded-2xl-sticker sticker-shadow flex justify-between items-center relative overflow-hidden border-2 border-white/20">
        <div className="z-10">
          <p className="text-[10px] font-black opacity-70 uppercase tracking-[0.3em] mb-1">Adventure Starts In</p>
          <h2 className="text-4xl font-black drop-shadow-sm">{countdown} Days</h2>
        </div>
        <div className="text-6xl opacity-20 absolute -right-2 -bottom-2 transform rotate-12 z-0">🏝️</div>
      </div>

      {/* Inspiration Pool Area */}
      <div 
        className={`transition-all duration-300 ${isPoolDragOver ? 'scale-[1.02]' : ''}`}
        onDragOver={(e) => { e.preventDefault(); setIsPoolDragOver(true); }}
        onDragLeave={() => setIsPoolDragOver(false)}
        onDrop={(e) => { e.preventDefault(); setIsPoolDragOver(false); handleDropOnPool(); }}
      >
        <div className="flex justify-between items-center px-1 mb-2">
           <h3 className="text-sm font-black text-navy flex items-center gap-2">
             <Sparkles size={16} className="text-donald" />
             Inspiration Pool
           </h3>
           <button 
              onClick={() => openAddModal('pool')}
              className="text-[10px] font-black bg-white px-2 py-1 rounded-full text-navy/40 border border-accent hover:text-stitch active:scale-95"
           >
             + IDEA
           </button>
        </div>

        <div className={`
           min-h-[100px] p-4 rounded-2xl-sticker border-2 border-dashed flex gap-3 overflow-x-auto snap-x scrollbar-hide items-center
           ${isPoolDragOver ? 'bg-stitch/10 border-stitch' : 'bg-white border-accent'}
        `}>
          {pool.length > 0 ? pool.map((item) => (
            <div 
              key={item.id}
              draggable
              onDragStart={(e) => handleDragStart(e, item, 'pool')}
              onDragEnd={handleDragEnd}
              onClick={() => openEditModal(item, 'pool')}
              className="flex-shrink-0 w-40 snap-center cursor-pointer active:cursor-grabbing group"
            >
              <div className="bg-paper p-3 rounded-xl-sticker sticker-shadow border border-accent relative hover:-translate-y-1 transition-transform duration-300 active:scale-105 active:shadow-xl h-full">
                 <div className="flex justify-between items-start mb-2">
                    <span 
                      className="px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-wider text-white"
                      style={{ backgroundColor: COLORS[item.category.toLowerCase() as keyof typeof COLORS] || COLORS.stitch }}
                    >
                      {item.category}
                    </span>
                    <button onClick={(e) => {e.stopPropagation(); deleteItem(item.id, 'pool')}} className="text-navy/10 hover:text-red-400"><X size={12} /></button>
                 </div>
                 <h4 className="font-black text-navy text-sm leading-tight mb-1 truncate">{item.location}</h4>
                 <div className="flex items-center justify-between mt-2 pt-2 border-t border-accent/30">
                    <p className="text-[9px] font-bold text-navy/30 truncate flex-1">{item.notes || 'No notes'}</p>
                    {/* Move Button for Pool items */}
                    <button 
                       onClick={(e) => { e.stopPropagation(); setMovingItem(item); }}
                       className="p-1 text-stitch hover:bg-stitch/10 rounded-full"
                    >
                       <ArrowRight size={12} />
                    </button>
                 </div>
              </div>
            </div>
          )) : (
            <div className="w-full text-center text-navy/20 flex flex-col items-center justify-center py-2" onClick={() => openAddModal('pool')}>
               <Lightbulb size={24} className="mb-1" />
               <p className="text-[10px] font-black uppercase tracking-widest">Drag items here or Tap to Add</p>
            </div>
          )}
        </div>
      </div>

      {/* Date Picker */}
      <div className="flex gap-2 overflow-x-auto pb-4 scrollbar-hide snap-x -mx-4 px-4">
        {days.map((day) => (
          <button
            key={day.index}
            onClick={() => setSelectedDay(day.index)}
            onDragOver={(e) => { e.preventDefault(); setDragOverDay(day.index); }}
            onDragLeave={() => setDragOverDay(null)}
            onDrop={(e) => { e.preventDefault(); handleDropOnDayButton(day.index); }}
            className={`flex-shrink-0 w-16 py-3 rounded-xl-sticker border-2 transition-all flex flex-col items-center snap-center relative ${
              selectedDay === day.index ? 'bg-donald border-white text-navy sticker-shadow scale-105 z-10' : 
              dragOverDay === day.index ? 'bg-stitch text-white border-stitch scale-110 shadow-lg z-20' : 'bg-paper border-accent opacity-50 text-navy'
            }`}
          >
            <p className="text-[10px] font-black uppercase leading-none mb-1 opacity-60">{day.weekday}</p>
            <p className="text-xl font-black leading-none">{day.date.split(' ')[1]}</p>
          </button>
        ))}
      </div>

      {/* Itinerary List */}
      <div 
        className="space-y-4 min-h-[300px]"
        onDragOver={(e) => e.preventDefault()}
        onDrop={(e) => { if (e.target === e.currentTarget) handleDropOnScheduleList(-1); }}
      >
        {currentDayItems.length > 0 ? currentDayItems.map((item, idx) => {
          // Check for linked bookings
          const linkedBooking = bookings.find(b => b.linkedScheduleId === item.id);

          return (
            <div 
              key={item.id} 
              className="relative group transition-all"
              onDragOver={(e) => e.preventDefault()}
              onDrop={(e) => { e.stopPropagation(); handleDropOnScheduleList(idx); }}
            >
              <div 
                className="flex items-start gap-3 relative"
                draggable
                onDragStart={(e) => handleDragStart(e, item, 'schedule')}
                onDragEnd={handleDragEnd}
                onClick={() => openEditModal(item, 'schedule')}
              >
                <div className="mt-6 text-navy/10 cursor-grab active:cursor-grabbing group-hover:text-navy/30 transition-colors hidden md:block">
                  <GripVertical size={20} />
                </div>

                <div className="flex-1 relative overflow-hidden rounded-xl-sticker cursor-pointer">
                  {/* Delete Action Background */}
                  <div className={`absolute inset-0 bg-red-500 flex items-center px-6 transition-opacity ${swipeId === item.id ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
                    <button onClick={(e) => { e.stopPropagation(); deleteItem(item.id, 'schedule'); }} className="text-white flex items-center gap-2 font-black">
                      <Trash2 size={20} /> DELETE
                    </button>
                  </div>

                  {/* Card Content */}
                  <div className={`bg-paper p-5 rounded-xl-sticker sticker-shadow border border-accent transition-all duration-300 active:scale-[1.02] hover:border-stitch/50 ${swipeId === item.id ? 'translate-x-32' : 'translate-x-0'}`}>
                    <div className="flex justify-between items-center mb-4">
                      <div className="flex items-center gap-3">
                        <div className="text-2xl font-black text-navy tracking-tight">{item.time}</div>
                        <span 
                          className="px-2.5 py-1 rounded-full text-[8px] font-black uppercase tracking-wider text-white shadow-sm" 
                          style={{ backgroundColor: COLORS[item.category.toLowerCase() as keyof typeof COLORS] || COLORS.stitch }}
                        >
                          {item.category}
                        </span>
                      </div>
                      <div className="flex items-center gap-2">
                         {/* Move Button for Mobile */}
                         <button 
                           onClick={(e) => { e.stopPropagation(); setMovingItem(item); }}
                           className="p-2 bg-cream text-navy/30 rounded-full hover:bg-stitch hover:text-white transition-colors"
                         >
                            <CalendarDays size={16} />
                         </button>
                         <button 
                           onClick={(e) => { e.stopPropagation(); setSwipeId(swipeId === item.id ? null : item.id); }} 
                           className="text-navy/20 active:scale-125 transition-transform"
                         >
                            <MoreHorizontal size={20} />
                         </button>
                      </div>
                    </div>

                    <div className="flex items-start justify-between gap-4">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-1">
                          <MapPin size={16} className="text-stitch flex-shrink-0" />
                          <h3 className="text-xl font-black text-navy leading-tight truncate">{item.location}</h3>
                        </div>
                        {/* Action Buttons Row */}
                        <div className="flex flex-wrap gap-2 mt-2">
                          {/* Navigate Button */}
                          <button 
                            onClick={(e) => handleOpenMaps(e, item.location)}
                            className="flex items-center gap-1.5 px-3 py-1.5 bg-cream rounded-full border border-accent text-[10px] font-black text-navy/60 hover:bg-green-100 hover:text-green-700 hover:border-green-200 transition-all active:scale-95"
                          >
                            <Navigation size={10} /> GO
                          </button>

                          {/* Linked Ticket Button */}
                          {linkedBooking && (
                            <button 
                              onClick={(e) => { e.stopPropagation(); onNavigate('bookings', linkedBooking.id); }}
                              className="flex items-center gap-1.5 px-3 py-1.5 bg-donald/20 rounded-full border border-donald/50 text-[10px] font-black text-navy/70 hover:bg-donald hover:text-navy transition-all active:scale-95"
                            >
                              <TicketIcon size={10} /> TICKET
                            </button>
                          )}
                        </div>
                      </div>
                    </div>
                    {item.notes && <div className="mt-4 pt-4 border-t border-accent/50 text-[10px] text-navy/70 italic leading-relaxed whitespace-pre-wrap">{item.notes}</div>}
                  </div>
                </div>
              </div>
            </div>
          );
        }) : (
          <div className="py-20 text-center opacity-30 flex flex-col items-center bg-paper/50 rounded-2xl border-2 border-dashed border-accent">
            <LayoutGrid size={40} className="mb-2" />
            <p className="font-black text-lg">Day {selectedDay + 1} is open</p>
            <p className="text-sm font-bold">Tap + to plan</p>
          </div>
        )}
      </div>

      <div className="fixed bottom-24 right-6 flex flex-col gap-3 z-50">
        <button onClick={() => setIsSettingsOpen(true)} className="w-12 h-12 bg-white text-navy rounded-full sticker-shadow border border-accent flex items-center justify-center active:scale-90 transition-transform">
          <Settings size={20} />
        </button>
        <button onClick={() => openAddModal('schedule')} className="w-14 h-14 bg-donald text-navy rounded-full sticker-shadow border-2 border-paper flex items-center justify-center active:scale-95 transition-transform shadow-lg">
          <Plus size={32} />
        </button>
      </div>

      {/* Move to Day Modal */}
      {movingItem && (
        <div className="fixed inset-0 z-[80] flex items-center justify-center p-6 bg-navy/20 backdrop-blur-sm animate-in fade-in" onClick={() => setMovingItem(null)}>
           <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-stitch/20 animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
              <div className="flex justify-between items-center mb-6">
                 <h3 className="text-lg font-black text-navy uppercase tracking-widest">Move to Day</h3>
                 <button onClick={() => setMovingItem(null)} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
              </div>
              <div className="grid grid-cols-2 gap-3">
                 {days.map(day => (
                    <button
                       key={day.index}
                       onClick={() => moveItemToDay(movingItem, day.index)}
                       className={`p-4 rounded-2xl border-2 transition-all text-left ${
                          movingItem.dayIndex === day.index 
                             ? 'bg-navy border-navy text-white' 
                             : 'bg-white border-accent text-navy hover:border-stitch'
                       }`}
                    >
                       <p className="text-[9px] font-black uppercase opacity-60 mb-1">{day.weekday}</p>
                       <p className="text-xl font-black">{day.date}</p>
                    </button>
                 ))}
              </div>
           </div>
        </div>
      )}

      {isSettingsOpen && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-navy/20 backdrop-blur-sm" onClick={() => setIsSettingsOpen(false)}>
          <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-stitch/20 relative animate-in zoom-in-95 flex flex-col max-h-[85vh]" onClick={e => e.stopPropagation()}>
             <div className="flex justify-between items-center mb-6">
               <h3 className="text-xl font-black text-navy uppercase tracking-wider">Settings</h3>
               <button onClick={() => setIsSettingsOpen(false)} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
            </div>
            <div className="overflow-y-auto pr-2 space-y-6 flex-1">
               <div className="space-y-4">
                 <h4 className="text-[10px] font-black uppercase text-navy/40 tracking-[0.2em]">General</h4>
                 <div><label className="text-[10px] uppercase text-navy/40 block">Region</label><input type="text" value={config.region} onChange={e => setConfig({...config, region: e.target.value})} className="w-full p-3 bg-cream rounded-xl font-bold border border-accent" /></div>
                 <div className="grid grid-cols-2 gap-4">
                   <div><label className="text-[10px] uppercase text-navy/40 block">Start</label><input type="date" value={config.startDate} onChange={e => setConfig({...config, startDate: e.target.value})} className="w-full p-3 bg-cream rounded-xl font-bold border border-accent text-xs" /></div>
                   <div><label className="text-[10px] uppercase text-navy/40 block">Days</label><input type="number" value={config.duration} onChange={e => setConfig({...config, duration: parseInt(e.target.value) || 1})} className="w-full p-3 bg-cream rounded-xl font-bold border border-accent" /></div>
                 </div>
               </div>
               <div className="space-y-4 pt-4 border-t border-accent/40">
                 <h4 className="text-[10px] font-black uppercase text-navy/40 tracking-[0.2em]">Members</h4>
                 <div className="space-y-2">
                    {members.map(member => (
                       <div key={member.id} className="flex items-center justify-between p-3 bg-cream rounded-xl border border-accent/50 group">
                          <div className="flex items-center gap-3">
                             <img src={member.avatar} className="w-8 h-8 rounded-full border border-white" />
                             <div><p className="font-black text-sm text-navy">{member.name}</p></div>
                          </div>
                          {currentUser.id !== member.id && <button onClick={() => onDeleteMember(member.id)} className="p-2 text-navy/10 hover:text-red-400"><Trash2 size={16} /></button>}
                       </div>
                    ))}
                 </div>
                 <div className="flex gap-2">
                    <input type="text" value={newMemberName} onChange={e => setNewMemberName(e.target.value)} placeholder="New Name" className="flex-1 p-3 bg-white border border-accent rounded-xl text-sm font-bold" />
                    <button onClick={handleAddMemberSubmit} disabled={!newMemberName.trim()} className="px-4 bg-navy text-white rounded-xl font-black"><Plus size={20} /></button>
                 </div>
               </div>
            </div>
          </div>
        </div>
      )}

      {isAddModalOpen && (
        <AddItemModal 
          target={addItemTarget} 
          mode={modalMode}
          initialData={editingItem} 
          duration={config.duration}
          startDate={config.startDate}
          onClose={() => setIsAddModalOpen(false)} 
          onSave={handleSaveItem} 
        />
      )}
    </div>
  );
};

// Simplified Add/Edit Modal
const AddItemModal: React.FC<{ 
  target: 'schedule' | 'pool'; 
  mode: 'add' | 'edit';
  initialData: ScheduleItem | null; 
  duration: number;
  startDate: string;
  onClose: () => void; 
  onSave: (item: any) => void 
}> = ({ target, mode, initialData, duration, startDate, onClose, onSave }) => {
  const [formData, setFormData] = useState({
    dayIndex: initialData?.dayIndex !== undefined ? initialData.dayIndex : (target === 'pool' ? -1 : 0),
    time: initialData?.time || '10:00', 
    title: initialData?.title || 'Activity', 
    location: initialData?.location || '', 
    category: initialData?.category || 'Attraction', 
    notes: initialData?.notes || '',
  });
  const [showDetails, setShowDetails] = useState(target === 'schedule'); // Auto-show details for Schedule

  const categories: Category[] = ['Attraction', 'Food', 'Transport', 'Stay', 'Other'];

  const daysOptions = Array.from({ length: duration }, (_, i) => {
    const d = new Date(startDate);
    d.setDate(d.getDate() + i);
    return {
       index: i,
       label: `Day ${i + 1} - ${d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`
    };
  });

  return (
    <div className="fixed inset-0 z-[70] flex flex-col bg-cream animate-in slide-in-from-bottom duration-300">
      <div className="p-4 flex justify-between items-center border-b border-accent bg-paper">
        <button onClick={onClose} className="text-navy/40 p-2"><X size={24} /></button>
        <h3 className="text-lg font-black text-navy uppercase tracking-widest">
           {mode === 'add' ? (target === 'pool' ? 'New Idea' : 'Add Stop') : 'Edit Item'}
        </h3>
        <button onClick={() => onSave(formData)} className="text-stitch font-black p-2" disabled={!formData.location}>DONE</button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {/* Main Input - Location */}
        <div className="bg-paper p-6 rounded-3xl-sticker border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/30 mb-2 block tracking-widest">Where to?</label>
          <div className="flex items-center gap-3">
            <MapPin size={28} className="text-stitch flex-shrink-0" />
            <input 
              autoFocus 
              type="text" 
              value={formData.location} 
              onChange={e => setFormData({...formData, location: e.target.value})} 
              placeholder="e.g. Tokyo Tower" 
              className="w-full text-2xl font-black bg-transparent border-none p-0 focus:ring-0 placeholder:text-navy/10" 
            />
          </div>
        </div>

        {/* Categories Chips */}
        <div>
           <label className="text-[10px] font-black uppercase text-navy/30 mb-3 block px-1 tracking-widest">Category</label>
           <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setFormData({...formData, category: cat as any})}
                  className={`flex-shrink-0 px-4 py-3 rounded-2xl font-black text-xs uppercase tracking-wider border-2 transition-all ${
                    formData.category === cat 
                      ? 'bg-navy border-navy text-white sticker-shadow scale-105' 
                      : 'bg-white border-accent text-navy/40'
                  }`}
                >
                  {cat}
                </button>
              ))}
           </div>
        </div>

        {/* Collapsible Details including Day Selector */}
        <div className="space-y-4">
           {target === 'pool' && !showDetails && (
              <button 
                onClick={() => setShowDetails(true)}
                className="w-full py-3 text-xs font-black text-stitch uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-stitch/5 rounded-xl transition-colors"
              >
                 <Plus size={14} /> Add Time, Day & Notes
              </button>
           )}

           {showDetails && (
             <div className="animate-in slide-in-from-top-4 fade-in duration-300 space-y-4">
               {/* Day Selector (Modify Date Function) */}
               <div className="bg-white p-4 rounded-2xl border border-accent">
                   <label className="text-[10px] font-black uppercase text-navy/30 mb-2 block">Day</label>
                   <select 
                      value={formData.dayIndex} 
                      onChange={e => setFormData({...formData, dayIndex: parseInt(e.target.value)})}
                      className="w-full font-black text-lg bg-transparent border-none p-0 focus:ring-0 text-navy"
                   >
                      <option value={-1}>Inspiration Pool (No Date)</option>
                      {daysOptions.map(d => (
                         <option key={d.index} value={d.index}>{d.label}</option>
                      ))}
                   </select>
               </div>

               <div className="bg-white p-4 rounded-2xl border border-accent">
                   <label className="text-[10px] font-black uppercase text-navy/30 mb-1 block">Time</label>
                   <input type="time" value={formData.time} onChange={e => setFormData({...formData, time: e.target.value})} className="w-full font-black text-lg bg-transparent border-none p-0 focus:ring-0" />
               </div>

               <div className="bg-white p-4 rounded-2xl border border-accent">
                  <label className="text-[10px] font-black uppercase text-navy/30 mb-1 block">Notes</label>
                  <textarea rows={3} value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} placeholder="Details..." className="w-full text-sm bg-transparent border-none p-0 focus:ring-0 resize-none font-medium" />
               </div>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

export default Schedule;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Plane, 
  Hotel, 
  Car, 
  Utensils, 
  Ticket as TicketIcon, 
  Plus, 
  X, 
  Camera, 
  Edit2, 
  Trash2, 
  Hash, 
  Search,
  User,
  Copy,
  Calendar,
  Sparkles,
  MapPin,
  ArrowUpRight,
  QrCode
} from 'lucide-react';
import { Booking, TripMember, ScheduleItem } from '../types';

interface BookingsProps {
  members: TripMember[];
  currentUser: TripMember;
  onNavigate: (tab: string, id?: string) => void;
  highlightId?: string | null;
}

const Bookings: React.FC<BookingsProps> = ({ members, currentUser, onNavigate, highlightId }) => {
  const [bookings, setBookings] = useState<Booking[]>(() => {
    const saved = localStorage.getItem('bookings');
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        type: 'Flight',
        title: 'CX504 Pacific Air',
        referenceNo: 'M7X9L2',
        bookedBy: '1',
        cost: 0,
        imageUrl: 'https://picsum.photos/seed/flight/600/200',
        details: { from: 'HKG', to: 'NRT', date: '12 OCT', time: '09:15', seat: '24A', gate: 'B12', airline: 'Cathay' }
      },
      {
        id: '2',
        type: 'Hotel',
        title: 'Shinjuku Prince Hotel',
        referenceNo: 'H-992831',
        bookedBy: '2',
        cost: 45000,
        imageUrl: '',
        details: { address: 'Kabukicho, Tokyo', checkIn: '12 OCT', checkOut: '17 OCT', room: 'Superior King' }
      }
    ];
  });

  // Load itinerary for linking
  const [itinerary] = useState<ScheduleItem[]>(() => {
    const saved = localStorage.getItem('itinerary');
    return saved ? JSON.parse(saved) : [];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBooking, setEditingBooking] = useState<Booking | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterUser, setFilterUser] = useState<string | 'All'>('All');

  useEffect(() => {
    localStorage.setItem('bookings', JSON.stringify(bookings));
  }, [bookings]);

  // Handle highlight request from props
  useEffect(() => {
    if (highlightId) {
       setExpandedId(highlightId);
    }
  }, [highlightId]);

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('Delete this booking?')) {
      setBookings(bookings.filter(b => b.id !== id));
      if (expandedId === id) setExpandedId(null);
    }
  };

  const handleEdit = (e: React.MouseEvent, booking: Booking) => {
    e.stopPropagation();
    setEditingBooking(booking); 
    setIsModalOpen(true);
  };

  const handleSave = (booking: Booking) => {
    if (editingBooking) {
      setBookings(bookings.map(b => b.id === booking.id ? booking : b));
    } else {
      setBookings([...bookings, { ...booking, id: Date.now().toString() }]);
    }
    setIsModalOpen(false);
    setEditingBooking(null);
  };

  const copyToClipboard = (e: React.MouseEvent, text: string) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
  };

  const filteredBookings = useMemo(() => {
    return bookings.filter(b => {
      const matchesSearch = 
        b.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
        b.type.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (b.referenceNo && b.referenceNo.toLowerCase().includes(searchTerm.toLowerCase()));

      const matchesUser = filterUser === 'All' || b.bookedBy === filterUser;

      return matchesSearch && matchesUser;
    });
  }, [bookings, searchTerm, filterUser]);

  // Helper to render the visible "Tab" strip when stacked
  const renderHeaderStrip = (booking: Booking, isExpanded: boolean) => {
    const bookedByMember = members.find(m => m.id === booking.bookedBy);

    let icon = <TicketIcon size={18} />;
    let bgColor = 'bg-white';
    let textColor = 'text-navy';
    let borderColor = 'border-accent';
    let accentColor = 'bg-accent';

    switch (booking.type) {
      case 'Flight':
        icon = <Plane size={18} className="text-white" />;
        bgColor = 'bg-navy';
        textColor = 'text-white';
        borderColor = 'border-navy';
        accentColor = 'bg-stitch';
        break;
      case 'Hotel':
        icon = <Hotel size={18} className="text-stitch" />;
        bgColor = 'bg-white';
        textColor = 'text-navy';
        borderColor = 'border-stitch';
        accentColor = 'bg-stitch';
        break;
      case 'Amusement':
        icon = <Sparkles size={18} className="text-navy" />;
        bgColor = 'bg-donald';
        textColor = 'text-navy';
        borderColor = 'border-donald';
        accentColor = 'bg-white';
        break;
      case 'Restaurant':
        icon = <Utensils size={18} className="text-red-400" />;
        bgColor = 'bg-white';
        textColor = 'text-navy';
        borderColor = 'border-red-200';
        accentColor = 'bg-red-200';
        break;
      case 'Car':
        icon = <Car size={18} className="text-navy" />;
        bgColor = 'bg-accent/30';
        textColor = 'text-navy';
        borderColor = 'border-accent';
        accentColor = 'bg-white';
        break;
    }

    // Determine key date/time info for the header
    const displayTime = booking.details.time || booking.details.checkIn || booking.details.datetime?.split('T')[1] || '';
    const displayDate = booking.details.date || booking.details.checkIn || booking.details.datetime?.split('T')[0] || '';

    return (
      <div className={`p-4 flex flex-col justify-between ${bgColor} ${textColor} transition-colors relative overflow-hidden min-h-[90px]`}>
        {/* Decorative Elements */}
        {booking.type === 'Flight' && <div className="absolute right-0 top-0 bottom-0 w-24 bg-white/10 -skew-x-12 translate-x-10" />}
        {booking.type === 'Amusement' && <div className="absolute inset-0 opacity-10" style={{backgroundImage: 'radial-gradient(circle, #fff 2px, transparent 2.5px)', backgroundSize: '12px 12px'}} />}

        {/* Top Row: Type & Icon */}
        <div className="flex justify-between items-start mb-1 relative z-10">
           <div className="flex items-center gap-3">
              <div className={`w-8 h-8 rounded-lg flex items-center justify-center shadow-sm ${accentColor === 'bg-white' ? 'bg-white/80' : accentColor}`}>
                {icon}
              </div>
              <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full ${booking.type === 'Flight' ? 'bg-white/20' : 'bg-navy/5'}`}>
                {booking.type}
              </span>
           </div>

           {/* Booked By Avatar Small */}
           {bookedByMember && (
             <img src={bookedByMember.avatar} className="w-6 h-6 rounded-full border border-white shadow-sm" />
           )}
        </div>

        {/* Bottom Row: Title & Time - Main Info */}
        <div className="flex justify-between items-end relative z-10">
           <div className="flex-1 min-w-0 pr-4">
              <h3 className="font-black text-lg leading-tight truncate">{booking.title}</h3>
              {booking.referenceNo && (
                 <span className={`flex items-center gap-1 text-[9px] font-bold opacity-60 mt-0.5`}>
                   <Hash size={8} /> {booking.referenceNo}
                 </span>
              )}
           </div>
           <div className="text-right flex-shrink-0">
              {displayDate && <p className="text-[9px] font-bold opacity-60 uppercase">{displayDate}</p>}
              {displayTime && <p className="text-sm font-black">{displayTime}</p>}
           </div>
        </div>
      </div>
    );
  };

  const renderBookingDetails = (booking: Booking) => {
    const hasImage = !!booking.imageUrl;
    const linkedItem = itinerary.find(i => i.id === booking.linkedScheduleId);

    return (
      <div className="animate-in fade-in duration-300 bg-white">

        {/* LINKED SCHEDULE BANNER */}
        {linkedItem && (
          <div 
            onClick={() => onNavigate('schedule')}
            className="bg-stitch/10 px-4 py-2 flex items-center justify-between cursor-pointer hover:bg-stitch/20 transition-colors border-b border-dashed border-stitch/30"
          >
             <div className="flex items-center gap-2 overflow-hidden">
                <MapPin size={12} className="text-stitch flex-shrink-0" />
                <span className="text-[10px] font-black uppercase text-stitch truncate">
                  Linked to: Day {linkedItem.dayIndex + 1} - {linkedItem.location}
                </span>
             </div>
             <ArrowUpRight size={12} className="text-stitch" />
          </div>
        )}

        {/* HERO SECTION: IMAGE / QR CODE (Admission Priority) */}
        <div className="p-4 flex flex-col items-center justify-center bg-white">
           {hasImage ? (
             <div className="w-full rounded-xl border-2 border-navy/5 p-1 shadow-inner bg-cream">
                <img src={booking.imageUrl} alt="Voucher" className="w-full h-auto max-h-[300px] object-contain rounded-lg mix-blend-multiply" />
             </div>
           ) : (
             <div className="w-full h-32 bg-cream rounded-xl border-2 border-dashed border-accent flex flex-col items-center justify-center text-navy/20">
                <QrCode size={40} />
                <p className="text-[10px] font-black uppercase mt-2">No Ticket Image</p>
             </div>
           )}
           <p className="text-[9px] font-bold text-navy/30 uppercase mt-2 tracking-widest">Present at Entry</p>
        </div>

        {/* Perforated Line Effect */}
        <div className="relative h-4 w-full bg-white overflow-hidden my-2">
            <div className="absolute top-1/2 left-0 w-full border-t-2 border-dashed border-accent/60"></div>
            <div className="absolute -left-2 top-1/2 -translate-y-1/2 w-4 h-4 bg-cream rounded-full"></div>
            <div className="absolute -right-2 top-1/2 -translate-y-1/2 w-4 h-4 bg-cream rounded-full"></div>
        </div>

        {/* DETAILS SECTION */}
        <div className="p-5 pt-0">
          {/* Reference Number Copy Block */}
          {booking.referenceNo && (
            <div 
              onClick={(e) => copyToClipboard(e, booking.referenceNo!)}
              className="flex items-center justify-between p-3 bg-cream rounded-xl border border-accent/50 mb-6 cursor-pointer active:scale-[0.98] transition-transform group"
            >
               <div>
                  <p className="text-[9px] font-black uppercase text-navy/30 tracking-widest">Booking Ref</p>
                  <p className="text-2xl font-black text-navy font-mono tracking-wider">{booking.referenceNo}</p>
               </div>
               <div className="w-8 h-8 rounded-full bg-white flex items-center justify-center shadow-sm text-stitch group-hover:scale-110 transition-transform">
                  <Copy size={14} />
               </div>
            </div>
          )}

          {/* Type Specific Grid */}
          <div className="grid grid-cols-2 gap-y-4 gap-x-6">
            {booking.type === 'Flight' && (
              <>
                <div><p className="text-[9px] font-black text-navy/30 uppercase">From</p><p className="text-lg font-black text-navy">{booking.details.from}</p></div>
                <div><p className="text-[9px] font-black text-navy/30 uppercase">To</p><p className="text-lg font-black text-navy">{booking.details.to}</p></div>
                <div><p className="text-[9px] font-black text-navy/30 uppercase">Gate</p><p className="text-lg font-black text-navy">{booking.details.gate || '-'}</p></div>
                <div><p className="text-[9px] font-black text-navy/30 uppercase">Seat</p><p className="text-lg font-black text-navy">{booking.details.seat || '-'}</p></div>
              </>
            )}

            {(booking.type === 'Hotel' || booking.type === 'Car') && (
               <>
                 <div className="col-span-2"><p className="text-[9px] font-black text-navy/30 uppercase">Address</p><p className="font-bold text-navy">{booking.details.address}</p></div>
                 <div><p className="text-[9px] font-black text-navy/30 uppercase">Start</p><p className="font-bold text-navy">{booking.details.checkIn}</p></div>
                 <div><p className="text-[9px] font-black text-navy/30 uppercase">End</p><p className="font-bold text-navy">{booking.details.checkOut}</p></div>
               </>
            )}

            {/* General Fields for others */}
            {Object.entries(booking.details).map(([key, value]) => {
                if (['from', 'to', 'gate', 'seat', 'checkIn', 'checkOut', 'address', 'imageUrl'].includes(key)) return null;
                return (
                  <div key={key} className={String(value).length > 20 ? 'col-span-2' : ''}>
                     <p className="text-[9px] font-black text-navy/30 uppercase">{key}</p>
                     <p className="font-bold text-navy break-words">{String(value)}</p>
                  </div>
                )
             })}
          </div>

          {/* Action Buttons */}
          <div className="flex justify-end gap-3 mt-8 pt-4 border-t border-accent/30">
             <button onClick={(e) => handleEdit(e, booking)} className="flex items-center gap-1 px-4 py-2 bg-cream rounded-full text-[10px] font-black text-navy hover:bg-stitch hover:text-white transition-colors">
               <Edit2 size={12} /> EDIT
             </button>
             <button onClick={(e) => handleDelete(e, booking.id)} className="flex items-center gap-1 px-4 py-2 bg-cream rounded-full text-[10px] font-black text-red-400 hover:bg-red-400 hover:text-white transition-colors">
               <Trash2 size={12} /> REMOVE
             </button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500 min-h-screen">

      {/* Search & Filter Header */}
      <div className="space-y-4 sticky top-0 bg-cream/95 backdrop-blur-sm z-[60] pt-2 pb-2 -mx-4 px-4 border-b border-accent/20">
         <div className="flex items-center gap-2 bg-white p-3 rounded-2xl-sticker border border-accent shadow-sm">
            <Search size={18} className="text-navy/30" />
            <input 
               type="text" 
               placeholder="Search tickets, Ref No..." 
               value={searchTerm}
               onChange={(e) => setSearchTerm(e.target.value)}
               className="flex-1 bg-transparent border-none p-0 text-navy font-bold placeholder:text-navy/20 focus:ring-0 text-sm"
            />
            {searchTerm && <button onClick={() => setSearchTerm('')}><X size={14} className="text-navy/30" /></button>}
         </div>

         <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-hide">
            <button 
               onClick={() => setFilterUser('All')}
               className={`flex-shrink-0 px-3 py-1.5 rounded-full flex items-center gap-1.5 border transition-all ${filterUser === 'All' ? 'bg-navy border-navy text-white' : 'bg-white border-accent text-navy/40'}`}
            >
               <User size={12} /> <span className="text-[10px] font-black uppercase">All</span>
            </button>
            {members.map(m => (
               <button 
                  key={m.id}
                  onClick={() => setFilterUser(m.id)}
                  className={`flex-shrink-0 pr-3 py-1 rounded-full flex items-center gap-2 border transition-all ${filterUser === m.id ? 'bg-stitch border-stitch text-white pl-1' : 'bg-white border-accent text-navy/40 pl-1'}`}
               >
                  <img src={m.avatar} className="w-5 h-5 rounded-full" />
                  <span className="text-[10px] font-black uppercase">{m.name}</span>
               </button>
            ))}
         </div>
      </div>

      <div className="flex justify-between items-center px-1">
        <div>
          <h2 className="text-2xl font-black text-navy">Ticket Wallet</h2>
          <p className="text-[10px] font-bold text-navy/30 uppercase tracking-[0.2em]">
             {filteredBookings.length} Vouchers Found
          </p>
        </div>
        <button 
          onClick={() => { setEditingBooking(null); setIsModalOpen(true); }}
          className="w-12 h-12 bg-donald rounded-full sticker-shadow border-2 border-white flex items-center justify-center text-navy active:scale-90 transition-transform shadow-lg z-50"
        >
          <Plus size={28} />
        </button>
      </div>

      {/* Stacked Layout Container */}
      <div className="relative pb-24 flex flex-col pt-4">
        {filteredBookings.length > 0 ? (
          filteredBookings.map((booking, index) => {
             const isExpanded = expandedId === booking.id;
             // Stack logic: Less overlap when expanded

             return (
               <div 
                  key={booking.id}
                  onClick={() => setExpandedId(isExpanded ? null : booking.id)}
                  className={`
                     relative w-full rounded-2xl-sticker overflow-hidden border-2 sticker-shadow transition-all duration-500 ease-in-out cursor-pointer
                     ${isExpanded 
                        ? 'z-50 my-4 scale-[1.02] shadow-2xl' 
                        : 'z-0 -mt-16 hover:-mt-12 hover:z-40 hover:scale-[1.01] hover:shadow-lg' // Increased negative margin
                     }
                     ${index === 0 && !isExpanded ? 'mt-0' : ''}
                     ${booking.type === 'Flight' ? 'border-navy' : booking.type === 'Amusement' ? 'border-donald' : 'border-accent'}
                  `}
                  style={{ 
                     // Ensure visual stacking order when collapsed
                     zIndex: isExpanded ? 50 : index 
                  }}
               >
                  {renderHeaderStrip(booking, isExpanded)}

                  {/* Expandable Content Area */}
                  <div className={`transition-[max-height] duration-500 ease-in-out overflow-hidden ${isExpanded ? 'max-h-[1000px]' : 'max-h-0'}`}>
                     {renderBookingDetails(booking)}
                  </div>
               </div>
             );
          })
        ) : (
          <div className="py-24 text-center opacity-30 flex flex-col items-center border-2 border-dashed border-accent rounded-3xl bg-paper/50 mt-4">
            <TicketIcon size={56} className="mb-4 text-navy/20" />
            <p className="font-black text-xl">Empty Pocket</p>
            <p className="text-sm font-bold max-w-[200px] mx-auto">No tickets found. Tap + to add one!</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <BookingFormModal 
          initialData={editingBooking} 
          members={members}
          itinerary={itinerary}
          currentUser={currentUser}
          onClose={() => setIsModalOpen(false)} 
          onSave={handleSave} 
        />
      )}
    </div>
  );
};

const BookingFormModal: React.FC<{ 
  initialData: Booking | null; 
  members: TripMember[]; 
  itinerary: ScheduleItem[];
  currentUser: TripMember; 
  onClose: () => void; 
  onSave: (b: Booking) => void 
}> = ({ initialData, members, itinerary, currentUser, onClose, onSave }) => {
  const [formData, setFormData] = useState<Partial<Booking>>(initialData || {
    type: 'Hotel',
    title: '',
    referenceNo: '',
    bookedBy: currentUser.id,
    linkedScheduleId: '',
    cost: 0,
    imageUrl: '',
    details: {}
  });

  const [imagePreview, setImagePreview] = useState<string>(initialData?.imageUrl || '');

  const types: Booking['type'][] = ['Flight', 'Hotel', 'Car', 'Restaurant', 'Amusement', 'Ticket'];

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64 = reader.result as string;
        setImagePreview(base64);
        setFormData({ ...formData, imageUrl: base64 });
      };
      reader.readAsDataURL(file);
    }
  };

  const removeImage = () => {
    setImagePreview('');
    setFormData({ ...formData, imageUrl: '' });
  };

  const updateDetail = (key: string, value: any) => {
    setFormData({
      ...formData,
      details: { ...formData.details, [key]: value }
    });
  };

  return (
    <div className="fixed inset-0 z-[100] flex flex-col bg-cream/95 backdrop-blur-md animate-in slide-in-from-bottom duration-300">
      <div className="p-4 flex justify-between items-center border-b border-accent bg-paper">
        <button onClick={onClose} className="text-navy/40 p-2"><X size={24} /></button>
        <h3 className="text-lg font-black text-navy uppercase tracking-widest">{initialData ? 'Edit Entry' : 'New Ticket'}</h3>
        <button onClick={() => onSave(formData as Booking)} className="text-stitch font-black p-2" disabled={!formData.title}>DONE</button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 pb-20">
        {/* Type Selection */}
        <div className="bg-paper p-4 rounded-2xl-sticker border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/40 mb-3 block">Category</label>
          <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
            {types.map(t => (
              <button
                key={t}
                onClick={() => setFormData({ ...formData, type: t })}
                className={`flex-shrink-0 px-5 py-2.5 rounded-full text-[10px] font-black uppercase tracking-widest transition-all ${
                  formData.type === t ? 'bg-navy text-white sticker-shadow scale-105' : 'bg-accent/20 text-navy/40'
                }`}
              >
                {t}
              </button>
            ))}
          </div>
        </div>

        {/* Linked Schedule Item (New) */}
        <div className="bg-paper p-4 rounded-2xl-sticker border border-accent sticker-shadow">
           <label className="text-[10px] font-black uppercase text-navy/40 mb-2 block flex items-center gap-1">
             <Calendar size={12} /> Connect to Schedule
           </label>
           <div className="relative">
             <select 
                value={formData.linkedScheduleId || ''}
                onChange={e => setFormData({...formData, linkedScheduleId: e.target.value})}
                className="w-full bg-cream border border-accent rounded-xl p-3 font-bold text-sm appearance-none focus:ring-0 focus:border-stitch"
             >
                <option value="">-- Unlinked --</option>
                {itinerary.filter(i => i.title || i.location).map(item => (
                   <option key={item.id} value={item.id}>
                      Day {item.dayIndex + 1} - {item.location || item.title} ({item.time})
                   </option>
                ))}
             </select>
             <div className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none opacity-50">▼</div>
           </div>
        </div>

        {/* Reference & Booker Info */}
        <div className="bg-paper p-4 rounded-2xl-sticker border border-accent sticker-shadow space-y-4">
           <div>
              <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">Booking Reference / PNR</label>
              <div className="flex items-center gap-2 bg-accent/10 p-2 rounded-xl border border-accent/20">
                 <Hash size={16} className="text-navy/30" />
                 <input 
                   type="text" 
                   value={formData.referenceNo || ''} 
                   onChange={e => setFormData({ ...formData, referenceNo: e.target.value.toUpperCase() })} 
                   placeholder="e.g. M7X9L2" 
                   className="w-full font-black text-navy bg-transparent border-none p-0 focus:ring-0 uppercase placeholder:normal-case" 
                 />
              </div>
           </div>

           <div>
              <label className="text-[10px] font-black uppercase text-navy/40 mb-2 block">Who Booked This?</label>
              <div className="flex gap-3 overflow-x-auto pb-1 scrollbar-hide">
                 {members.map(m => (
                    <button 
                       key={m.id}
                       onClick={() => setFormData({...formData, bookedBy: m.id})}
                       className={`flex-shrink-0 flex items-center gap-2 px-3 py-1.5 rounded-full border transition-all ${formData.bookedBy === m.id ? 'bg-stitch border-stitch text-white' : 'bg-white border-accent text-navy/40'}`}
                    >
                       <img src={m.avatar} className="w-5 h-5 rounded-full" />
                       <span className="text-[10px] font-black uppercase">{m.name}</span>
                    </button>
                 ))}
              </div>
           </div>
        </div>

        {/* Voucher Snapshot */}
        <div 
          className="w-full aspect-[21/9] bg-white rounded-2xl-sticker sticker-shadow border-2 border-dashed border-accent flex flex-col items-center justify-center relative overflow-hidden group transition-all active:scale-95"
          onClick={() => document.getElementById('imageInput')?.click()}
        >
          {imagePreview ? (
            <div className="relative w-full h-full">
               <img src={imagePreview} alt="Preview" className="w-full h-full object-cover" />
               <button 
                  onClick={(e) => { e.stopPropagation(); removeImage(); }}
                  className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full shadow-lg"
               >
                 <X size={14} />
               </button>
            </div>
          ) : (
            <div className="flex flex-col items-center text-navy/20 w-full h-full justify-center">
              <Camera size={40} className="mb-2" />
              <p className="text-[10px] font-black uppercase">Snap Ticket / Voucher</p>
              <p className="text-[8px] opacity-60 mt-1 uppercase">(Required for entry)</p>
            </div>
          )}
          <input id="imageInput" type="file" accept="image/*" onChange={handleImageUpload} className="hidden" />
        </div>

        {/* Main Details */}
        <div className="bg-paper p-4 rounded-2xl-sticker border border-accent sticker-shadow space-y-4">
          <div>
            <label className="text-[10px] font-black uppercase text-navy/40 mb-1 block">Title / Place</label>
            <input 
              type="text" 
              value={formData.title} 
              onChange={e => setFormData({ ...formData, title: e.target.value })} 
              placeholder="e.g. Disney Ticket" 
              className="w-full text-xl font-black text-navy bg-transparent border-none p-0 focus:ring-0" 
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            {formData.type === 'Flight' && (
              <>
                 <div><label className="text-[9px] uppercase opacity-40 font-bold block">From</label><input type="text" placeholder="HKG" className="w-full font-bold bg-cream/50 p-2 rounded-lg" value={formData.details?.from || ''} onChange={e => updateDetail('from', e.target.value)} /></div>
                 <div><label className="text-[9px] uppercase opacity-40 font-bold block">To</label><input type="text" placeholder="NRT" className="w-full font-bold bg-cream/50 p-2 rounded-lg" value={formData.details?.to || ''} onChange={e => updateDetail('to', e.target.value)} /></div>
                 <div><label className="text-[9px] uppercase opacity-40 font-bold block">Date</label><input type="text" placeholder="12 OCT" className="w-full font-bold bg-cream/50 p-2 rounded-lg" value={formData.details?.date || ''} onChange={e => updateDetail('date', e.target.value)} /></div>
                 <div><label className="text-[9px] uppercase opacity-40 font-bold block">Time</label><input type="time" className="w-full font-bold bg-cream/50 p-2 rounded-lg" value={formData.details?.time || ''} onChange={e => updateDetail('time', e.target.value)} /></div>
                 <div><label className="text-[9px] uppercase opacity-40 font-bold block">Seat</label><input type="text" placeholder="1A" className="w-full font-bold bg-cream/50 p-2 rounded-lg" value={formData.details?.seat || ''} onChange={e => updateDetail('seat', e.target.value)} /></div>
                 <div><label className="text-[9px] uppercase opacity-40 font-bold block">Gate</label><input type="text" placeholder="-" className="w-full font-bold bg-cream/50 p-2 rounded-lg" value={formData.details?.gate || ''} onChange={e => updateDetail('gate', e.target.value)} /></div>
              </>
            )}

            {(formData.type === 'Hotel' || formData.type === 'Car') && (
               <>
                 <div className="col-span-2"><label className="text-[9px] uppercase opacity-40 font-bold block">Address/Pick up</label><input type="text" className="w-full font-bold bg-cream/50 p-2 rounded-lg" value={formData.details?.address || ''} onChange={e => updateDetail('address', e.target.value)} /></div>
                 <div><label className="text-[9px] uppercase opacity-40 font-bold block">Check In/Start</label><input type="date" className="w-full font-bold bg-cream/50 p-2 rounded-lg" value={formData.details?.checkIn || ''} onChange={e => updateDetail('checkIn', e.target.value)} /></div>
                 <div><label className="text-[9px] uppercase opacity-40 font-bold block">Check Out/End</label><input type="date" className="w-full font-bold bg-cream/50 p-2 rounded-lg" value={formData.details?.checkOut || ''} onChange={e => updateDetail('checkOut', e.target.value)} /></div>
               </>
            )}

            {['Restaurant', 'Amusement', 'Ticket'].includes(formData.type!) && (
               <>
                 <div className="col-span-2"><label className="text-[9px] uppercase opacity-40 font-bold block">Date & Time</label><input type="datetime-local" className="w-full font-bold bg-cream/50 p-2 rounded-lg" value={formData.details?.datetime || ''} onChange={e => updateDetail('datetime', e.target.value)} /></div>
                 <div className="col-span-2"><label className="text-[9px] uppercase opacity-40 font-bold block">Notes</label><input type="text" placeholder="Table no, Entry code..." className="w-full font-bold bg-cream/50 p-2 rounded-lg" value={formData.details?.notes || ''} onChange={e => updateDetail('notes', e.target.value)} /></div>
               </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Bookings;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  MapPin, 
  Settings, 
  Plus, 
  X, 
  GripVertical,
  Trash2,
  Sparkles,
  Lightbulb,
  LayoutGrid,
  MoreHorizontal,
  CalendarDays,
  ArrowRight,
  Navigation,
  Ticket as TicketIcon,
  Download,
  Upload,
  FileJson
} from 'lucide-react';
import { TripConfig, ScheduleItem, Category, TripMember, Booking } from '../types';
import { COLORS } from '../constants';

interface ScheduleProps {
  config: TripConfig;
  members: TripMember[];
  currentUser: TripMember;
  onAddMember: (name: string, avatar: string) => void;
  onDeleteMember: (id: string) => void;
  onSwitchUser: (member: TripMember) => void;
  onNavigate: (tab: any, id?: string) => void;
}

const Schedule: React.FC<ScheduleProps> = ({ 
  config: initialConfig, 
  members, 
  currentUser, 
  onAddMember, 
  onDeleteMember, 
  onSwitchUser,
  onNavigate
}) => {
  const [config, setConfig] = useState<TripConfig>(() => {
    const saved = localStorage.getItem('tripConfig');
    return saved ? JSON.parse(saved) : initialConfig;
  });

  const [itinerary, setItinerary] = useState<ScheduleItem[]>(() => {
    const saved = localStorage.getItem('itinerary');
    return saved ? JSON.parse(saved) : [
      { id: '1', dayIndex: 0, time: '10:00', title: 'Arrival', location: 'NRT Terminal 1', category: 'Transport' as Category },
      { id: '2', dayIndex: 0, time: '13:30', title: 'Lunch', location: 'Ichiran Shinjuku', category: 'Food' as Category },
    ];
  });

  const [pool, setPool] = useState<ScheduleItem[]>(() => {
    const saved = localStorage.getItem('inspiration_pool');
    return saved ? JSON.parse(saved) : [
      { id: 'p1', dayIndex: -1, time: '--:--', title: 'Idea', location: 'TeamLab Planets', category: 'Attraction' as Category },
      { id: 'p2', dayIndex: -1, time: '--:--', title: 'Idea', location: 'Shibuya Sky', category: 'Attraction' as Category },
    ];
  });

  // State to hold bookings for linking
  const [bookings, setBookings] = useState<Booking[]>([]);

  const [selectedDay, setSelectedDay] = useState(0);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<'add' | 'edit'>('add');
  const [editingItem, setEditingItem] = useState<ScheduleItem | null>(null);
  const [addItemTarget, setAddItemTarget] = useState<'schedule' | 'pool'>('schedule');

  // New state for "Move to Day" modal
  const [movingItem, setMovingItem] = useState<ScheduleItem | null>(null);

  const [newMemberName, setNewMemberName] = useState('');
  const [draggedData, setDraggedData] = useState<{ item: ScheduleItem, source: 'pool' | 'schedule' } | null>(null);
  const [dragOverDay, setDragOverDay] = useState<number | null>(null);
  const [isPoolDragOver, setIsPoolDragOver] = useState(false);
  const [swipeId, setSwipeId] = useState<string | null>(null);

  // Ref for file import
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => { localStorage.setItem('tripConfig', JSON.stringify(config)); }, [config]);
  useEffect(() => { localStorage.setItem('itinerary', JSON.stringify(itinerary)); }, [itinerary]);
  useEffect(() => { localStorage.setItem('inspiration_pool', JSON.stringify(pool)); }, [pool]);

  // Load bookings to check for links
  useEffect(() => {
    const savedBookings = localStorage.getItem('bookings');
    if (savedBookings) {
      setBookings(JSON.parse(savedBookings));
    }
  }, [isAddModalOpen, selectedDay]); // Refresh when modals close or day changes just in case

  const countdown = useMemo(() => {
    const start = new Date(config.startDate).getTime();
    const now = new Date().getTime();
    const diff = Math.ceil((start - now) / (1000 * 60 * 60 * 24));
    return diff > 0 ? diff : 0;
  }, [config.startDate]);

  const days = useMemo(() => {
    return Array.from({ length: config.duration }, (_, i) => {
      const d = new Date(config.startDate);
      d.setDate(d.getDate() + i);
      return {
        index: i,
        date: d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
        weekday: d.toLocaleDateString('en-US', { weekday: 'short' })
      };
    });
  }, [config.startDate, config.duration]);

  const currentDayItems = useMemo(() => 
    itinerary.filter(item => item.dayIndex === selectedDay).sort((a, b) => a.time.localeCompare(b.time)),
  [itinerary, selectedDay]);

  // Drag & Drop
  const handleDragStart = (e: React.DragEvent, item: ScheduleItem, source: 'pool' | 'schedule') => {
    setDraggedData({ item, source });
    e.dataTransfer.effectAllowed = 'move';
    if (e.currentTarget instanceof HTMLElement) e.currentTarget.style.opacity = '0.5';
  };
  const handleDragEnd = (e: React.DragEvent) => {
    if (e.currentTarget instanceof HTMLElement) e.currentTarget.style.opacity = '1';
    setDraggedData(null);
    setDragOverDay(null);
    setIsPoolDragOver(false);
  };
  const handleDropOnDayButton = (dayIndex: number) => {
    if (!draggedData) return;
    const { item, source } = draggedData;
    if (source === 'pool') setPool(prev => prev.filter(i => i.id !== item.id));
    else setItinerary(prev => prev.filter(i => i.id !== item.id));
    setItinerary(prev => [...prev, { ...item, dayIndex: dayIndex }]);
    setSelectedDay(dayIndex);
  };
  const handleDropOnPool = () => {
    if (!draggedData) return;
    const { item, source } = draggedData;
    if (source === 'schedule') {
      setItinerary(prev => prev.filter(i => i.id !== item.id));
      setPool(prev => [...prev, { ...item, dayIndex: -1 }]);
    }
  };
  const handleDropOnScheduleList = (targetIndex: number) => {
    if (!draggedData) return;
    const { item, source } = draggedData;
    let newList = [...itinerary];
    if (source === 'schedule') newList = newList.filter(i => i.id !== item.id);
    else setPool(prev => prev.filter(i => i.id !== item.id));
    const currentItems = newList.filter(i => i.dayIndex === selectedDay);
    const newItem = { ...item, dayIndex: selectedDay };
    const otherDaysItems = newList.filter(i => i.dayIndex !== selectedDay);
    if (targetIndex === -1) currentItems.push(newItem);
    else currentItems.splice(targetIndex, 0, newItem);
    setItinerary([...otherDaysItems, ...currentItems]);
  };

  // CRUD & Move
  const deleteItem = (id: string, from: 'pool' | 'schedule') => {
    if (from === 'pool') setPool(pool.filter(i => i.id !== id));
    else setItinerary(itinerary.filter(i => i.id !== id));
    setSwipeId(null);
  };

  const moveItemToDay = (item: ScheduleItem, targetDayIndex: number) => {
    // Remove from current list
    if (item.dayIndex === -1) {
       setPool(pool.filter(i => i.id !== item.id));
    } else {
       setItinerary(itinerary.filter(i => i.id !== item.id));
    }
    // Add to new day
    const updatedItem = { ...item, dayIndex: targetDayIndex };
    setItinerary(prev => [...prev, updatedItem]);
    setMovingItem(null);
    setSelectedDay(targetDayIndex);
  };

  const openAddModal = (target: 'pool' | 'schedule') => {
    setAddItemTarget(target);
    setModalMode('add');
    setEditingItem(null);
    setIsAddModalOpen(true);
  };

  const openEditModal = (item: ScheduleItem, target: 'pool' | 'schedule') => {
    setAddItemTarget(target);
    setModalMode('edit');
    setEditingItem(item);
    setIsAddModalOpen(true);
    setSwipeId(null);
  };

  const handleSaveItem = (itemData: any) => {
    // Check if dayIndex changed during edit (for schedule items)
    const targetDayIndex = itemData.dayIndex !== undefined ? itemData.dayIndex : (addItemTarget === 'schedule' ? selectedDay : -1);

    if (modalMode === 'add') {
      const newItem: ScheduleItem = { 
        ...itemData, 
        id: Date.now().toString(), 
        dayIndex: targetDayIndex
      };
      if (targetDayIndex === -1) setPool([...pool, newItem]);
      else setItinerary([...itinerary, newItem]);
    } else if (editingItem) {
      const updatedItem = { ...editingItem, ...itemData, dayIndex: targetDayIndex };

      // Handle moving between pool and schedule or changing days
      const oldDayIndex = editingItem.dayIndex;

      if (oldDayIndex !== targetDayIndex) {
         // Remove from old location
         if (oldDayIndex === -1) setPool(prev => prev.filter(i => i.id !== editingItem.id));
         else setItinerary(prev => prev.filter(i => i.id !== editingItem.id));

         // Add to new location
         if (targetDayIndex === -1) setPool(prev => [...prev, updatedItem]);
         else setItinerary(prev => [...prev, updatedItem]);
      } else {
         // Just update in place
         if (targetDayIndex === -1) setPool(pool.map(i => i.id === updatedItem.id ? updatedItem : i));
         else setItinerary(itinerary.map(i => i.id === updatedItem.id ? updatedItem : i));
      }
    }
    setIsAddModalOpen(false);
  };

  const handleAddMemberSubmit = () => {
    if (newMemberName.trim()) {
      const randomId = Math.floor(Math.random() * 1000);
      onAddMember(newMemberName.trim(), `https://picsum.photos/seed/${newMemberName}${randomId}/200`);
      setNewMemberName('');
    }
  };

  const handleOpenMaps = (e: React.MouseEvent, location: string) => {
    e.stopPropagation();
    const query = encodeURIComponent(location);
    window.open(`https://www.google.com/maps/search/?api=1&query=${query}`, '_blank');
  };

  // Export Data Logic
  const handleExportData = () => {
    const backupData = {
      tripConfig: localStorage.getItem('tripConfig'),
      itinerary: localStorage.getItem('itinerary'),
      inspiration_pool: localStorage.getItem('inspiration_pool'),
      trip_members: localStorage.getItem('trip_members'),
      bookings: localStorage.getItem('bookings'),
      expenses: localStorage.getItem('expenses'),
      journal_posts: localStorage.getItem('journal_posts'),
      planning_items: localStorage.getItem('planning_items'),
      baseCurrency: localStorage.getItem('baseCurrency'),
      timestamp: new Date().toISOString()
    };

    const blob = new Blob([JSON.stringify(backupData)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `OhanaTrip_Backup_${config.tripName.replace(/\s+/g, '_')}_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  // Import Data Logic
  const handleImportData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    if (window.confirm('⚠️ 警告：匯入行程檔案將會「完全覆蓋」目前所有的行程、記帳與票券資料。\n\n確定要載入備份檔案嗎？')) {
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const rawResult = event.target?.result as string;
          const data = JSON.parse(rawResult);

          // Restore Keys if they exist
          if (data.tripConfig) localStorage.setItem('tripConfig', data.tripConfig);
          if (data.itinerary) localStorage.setItem('itinerary', data.itinerary);
          if (data.inspiration_pool) localStorage.setItem('inspiration_pool', data.inspiration_pool);
          if (data.trip_members) localStorage.setItem('trip_members', data.trip_members);
          if (data.bookings) localStorage.setItem('bookings', data.bookings);
          if (data.expenses) localStorage.setItem('expenses', data.expenses);
          if (data.journal_posts) localStorage.setItem('journal_posts', data.journal_posts);
          if (data.planning_items) localStorage.setItem('planning_items', data.planning_items);
          if (data.baseCurrency) localStorage.setItem('baseCurrency', data.baseCurrency);

          alert('✅ 匯入成功！App 將重新啟動以載入新行程。');
          window.location.reload();
        } catch (error) {
          console.error('Import failed', error);
          alert('❌ 匯入失敗：檔案格式錯誤或損毀。');
        }
      };
      reader.readAsText(file);
    }

    // Reset Input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500">
      {/* Countdown Card */}
      <div className="bg-stitch text-white p-6 rounded-2xl-sticker sticker-shadow flex justify-between items-center relative overflow-hidden border-2 border-white/20">
        <div className="z-10">
          <p className="text-[10px] font-black opacity-70 uppercase tracking-[0.3em] mb-1">Adventure Starts In</p>
          <h2 className="text-4xl font-black drop-shadow-sm">{countdown} Days</h2>
        </div>
        <div className="text-6xl opacity-20 absolute -right-2 -bottom-2 transform rotate-12 z-0">🏝️</div>
      </div>

      {/* Inspiration Pool Area */}
      <div 
        className={`transition-all duration-300 ${isPoolDragOver ? 'scale-[1.02]' : ''}`}
        onDragOver={(e) => { e.preventDefault(); setIsPoolDragOver(true); }}
        onDragLeave={() => setIsPoolDragOver(false)}
        onDrop={(e) => { e.preventDefault(); setIsPoolDragOver(false); handleDropOnPool(); }}
      >
        <div className="flex justify-between items-center px-1 mb-2">
           <h3 className="text-sm font-black text-navy flex items-center gap-2">
             <Sparkles size={16} className="text-donald" />
             Inspiration Pool
           </h3>
           <button 
              onClick={() => openAddModal('pool')}
              className="text-[10px] font-black bg-white px-2 py-1 rounded-full text-navy/40 border border-accent hover:text-stitch active:scale-95"
           >
             + IDEA
           </button>
        </div>

        <div className={`
           min-h-[100px] p-4 rounded-2xl-sticker border-2 border-dashed flex gap-3 overflow-x-auto snap-x scrollbar-hide items-center
           ${isPoolDragOver ? 'bg-stitch/10 border-stitch' : 'bg-white border-accent'}
        `}>
          {pool.length > 0 ? pool.map((item) => (
            <div 
              key={item.id}
              draggable
              onDragStart={(e) => handleDragStart(e, item, 'pool')}
              onDragEnd={handleDragEnd}
              onClick={() => openEditModal(item, 'pool')}
              className="flex-shrink-0 w-40 snap-center cursor-pointer active:cursor-grabbing group"
            >
              <div className="bg-paper p-3 rounded-xl-sticker sticker-shadow border border-accent relative hover:-translate-y-1 transition-transform duration-300 active:scale-105 active:shadow-xl h-full">
                 <div className="flex justify-between items-start mb-2">
                    <span 
                      className="px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-wider text-white"
                      style={{ backgroundColor: COLORS[item.category.toLowerCase() as keyof typeof COLORS] || COLORS.stitch }}
                    >
                      {item.category}
                    </span>
                    <button onClick={(e) => {e.stopPropagation(); deleteItem(item.id, 'pool')}} className="text-navy/10 hover:text-red-400"><X size={12} /></button>
                 </div>
