           >
              <ChevronUp size={14} strokeWidth={3} />
           </button>
           <button 
              onClick={(e) => handleDuplicate(e, booking)}
              className="p-1.5 rounded-full hover:bg-white/20 active:scale-90 transition-all"
              title="Duplicate"
