            {(booking.type === 'Hotel' || booking.type === 'Car') && (
               <>
                 <div className="col-span-2"><p className="text-[9px] font-black text-navy/30 uppercase">Address</p><p className="font-bold text-navy">{booking.details.address}</p></div>
