            {Object.entries(booking.details).map(([key, value]) => {
                const ignoredKeys = [
                    'from', 'to', 'gate', 'seat', 'checkIn', 'checkOut', 'address', 'imageUrl', 
                    'arrivalTime', 'time', 'date', 'airline', 'flightNo', 'class', 'room', 'vehicle'
