    'https://picsum.photos/seed/minnie/200',
    'https://picsum.photos/seed/goofy/200'
  ];

  const handleExportPDF = async () => {
    setIsExporting(true);

    // 從 localStorage 獲取數據
    const itinerary: ScheduleItem[] = JSON.parse(localStorage.getItem('itinerary') || '[]');
    const bookings: Booking[] = JSON.parse(localStorage.getItem('bookings') || '[]');
    const expenses: Expense[] = JSON.parse(localStorage.getItem('expenses') || '[]');
    const journalPosts: JournalPost[] = JSON.parse(localStorage.getItem('journal_posts') || '[]');
    const tripConfig: TripConfig = JSON.parse(localStorage.getItem('tripConfig') || '{}');
    const baseCurrency = localStorage.getItem('baseCurrency') || 'JPY';

    // 建立一個臨時的隱藏元素來渲染 PDF 內容
    const printWindow = document.createElement('div');
    printWindow.style.position = 'fixed';
    printWindow.style.left = '-9999px';
    printWindow.style.top = '0';
    printWindow.style.width = '800px';
    printWindow.style.backgroundColor = '#F8F9F5';
    printWindow.style.fontFamily = 'Quicksand, sans-serif';
    document.body.appendChild(printWindow);

    // 渲染 PDF 模板
    printWindow.innerHTML = `
      <div style="padding: 40px; color: #1F3C88;">
        <!-- 封面 -->
        <div style="text-align: center; margin-bottom: 60px; padding: 40px; background: white; border-radius: 40px; border: 4px solid #6EC1E4;">
          <h1 style="font-size: 48px; margin-bottom: 10px;">${tripConfig.tripName || 'Ohana Trip'}</h1>
          <p style="font-size: 18px; opacity: 0.6; margin-bottom: 30px;">${tripConfig.region} | ${tripConfig.startDate} (${tripConfig.duration} Days)</p>
          <div style="display: flex; justify-content: center; gap: 20px;">
            ${members.map(m => `
              <div style="text-align: center;">
                <img src="${m.avatar}" style="width: 60px; hieght: 60px; border-radius: 50%; border: 3px solid #FFD966;" />
                <p style="font-size: 12px; font-weight: bold; margin-top: 5px;">${m.name}</p>
              </div>
            `).join('')}
          </div>
        </div>

        <!-- 行程 -->
        <div style="margin-bottom: 40px;">
          <h2 style="border-bottom: 4px solid #FFD966; display: inline-block; padding-bottom: 5px; margin-bottom: 20px;">📅 Schedule</h2>
          ${Array.from({length: tripConfig.duration}).map((_, dayIdx) => {
            const dayItems = itinerary.filter(i => i.dayIndex === dayIdx);
            return `
              <div style="margin-bottom: 20px;">
                <h3 style="font-size: 16px; color: #6EC1E4;">Day ${dayIdx + 1}</h3>
                ${dayItems.map(item => `
                  <div style="display: flex; gap: 15px; background: white; padding: 10px; border-radius: 15px; margin-bottom: 10px;">
                    <span style="font-weight: bold; min-width: 50px;">${item.time}</span>
                    <span>${item.location}</span>
                  </div>
                `).join('')}
              </div>
            `;
          }).join('')}
        </div>

        <!-- 財務 -->
        <div style="margin-bottom: 40px;">
          <h2 style="border-bottom: 4px solid #6EC1E4; display: inline-block; padding-bottom: 5px; margin-bottom: 20px;">💰 Expenses Summary</h2>
          <div style="background: white; padding: 20px; border-radius: 20px; border: 2px dashed #E0E5D5;">
            <p style="font-size: 24px; font-weight: 1000;">Total: ${baseCurrency} ${expenses.reduce((acc, e) => acc + e.amount, 0).toLocaleString()}</p>
            <p style="font-size: 12px; opacity: 0.5;">* Based on your recorded transactions</p>
          </div>
        </div>

        <!-- 回憶 -->
        <div>
          <h2 style="border-bottom: 4px solid #6EC1E4; display: inline-block; padding-bottom: 5px; margin-bottom: 20px;">📸 Memory Highlights</h2>
          <div style="display: grid; grid-template-cols: 1fr 1fr; gap: 20px;">
            ${journalPosts.slice(0, 4).map(post => `
              <div style="background: white; padding: 15px; border-radius: 20px;">
                <p style="font-size: 12px; font-style: italic;">"${post.content.substring(0, 100)}..."</p>
                <p style="font-size: 10px; margin-top: 10px; text-align: right;">— ${members.find(m => m.id === post.authorId)?.name}</p>
              </div>
            `).join('')}
          </div>
        </div>

        <div style="text-align: center; margin-top: 100px; opacity: 0.2; font-size: 10px;">
          Ohana means family. Family means nobody gets left behind or forgotten.
        </div>
      </div>
    `;

    try {
      const canvas = await html2canvas(printWindow, { useCORS: true, scale: 2 });
      const imgData = canvas.toDataURL('image/png');
      const pdf = new jsPDF('p', 'mm', 'a4');
      const imgProps = pdf.getImageProperties(imgData);
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;

      pdf.addImage(imgData, 'PNG', 0, 0, pdfWidth, pdfHeight);
      pdf.save(`Ohana_Trip_${tripConfig.tripName || 'Report'}.pdf`);
    } catch (e) {
      console.error("PDF Export failed", e);
      alert("導出失敗，請檢查網路連接後再試一次。");
    } finally {
      document.body.removeChild(printWindow);
      setIsExporting(false);
    }
  };

  const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        const img = new Image();
        img.src = ev.target?.result as string;
        img.onload = () => {
          const canvas = document.createElement('canvas');
          const ctx = canvas.getContext('2d');
          const size = 200; // Resize to 200x200
          canvas.width = size;
          canvas.height = size;

          // Center Crop
          const ratio = Math.max(size / img.width, size / img.height);
          const centerShift_x = (size - img.width * ratio) / 2;
          const centerShift_y = (size - img.height * ratio) / 2;

          ctx?.drawImage(img, 0, 0, img.width, img.height, centerShift_x, centerShift_y, img.width * ratio, img.height * ratio);
          setUploadedAvatar(canvas.toDataURL('image/jpeg', 0.8));
        };
      };
      reader.readAsDataURL(file);
    }
  };

  const openAddModal = () => {
    setEditingMember(null);
    setNewName('');
    setAvatarType('preset');
    setSelectedAvatar('https://picsum.photos/seed/new_member/200');
    setUploadedAvatar('');
    setIsAddModalOpen(true);
  };

  const openEditModal = (member: TripMember) => {
    setEditingMember(member);
    setNewName(member.name);
    // Determine avatar type roughly
    if (member.avatar.startsWith('data:image/svg')) {
      setAvatarType('emoji');
      // Try to extract emoji if possible, or just default
      setEmojiChar('😎'); 
    } else if (member.avatar.startsWith('data:image')) {
      setAvatarType('upload');
      setUploadedAvatar(member.avatar);
    } else {
      setAvatarType('preset');
      setSelectedAvatar(member.avatar);
    }
    setIsAddModalOpen(true);
  };

  const handleSaveSubmit = () => {
    if (newName.trim()) {
      let finalAvatar = selectedAvatar;

      if (avatarType === 'emoji') {
         const svg = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 100 100"><rect width="100" height="100" fill="#f8f9f5" rx="20" ry="20"/><text y=".9em" font-size="80" x="50" text-anchor="middle">${emojiChar}</text></svg>`;
         finalAvatar = `data:image/svg+xml,${encodeURIComponent(svg)}`;
      } else if (avatarType === 'upload' && uploadedAvatar) {
         finalAvatar = uploadedAvatar;
      }

      if (editingMember) {
        onUpdate(editingMember.id, newName.trim(), finalAvatar);
      } else {
        onAdd(newName.trim(), finalAvatar);
      }

      setNewName('');
      setUploadedAvatar('');
      setIsAddModalOpen(false);
      setEditingMember(null);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500 pb-20">
      {/* Current User Profile Section */}
      <div className="text-center py-4 bg-white/40 rounded-3xl-sticker p-6 border border-white/60 sticker-shadow">
        <div className="relative inline-block">
          <div className="w-32 h-32 rounded-full border-4 border-donald sticker-shadow overflow-hidden mb-4 p-1 bg-white">
            <img src={currentUser.avatar} alt={currentUser.name} className="w-full h-full rounded-full object-cover" />
          </div>
          <div className="absolute bottom-4 right-0 w-10 h-10 bg-stitch text-white rounded-full flex items-center justify-center border-4 border-paper sticker-shadow animate-pulse">
            <Sparkles size={18} />
          </div>
        </div>
        <h2 className="text-3xl font-black text-navy">{currentUser.name}</h2>
        <p className="text-[10px] font-black text-navy/30 uppercase tracking-[0.2em] mt-1">Active Trip Planner</p>
      </div>

      {/* Quick Stats Grid */}
      <div className="grid grid-cols-2 gap-4">
         <div className="bg-white p-4 rounded-xl-sticker sticker-shadow border border-accent flex flex-col items-center text-center">
            <div className="w-10 h-10 bg-stitch/10 text-stitch rounded-full flex items-center justify-center mb-2">
               <Award size={20} />
            </div>
            <p className="text-[10px] font-black opacity-40 uppercase tracking-widest">Badges</p>
            <p className="text-sm font-black text-navy">12 Collected</p>
         </div>
         <div className="bg-white p-4 rounded-xl-sticker sticker-shadow border border-accent flex flex-col items-center text-center">
            <div className="w-10 h-10 bg-donald/10 text-donald rounded-full flex items-center justify-center mb-2">
               <Map size={20} />
            </div>
            <p className="text-[10px] font-black opacity-40 uppercase tracking-widest">Visited</p>
            <p className="text-sm font-black text-navy">4 Spots</p>
         </div>
      </div>

      {/* Trip Members Section */}
      <div className="space-y-4">
        <div className="flex justify-between items-center px-1">
          <h3 className="text-sm font-black text-navy uppercase tracking-[0.2em]">Trip Ohana</h3>
          <button 
            onClick={openAddModal}
            className="p-2 bg-stitch/10 text-stitch rounded-full hover:bg-stitch hover:text-white transition-all active:scale-90"
          >
            <UserPlus size={18} />
          </button>
        </div>

        <div className="space-y-3">
          {members.map((member) => (
            <div 
              key={member.id}
              className={`w-full p-4 rounded-xl-sticker sticker-shadow border-2 flex items-center gap-4 transition-all group ${
                currentUser.id === member.id ? 'bg-stitch/5 border-stitch' : 'bg-white border-accent'
              }`}
            >
              <button 
                onClick={() => onSwitch(member)}
                className="flex flex-1 items-center gap-4 text-left"
              >
                <div className={`relative w-12 h-12 rounded-full border-2 overflow-hidden flex-shrink-0 ${currentUser.id === member.id ? 'border-stitch' : 'border-accent'}`}>
                  <img src={member.avatar} alt={member.name} className="w-full h-full object-cover" />
                  {currentUser.id === member.id && (
                    <div className="absolute inset-0 bg-stitch/20 flex items-center justify-center">
                      <Check size={20} className="text-white drop-shadow-md" />
                    </div>
                  )}
                </div>
                <div className="flex-1">
                  <h4 className="font-black text-navy text-sm">{member.name}</h4>
                  <p className="text-[9px] font-bold text-navy/30 uppercase tracking-wider">
                    {currentUser.id === member.id ? 'Currently Controlling' : 'View Stats'}
                  </p>
                </div>
              </button>

              <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                 <button 
                   onClick={() => openEditModal(member)}
                   className="p-2 text-navy/10 hover:text-stitch active:scale-90"
                 >
                   <Edit2 size={16} />
                 </button>
                 {member.id !== currentUser.id && (
                   <button 
                     onClick={() => onDelete(member.id)}
                     className="p-2 text-navy/10 hover:text-red-400 active:scale-90"
                   >
                     <Trash2 size={16} />
                   </button>
                 )}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Export Section */}
      <div className="pt-4 border-t border-accent/40">
        <button 
          onClick={handleExportPDF}
          disabled={isExporting}
          className="w-full py-5 bg-navy text-white font-black rounded-2xl-sticker sticker-shadow flex items-center justify-center gap-3 active:scale-95 transition-all shadow-xl disabled:opacity-50"
        >
          {isExporting ? <Loader2 size={24} className="animate-spin" /> : <FileDown size={24} />}
          <div className="text-left">
            <p className="text-xs uppercase tracking-widest leading-none">Export Ohana Memory</p>
            <p className="text-[9px] font-bold opacity-40 uppercase mt-1">Generate PDF Travel Report</p>
          </div>
        </button>
      </div>

      {/* Add/Edit Member Modal */}
      {isAddModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-navy/20 backdrop-blur-sm animate-in fade-in" onClick={() => setIsAddModalOpen(false)}>
          <div className="bg-paper w-full max-w-sm rounded-3xl-sticker p-6 sticker-shadow border-4 border-stitch animate-in zoom-in-95" onClick={e => e.stopPropagation()}>
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-lg font-black text-navy uppercase tracking-widest">{editingMember ? 'Edit Traveler' : 'New Traveler'}</h3>
              <button onClick={() => setIsAddModalOpen(false)} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
            </div>

            <div className="space-y-6">
              {/* Avatar Preview */}
              <div className="flex flex-col items-center">
                <div className="w-24 h-24 rounded-full border-4 border-stitch overflow-hidden mb-4 p-1 bg-white sticker-shadow flex items-center justify-center">
                   {avatarType === 'emoji' ? (
                      <span className="text-6xl">{emojiChar}</span>
                   ) : (
                      <img src={avatarType === 'upload' && uploadedAvatar ? uploadedAvatar : selectedAvatar} alt="preview" className="w-full h-full rounded-full object-cover" />
                   )}
                </div>

                {/* Avatar Type Selector */}
                <div className="flex gap-2 p-1 bg-cream rounded-xl border border-accent/60 mb-3">
                   <button onClick={() => setAvatarType('preset')} className={`p-2 rounded-lg ${avatarType === 'preset' ? 'bg-white shadow-sm text-navy' : 'text-navy/40'}`}><ImageIcon size={16} /></button>
                   <button onClick={() => setAvatarType('emoji')} className={`p-2 rounded-lg ${avatarType === 'emoji' ? 'bg-white shadow-sm text-navy' : 'text-navy/40'}`}><Smile size={16} /></button>
                   <button onClick={() => setAvatarType('upload')} className={`p-2 rounded-lg ${avatarType === 'upload' ? 'bg-white shadow-sm text-navy' : 'text-navy/40'}`}><Upload size={16} /></button>
                </div>

                {/* Inputs based on type */}
                {avatarType === 'preset' && (
                  <div className="flex gap-2 overflow-x-auto w-full pb-2 scrollbar-hide px-2">
                    {avatarOptions.map((av, idx) => (
                      <button 
                        key={idx} 
                        onClick={() => setSelectedAvatar(av)}
                        className={`flex-shrink-0 w-10 h-10 rounded-full border-2 transition-all ${selectedAvatar === av ? 'border-stitch scale-110' : 'border-transparent opacity-50'}`}
                      >
                        <img src={av} alt="option" className="w-full h-full rounded-full object-cover" />
                      </button>
                    ))}
                  </div>
                )}

                {avatarType === 'emoji' && (
                  <div className="w-full">
                     <input 
                       type="text" 
                       maxLength={2}
                       value={emojiChar} 
                       onChange={e => setEmojiChar(e.target.value)} 
                       className="w-full text-center text-4xl bg-white border-b-2 border-accent focus:border-stitch outline-none py-2"
                     />
                     <p className="text-center text-[10px] uppercase font-bold text-navy/30 mt-1">Type an Emoji</p>
                  </div>
                )}

                {avatarType === 'upload' && (
                  <div 
                    className="w-full h-24 border-2 border-dashed border-accent rounded-xl flex flex-col items-center justify-center cursor-pointer bg-white relative overflow-hidden group hover:border-stitch/50 transition-colors"
                    onClick={() => document.getElementById('member-avatar-upload')?.click()}
                  >
                     {uploadedAvatar ? (
                        <div className="relative w-full h-full group-hover:opacity-50 transition-opacity">
                           <img src={uploadedAvatar} className="w-full h-full object-cover" />
                           <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100">
                             <Camera size={20} className="text-navy" />
                           </div>
                        </div>
                     ) : (
                        <>
                           <Camera size={20} className="text-stitch mb-1" />
                           <span className="text-[10px] font-black text-navy/40 uppercase">Tap to Upload</span>
                        </>
                     )}
                     <input 
                       id="member-avatar-upload"
                       type="file" 
                       accept="image/*"
                       onChange={handleAvatarUpload}
                       className="hidden" 
                     />
                  </div>
                )}
              </div>

              <div className="bg-cream p-4 rounded-2xl border border-accent">
                <label className="text-[10px] font-black uppercase text-navy/30 mb-1 block tracking-widest">Member Name</label>
                <input 
                  autoFocus
                  type="text" 
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  placeholder="e.g. Lilo"
                  className="w-full bg-transparent border-none p-0 font-black text-navy text-lg focus:ring-0 placeholder:text-navy/10"
                />
              </div>

              <button 
                onClick={handleSaveSubmit}
                disabled={!newName.trim()}
                className="w-full py-4 bg-stitch text-white font-black rounded-xl-sticker sticker-shadow active:scale-95 transition-all disabled:opacity-30 disabled:pointer-events-none"
              >
                {editingMember ? 'SAVE CHANGES' : 'JOIN THE OHANA'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Decorative Logout Styled Button */}
      <button className="w-full py-4 text-red-300 font-black flex items-center justify-center gap-2 mt-4 active:scale-95 transition-all text-xs tracking-widest uppercase">
        <LogOut size={16} />
        Leave Trip
      </button>
    </div>
  );
};

export default Members;

export type Category = 'Attraction' | 'Restaurant' | 'Transport' | 'Stay' | 'Shopping' | 'Other';

export interface TripMember {
  id: string;
  name: string;
  avatar: string;
}

export interface ScheduleItem {
  id: string;
  dayIndex: number;
  time: string;
  endTime?: string; // Optional end time for duration calculation
  title: string;
  location: string;
  category: Category;
  notes?: string;
  photo?: string;
  distanceInfo?: string; // e.g. "2.4km, 15 min walk"
}

export interface Booking {
  id: string;
  type: 'Flight' | 'Hotel' | 'Car' | 'Restaurant' | 'Amusement' | 'Ticket';
  title: string;
  referenceNo?: string; // e.g. Booking Reference / PNR
  bookedBy?: string; // Member ID who booked this
  details: any;
  cost: number;
  imageUrl?: string;
  linkedScheduleId?: string; // ID of the related ScheduleItem
}

export interface Expense {
  id: string;
  amount: number;
  currency: string; // Dynamic currency
  category: string; // Used for icon/color logic (Food, Transport, etc.)
  title: string;    // Custom name of the expense (e.g. "7-11 Snacks")
  paidBy: string;   // Member ID
  splitWith: string[]; // Array of Member IDs involved in the cost
  settledBy?: string[]; // New: Array of Member IDs who have paid back their share
  date: string;
}

export interface PlanningItem {
  id: string;
  type: 'Packing' | 'Shopping';
  title: string;
  assignedTo: string; // 'All' or Member ID
  completed: boolean;
}

export interface TripConfig {
  startDate: string;
  duration: number;
  tripName: string;
  region: string;
}

import React, { useState, useEffect } from 'react';
import { 
  Calendar, 
  Ticket, 
  Wallet, 
  Camera, 
  CheckSquare, 
  Users,
  CloudCheck
} from 'lucide-react';
import { MOCK_MEMBERS, MOCK_TRIP_CONFIG } from './constants';
import { TripMember } from './types';
import Schedule from './modules/Schedule';
import Bookings from './modules/Bookings';
import Expense from './modules/Expense';
import Planning from './modules/Planning';
import Members from './modules/Members';

type Tab = 'schedule' | 'bookings' | 'expense' | 'planning' | 'members';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<Tab>('schedule');
  const [highlightId, setHighlightId] = useState<string | null>(null);
  const [lastSync, setLastSync] = useState<string>(new Date().toLocaleTimeString());
  const [members, setMembers] = useState<TripMember[]>(() => {
    const saved = localStorage.getItem('trip_members');
    return saved ? JSON.parse(saved) : MOCK_MEMBERS;
  });
  const [currentUser, setCurrentUser] = useState<TripMember>(() => {
    const savedUser = localStorage.getItem('currentUser');
    if (savedUser) {
      const parsed = JSON.parse(savedUser);
      const exists = members.find(m => m.id === parsed.id);
      return exists || members[0];
    }
    return members[0];
  });
  const [tripConfig, setTripConfig] = useState(MOCK_TRIP_CONFIG);

  useEffect(() => {
    const savedTab = localStorage.getItem('activeTab') as Tab;
    if (savedTab && savedTab !== 'journal' as any) setActiveTab(savedTab); // Fallback if journal was active
  }, []);

  useEffect(() => {
    localStorage.setItem('activeTab', activeTab);
  }, [activeTab]);

  useEffect(() => {
    localStorage.setItem('trip_members', JSON.stringify(members));
    setLastSync(new Date().toLocaleTimeString());
  }, [members]);

  useEffect(() => {
    localStorage.setItem('currentUser', JSON.stringify(currentUser));
  }, [currentUser]);

  const handleSwitchUser = (user: TripMember) => {
    setCurrentUser(user);
  };

  const handleAddMember = (name: string, avatar: string) => {
    const newMember: TripMember = { id: Date.now().toString(), name, avatar };
    setMembers([...members, newMember]);
  };

  const handleUpdateMember = (id: string, name: string, avatar: string) => {
    setMembers(members.map(m => m.id === id ? { ...m, name, avatar } : m));
    // If updating current user, update local state too
    if (currentUser.id === id) {
      setCurrentUser({ ...currentUser, name, avatar });
    }
  };

  const handleDeleteMember = (id: string) => {
    if (id === currentUser.id) {
      alert("Ohana! 你不能刪除目前正在使用的身分。");
      return;
    }
    if (confirm("確定要移除這位成員嗎？這會影響分帳計算。")) {
      setMembers(members.filter(m => m.id !== id));
    }
  };

  const handleNavigate = (tab: Tab, id?: string) => {
    setActiveTab(tab);
    if (id) {
      setHighlightId(id);
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'schedule': return (
        <Schedule 
          config={tripConfig} 
          members={members}
          currentUser={currentUser}
          onAddMember={handleAddMember}
          onDeleteMember={handleDeleteMember}
          onSwitchUser={handleSwitchUser}
          onNavigate={handleNavigate}
        />
      );
      case 'bookings': return (
        <Bookings 
          members={members} 
          currentUser={currentUser} 
          onNavigate={handleNavigate}
          highlightId={highlightId}
        />
      );
      case 'expense': return <Expense currentUser={currentUser} members={members} />;
      case 'planning': return <Planning members={members} />;
      case 'members': return (
        <Members 
          currentUser={currentUser} 
          members={members} 
          onSwitch={handleSwitchUser}
          onAdd={handleAddMember}
          onUpdate={handleUpdateMember}
          onDelete={handleDeleteMember}
        />
      );
      default: return (
        <Schedule 
          config={tripConfig} 
          members={members}
          currentUser={currentUser}
          onAddMember={handleAddMember}
          onDeleteMember={handleDeleteMember}
          onSwitchUser={handleSwitchUser}
          onNavigate={handleNavigate}
        />
      );
    }
  };

  return (
    <div className="flex flex-col h-screen max-w-md mx-auto bg-cream shadow-2xl relative overflow-hidden">
      {/* Top Sync Bar (Aesthetic) */}
      <div className="absolute top-0 left-0 right-0 z-[60] px-4 py-1 flex justify-center items-center gap-1.5 pointer-events-none">
        <div className="bg-navy/10 backdrop-blur-md px-3 py-1 rounded-full flex items-center gap-1">
          <div className="w-1.5 h-1.5 bg-green-400 rounded-full animate-pulse" />
          <span className="text-[8px] font-black text-navy/40 uppercase tracking-widest">
            Ohana Sync: {lastSync}
          </span>
        </div>
      </div>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto pb-24 px-4 pt-10">
        {renderContent()}
      </main>

      {/* Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-paper/90 backdrop-blur-lg border-t border-accent px-2 py-3 flex justify-around items-center z-50 rounded-t-3xl shadow-[0_-4px_10px_rgba(0,0,0,0.05)] safe-bottom">
        <NavButton active={activeTab === 'schedule'} onClick={() => handleNavigate('schedule')} icon={<Calendar size={22} />} label="行程" />
        <NavButton active={activeTab === 'bookings'} onClick={() => handleNavigate('bookings')} icon={<Ticket size={22} />} label="票券" />
        <NavButton active={activeTab === 'expense'} onClick={() => handleNavigate('expense')} icon={<Wallet size={22} />} label="記帳" />
        <NavButton active={activeTab === 'planning'} onClick={() => handleNavigate('planning')} icon={<CheckSquare size={22} />} label="清單" />
        <NavButton active={activeTab === 'members'} onClick={() => handleNavigate('members')} icon={<Users size={22} />} label="成員" />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`flex flex-col items-center gap-1 transition-all duration-300 ${active ? 'text-stitch scale-110' : 'text-navy/30'}`}
  >
    <div className={`p-1.5 rounded-xl transition-colors ${active ? 'bg-stitch/10' : 'bg-transparent'}`}>
      {icon}
    </div>
    <span className={`text-[10px] font-bold uppercase tracking-tighter ${active ? 'opacity-100' : 'opacity-60'}`}>{label}</span>
  </button>
);

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { TripMember, Expense as ExpenseType } from '../types';
import { 
  Plus, 
  Trash2, 
  Edit2, 
  X, 
  Check, 
  Calculator, 
  RefreshCw, 
  Settings2, 
  TrendingUp, 
  TrendingDown, 
  ArrowRight,
  Wallet,
  ChevronDown,
  Coins,
  Calendar,
  Tag,
  PieChart,
  CheckCircle2,
  Users
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { COLORS } from '../constants';

const Expense: React.FC<{ currentUser: TripMember; members: TripMember[] }> = ({ currentUser, members }) => {
  // --- Data States ---
  const [expenses, setExpenses] = useState<ExpenseType[]>(() => {
    const saved = localStorage.getItem('expenses');
    const parsed = saved ? JSON.parse(saved) : [];
    // Migration: ensure settledBy array exists if coming from old data
    return parsed.map((e: any) => ({
      ...e,
      settledBy: e.settledBy || (e.isSettled ? e.splitWith : []) // if old binary 'isSettled' was true, mark everyone as settled
    }));
  });

  // --- Currency System States ---
  const [activeCurrencies, setActiveCurrencies] = useState<string[]>(() => {
    const saved = localStorage.getItem('activeCurrencies');
    return saved ? JSON.parse(saved) : ['JPY', 'HKD', 'AUD'];
  });

  const [rates, setRates] = useState<Record<string, number>>(() => {
    const saved = localStorage.getItem('exchangeRates');
    return saved ? JSON.parse(saved) : { JPY: 1, HKD: 19.2, AUD: 96.5, USD: 150.0, EUR: 162.0, TWD: 4.7 };
  });

  const [displayCurrency, setDisplayCurrency] = useState<string>(() => {
    return localStorage.getItem('displayCurrency') || 'HKD';
  });

  // --- UI States ---
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isSettlementOpen, setIsSettlementOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<ExpenseType | null>(null);
  const [loadingRates, setLoadingRates] = useState(false);

  const AVAILABLE_CURRENCIES = ['JPY', 'HKD', 'AUD', 'USD', 'EUR', 'GBP', 'TWD', 'KRW', 'SGD', 'CNY', 'THB'];

  // --- Effects ---
  useEffect(() => { localStorage.setItem('expenses', JSON.stringify(expenses)); }, [expenses]);
  useEffect(() => { localStorage.setItem('activeCurrencies', JSON.stringify(activeCurrencies)); }, [activeCurrencies]);
  useEffect(() => { localStorage.setItem('exchangeRates', JSON.stringify(rates)); }, [rates]);
  useEffect(() => { localStorage.setItem('displayCurrency', displayCurrency); }, [displayCurrency]);

  // --- Helpers ---
  const convert = (amount: number, from: string, to: string) => {
    const rateFrom = rates[from] || 1;
    const rateTo = rates[to] || 1;
    const amountInJPY = amount * rateFrom;
    return amountInJPY / rateTo;
  };

  const formatMoney = (amount: number, currency: string) => {
    return `${currency} ${amount.toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 1 })}`;
  };

  const getCategoryColor = (cat: string) => {
    const map: Record<string, string> = {
      'Food': COLORS.restaurant,
      'Restaurant': COLORS.restaurant,
      'Transport': COLORS.transport,
      'Stay': COLORS.stay,
      'Shopping': COLORS.shopping,
      'Attraction': COLORS.attraction,
      'Ticket': COLORS.attraction,
      'Other': COLORS.other
    };
    return map[cat] || COLORS.other;
  };

  // Toggle settled status for a specific member
  const toggleMemberSettled = (e: React.MouseEvent, expenseId: string, memberId: string) => {
    e.stopPropagation();
    setExpenses(prev => prev.map(exp => {
      if (exp.id === expenseId) {
        const currentSettled = exp.settledBy || [];
        const isSettled = currentSettled.includes(memberId);
        return {
          ...exp,
          settledBy: isSettled 
            ? currentSettled.filter(id => id !== memberId) 
            : [...currentSettled, memberId]
        };
      }
      return exp;
    }));
  };

  // --- Smart Settlement Logic ---
  const balances = useMemo(() => {
    const bal: Record<string, number> = {};
    members.forEach(m => bal[m.id] = 0);

    expenses.forEach(exp => {
      // 1. Normalize everything to JPY (Pivot)
      const amountInJPY = exp.amount * (rates[exp.currency] || 1);

      // 2. Calculate Debtor share per person
      const splitCount = exp.splitWith.length || 1;
      const shareInJPY = amountInJPY / splitCount;

      // 3. Process each splitter
      exp.splitWith.forEach(debtorId => {
        const isSelf = debtorId === exp.paidBy;

        // Skip if this specific debtor has settled ("找左數")
        // Or if it's the payer themselves (no debt to self)
        if (exp.settledBy?.includes(debtorId)) {
          return; 
        }

        if (!isSelf) {
          // Debtor owes share
          if (bal[debtorId] !== undefined) bal[debtorId] -= shareInJPY;
          // Payer receives credit ONLY for the unsettled parts
          if (bal[exp.paidBy] !== undefined) bal[exp.paidBy] += shareInJPY;
        }
      });
    });
    return bal;
  }, [expenses, rates, members]);

  // Total spent (Includes everything regardless of settlement, just for stats)
  const totalSpentDisplay = useMemo(() => {
    const totalJPY = expenses.reduce((sum, exp) => sum + (exp.amount * (rates[exp.currency] || 1)), 0);
    return convert(totalJPY, 'JPY', displayCurrency);
  }, [expenses, rates, displayCurrency]);

  // Category Breakdown Logic
  const categoryStats = useMemo(() => {
    const stats: Record<string, number> = {};
    let total = 0;

    expenses.forEach(exp => {
      const val = convert(exp.amount, exp.currency, displayCurrency);
      const cat = exp.category || 'Other';
      stats[cat] = (stats[cat] || 0) + val;
      total += val;
    });

    return Object.entries(stats)
      .map(([name, value]) => ({ 
        name, 
        value, 
        percent: total > 0 ? (value / total) * 100 : 0 
      }))
      .sort((a, b) => b.value - a.value);
  }, [expenses, rates, displayCurrency]);

  const fetchRates = async () => {
    if (!process.env.API_KEY) {
      alert("Missing API Key");
      return;
    }
    setLoadingRates(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const currenciesToFetch = activeCurrencies.filter(c => c !== 'JPY').join(', ');

      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Get real-time exchange rates for 1 unit of [${currenciesToFetch}] to JPY. Return valid JSON only, like {"HKD": 19.5, "USD": 150.2}.`,
        config: { responseMimeType: "application/json" }
      });

      const jsonText = response.text || "{}";
      const newRatesData = JSON.parse(jsonText);

      setRates(prev => ({ ...prev, ...newRatesData, JPY: 1 }));
      alert("匯率已更新！ (Rates updated)");
    } catch (e) {
      console.error(e);
      alert("匯率更新失敗 (Failed to update rates).");
    } finally {
      setLoadingRates(false);
    }
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500 relative min-h-screen">

      {/* --- DASHBOARD --- */}
      <div className="bg-white/90 backdrop-blur-md p-6 rounded-3xl-sticker sticker-shadow border border-stitch/20 relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-donald/10 rounded-full blur-3xl pointer-events-none" />

        <div className="relative z-10">
           <div className="flex justify-between items-center mb-2">
              <p className="text-[10px] font-black uppercase tracking-[0.2em] text-navy/30">Total Trip Spending</p>
              <button 
                onClick={() => setIsSettingsOpen(true)}
                className="flex items-center gap-1 px-2 py-1 bg-cream rounded-lg text-[9px] font-black text-navy/40 hover:text-stitch transition-colors"
              >
                 <Settings2 size={12} /> Manage
              </button>
           </div>

           <div className="flex items-baseline gap-2 mb-6">
              <button 
                onClick={() => setIsSettingsOpen(true)}
                className="text-2xl font-black text-stitch/80 hover:bg-stitch/10 px-2 rounded-lg transition-colors flex items-center gap-1"
              >
                 {displayCurrency} <ChevronDown size={16} />
              </button>
              <h1 className="text-5xl font-black text-navy tracking-tight">
                 {Math.round(totalSpentDisplay).toLocaleString()}
              </h1>
           </div>

           <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={() => { setEditingExpense(null); setIsModalOpen(true); }}
                className="bg-stitch text-white py-3.5 rounded-2xl-sticker font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 sticker-shadow active:scale-95 transition-all shadow-lg shadow-stitch/20"
              >
                 <Plus size={16} /> Record
              </button>
              <button 
                onClick={() => setIsSettlementOpen(true)}
                className="bg-white text-navy border border-accent py-3.5 rounded-2xl-sticker font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 sticker-shadow active:scale-95 transition-all"
              >
                 <Wallet size={16} /> Quick Settle
              </button>
           </div>
        </div>
      </div>

      {/* --- CATEGORY BREAKDOWN --- */}
      <div className="bg-white p-5 rounded-2xl-sticker sticker-shadow border border-accent/40 relative overflow-hidden">
        <div className="flex justify-between items-center mb-4">
           <h3 className="text-[10px] font-black text-navy/30 uppercase tracking-[0.2em] flex items-center gap-1">
             <PieChart size={12} /> Breakdown
           </h3>
           <span className="text-[9px] font-bold text-navy/20">in {displayCurrency}</span>
        </div>

        <div className="space-y-4">
          {categoryStats.length > 0 ? categoryStats.map((stat, idx) => (
            <div key={stat.name} className="relative group">
              <div className="flex justify-between items-end mb-1.5 z-10 relative">
                 <div className="flex items-center gap-2">
                    <span 
                       className="w-2 h-2 rounded-full" 
                       style={{ backgroundColor: getCategoryColor(stat.name) }}
                    />
                    <span className="text-xs font-black text-navy">{stat.name}</span>
                 </div>
                 <div className="text-right flex items-baseline gap-2">
                   <span className="text-[10px] font-bold text-navy/40">{Math.round(stat.value).toLocaleString()}</span>
                   <span className="text-xs font-black text-navy">{Math.round(stat.percent)}%</span>
                 </div>
              </div>

              <div className="w-full h-2.5 bg-cream rounded-full overflow-hidden">
                 <div 
                   className="h-full rounded-full transition-all duration-1000 ease-out"
                   style={{ 
                     width: `${stat.percent}%`,
                     backgroundColor: getCategoryColor(stat.name) 
                   }}
                 />
              </div>
            </div>
          )) : (
            <div className="py-4 text-center opacity-30 text-[10px] font-bold text-navy uppercase tracking-widest">
               No spending data yet
            </div>
          )}
        </div>
      </div>

      {/* --- EXPENSE LIST --- */}
      <div className="space-y-4 pt-2">
         <h3 className="text-[11px] font-black text-navy/20 uppercase tracking-[0.3em] flex items-center gap-2 px-1">
            Activity Log
         </h3>

         {expenses.length > 0 ? (
           <div className="space-y-3">
             {expenses.map((exp) => {
               const payer = members.find(m => m.id === exp.paidBy);
               const isExpanded = expandedId === exp.id;
               const displayName = exp.title || exp.category;

               // Determine full settled status
               const allSettled = exp.splitWith.length > 0 && exp.splitWith.every(id => exp.settledBy?.includes(id));
               const partiallySettled = exp.settledBy && exp.settledBy.length > 0 && !allSettled;

               return (
                 <div 
                   key={exp.id}
                   onClick={() => setExpandedId(isExpanded ? null : exp.id)}
                   className={`
                      relative rounded-2xl-sticker border transition-all duration-300 overflow-hidden cursor-pointer 
                      ${isExpanded ? 'bg-white border-stitch shadow-lg scale-[1.01] z-10' : 'bg-white border-accent/40 sticker-shadow hover:border-stitch/30'}
                      ${allSettled ? 'opacity-70 bg-gray-50/50' : ''}
                   `}
                 >
                    {/* Collapsed View */}
                    <div className="p-4 flex items-center gap-4 relative">
                       {/* Fully Settled Badge */}
                       {allSettled && (
                          <div className="absolute top-2 right-2 flex items-center gap-1 px-2 py-0.5 bg-green-100 text-green-700 rounded-full border border-green-200 z-20">
                             <Check size={8} strokeWidth={4} />
                             <span className="text-[8px] font-black uppercase tracking-wider">All Settled</span>
                          </div>
                       )}

                       {/* Partially Settled Badge */}
                       {partiallySettled && (
                          <div className="absolute top-2 right-2 flex items-center gap-1 px-2 py-0.5 bg-orange-100 text-orange-600 rounded-full border border-orange-200 z-20">
                             <CheckCircle2 size={8} strokeWidth={4} />
                             <span className="text-[8px] font-black uppercase tracking-wider">Partial</span>
                          </div>
                       )}

                       {/* Icon */}
                       <div className={`w-10 h-10 rounded-full flex items-center justify-center text-lg shadow-inner flex-shrink-0 ${allSettled ? 'grayscale opacity-50 bg-gray-100' : 'bg-cream'}`} style={{ color: allSettled ? '#999' : getCategoryColor(exp.category) }}>
                          {exp.category === 'Food' || exp.category === 'Restaurant' ? '🍜' : 
                           exp.category === 'Transport' ? '🚕' : 
                           exp.category === 'Shopping' ? '🛍️' : 
                           exp.category === 'Stay' ? '🏨' : 
                           exp.category === 'Attraction' || exp.category === 'Ticket' ? '🎫' : '💸'}
                       </div>

                       {/* Main Details */}
                       <div className="flex-1 min-w-0">
                          <h4 className={`font-black text-sm truncate ${allSettled ? 'text-navy/50 line-through' : 'text-navy'}`}>{displayName}</h4>
                          <div className="flex items-center gap-2 mt-0.5">
                             <img src={payer?.avatar} className={`w-4 h-4 rounded-full border border-white ${allSettled ? 'grayscale' : ''}`} />
                             <span className="text-[10px] font-bold text-navy/40 uppercase">{payer?.name} Paid</span>
                          </div>
                       </div>

                       {/* Amount */}
                       <div className="text-right">
                          <p className={`font-black text-sm ${allSettled ? 'text-navy/40' : 'text-navy'}`}>{formatMoney(exp.amount, exp.currency)}</p>
                          <p className="text-[9px] font-bold text-navy/20">
                             ≈ {displayCurrency} {Math.round(convert(exp.amount, exp.currency, displayCurrency)).toLocaleString()}
                          </p>
                       </div>
                    </div>

                    {/* Expanded View: Settlement Toggles */}
                    <div className={`bg-stitch/5 border-t border-stitch/10 overflow-hidden transition-[max-height, padding] duration-300 ease-in-out ${isExpanded ? 'max-h-80' : 'max-h-0'}`}>
                       <div className="p-4 flex flex-col gap-3">

                          {/* Splitter Settlement List */}
                          <div className="bg-white rounded-xl border border-accent/40 p-3">
                             <p className="text-[9px] font-bold text-navy/30 uppercase tracking-wider mb-2 flex items-center gap-1">
                               <Users size={10} /> Split Status (Tap to toggle settled)
                             </p>
                             <div className="space-y-2">
                               {exp.splitWith.map(uid => {
                                  const m = members.find(mem => mem.id === uid);
                                  const isMemberSettled = exp.settledBy?.includes(uid);
                                  const isPayer = uid === exp.paidBy;

                                  return (
                                     <button 
                                        key={uid}
                                        onClick={(e) => toggleMemberSettled(e, exp.id, uid)}
                                        className={`w-full flex items-center justify-between p-2 rounded-lg border transition-all ${
                                           isMemberSettled 
                                           ? 'bg-green-50 border-green-200 opacity-60' 
                                           : isPayer 
                                              ? 'bg-cream border-transparent cursor-default'
                                              : 'bg-white border-accent hover:border-stitch'
                                        }`}
                                        disabled={isPayer} // Payer doesn't need to "settle" with themselves
                                     >
                                        <div className="flex items-center gap-2">
                                           <img src={m?.avatar} className={`w-6 h-6 rounded-full border ${isMemberSettled ? 'grayscale' : 'border-white'}`} />
                                           <span className={`text-[10px] font-black uppercase ${isMemberSettled ? 'text-green-600 line-through' : 'text-navy'}`}>
                                              {m?.name} {isPayer && '(Payer)'}
                                           </span>
                                        </div>
                                        {/* Status Icon */}
                                        {!isPayer && (
                                           <div className={`w-5 h-5 rounded-full flex items-center justify-center border ${isMemberSettled ? 'bg-green-500 border-green-500 text-white' : 'border-accent'}`}>
                                              {isMemberSettled && <Check size={12} strokeWidth={3} />}
                                           </div>
                                        )}
                                     </button>
                                  );
                               })}
                             </div>
                          </div>

                          <div className="flex justify-end gap-2 pt-2 border-t border-navy/5">
                             <button 
                               onClick={(e) => { e.stopPropagation(); setEditingExpense(exp); setIsModalOpen(true); }}
                               className="p-2 bg-white text-stitch rounded-xl shadow-sm border border-stitch/20 hover:bg-stitch hover:text-white transition-colors flex items-center gap-1 text-[10px] font-black px-3"
                             >
                                <Edit2 size={12} /> EDIT
                             </button>
                             <button 
                               onClick={(e) => { e.stopPropagation(); setExpenses(expenses.filter(e => e.id !== exp.id)); }}
                               className="p-2 bg-white text-red-400 rounded-xl shadow-sm border border-red-100 hover:bg-red-400 hover:text-white transition-colors flex items-center gap-1 text-[10px] font-black px-3"
                             >
                                <Trash2 size={12} /> DELETE
                             </button>
                          </div>
                       </div>
                    </div>
                 </div>
               );
             })}
           </div>
         ) : (
            <div className="py-24 text-center opacity-20 border-2 border-dashed border-accent rounded-3xl bg-paper/50">
               <Wallet size={48} className="mx-auto mb-3" />
               <p className="font-black uppercase text-[10px] tracking-widest">No expenses yet</p>
            </div>
         )}
      </div>

      {/* --- CURRENCY SETTINGS DRAWER --- */}
      {isSettingsOpen && (
        <div className="fixed inset-0 z-[100] flex items-end justify-center bg-navy/20 backdrop-blur-sm" onClick={() => setIsSettingsOpen(false)}>
           <div className="bg-white w-full max-w-md rounded-t-3xl p-6 pb-10 sticker-shadow animate-in slide-in-from-bottom duration-300" onClick={e => e.stopPropagation()}>
              <div className="w-12 h-1 bg-accent rounded-full mx-auto mb-6 opacity-50" />

              <div className="flex justify-between items-center mb-6">
                 <h3 className="text-lg font-black text-navy uppercase tracking-widest">Currency & Rates</h3>
                 <button onClick={() => setIsSettingsOpen(false)} className="p-2 bg-cream rounded-full text-navy/40"><X size={20} /></button>
              </div>

              <div className="mb-6">
                 <label className="text-[10px] font-black uppercase text-navy/30 mb-2 block tracking-widest">Display Currency</label>
                 <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
                    {activeCurrencies.map(cur => (
                       <button 
                         key={cur}
                         onClick={() => setDisplayCurrency(cur)}
                         className={`flex-shrink-0 px-4 py-2 rounded-xl border-2 font-black text-xs transition-all ${displayCurrency === cur ? 'bg-navy border-navy text-white shadow-md' : 'bg-white border-accent text-navy/40'}`}
                       >
                         {cur}
                       </button>
                    ))}
                 </div>
              </div>

              <div className="mb-6">
                 <label className="text-[10px] font-black uppercase text-navy/30 mb-2 block tracking-widest">Active Currencies</label>
                 <div className="flex flex-wrap gap-2">
                    {AVAILABLE_CURRENCIES.map(cur => {
                       const isActive = activeCurrencies.includes(cur);
                       return (
                          <button 
                             key={cur}
                             onClick={() => setActiveCurrencies(prev => isActive ? prev.filter(c => c !== cur) : [...prev, cur])}
                             className={`px-3 py-1.5 rounded-lg text-[10px] font-bold border transition-all ${isActive ? 'bg-stitch/10 border-stitch text-stitch' : 'bg-cream border-transparent text-navy/20'}`}
                          >
                             {cur}
                          </button>
                       );
                    })}
                 </div>
              </div>

              <button 
                 onClick={fetchRates}
                 disabled={loadingRates}
                 className="w-full py-4 bg-navy text-white font-black rounded-2xl-sticker uppercase text-xs tracking-widest flex items-center justify-center gap-2 active:scale-95 transition-all"
              >
                 <RefreshCw size={16} className={loadingRates ? 'animate-spin' : ''} />
                 {loadingRates ? 'Syncing...' : 'Update Rates'}
              </button>
           </div>
        </div>
      )}

      {/* --- ADD/EDIT EXPENSE MODAL --- */}
      {isModalOpen && (
        <ExpenseModal 
          expense={editingExpense} 
          members={members} 
          currencies={activeCurrencies}
          onClose={() => setIsModalOpen(false)} 
          onSave={(e) => {
            if (editingExpense) setExpenses(expenses.map(ex => ex.id === e.id ? e : ex));
            else setExpenses([{ ...e, id: Date.now().toString() }, ...expenses]);
            setIsModalOpen(false);
          }} 
        />
      )}

      {/* --- SETTLEMENT MODAL --- */}
      {isSettlementOpen && (
         <SettlementModal 
            balances={balances} 
            displayCurrency={displayCurrency} 
            convert={convert} 
            members={members}
            onClose={() => setIsSettlementOpen(false)} 
         />
      )}
    </div>
  );
};

