                               className="w-12 h-12 text-center text-2xl bg-white border border-accent rounded-xl focus:ring-2 focus:ring-donald outline-none" 
                             />
                             <p className="text-[10px] text-navy/40 font-bold">Pick an emoji avatar!</p>
