                             {currentUser.id !== member.id && <button onClick={() => onDeleteMember(member.id)} className="p-2 text-navy/20 hover:text-red-400 active:scale-90"><Trash2 size={16} /></button>}
                          </div>
                       </div>
                    ))}
                 </div>

                 {/* Add/Edit Member Input Area */}
                 <div className={`bg-cream p-4 rounded-xl border transition-all ${editingMemberId ? 'border-stitch ring-1 ring-stitch shadow-md' : 'border-accent/60'}`}>
                    <div className="flex justify-between items-center mb-2">
                       <p className="text-[10px] font-black uppercase text-navy/30 tracking-widest">{editingMemberId ? 'Edit Member' : 'Add New Member'}</p>
                       {editingMemberId && (
                          <button onClick={cancelEditingMember} className="flex items-center gap-1 text-[9px] font-bold text-red-400 uppercase">
                             <RotateCcw size={10} /> Cancel
                          </button>
                       )}
                    </div>

                    <div className="space-y-3">
                       <input 
                          type="text" 
                          value={newMemberName} 
                          onChange={e => setNewMemberName(e.target.value)} 
                          placeholder="Name" 
                          className="w-full p-3 bg-white border border-accent rounded-xl text-sm font-bold focus:ring-2 focus:ring-stitch outline-none" 
                       />

                       {/* Avatar Type Selector */}
                       <div className="flex gap-1 p-1 bg-white rounded-lg border border-accent/40">
                          <button 
                            onClick={() => setNewMemberAvatarType('emoji')}
                            className={`flex-1 py-1.5 rounded-md text-[10px] font-black uppercase flex items-center justify-center gap-1 transition-all ${newMemberAvatarType === 'emoji' ? 'bg-donald text-navy shadow-sm' : 'text-navy/30'}`}
                          >
                            <Smile size={12} /> Emoji
                          </button>
                          <button 
                            onClick={() => setNewMemberAvatarType('upload')}
                            className={`flex-1 py-1.5 rounded-md text-[10px] font-black uppercase flex items-center justify-center gap-1 transition-all ${newMemberAvatarType === 'upload' ? 'bg-stitch text-white shadow-sm' : 'text-navy/30'}`}
                          >
                            <Upload size={12} /> Upload
                          </button>
                          <button 
                            onClick={() => setNewMemberAvatarType('random')}
                            className={`flex-1 py-1.5 rounded-md text-[10px] font-black uppercase flex items-center justify-center gap-1 transition-all ${newMemberAvatarType === 'random' ? 'bg-white border text-navy shadow-sm' : 'text-navy/30'}`}
                          >
                            <ImageIcon size={12} /> Random
                          </button>
                       </div>

                       {/* Conditional Input */}
                       {newMemberAvatarType === 'emoji' && (
                          <div className="flex items-center gap-2">
                             <input 
                               type="text" 
                               maxLength={2}
                               value={newMemberEmoji} 
                               onChange={e => setNewMemberEmoji(e.target.value)} 
                               className="w-12 h-12 text-center text-2xl bg-white border border-accent rounded-xl focus:ring-2 focus:ring-donald outline-none" 
                             />
                             <p className="text-[10px] text-navy/40 font-bold">Pick an emoji avatar!</p>
                          </div>
                       )}

                       {newMemberAvatarType === 'upload' && (
                          <div 
                            className="w-full h-24 border-2 border-dashed border-accent rounded-xl flex flex-col items-center justify-center cursor-pointer bg-white relative overflow-hidden group hover:border-stitch/50 transition-colors"
                            onClick={() => document.getElementById('setting-avatar-upload')?.click()}
                          >
                             {uploadedAvatar ? (
                                <div className="relative w-full h-full group-hover:opacity-90 transition-opacity">
                                   <img src={uploadedAvatar} className="w-full h-full object-cover" />
                                   <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity bg-black/20">
                                      <Camera size={20} className="text-white drop-shadow-md" />
                                   </div>
                                   {/* DELETE AVATAR BUTTON */}
                                   <button 
                                      onClick={(e) => { 
                                        e.stopPropagation(); 
                                        setUploadedAvatar(''); 
                                      }}
                                      className="absolute top-2 right-2 p-1.5 bg-red-500 text-white rounded-full shadow-lg hover:bg-red-600 active:scale-95 transition-all z-10"
                                      title="Remove Avatar"
                                   >
                                      <X size={12} strokeWidth={3} />
                                   </button>
                                </div>
                             ) : (
                                <>
                                   <Camera size={20} className="text-stitch mb-1" />
                                   <span className="text-[10px] font-black text-navy/40 uppercase">Tap to Upload</span>
                                </>
                             )}
                             <input 
                               id="setting-avatar-upload"
                               type="file" 
                               accept="image/*"
                               onChange={handleAvatarUpload}
                               className="hidden" 
                             />
                          </div>
                       )}

                       {newMemberAvatarType === 'random' && (
                          <p className="text-[10px] text-navy/40 font-bold px-1">A random cute photo will be assigned.</p>
                       )}

                       <button onClick={handleMemberSubmit} disabled={!newMemberName.trim()} className="w-full py-3 bg-navy text-white rounded-xl font-black flex items-center justify-center gap-2 disabled:opacity-50 mt-2 hover:bg-navy/90 active:scale-95 transition-all">
                          {editingMemberId ? <><Check size={16} /> Save Changes</> : <><Plus size={16} /> Add Member</>}
                       </button>
                    </div>
                 </div>
               </div>

               {/* Data Backup & Restore Section */}
               <div className="space-y-4 pt-4 border-t border-accent/40">
                 <h4 className="text-[10px] font-black uppercase text-navy/40 tracking-[0.2em] flex items-center gap-2">
                   <FileJson size={12} /> Data Backup
                 </h4>
                 <div className="grid grid-cols-2 gap-3">
                   {/* Export Button */}
                   <button 
                      onClick={handleExportData}
                      className="flex flex-col items-center justify-center gap-2 p-4 bg-navy/5 border-2 border-navy/10 rounded-2xl hover:bg-stitch/10 hover:border-stitch/30 transition-colors active:scale-95"
                   >
                      <div className="p-2 bg-white rounded-full text-navy shadow-sm">
                        <Download size={18} />
                      </div>
                      <span className="text-[10px] font-black uppercase tracking-wider text-navy">Export Trip</span>
                   </button>

                   {/* Import Button */}
                   <button 
                      onClick={() => fileInputRef.current?.click()}
                      className="flex flex-col items-center justify-center gap-2 p-4 bg-donald/10 border-2 border-donald/20 rounded-2xl hover:bg-donald/20 hover:border-donald/40 transition-colors active:scale-95"
                   >
                      <div className="p-2 bg-white rounded-full text-navy shadow-sm">
                        <Upload size={18} />
                      </div>
                      <span className="text-[10px] font-black uppercase tracking-wider text-navy">Import Trip</span>
                      <input 
                        type="file" 
                        ref={fileInputRef} 
                        onChange={handleImportData} 
                        accept=".json"
                        className="hidden" 
                      />
                   </button>
                 </div>
                 <p className="text-[9px] text-navy/30 text-center px-4 leading-tight">
                   Backup your itinerary to share with friends or restore on another device.
                 </p>
               </div>
            </div>
          </div>
        </div>
      )}

      {isAddModalOpen && (
        <AddItemModal 
          target={addItemTarget} 
          mode={modalMode}
          initialData={editingItem} 
          duration={config.duration}
          startDate={config.startDate}
          onClose={() => setIsAddModalOpen(false)} 
          onSave={handleSaveItem} 
        />
      )}
    </div>
  );
};

// Simplified Add/Edit Modal
const AddItemModal: React.FC<{ 
  target: 'schedule' | 'pool'; 
  mode: 'add' | 'edit';
  initialData: ScheduleItem | null; 
  duration: number;
  startDate: string;
  onClose: () => void; 
  onSave: (item: any) => void 
}> = ({ target, mode, initialData, duration, startDate, onClose, onSave }) => {
  const [formData, setFormData] = useState({
    dayIndex: initialData?.dayIndex !== undefined ? initialData.dayIndex : (target === 'pool' ? -1 : 0),
    time: initialData?.time || '10:00', 
    endTime: initialData?.endTime || '',
    title: initialData?.title || '', 
    location: initialData?.location || '', 
    category: initialData?.category || 'Attraction', 
    notes: initialData?.notes || '',
  });

  const [showDetails, setShowDetails] = useState(target === 'schedule' || mode === 'edit'); 

  const categories: Category[] = ['Attraction', 'Restaurant', 'Transport', 'Stay', 'Shopping', 'Other'];

  const daysOptions = Array.from({ length: duration }, (_, i) => {
    const d = new Date(startDate);
    d.setDate(d.getDate() + i);
    return {
       index: i,
       label: `Day ${i + 1} - ${d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`
    };
  });

  return (
    <div className="fixed inset-0 z-[70] flex flex-col bg-cream animate-in slide-in-from-bottom duration-300">
      <div className="p-4 flex justify-between items-center border-b border-accent bg-paper">
        <button onClick={onClose} className="text-navy/40 p-2"><X size={24} /></button>
        <h3 className="text-lg font-black text-navy uppercase tracking-widest">
           {mode === 'add' ? (target === 'pool' ? 'New Idea' : 'Add Stop') : 'Edit Item'}
        </h3>
        <button onClick={() => onSave(formData)} className="text-stitch font-black p-2" disabled={!formData.location}>DONE</button>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        {/* Main Input - Location */}
        <div className="bg-paper p-6 rounded-3xl-sticker border border-accent sticker-shadow">
          <label className="text-[10px] font-black uppercase text-navy/30 mb-2 block tracking-widest">Where to?</label>
          <div className="flex items-center gap-3">
            <MapPin size={28} className="text-stitch flex-shrink-0" />
            <input 
              autoFocus 
              type="text" 
              value={formData.location} 
              onChange={e => setFormData({...formData, location: e.target.value})} 
              placeholder="e.g. Tokyo Tower" 
              className="w-full text-2xl font-black bg-transparent border-none p-0 focus:ring-0 placeholder:text-navy/10" 
            />
          </div>
          <div className="mt-4 pt-4 border-t border-accent/20">
             <label className="text-[10px] font-black uppercase text-navy/30 mb-2 block tracking-widest">Title (Optional)</label>
             <input 
               type="text" 
               value={formData.title} 
               onChange={e => setFormData({...formData, title: e.target.value})} 
               placeholder="Activity Name (e.g. Shopping Spree)" 
               className="w-full text-lg font-bold bg-transparent border-none p-0 focus:ring-0 placeholder:text-navy/10" 
             />
          </div>
        </div>

        {/* Categories Chips */}
        <div>
           <label className="text-[10px] font-black uppercase text-navy/30 mb-3 block px-1 tracking-widest">Category</label>
           <div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setFormData({...formData, category: cat as any})}
                  className={`flex-shrink-0 px-4 py-3 rounded-2xl font-black text-xs uppercase tracking-wider border-2 transition-all ${
                    formData.category === cat 
                      ? 'bg-navy border-navy text-white sticker-shadow scale-105' 
                      : 'bg-white border-accent text-navy/40'
                  }`}
                >
                  {cat}
                </button>
              ))}
           </div>
        </div>

        {/* Collapsible Details including Day Selector */}
        <div className="space-y-4">
           {/* If details hidden (adding new pool item), show expand button */}
           {!showDetails && (
              <button 
                onClick={() => setShowDetails(true)}
                className="w-full py-3 text-xs font-black text-stitch uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-stitch/5 rounded-xl transition-colors"
              >
                 <Plus size={14} /> Add Time, Day & Notes
              </button>
           )}

           {showDetails && (
             <div className="animate-in slide-in-from-top-4 fade-in duration-300 space-y-4">
               {/* Day Selector (Modify Date Function) */}
               <div className="bg-white p-4 rounded-2xl border border-accent">
                   <label className="text-[10px] font-black uppercase text-navy/30 mb-2 block">Day</label>
                   <select 
                      value={formData.dayIndex} 
                      onChange={e => setFormData({...formData, dayIndex: parseInt(e.target.value)})}
                      className="w-full font-black text-lg bg-transparent border-none p-0 focus:ring-0 text-navy"
                   >
                      <option value={-1}>Inspiration Pool (No Date)</option>
                      {daysOptions.map(d => (
                         <option key={d.index} value={d.index}>{d.label}</option>
                      ))}
                   </select>
               </div>

               <div className="bg-white p-4 rounded-2xl border border-accent">
                   <label className="text-[10px] font-black uppercase text-navy/30 mb-2 block">Time & Duration</label>
                   <div className="flex items-center gap-3">
                      <div className="flex-1">
                         <span className="text-[9px] uppercase text-navy/20 font-bold block mb-1">Start</span>
                         <input type="time" value={formData.time} onChange={e => setFormData({...formData, time: e.target.value})} className="w-full font-black text-xl bg-transparent border-none p-0 focus:ring-0" />
                      </div>
                      <ArrowRight size={16} className="text-navy/10 mt-4" />
                      <div className="flex-1">
                         <span className="text-[9px] uppercase text-navy/20 font-bold block mb-1">End (Optional)</span>
                         <input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="w-full font-black text-xl bg-transparent border-none p-0 focus:ring-0 text-navy/60" />
                      </div>
                   </div>
               </div>

               <div className="bg-white p-4 rounded-2xl border border-accent">
                  <label className="text-[10px] font-black uppercase text-navy/30 mb-1 block">Notes</label>
                  <textarea rows={3} value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} placeholder="Details..." className="w-full text-sm bg-transparent border-none p-0 focus:ring-0 resize-none font-medium" />
               </div>
             </div>
           )}
        </div>
      </div>
    </div>
  );
};

export default Schedule;

import React, { useState, useEffect, useMemo } from 'react';
import { TripMember, Expense as ExpenseType } from '../types';
import { 
  Plus, 
  Trash2, 
  Edit2, 
  X, 
  Check, 
  Calculator, 
  RefreshCw, 
  Settings2, 
  TrendingUp, 
  TrendingDown, 
  ArrowRight,
  Wallet,
  ChevronDown,
  Coins,
  Calendar,
  Tag,
  PieChart,
  CheckCircle2,
  Users,
  Search,
  ChevronRight,
  BarChart3
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { COLORS } from '../constants';

const Expense: React.FC<{ currentUser: TripMember; members: TripMember[] }> = ({ currentUser, members }) => {
  // --- Data States ---
  const [expenses, setExpenses] = useState<ExpenseType[]>(() => {
    const saved = localStorage.getItem('expenses');
    const parsed = saved ? JSON.parse(saved) : [];
    return parsed.map((e: any) => ({
      ...e,
      settledBy: e.settledBy || (e.isSettled ? e.splitWith : [])
    }));
  });

  // --- Currency System States ---
  const [activeCurrencies, setActiveCurrencies] = useState<string[]>(() => {
    const saved = localStorage.getItem('activeCurrencies');
    return saved ? JSON.parse(saved) : ['JPY', 'HKD', 'AUD'];
  });

  const [rates, setRates] = useState<Record<string, number>>(() => {
    const saved = localStorage.getItem('exchangeRates');
    return saved ? JSON.parse(saved) : { JPY: 1, HKD: 19.2, AUD: 96.5, USD: 150.0, EUR: 162.0, TWD: 4.7 };
  });

  const [displayCurrency, setDisplayCurrency] = useState<string>(() => {
    return localStorage.getItem('displayCurrency') || 'HKD';
  });

  // --- UI States ---
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isSettlementOpen, setIsSettlementOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<ExpenseType | null>(null);
  const [loadingRates, setLoadingRates] = useState(false);

  // New States: Breakdown Mode, Search, etc.
  const [breakdownMode, setBreakdownMode] = useState<'category' | 'daily'>('category');
  const [isSearchVisible, setIsSearchVisible] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  const AVAILABLE_CURRENCIES = ['JPY', 'HKD', 'AUD', 'USD', 'EUR', 'GBP', 'TWD', 'KRW', 'SGD', 'CNY', 'THB'];

  // --- Effects ---
  useEffect(() => { localStorage.setItem('expenses', JSON.stringify(expenses)); }, [expenses]);
  useEffect(() => { localStorage.setItem('activeCurrencies', JSON.stringify(activeCurrencies)); }, [activeCurrencies]);
  useEffect(() => { localStorage.setItem('exchangeRates', JSON.stringify(rates)); }, [rates]);
  useEffect(() => { localStorage.setItem('displayCurrency', displayCurrency); }, [displayCurrency]);

  // --- Helpers ---
  const convert = (amount: number, from: string, to: string) => {
    const rateFrom = rates[from] || 1;
    const rateTo = rates[to] || 1;
    const amountInJPY = amount * rateFrom;
    return amountInJPY / rateTo;
  };

  const formatMoney = (amount: number, currency: string) => {
    return `${currency} ${amount.toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 1 })}`;
  };

  const getCategoryColor = (cat: string) => {
    const map: Record<string, string> = {
      'Food': COLORS.restaurant,
      'Restaurant': COLORS.restaurant,
      'Transport': COLORS.transport,
      'Stay': COLORS.stay,
      'Shopping': COLORS.shopping,
      'Attraction': COLORS.attraction,
      'Ticket': COLORS.attraction,
      'Other': COLORS.other
    };
    return map[cat] || COLORS.other;
  };

  const toggleMemberSettled = (e: React.MouseEvent, expenseId: string, memberId: string) => {
    e.stopPropagation();
    setExpenses(prev => prev.map(exp => {
      if (exp.id === expenseId) {
        const currentSettled = exp.settledBy || [];
        const isSettled = currentSettled.includes(memberId);
        return {
          ...exp,
          settledBy: isSettled 
            ? currentSettled.filter(id => id !== memberId) 
            : [...currentSettled, memberId]
        };
      }
      return exp;
    }));
  };

  // --- Derived Data ---

  const todayDate = new Date().toISOString().split('T')[0];

  const todayStats = useMemo(() => {
    const todayExpenses = expenses.filter(e => e.date === todayDate);
    const totalJPY = todayExpenses.reduce((sum, exp) => sum + (exp.amount * (rates[exp.currency] || 1)), 0);
    return {
      count: todayExpenses.length,
      total: convert(totalJPY, 'JPY', displayCurrency)
    };
  }, [expenses, rates, displayCurrency, todayDate]);

  const filteredExpenses = useMemo(() => {
    return expenses.filter(exp => {
      const matchSearch = exp.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
                          exp.category.toLowerCase().includes(searchTerm.toLowerCase());
      return matchSearch;
    }).sort((a, b) => b.date.localeCompare(a.date));
  }, [expenses, searchTerm]);

  const balances = useMemo(() => {
    const bal: Record<string, number> = {};
    members.forEach(m => bal[m.id] = 0);

    expenses.forEach(exp => {
      const amountInJPY = exp.amount * (rates[exp.currency] || 1);
      const splitCount = exp.splitWith.length || 1;
      const shareInJPY = amountInJPY / splitCount;

      exp.splitWith.forEach(debtorId => {
        if (exp.settledBy?.includes(debtorId)) return; 
        if (debtorId !== exp.paidBy) {
          if (bal[debtorId] !== undefined) bal[debtorId] -= shareInJPY;
          if (bal[exp.paidBy] !== undefined) bal[exp.paidBy] += shareInJPY;
        }
      });
    });
    return bal;
  }, [expenses, rates, members]);

  const totalSpentDisplay = useMemo(() => {
    const totalJPY = expenses.reduce((sum, exp) => sum + (exp.amount * (rates[exp.currency] || 1)), 0);
    return convert(totalJPY, 'JPY', displayCurrency);
  }, [expenses, rates, displayCurrency]);

  const breakdownStats = useMemo(() => {
    if (breakdownMode === 'category') {
      const stats: Record<string, number> = {};
      let total = 0;
      expenses.forEach(exp => {
        const val = convert(exp.amount, exp.currency, displayCurrency);
        const cat = exp.category || 'Other';
        stats[cat] = (stats[cat] || 0) + val;
        total += val;
      });
      return Object.entries(stats)
        .map(([name, value]) => ({ 
          name, 
          value, 
          percent: total > 0 ? (value / total) * 100 : 0 
        }))
        .sort((a, b) => b.value - a.value);
    } else {
      const stats: Record<string, number> = {};
      let total = 0;
      expenses.forEach(exp => {
        const val = convert(exp.amount, exp.currency, displayCurrency);
        const date = exp.date;
        stats[date] = (stats[date] || 0) + val;
        total += val;
      });
      return Object.entries(stats)
        .map(([name, value]) => ({ 
          name, 
          value, 
          percent: total > 0 ? (value / total) * 100 : 0 
        }))
        .sort((a, b) => b.name.localeCompare(a.name)); // Sort by date descending
    }
  }, [expenses, rates, displayCurrency, breakdownMode]);

  const fetchRates = async () => {
    if (!process.env.API_KEY) {
      alert("Missing API Key");
      return;
    }
    setLoadingRates(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const currenciesToFetch = activeCurrencies.filter(c => c !== 'JPY').join(', ');
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Get real-time exchange rates for 1 unit of [${currenciesToFetch}] to JPY. Return valid JSON only, like {"HKD": 19.5, "USD": 150.2}.`,
        config: { responseMimeType: "application/json" }
      });
      const jsonText = response.text || "{}";
      const newRatesData = JSON.parse(jsonText);
      setRates(prev => ({ ...prev, ...newRatesData, JPY: 1 }));
      alert("匯率已更新！");
    } catch (e) {
      console.error(e);
      alert("匯率更新失敗。");
    } finally {
      setLoadingRates(false);
    }
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500 relative min-h-screen">

      {/* --- DASHBOARD --- */}
      <div className="bg-white/90 backdrop-blur-md p-6 rounded-3xl-sticker sticker-shadow border border-stitch/20 relative overflow-hidden">
        <div className="absolute -top-10 -right-10 w-40 h-40 bg-donald/10 rounded-full blur-3xl pointer-events-none" />

        <div className="relative z-10">
           <div className="flex justify-between items-center mb-2">
              <p className="text-[10px] font-black uppercase tracking-[0.2em] text-navy/30">Total Trip Spending</p>
              <div className="flex items-center gap-2">
                <button 
                  onClick={() => setIsSearchVisible(!isSearchVisible)}
                  className={`p-1.5 rounded-lg transition-colors ${isSearchVisible ? 'bg-stitch text-white' : 'bg-cream text-navy/40 hover:text-stitch'}`}
                >
                  <Search size={14} />
                </button>
                <button 
                  onClick={() => setIsSettingsOpen(true)}
                  className="flex items-center gap-1 px-2 py-1 bg-cream rounded-lg text-[9px] font-black text-navy/40 hover:text-stitch transition-colors"
                >
                  <Settings2 size={12} /> Manage
                </button>
              </div>
           </div>

           <div className="flex items-baseline gap-2 mb-4">
              <button 
                onClick={() => setIsSettingsOpen(true)}
                className="text-2xl font-black text-stitch/80 hover:bg-stitch/10 px-2 rounded-lg transition-colors flex items-center gap-1"
              >
                 {displayCurrency} <ChevronDown size={16} />
              </button>
              <h1 className="text-5xl font-black text-navy tracking-tight">
                 {Math.round(totalSpentDisplay).toLocaleString()}
              </h1>
           </div>

           {/* Today's Summary Block */}
           <div className="bg-stitch/10 rounded-2xl p-4 mb-6 border border-stitch/20 flex justify-between items-center">
             <div>
               <p className="text-[9px] font-black text-stitch uppercase tracking-widest mb-0.5">Today's Summary</p>
               <h4 className="text-xl font-black text-navy">{displayCurrency} {Math.round(todayStats.total).toLocaleString()}</h4>
             </div>
             <div className="text-right">
               <span className="bg-white px-2 py-1 rounded-full text-[9px] font-black text-stitch border border-stitch/20">
                 {todayStats.count} RECORDS
               </span>
             </div>
           </div>

           <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={() => { setEditingExpense(null); setIsModalOpen(true); }}
                className="bg-stitch text-white py-3.5 rounded-2xl-sticker font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 sticker-shadow active:scale-95 transition-all shadow-lg shadow-stitch/20"
              >
                 <Plus size={16} /> Record
              </button>
              <button 
                onClick={() => setIsSettlementOpen(true)}
                className="bg-white text-navy border border-accent py-3.5 rounded-2xl-sticker font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 sticker-shadow active:scale-95 transition-all"
              >
                 <Wallet size={16} /> Quick Settle
              </button>
           </div>
        </div>
      </div>

      {/* --- SEARCH BAR (Conditional) --- */}
      {isSearchVisible && (
        <div className="animate-in slide-in-from-top-2 duration-300">
          <div className="bg-white p-3 rounded-2xl border border-stitch/30 flex items-center gap-2">
            <Search size={16} className="text-stitch ml-1" />
            <input 
              type="text" 
              value={searchTerm} 
              onChange={(e) => setSearchTerm(e.target.value)}
              placeholder="Search title or category..."
              className="flex-1 bg-transparent border-none focus:ring-0 text-sm font-bold text-navy p-0"
              autoFocus
            />
            {searchTerm && <button onClick={() => setSearchTerm('')}><X size={16} className="text-navy/20" /></button>}
          </div>
        </div>
      )}

      {/* --- BREAKDOWN SECTION --- */}
      <div className="bg-white p-5 rounded-2xl-sticker sticker-shadow border border-accent/40 relative overflow-hidden">
        <div className="flex justify-between items-center mb-4">
           <div className="flex gap-4">
              <button 
                onClick={() => setBreakdownMode('category')}
                className={`text-[10px] font-black uppercase tracking-[0.2em] flex items-center gap-1.5 transition-colors ${breakdownMode === 'category' ? 'text-stitch' : 'text-navy/20'}`}
              >
                <PieChart size={12} /> By Category
              </button>
              <button 
                onClick={() => setBreakdownMode('daily')}
                className={`text-[10px] font-black uppercase tracking-[0.2em] flex items-center gap-1.5 transition-colors ${breakdownMode === 'daily' ? 'text-stitch' : 'text-navy/20'}`}
              >
                <BarChart3 size={12} /> By Date
              </button>
           </div>
           <span className="text-[9px] font-bold text-navy/20">in {displayCurrency}</span>
        </div>

        <div className="space-y-4">
          {breakdownStats.length > 0 ? breakdownStats.map((stat, idx) => (
            <div key={stat.name} className="relative group">
              <div className="flex justify-between items-end mb-1.5 z-10 relative">
                 <div className="flex items-center gap-2">
                    <span 
                       className="w-2 h-2 rounded-full" 
                       style={{ backgroundColor: breakdownMode === 'category' ? getCategoryColor(stat.name) : COLORS.stitch }}
                    />
                    <span className="text-xs font-black text-navy">{stat.name}</span>
                 </div>
                 <div className="text-right flex items-baseline gap-2">
                   <span className="text-[10px] font-bold text-navy/40">{Math.round(stat.value).toLocaleString()}</span>
                   <span className="text-xs font-black text-navy">{Math.round(stat.percent)}%</span>
                 </div>
              </div>
              <div className="w-full h-2.5 bg-cream rounded-full overflow-hidden">
                 <div 
                   className="h-full rounded-full transition-all duration-1000 ease-out"
                   style={{ 
                     width: `${stat.percent}%`,
                     backgroundColor: breakdownMode === 'category' ? getCategoryColor(stat.name) : COLORS.stitch 
                   }}
                 />
              </div>
            </div>
          )) : (
            <div className="py-4 text-center opacity-30 text-[10px] font-bold text-navy uppercase tracking-widest">
               No spending data yet
            </div>
          )}
        </div>
      </div>

      {/* --- EXPENSE LIST --- */}
      <div className="space-y-4 pt-2">
         <h3 className="text-[11px] font-black text-navy/20 uppercase tracking-[0.3em] flex items-center gap-2 px-1">
            Activity Log
         </h3>

         {filteredExpenses.length > 0 ? (
           <div className="space-y-3">
             {filteredExpenses.map((exp) => {
               const payer = members.find(m => m.id === exp.paidBy);
               const isExpanded = expandedId === exp.id;
               const displayName = exp.title || exp.category;
               const allSettled = exp.splitWith.length > 0 && exp.splitWith.every(id => exp.settledBy?.includes(id));
               const partiallySettled = exp.settledBy && exp.settledBy.length > 0 && !allSettled;

               return (
                 <div 
                   key={exp.id}
                   onClick={() => setExpandedId(isExpanded ? null : exp.id)}
                   className={`
                      relative rounded-2xl-sticker border transition-all duration-300 overflow-hidden cursor-pointer 
                      ${isExpanded ? 'bg-white border-stitch shadow-lg scale-[1.01] z-10' : 'bg-white border-accent/40 sticker-shadow hover:border-stitch/30'}
                      ${allSettled ? 'opacity-70 bg-gray-50/50' : ''}
                   `}
                 >
                    <div className="p-4 flex items-center gap-4 relative">
                       {/* Date Badge */}
                       <div className="absolute top-2 right-14 text-[8px] font-black text-navy/20 uppercase tracking-widest flex items-center gap-1">
                         <Calendar size={8} /> {exp.date}
                       </div>

                       {allSettled && (
                          <div className="absolute top-2 right-2 flex items-center gap-1 px-2 py-0.5 bg-green-100 text-green-700 rounded-full border border-green-200 z-20">
                             <Check size={8} strokeWidth={4} />
                             <span className="text-[8px] font-black uppercase tracking-wider">All Settled</span>
                          </div>
                       )}
                       {partiallySettled && (
                          <div className="absolute top-2 right-2 flex items-center gap-1 px-2 py-0.5 bg-orange-100 text-orange-600 rounded-full border border-orange-200 z-20">
                             <CheckCircle2 size={8} strokeWidth={4} />
                             <span className="text-[8px] font-black uppercase tracking-wider">Partial</span>
                          </div>
                       )}

                       <div className={`w-10 h-10 rounded-full flex items-center justify-center text-lg shadow-inner flex-shrink-0 ${allSettled ? 'grayscale opacity-50 bg-gray-100' : 'bg-cream'}`} style={{ color: allSettled ? '#999' : getCategoryColor(exp.category) }}>
                          {exp.category === 'Food' || exp.category === 'Restaurant' ? '🍜' : 
                           exp.category === 'Transport' ? '🚕' : 
                           exp.category === 'Shopping' ? '🛍️' : 
                           exp.category === 'Stay' ? '🏨' : 
                           exp.category === 'Attraction' || exp.category === 'Ticket' ? '🎫' : '💸'}
                       </div>

                       <div className="flex-1 min-w-0">
                          <h4 className={`font-black text-sm truncate ${allSettled ? 'text-navy/50 line-through' : 'text-navy'}`}>{displayName}</h4>
                          <div className="flex items-center gap-2 mt-0.5">
                             <img src={payer?.avatar} className={`w-4 h-4 rounded-full border border-white ${allSettled ? 'grayscale' : ''}`} />
                             <span className="text-[10px] font-bold text-navy/40 uppercase">{payer?.name} Paid</span>
                          </div>
                       </div>

                       <div className="text-right">
                          <p className={`font-black text-sm ${allSettled ? 'text-navy/40' : 'text-navy'}`}>{formatMoney(exp.amount, exp.currency)}</p>
                          <p className="text-[9px] font-bold text-navy/20">
                             ≈ {displayCurrency} {Math.round(convert(exp.amount, exp.currency, displayCurrency)).toLocaleString()}
                          </p>
                       </div>
                    </div>

                    <div className={`bg-stitch/5 border-t border-stitch/10 overflow-hidden transition-[max-height, padding] duration-300 ease-in-out ${isExpanded ? 'max-h-80' : 'max-h-0'}`}>
                       <div className="p-4 flex flex-col gap-3">
                          <div className="bg-white rounded-xl border border-accent/40 p-3">
                             <p className="text-[9px] font-bold text-navy/30 uppercase tracking-wider mb-2 flex items-center gap-1">
                               <Users size={10} /> Split Status (Tap to toggle settled)
                             </p>
                             <div className="space-y-2">
                               {exp.splitWith.map(uid => {
                                  const m = members.find(mem => mem.id === uid);
                                  const isMemberSettled = exp.settledBy?.includes(uid);
                                  const isPayer = uid === exp.paidBy;
                                  return (
                                     <button 
                                        key={uid}
