            </div>
          </div>
        </div>
      )}
      {isAddModalOpen && (
        <AddItemModal target={addItemTarget} mode={modalMode} initialData={editingItem} duration={config.duration} startDate={config.startDate} onClose={() => setIsAddModalOpen(false)} onSave={handleSaveItem} />
      )}
    </div>
  );
};

const AddItemModal: React.FC<{ target: 'pool' | 'schedule'; mode: 'add' | 'edit'; initialData: ScheduleItem | null; duration: number; startDate: string; onClose: () => void; onSave: (item: any) => void }> = ({ target, mode, initialData, duration, startDate, onClose, onSave }) => {
  const [formData, setFormData] = useState({ dayIndex: initialData?.dayIndex !== undefined ? initialData.dayIndex : (target === 'pool' ? -1 : 0), time: initialData?.time || '10:00', endTime: initialData?.endTime || '', title: initialData?.title || '', location: initialData?.location || '', category: initialData?.category || 'Attraction', notes: initialData?.notes || '', });
  const [showDetails, setShowDetails] = useState(target === 'schedule' || mode === 'edit'); 
  const categories: Category[] = ['Attraction', 'Restaurant', 'Transport', 'Stay', 'Shopping', 'Other'];
  const daysOptions = Array.from({ length: duration }, (_, i) => { const d = new Date(startDate); d.setDate(d.getDate() + i); return { index: i, label: `Day ${i + 1} - ${d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}` }; });

  return (
    <div className="fixed inset-0 z-[70] flex flex-col bg-cream animate-in slide-in-from-bottom duration-300">
      <div className="p-4 flex justify-between items-center border-b border-accent bg-paper"><button onClick={onClose} className="text-navy/40 p-2"><X size={24} /></button><h3 className="text-lg font-black text-navy uppercase tracking-widest">{mode === 'add' ? (target === 'pool' ? 'New Idea' : 'Add Stop') : 'Edit Item'}</h3><button onClick={() => onSave(formData)} className="text-stitch font-black p-2" disabled={!formData.location}>DONE</button></div>
      <div className="flex-1 overflow-y-auto p-6 space-y-6">
        <div className="bg-paper p-6 rounded-3xl-sticker border border-accent sticker-shadow"><label className="text-[10px] font-black uppercase text-navy/30 mb-2 block tracking-widest">Where to?</label><div className="flex items-center gap-3"><MapPin size={28} className="text-stitch flex-shrink-0" /><input autoFocus type="text" value={formData.location} onChange={e => setFormData({...formData, location: e.target.value})} placeholder="e.g. Tokyo Tower" className="w-full text-2xl font-black bg-transparent border-none p-0 focus:ring-0 placeholder:text-navy/10" /></div><div className="mt-4 pt-4 border-t border-accent/20"><label className="text-[10px] font-black uppercase text-navy/30 mb-2 block tracking-widest">Title (Optional)</label><input type="text" value={formData.title} onChange={e => setFormData({...formData, title: e.target.value})} placeholder="Activity Name" className="w-full text-lg font-bold bg-transparent border-none p-0 focus:ring-0 placeholder:text-navy/10" /></div></div>
        <div><label className="text-[10px] font-black uppercase text-navy/30 mb-3 block px-1 tracking-widest">Category</label><div className="flex gap-2 overflow-x-auto pb-2 scrollbar-hide">{categories.map(cat => <button key={cat} onClick={() => setFormData({...formData, category: cat as any})} className={`flex-shrink-0 px-4 py-3 rounded-2xl font-black text-xs uppercase tracking-wider border-2 transition-all ${formData.category === cat ? 'bg-navy border-navy text-white sticker-shadow scale-105' : 'bg-white border-accent text-navy/40'}`}>{cat}</button>)}</div></div>
        <div className="space-y-4">{!showDetails && <button onClick={() => setShowDetails(true)} className="w-full py-3 text-xs font-black text-stitch uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-stitch/5 rounded-xl transition-colors"><Plus size={14} /> Add Time, Day & Notes</button>}{showDetails && <div className="animate-in slide-in-from-top-4 fade-in duration-300 space-y-4"><div className="bg-white p-4 rounded-2xl border border-accent"><label className="text-[10px] font-black uppercase text-navy/30 mb-2 block">Day</label><select value={formData.dayIndex} onChange={e => setFormData({...formData, dayIndex: parseInt(e.target.value)})} className="w-full font-black text-lg bg-transparent border-none p-0 focus:ring-0 text-navy"><option value={-1}>Pool (No Date)</option>{daysOptions.map(d => <option key={d.index} value={d.index}>{d.label}</option>)}</select></div><div className="bg-white p-4 rounded-2xl border border-accent"><label className="text-[10px] font-black uppercase text-navy/30 mb-2 block">Time</label><div className="flex items-center gap-3"><div className="flex-1"><span className="text-[9px] uppercase text-navy/20 font-bold block mb-1">Start</span><input type="time" value={formData.time} onChange={e => setFormData({...formData, time: e.target.value})} className="w-full font-black text-xl bg-transparent border-none p-0 focus:ring-0" /></div><ArrowRight size={16} className="text-navy/10 mt-4" /><div className="flex-1"><span className="text-[9px] uppercase text-navy/20 font-bold block mb-1">End</span><input type="time" value={formData.endTime} onChange={e => setFormData({...formData, endTime: e.target.value})} className="w-full font-black text-xl bg-transparent border-none p-0 focus:ring-0 text-navy/60" /></div></div></div><div className="bg-white p-4 rounded-2xl border border-accent"><label className="text-[10px] font-black uppercase text-navy/30 mb-1 block">Notes</label><textarea rows={3} value={formData.notes} onChange={e => setFormData({...formData, notes: e.target.value})} placeholder="Details..." className="w-full text-sm bg-transparent border-none p-0 focus:ring-0 resize-none font-medium" /></div></div>}</div>
      </div>
    </div>
  );
};

export default Schedule;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Plane, 
  Hotel, 
  Car, 
  Utensils, 
  Ticket as TicketIcon, 
  Plus, 
  X, 
  Camera, 
  Edit2, 
  Trash2, 
  Hash, 
  Search,
  User,
  Copy,
  Calendar,
  Sparkles,
  MapPin,
  ArrowUpRight,
  QrCode,
  Wand2,
  CopyPlus,
  ArrowUp,
  ArrowDown,
  ChevronUp,
  ChevronDown,
  Download,
  AlertTriangle,
  Link
} from 'lucide-react';
import { Booking, TripMember, ScheduleItem } from '../types.ts';
import { GoogleGenAI } from "@google/genai";

interface BookingsProps {
  members: TripMember[];
  currentUser: TripMember;
  onNavigate: (tab: string, id?: string) => void;
  highlightId?: string | null;
}

const Bookings: React.FC<BookingsProps> = ({ members, currentUser, onNavigate, highlightId }) => {
  const [bookings, setBookings] = useState<Booking[]>(() => {
    const saved = localStorage.getItem('bookings');
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        type: 'Flight',
        title: 'CX504 Pacific Air',
        referenceNo: 'M7X9L2',
        bookedBy: '1',
        cost: 0,
        imageUrl: 'https://picsum.photos/seed/flight/600/200',
        details: { from: 'HKG', to: 'NRT', date: '12 OCT', time: '09:15', arrivalTime: '14:30', seat: '24A', gate: 'B12', airline: 'Cathay', class: 'Economy', flightNo: 'CX504' }
      },
      {
        id: '2',
        type: 'Hotel',
        title: 'Shinjuku Prince Hotel',
        referenceNo: 'H-992831',
        bookedBy: '2',
        cost: 45000,
        imageUrl: '',
        details: { address: 'Kabukicho, Tokyo', checkIn: '12 OCT', checkOut: '17 OCT', room: 'Superior King' }
      }
    ];
  });

  const [itinerary, setItinerary] = useState<ScheduleItem[]>(() => {
    const saved = localStorage.getItem('itinerary');
    return saved ? JSON.parse(saved) : [];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBooking, setEditingBooking] = useState<Booking | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isSearchVisible, setIsSearchVisible] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterUser, setFilterUser] = useState<string | 'All'>('All');

  useEffect(() => {
    localStorage.setItem('bookings', JSON.stringify(bookings));
  }, [bookings]);

  useEffect(() => {
    const saved = localStorage.getItem('itinerary');
    if (saved) setItinerary(JSON.parse(saved));
    if (highlightId) setExpandedId(highlightId);
  }, [highlightId, isModalOpen]);

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('Delete?')) {
      setBookings(bookings.filter(b => b.id !== id));
      if (expandedId === id) setExpandedId(null);
    }
  };

  const handleEdit = (e: React.MouseEvent, booking: Booking) => {
    e.stopPropagation();
    setEditingBooking(booking); 
    setIsModalOpen(true);
  };

  const handleDuplicate = (e: React.MouseEvent, booking: Booking) => {
    e.stopPropagation();
    const newBooking: Booking = { ...booking, id: Date.now().toString(), title: `${booking.title} (Copy)` };
    const index = bookings.findIndex(b => b.id === booking.id);
    const newBookings = [...bookings];
    newBookings.splice(index + 1, 0, newBooking);
    setBookings(newBookings);
  };

  const handleMove = (e: React.MouseEvent, id: string, direction: 'up' | 'down') => {
    e.stopPropagation();
    const index = bookings.findIndex(b => b.id === id);
    if (index === -1) return;
    const newBookings = [...bookings];
    if (direction === 'up') {
      if (index === 0) return;
      [newBookings[index - 1], newBookings[index]] = [newBookings[index], newBookings[index - 1]];
    } else {
      if (index === newBookings.length - 1) return;
      [newBookings[index + 1], newBookings[index]] = [newBookings[index], newBookings[index + 1]];
    }
    setBookings(newBookings);
  };

  const handleSave = (booking: Booking) => {
    if (editingBooking) setBookings(bookings.map(b => b.id === booking.id ? booking : b));
    else setBookings([...bookings, { ...booking, id: Date.now().toString() }]);
    setIsModalOpen(false);
    setEditingBooking(null);
  };

  const copyToClipboard = (e: React.MouseEvent, text: string) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
  };

  const filteredBookings = useMemo(() => {
    return bookings.filter(b => {
      const matchesSearch = b.title.toLowerCase().includes(searchTerm.toLowerCase()) || b.type.toLowerCase().includes(searchTerm.toLowerCase()) || (b.referenceNo && b.referenceNo.toLowerCase().includes(searchTerm.toLowerCase()));
      const matchesUser = filterUser === 'All' || b.bookedBy === filterUser;
      return matchesSearch && matchesUser;
    });
  }, [bookings, searchTerm, filterUser]);

  const renderHeaderStrip = (booking: Booking, isExpanded: boolean, index: number, total: number) => {
    let icon = <TicketIcon size={18} />;
    let bgColor = 'bg-white';
    let textColor = 'text-navy';
    let accentColor = 'bg-accent';
    switch (booking.type) {
      case 'Flight': icon = <Plane size={18} className="text-white" />; bgColor = 'bg-navy'; textColor = 'text-white'; accentColor = 'bg-stitch'; break;
      case 'Hotel': icon = <Hotel size={18} className="text-stitch" />; accentColor = 'bg-stitch'; break;
      case 'Amusement': icon = <Sparkles size={18} className="text-navy" />; bgColor = 'bg-donald'; accentColor = 'bg-white'; break;
      case 'Restaurant': icon = <Utensils size={18} className="text-red-400" />; accentColor = 'bg-red-200'; break;
      case 'Car': icon = <Car size={18} className="text-navy" />; bgColor = 'bg-accent/30'; accentColor = 'bg-white'; break;
    }
    const displayTime = booking.details.time || booking.details.checkIn || booking.details.datetime?.split('T')[1] || '';
    const displayDate = booking.details.date || booking.details.checkIn || booking.details.datetime?.split('T')[0] || '';
    const arrivalTime = booking.details.arrivalTime;

    return (
      <div className={`flex relative min-h-[100px] ${bgColor} ${textColor} transition-colors overflow-hidden`}>
        <div className="flex-1 p-4 flex flex-col relative z-10">
          <div className="flex justify-between items-start mb-2">
             <div className="flex items-center gap-3">
                <div className={`w-8 h-8 rounded-lg flex items-center justify-center shadow-sm ${accentColor === 'bg-white' ? 'bg-white/80' : accentColor}`}>{icon}</div>
                <div className="flex flex-col"><span className={`text-[9px] font-black uppercase tracking-widest opacity-60`}>{booking.type}</span><span className="text-xs font-black leading-none">{displayDate}</span></div>
             </div>
             <div className="text-right">{booking.type === 'Flight' && arrivalTime ? <div className="flex flex-col items-end"><div className="flex items-center gap-1"><span className="text-sm font-black">{displayTime}</span><span className="opacity-50 text-[10px]">➔</span><span className="text-sm font-black">{arrivalTime}</span></div></div> : <p className="text-lg font-black">{displayTime}</p>}</div>
          </div>
          <div className="flex-1"><h3 className="font-black text-lg leading-tight truncate pr-2">{booking.title}</h3>{booking.referenceNo && <span className="flex items-center gap-1 text-[9px] font-bold opacity-60 mt-0.5"><Hash size={8} /> {booking.referenceNo}</span>}</div>
        </div>
        <div className={`w-10 flex flex-col items-center justify-center gap-1 border-l ${booking.type === 'Flight' ? 'border-white/10 bg-black/10' : 'border-black/5 bg-black/5'}`} onClick={e => e.stopPropagation()}>
           <button onClick={(e) => handleMove(e, booking.id, 'up')} disabled={index === 0} className="p-1.5 rounded-full hover:bg-white/20 disabled:opacity-20"><ChevronUp size={14} strokeWidth={3} /></button>
           <button onClick={(e) => handleDuplicate(e, booking)} className="p-1.5 rounded-full hover:bg-white/20"><CopyPlus size={12} /></button>
           <button onClick={(e) => handleMove(e, booking.id, 'down')} disabled={index === total - 1} className="p-1.5 rounded-full hover:bg-white/20 disabled:opacity-20"><ChevronDown size={14} strokeWidth={3} /></button>
        </div>
      </div>
    );
  };

  const renderBookingDetails = (booking: Booking) => {
    const hasImage = !!booking.imageUrl;
    const linkedItem = itinerary.find(i => i.id === booking.linkedScheduleId);
    const DetailField = ({ label, value, fullWidth = false }: { label: string, value: any, fullWidth?: boolean }) => {
       if (!value || value === '') return null;
       return (
         <div className={`${fullWidth ? 'col-span-2' : ''}`}>
            <p className="text-[9px] font-black text-navy/30 uppercase tracking-widest mb-0.5">{label}</p>
            <p className="font-bold text-navy text-sm break-words leading-tight">{String(value)}</p>
         </div>
       );
    };

    return (
