            {Object.entries(booking.details).map(([key, value]) => { const ignoredKeys = ['from', 'to', 'gate', 'seat', 'checkIn', 'checkOut', 'address', 'imageUrl', 'arrivalTime', 'time', 'date', 'airline', 'flightNo', 'class', 'room', 'vehicle']; if (ignoredKeys.includes(key)) return null; return <DetailField key={key} label={key} value={value as any} fullWidth={String(value).length > 20} />; })}
