import React, { useState, useEffect, useMemo, useRef } from 'react';
import { TripMember, Expense as ExpenseType } from '../types.ts';
import { 
  Plus, 
  Trash2, 
  Edit2, 
  X, 
  Check, 
  RefreshCw, 
  Settings2, 
  ArrowRight,
  Wallet,
  ChevronDown,
  Calendar,
  Tag,
  PieChart,
  Search,
  BarChart3,
  FilterX
} from 'lucide-react';
import { GoogleGenAI } from "@google/genai";
import { COLORS } from '../constants.ts';

const Expense: React.FC<{ currentUser: TripMember; members: TripMember[] }> = ({ currentUser, members }) => {
  const [expenses, setExpenses] = useState<ExpenseType[]>(() => {
    const saved = localStorage.getItem('expenses');
    return saved ? JSON.parse(saved) : [];
  });
  const [activeCurrencies, setActiveCurrencies] = useState<string[]>(() => {
    const saved = localStorage.getItem('activeCurrencies');
    return saved ? JSON.parse(saved) : ['JPY', 'HKD', 'AUD'];
  });
  const [rates, setRates] = useState<Record<string, number>>(() => {
    const saved = localStorage.getItem('exchangeRates');
    return saved ? JSON.parse(saved) : { JPY: 1, HKD: 19.2, AUD: 96.5, USD: 150.0, EUR: 162.0, TWD: 4.7 };
  });
  const [displayCurrency, setDisplayCurrency] = useState<string>(() => {
    return localStorage.getItem('displayCurrency') || 'HKD';
  });

  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isSettlementOpen, setIsSettlementOpen] = useState(false);
  const [editingExpense, setEditingExpense] = useState<ExpenseType | null>(null);
  const [loadingRates, setLoadingRates] = useState(false);
  const [breakdownMode, setBreakdownMode] = useState<'category' | 'daily'>('category');
  const [isSearchVisible, setIsSearchVisible] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedFilterDate, setSelectedFilterDate] = useState<string | null>(null);
  const logRef = useRef<HTMLDivElement>(null);

  useEffect(() => { localStorage.setItem('expenses', JSON.stringify(expenses)); }, [expenses]);
  useEffect(() => { localStorage.setItem('activeCurrencies', JSON.stringify(activeCurrencies)); }, [activeCurrencies]);
  useEffect(() => { localStorage.setItem('exchangeRates', JSON.stringify(rates)); }, [rates]);
  useEffect(() => { localStorage.setItem('displayCurrency', displayCurrency); }, [displayCurrency]);

  const convert = (amount: number, from: string, to: string) => {
    const rateFrom = rates[from] || 1;
    const rateTo = rates[to] || 1;
    return (amount * rateFrom) / rateTo;
  };

  const getCategoryColor = (cat: string) => {
    const map: Record<string, string> = { 'Food': COLORS.restaurant, 'Restaurant': COLORS.restaurant, 'Transport': COLORS.transport, 'Stay': COLORS.stay, 'Shopping': COLORS.shopping, 'Attraction': COLORS.attraction, 'Ticket': COLORS.attraction, 'Other': COLORS.other };
    return map[cat] || COLORS.other;
  };

  const todayDate = new Date().toISOString().split('T')[0];
  const { todayStats, totalSpentDisplay, breakdownStats } = useMemo(() => {
    const todayExpenses = expenses.filter(e => e.date === todayDate);
    const todayTotalJPY = todayExpenses.reduce((sum, e) => sum + (e.amount * (rates[e.currency] || 1)), 0);
    const totalJPY = expenses.reduce((sum, e) => sum + (e.amount * (rates[e.currency] || 1)), 0);
    let stats: any[] = [];
    if (breakdownMode === 'category') {
      const catMap: Record<string, number> = {};
      expenses.forEach(e => { const val = convert(e.amount, e.currency, displayCurrency); catMap[e.category] = (catMap[e.category] || 0) + val; });
      stats = Object.entries(catMap).map(([name, value]) => ({ name, value, percent: totalJPY > 0 ? (value / convert(totalJPY, 'JPY', displayCurrency)) * 100 : 0 })).sort((a, b) => b.value - a.value);
    } else {
      const dateMap: Record<string, number> = {};
      expenses.forEach(e => { const val = convert(e.amount, e.currency, displayCurrency); dateMap[e.date] = (dateMap[e.date] || 0) + val; });
      stats = Object.entries(dateMap).map(([name, value]) => ({ name, value, percent: totalJPY > 0 ? (value / convert(totalJPY, 'JPY', displayCurrency)) * 100 : 0 })).sort((a, b) => b.name.localeCompare(a.name));
    }
    return { todayStats: { count: todayExpenses.length, total: convert(todayTotalJPY, 'JPY', displayCurrency) }, totalSpentDisplay: convert(totalJPY, 'JPY', displayCurrency), breakdownStats: stats };
  }, [expenses, rates, displayCurrency, breakdownMode, todayDate]);

  const groupedExpenses = useMemo(() => {
    const filtered = expenses.filter(e => {
      const matchSearch = e.title.toLowerCase().includes(searchTerm.toLowerCase()) || e.category.toLowerCase().includes(searchTerm.toLowerCase());
      const matchDate = selectedFilterDate ? e.date === selectedFilterDate : true;
      return matchSearch && matchDate;
    }).sort((a, b) => b.date.localeCompare(a.date));
    const groups: Record<string, ExpenseType[]> = {};
    filtered.forEach(e => { if (!groups[e.date]) groups[e.date] = []; groups[e.date].push(e); });
    return groups;
  }, [expenses, searchTerm, selectedFilterDate]);

  const balances = useMemo(() => {
    const bal: Record<string, number> = {};
    members.forEach(m => bal[m.id] = 0);
    expenses.forEach(exp => {
      const amountJPY = exp.amount * (rates[exp.currency] || 1);
      const shareJPY = amountJPY / (exp.splitWith.length || 1);
      exp.splitWith.forEach(uid => { if (exp.settledBy?.includes(uid)) return; if (uid !== exp.paidBy) { if (bal[uid] !== undefined) bal[uid] -= shareJPY; if (bal[exp.paidBy] !== undefined) bal[exp.paidBy] += shareJPY; } });
    });
    return bal;
  }, [expenses, rates, members]);

  const fetchRates = async () => {
    if (!process.env.API_KEY) return;
    setLoadingRates(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const currencies = activeCurrencies.filter(c => c !== 'JPY').join(', ');
      const response = await ai.models.generateContent({ model: "gemini-3-flash-preview", contents: `Rates for 1 unit of [${currencies}] to JPY. Return JSON like {"HKD": 19.5}.`, config: { responseMimeType: "application/json" } });
      const data = JSON.parse(response.text || "{}");
      setRates(prev => ({ ...prev, ...data, JPY: 1 }));
    } catch (e) { console.error(e); }
    finally { setLoadingRates(false); }
  };
  const scrollToLog = () => logRef.current?.scrollIntoView({ behavior: 'smooth' });

  return (
    <div className="space-y-6 pb-24 animate-in relative min-h-screen">
      <div className="bg-white/95 backdrop-blur-md p-6 rounded-3xl-sticker sticker-shadow border border-stitch/20 relative overflow-hidden">
        <div className="relative z-10">
           <div className="flex justify-between items-center mb-2"><p className="text-[10px] font-black uppercase tracking-[0.2em] text-navy/30">Total Spent</p><div className="flex items-center gap-2"><button onClick={() => setIsSearchVisible(!isSearchVisible)} className={`p-1.5 rounded-lg ${isSearchVisible ? 'bg-stitch text-white' : 'bg-cream text-navy/40'}`}><Search size={14} /></button><button onClick={() => setIsSettingsOpen(true)} className="flex items-center gap-1 px-2 py-1 bg-cream rounded-lg text-[9px] font-black text-navy/40"><Settings2 size={12} /></button></div></div>
           <div className="flex items-baseline gap-2 mb-4"><button onClick={() => setIsSettingsOpen(true)} className="text-2xl font-black text-stitch flex items-center gap-1">{displayCurrency} <ChevronDown size={16} /></button><h1 className="text-5xl font-black text-navy tracking-tight">{Math.round(totalSpentDisplay).toLocaleString()}</h1></div>
           <div onClick={() => { setSelectedFilterDate(selectedFilterDate === todayDate ? null : todayDate); scrollToLog(); }} className={`p-4 mb-6 border rounded-2xl flex justify-between items-center cursor-pointer ${selectedFilterDate === todayDate ? 'bg-stitch text-white' : 'bg-stitch/10 text-navy'}`}><div><p className="text-[9px] font-black uppercase opacity-70">Today</p><h4 className="text-xl font-black">{displayCurrency} {Math.round(todayStats.total).toLocaleString()}</h4></div><div className="text-right"><span className="px-2 py-1 rounded-full text-[9px] font-black border bg-white/20">{todayStats.count} RECORDS</span></div></div>
           <div className="grid grid-cols-2 gap-3"><button onClick={() => { setEditingExpense(null); setIsModalOpen(true); }} className="bg-stitch text-white py-3.5 rounded-2xl-sticker font-black text-xs uppercase flex items-center justify-center gap-2 sticker-shadow"><Plus size={16} /> Record</button><button onClick={() => setIsSettlementOpen(true)} className="bg-white text-navy border border-accent py-3.5 rounded-2xl-sticker font-black text-xs uppercase flex items-center justify-center gap-2 sticker-shadow"><Wallet size={16} /> Settlement</button></div>
        </div>
      </div>
      {isSearchVisible && <div className="slide-down"><div className="bg-white p-3 rounded-2xl border border-stitch/30 flex items-center gap-2"><Search size={16} className="text-stitch ml-1" /><input autoFocus value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} placeholder="Search..." className="flex-1 bg-transparent border-none text-sm font-bold text-navy" /></div></div>}
      <div className="bg-white p-5 rounded-2xl-sticker sticker-shadow border border-accent/40"><div className="flex gap-4 mb-4"><button onClick={() => setBreakdownMode('category')} className={`text-[10px] font-black uppercase tracking-[0.2em] ${breakdownMode === 'category' ? 'text-stitch' : 'text-navy/20'}`}>Category</button><button onClick={() => setBreakdownMode('daily')} className={`text-[10px] font-black uppercase tracking-[0.2em] ${breakdownMode === 'daily' ? 'text-stitch' : 'text-navy/20'}`}>Daily</button></div><div className="space-y-4">{breakdownStats.map((stat) => <div key={stat.name} className="relative group"><div className="flex justify-between items-end mb-1 z-10 relative"><div className="flex items-center gap-2"><span className="w-2 h-2 rounded-full" style={{ backgroundColor: breakdownMode === 'category' ? getCategoryColor(stat.name) : COLORS.stitch }} /><span className="text-xs font-black">{stat.name}</span></div><span className="text-xs font-black">{Math.round(stat.percent)}%</span></div><div className="w-full h-2.5 bg-cream rounded-full overflow-hidden"><div className="h-full rounded-full transition-all" style={{ width: `${stat.percent}%`, backgroundColor: breakdownMode === 'category' ? getCategoryColor(stat.name) : COLORS.stitch }} /></div></div>)}</div></div>
      <div className="space-y-6 pt-2" ref={logRef}><div className="flex justify-between items-center px-1"><h3 className="text-[11px] font-black text-navy/20 uppercase tracking-[0.3em]">Log</h3>{selectedFilterDate && <button onClick={() => setSelectedFilterDate(null)} className="text-[9px] font-black text-stitch uppercase">Clear</button>}</div>{Object.entries(groupedExpenses).map(([date, dateExpenses]) => <div key={date} className="space-y-3"><div className="flex items-center gap-3 px-1"><span className="text-[10px] font-black text-navy/40 uppercase tracking-widest">{date}</span><div className="h-px flex-1 bg-accent/30" /></div>{dateExpenses.map(exp => { const isExpanded = expandedId === exp.id; return <div key={exp.id} onClick={() => setExpandedId(isExpanded ? null : exp.id)} className={`relative rounded-2xl-sticker border transition-all cursor-pointer ${isExpanded ? 'bg-white border-stitch shadow-lg' : 'bg-white border-accent/40 sticker-shadow'}`}><div className="p-4 flex items-center gap-4"><div className="w-10 h-10 rounded-full flex items-center justify-center text-lg bg-cream">{exp.category === 'Food' ? '🍜' : exp.category === 'Transport' ? '🚕' : '💸'}</div><div className="flex-1 truncate"><h4 className="font-black text-sm truncate">{exp.title}</h4></div><div className="text-right"><p className="font-black text-sm text-navy">{exp.currency} {exp.amount}</p></div></div>{isExpanded && <div className="p-4 pt-0 border-t border-stitch/10"><div className="flex justify-end gap-2 mt-3"><button onClick={(e) => { e.stopPropagation(); setEditingExpense(exp); setIsModalOpen(true); }} className="p-2 text-stitch text-[10px] font-black">EDIT</button><button onClick={(e) => { e.stopPropagation(); setExpenses(expenses.filter(i => i.id !== exp.id)); }} className="p-2 text-red-400 text-[10px] font-black">DELETE</button></div></div>}</div>; })}</div>)}</div>
      {isModalOpen && <ExpenseModal expense={editingExpense} members={members} currencies={activeCurrencies} onClose={() => setIsModalOpen(false)} onSave={(e) => { if (editingExpense) setExpenses(expenses.map(ex => ex.id === e.id ? e : ex)); else setExpenses([{ ...e, id: Date.now().toString() }, ...expenses]); setIsModalOpen(false); }} />}
      {isSettingsOpen && <div className="fixed inset-0 z-[100] flex items-end justify-center bg-navy/20 backdrop-blur-sm" onClick={() => setIsSettingsOpen(false)}><div className="bg-white w-full max-w-md rounded-t-3xl p-6 pb-10" onClick={e => e.stopPropagation()}><div className="flex justify-between items-center mb-6"><h3 className="text-lg font-black text-navy uppercase">Settings</h3><button onClick={() => setIsSettingsOpen(false)} className="p-2 bg-cream rounded-full"><X size={20} /></button></div><div className="mb-6"><label className="text-[10px] font-black uppercase text-navy/30 mb-2 block">Display Currency</label><div className="flex gap-2 overflow-x-auto pb-2">{activeCurrencies.map(cur => <button key={cur} onClick={() => setDisplayCurrency(cur)} className={`px-4 py-2 rounded-xl border-2 font-black text-xs ${displayCurrency === cur ? 'bg-navy border-navy text-white' : 'bg-white border-accent'}`}>{cur}</button>)}</div></div><button onClick={fetchRates} disabled={loadingRates} className="w-full py-4 bg-navy text-white font-black rounded-2xl uppercase text-xs tracking-widest flex items-center justify-center gap-2"><RefreshCw size={16} className={loadingRates ? 'animate-spin' : ''} /> SYNC RATES</button></div></div>}
      {isSettlementOpen && <SettlementModal balances={balances} displayCurrency={displayCurrency} convert={convert} members={members} onClose={() => setIsSettlementOpen(false)} />}
    </div>
  );
};

const SettlementModal: React.FC<{ balances: Record<string, number>, displayCurrency: string, convert: any, members: TripMember[], onClose: () => void }> = ({ balances, displayCurrency, convert, members, onClose }) => {
   // Fix: Explicitly type suggestions as any[] to avoid 'unknown' inference and fix map() error.
   const suggestions: any[] = useMemo(() => { const people = Object.entries(balances).map(([id, amount]) => ({ id, amount: amount as number })); const debtors = people.filter(p => p.amount < -1).sort((a, b) => a.amount - b.amount); const creditors = people.filter(p => p.amount > 1).sort((a, b) => b.amount - a.amount); const tx: any[] = []; let i = 0, j = 0; while (i < debtors.length && j < creditors.length) { const amount = Math.min(Math.abs(debtors[i].amount), creditors[j].amount); tx.push({ from: debtors[i].id, to: creditors[j].id, amount }); debtors[i].amount += amount; creditors[j].amount -= amount; if (Math.abs(debtors[i].amount) < 1) i++; if (creditors[j].amount < 1) j++; } return tx; }, [balances]);
   return (<div className="fixed inset-0 z-[120] flex items-center justify-center p-6 bg-navy/5 backdrop-blur-sm" onClick={onClose}><div className="bg-paper w-full max-w-sm rounded-3xl p-6 border-4 border-stitch/30" onClick={e => e.stopPropagation()}><h3 className="text-lg font-black text-navy uppercase tracking-widest mb-6">Settlement</h3><div className="space-y-3 max-h-[60vh] overflow-y-auto">{suggestions.map((t, idx) => <div key={idx} className="bg-white p-4 rounded-2xl border border-accent flex items-center justify-between"><div className="flex items-center gap-2"><img src={members.find(m => m.id === t.from)?.avatar} className="w-6 h-6 rounded-full" /><ArrowRight size={14} className="text-navy/20" /><img src={members.find(m => m.id === t.to)?.avatar} className="w-6 h-6 rounded-full" /></div><p className="font-black text-navy text-sm">{displayCurrency} {Math.round(convert(t.amount, 'JPY', displayCurrency)).toLocaleString()}</p></div>)}</div></div></div>);
};

const ExpenseModal: React.FC<{ expense: ExpenseType | null; members: TripMember[]; currencies: string[]; onClose: () => void; onSave: (e: ExpenseType) => void }> = ({ expense, members, currencies, onClose, onSave }) => {
  const [formData, setFormData] = useState<Partial<ExpenseType>>(expense || { 
    amount: 0, 
    currency: currencies[0], 
    category: 'Other', 
    title: '', 
    paidBy: members[0].id, 
    splitWith: members.map(m => m.id), 
    settledBy: [], 
    date: new Date().toISOString().split('T')[0] 
  });
  const categories = ['Food', 'Transport', 'Stay', 'Shopping', 'Attraction', 'Other'];

  return (
    <div className="fixed inset-0 z-[110] flex items-end justify-center bg-navy/20 backdrop-blur-sm" onClick={onClose}>
      <div className="bg-paper w-full max-w-md rounded-t-3xl p-6 sticker-shadow border-t-4 border-stitch animate-in slide-in-from-bottom duration-300" onClick={e => e.stopPropagation()}>
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-black text-navy uppercase">{expense ? 'Edit Record' : 'New Record'}</h3>
          <button onClick={onClose} className="p-2 bg-cream rounded-full"><X size={20} /></button>
        </div>
        <div className="space-y-4">
          <div className="flex gap-2">
            <input type="number" value={formData.amount} onChange={e => setFormData({ ...formData, amount: parseFloat(e.target.value) || 0 })} placeholder="0" className="flex-1 p-4 bg-cream rounded-2xl font-black text-2xl border border-accent" />
            <select value={formData.currency} onChange={e => setFormData({ ...formData, currency: e.target.value })} className="p-4 bg-white border border-accent rounded-2xl font-black">{currencies.map(c => <option key={c} value={c}>{c}</option>)}</select>
          </div>
          <input type="text" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} placeholder="What for? e.g. Sushi" className="w-full p-4 bg-cream rounded-2xl font-bold border border-accent" />
          <div className="grid grid-cols-2 gap-3">
             <div><label className="text-[10px] font-black uppercase text-navy/30 mb-1 block">Date</label><input type="date" value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} className="w-full p-3 bg-white border border-accent rounded-xl font-bold text-xs" /></div>
             <div><label className="text-[10px] font-black uppercase text-navy/30 mb-1 block">Category</label><select value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value })} className="w-full p-3 bg-white border border-accent rounded-xl font-bold text-xs">{categories.map(c => <option key={c} value={c}>{c}</option>)}</select></div>
          </div>
          <div>
            <label className="text-[10px] font-black uppercase text-navy/30 mb-1 block">Paid By</label>
            <div className="flex gap-2 overflow-x-auto pb-1">{members.map(m => <button key={m.id} onClick={() => setFormData({ ...formData, paidBy: m.id })} className={`flex-shrink-0 flex items-center gap-2 p-2 rounded-full border transition-all ${formData.paidBy === m.id ? 'bg-navy text-white border-navy' : 'bg-white border-accent text-navy/40'}`}><img src={m.avatar} className="w-5 h-5 rounded-full" /><span className="text-[10px] font-black uppercase pr-1">{m.name}</span></button>)}</div>
          </div>
          <button onClick={() => onSave(formData as ExpenseType)} disabled={!formData.title || !formData.amount} className="w-full py-4 bg-stitch text-white font-black rounded-2xl uppercase text-xs tracking-widest mt-4">SAVE</button>
        </div>
      </div>
    </div>
  );
};

export default Expense;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Plane, 
  Hotel, 
  Car, 
  Utensils, 
  Ticket as TicketIcon, 
  Plus, 
  X, 
  Camera, 
  Edit2, 
  Trash2, 
  Hash, 
  Search,
  User,
  Copy,
  Calendar,
  Sparkles,
  MapPin,
  ArrowUpRight,
  QrCode,
  Wand2,
  CopyPlus,
  ArrowUp,
  ArrowDown,
  ChevronUp,
  ChevronDown,
  Download,
  AlertTriangle,
  Link
} from 'lucide-react';
import { Booking, TripMember, ScheduleItem } from '../types.ts';
import { GoogleGenAI } from "@google/genai";

interface BookingsProps {
  members: TripMember[];
  currentUser: TripMember;
  onNavigate: (tab: string, id?: string) => void;
  highlightId?: string | null;
}

const Bookings: React.FC<BookingsProps> = ({ members, currentUser, onNavigate, highlightId }) => {
  const [bookings, setBookings] = useState<Booking[]>(() => {
    const saved = localStorage.getItem('bookings');
    return saved ? JSON.parse(saved) : [
      {
        id: '1',
        type: 'Flight',
        title: 'CX504 Pacific Air',
        referenceNo: 'M7X9L2',
        bookedBy: '1',
        cost: 0,
        imageUrl: 'https://picsum.photos/seed/flight/600/200',
        details: { from: 'HKG', to: 'NRT', date: '12 OCT', time: '09:15', arrivalTime: '14:30', seat: '24A', gate: 'B12', airline: 'Cathay', class: 'Economy', flightNo: 'CX504' }
      },
      {
        id: '2',
        type: 'Hotel',
        title: 'Shinjuku Prince Hotel',
        referenceNo: 'H-992831',
        bookedBy: '2',
        cost: 45000,
        imageUrl: '',
        details: { address: 'Kabukicho, Tokyo', checkIn: '12 OCT', checkOut: '17 OCT', room: 'Superior King' }
      }
    ];
  });

  const [itinerary, setItinerary] = useState<ScheduleItem[]>(() => {
    const saved = localStorage.getItem('itinerary');
    return saved ? JSON.parse(saved) : [];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingBooking, setEditingBooking] = useState<Booking | null>(null);
  const [expandedId, setExpandedId] = useState<string | null>(null);

  // Search State
  const [isSearchVisible, setIsSearchVisible] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterUser, setFilterUser] = useState<string | 'All'>('All');

  useEffect(() => {
    localStorage.setItem('bookings', JSON.stringify(bookings));
  }, [bookings]);

  useEffect(() => {
    // Refresh itinerary data when modal opens to get latest schedule items
    const saved = localStorage.getItem('itinerary');
    if (saved) setItinerary(JSON.parse(saved));

    if (highlightId) setExpandedId(highlightId);
  }, [highlightId, isModalOpen]);

  const handleDelete = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    if (confirm('Delete this booking?')) {
      setBookings(bookings.filter(b => b.id !== id));
      if (expandedId === id) setExpandedId(null);
    }
  };

  const handleEdit = (e: React.MouseEvent, booking: Booking) => {
    e.stopPropagation();
    setEditingBooking(booking); 
    setIsModalOpen(true);
  };

  const handleDuplicate = (e: React.MouseEvent, booking: Booking) => {
    e.stopPropagation();
    const newBooking: Booking = {
      ...booking,
      id: Date.now().toString(),
      title: `${booking.title} (Copy)`,
    };
    const index = bookings.findIndex(b => b.id === booking.id);
    const newBookings = [...bookings];
    newBookings.splice(index + 1, 0, newBooking);
    setBookings(newBookings);
  };

  const handleMove = (e: React.MouseEvent, id: string, direction: 'up' | 'down') => {
    e.stopPropagation();
    const index = bookings.findIndex(b => b.id === id);
    if (index === -1) return;

    const newBookings = [...bookings];
    if (direction === 'up') {
      if (index === 0) return;
      [newBookings[index - 1], newBookings[index]] = [newBookings[index], newBookings[index - 1]];
    } else {
      if (index === newBookings.length - 1) return;
      [newBookings[index + 1], newBookings[index]] = [newBookings[index], newBookings[index + 1]];
    }
    setBookings(newBookings);
  };

  const handleSave = (booking: Booking) => {
    if (editingBooking) {
      setBookings(bookings.map(b => b.id === booking.id ? booking : b));
    } else {
      setBookings([...bookings, { ...booking, id: Date.now().toString() }]);
    }
    setIsModalOpen(false);
    setEditingBooking(null);
  };

  const copyToClipboard = (e: React.MouseEvent, text: string) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
  };

  const filteredBookings = useMemo(() => {
    return bookings.filter(b => {
      const matchesSearch = 
        b.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
        b.type.toLowerCase().includes(searchTerm.toLowerCase()) ||
        (b.referenceNo && b.referenceNo.toLowerCase().includes(searchTerm.toLowerCase()));

      const matchesUser = filterUser === 'All' || b.bookedBy === filterUser;
      return matchesSearch && matchesUser;
    });
  }, [bookings, searchTerm, filterUser]);

  // Updated Header Strip: Info moved to TOP for visibility when stacked
  const renderHeaderStrip = (booking: Booking, isExpanded: boolean, index: number, total: number) => {
    const bookedByMember = members.find(m => m.id === booking.bookedBy);

    let icon = <TicketIcon size={18} />;
    let bgColor = 'bg-white';
    let textColor = 'text-navy';
    let borderColor = 'border-accent';
    let accentColor = 'bg-accent';

    switch (booking.type) {
      case 'Flight':
        icon = <Plane size={18} className="text-white" />;
        bgColor = 'bg-navy';
        textColor = 'text-white';
        borderColor = 'border-navy';
        accentColor = 'bg-stitch';
        break;
      case 'Hotel':
        icon = <Hotel size={18} className="text-stitch" />;
        bgColor = 'bg-white';
        textColor = 'text-navy';
        borderColor = 'border-stitch';
        accentColor = 'bg-stitch';
        break;
      case 'Amusement':
        icon = <Sparkles size={18} className="text-navy" />;
        bgColor = 'bg-donald';
        textColor = 'text-navy';
        borderColor = 'border-donald';
        accentColor = 'bg-white';
        break;
      case 'Restaurant':
        icon = <Utensils size={18} className="text-red-400" />;
        bgColor = 'bg-white';
        textColor = 'text-navy';
        borderColor = 'border-red-200';
        accentColor = 'bg-red-200';
        break;
      case 'Car':
        icon = <Car size={18} className="text-navy" />;
        bgColor = 'bg-accent/30';
        textColor = 'text-navy';
        borderColor = 'border-accent';
        accentColor = 'bg-white';
        break;
    }

    // Determine key date/time info
    const displayTime = booking.details.time || booking.details.checkIn || booking.details.datetime?.split('T')[1] || '';
    const displayDate = booking.details.date || booking.details.checkIn || booking.details.datetime?.split('T')[0] || '';
    const arrivalTime = booking.details.arrivalTime;

    return (
      <div className={`flex relative min-h-[100px] ${bgColor} ${textColor} transition-colors overflow-hidden`}>
        {/* Decorative Elements */}
        {booking.type === 'Flight' && <div className="absolute right-0 top-0 bottom-0 w-32 bg-white/10 -skew-x-12 translate-x-10 pointer-events-none" />}
        {booking.type === 'Amusement' && <div className="absolute inset-0 opacity-10 pointer-events-none" style={{backgroundImage: 'radial-gradient(circle, #fff 2px, transparent 2.5px)', backgroundSize: '12px 12px'}} />}

        {/* Main Content Area */}
        <div className="flex-1 p-4 flex flex-col relative z-10">
          {/* TOP ROW: Key Info (Visible when stacked) */}
          <div className="flex justify-between items-start mb-2">
             <div className="flex items-center gap-3">
                <div className={`w-8 h-8 rounded-lg flex items-center justify-center shadow-sm ${accentColor === 'bg-white' ? 'bg-white/80' : accentColor}`}>
                  {icon}
                </div>
                <div className="flex flex-col">
                  <span className={`text-[9px] font-black uppercase tracking-widest opacity-60`}>
                    {booking.type}
                  </span>
                  {/* Date is critical, show it at top */}
                  <span className="text-xs font-black leading-none">{displayDate}</span>
                </div>
             </div>

             {/* Time Display */}
             <div className="text-right">
                {booking.type === 'Flight' && arrivalTime ? (
                  <div className="flex flex-col items-end">
                     <div className="flex items-center gap-1">
                        <span className="text-sm font-black">{displayTime}</span>
                        <span className="opacity-50 text-[10px]">➔</span>
                        <span className="text-sm font-black">{arrivalTime}</span>
                     </div>
                  </div>
                ) : (
                  <p className="text-lg font-black">{displayTime}</p>
                )}
             </div>
          </div>

          {/* MID ROW: Title */}
          <div className="flex-1">
             <h3 className="font-black text-lg leading-tight pr-2">{booking.title}</h3>
             {booking.referenceNo && (
                <span className="flex items-center gap-1 text-[9px] font-bold opacity-60 mt-0.5">
                  <Hash size={8} /> {booking.referenceNo}
                </span>
             )}
          </div>
        </div>

        {/* RIGHT SIDE: Sorting Controls (Hidden strip) */}
        <div className={`w-10 flex flex-col items-center justify-center gap-1 border-l ${booking.type === 'Flight' ? 'border-white/10 bg-black/10' : 'border-black/5 bg-black/5'}`} onClick={e => e.stopPropagation()}>
           <button 
              onClick={(e) => handleMove(e, booking.id, 'up')}
              disabled={index === 0}
              className={`p-1.5 rounded-full hover:bg-white/20 active:scale-90 disabled:opacity-20 transition-all`}
           >
              <ChevronUp size={14} strokeWidth={3} />
           </button>
           <button 
              onClick={(e) => handleDuplicate(e, booking)}
              className="p-1.5 rounded-full hover:bg-white/20 active:scale-90 transition-all"
              title="Duplicate"
           >
              <CopyPlus size={12} />
           </button>
           <button 
              onClick={(e) => handleMove(e, booking.id, 'down')}
              disabled={index === total - 1}
              className={`p-1.5 rounded-full hover:bg-white/20 active:scale-90 disabled:opacity-20 transition-all`}
           >
              <ChevronDown size={14} strokeWidth={3} />
           </button>
        </div>
      </div>
    );
  };

  const renderBookingDetails = (booking: Booking) => {
    const hasImage = !!booking.imageUrl;
    const linkedItem = itinerary.find(i => i.id === booking.linkedScheduleId);

    // Helper for conditional rendering - Hides empty fields
    // Fix: Added 'key' to interface to satisfy TypeScript strict prop checks when component is used in map()
    const DetailField = ({ label, value, fullWidth = false, className = '' }: { label: string, value: any, fullWidth?: boolean, className?: string, key?: React.Key }) => {
       if (!value || value === '') return null;
       return (
         <div className={`${fullWidth ? 'col-span-2' : ''} ${className}`}>
            <p className="text-[9px] font-black text-navy/30 uppercase tracking-widest mb-0.5">{label}</p>
            <p className="font-bold text-navy text-sm break-words leading-tight">{String(value)}</p>
         </div>
       );
    };

    return (
      <div className="animate-in fade-in duration-300 bg-white rounded-b-2xl-sticker overflow-hidden">

        {/* LINKED SCHEDULE BANNER */}
        {linkedItem && (
          <div 
            onClick={() => onNavigate('schedule')}
            className="bg-stitch/10 px-4 py-2 flex items-center justify-between cursor-pointer hover:bg-stitch/20 transition-colors border-b border-dashed border-stitch/30"
          >
             <div className="flex items-center gap-2 overflow-hidden">
                <MapPin size={12} className="text-stitch flex-shrink-0" />
                <span className="text-[10px] font-black uppercase text-stitch truncate">
                  Linked to: Day {linkedItem.dayIndex + 1} - {linkedItem.location}
                </span>
             </div>
             <ArrowUpRight size={12} className="text-stitch" />
          </div>
        )}

        {/* IMAGE SECTION - Only show if exists */}
        {hasImage && (
             <div className="p-4 bg-white">
                 <div className="w-full rounded-xl border-2 border-navy/5 p-1 shadow-inner bg-cream relative group">
                    <img src={booking.imageUrl} alt="Voucher" className="w-full h-auto max-h-[300px] object-contain rounded-lg mix-blend-multiply" />
                    <a 
                      href={booking.imageUrl} 
                      download={`ticket-${booking.title.replace(/\s+/g, '_')}.jpg`} 
                      onClick={e => e.stopPropagation()} 
                      className="absolute bottom-2 right-2 p-2 bg-white/80 rounded-full shadow-sm text-navy/40 hover:text-navy opacity-0 group-hover:opacity-100 transition-opacity"
                      title="Download Image"
                    >
                      <Download size={14} />
                    </a>
                 </div>
             </div>
        )}

        {/* Perforated Line - Separator */}
        <div className="relative h-4 w-full bg-white overflow-hidden -mt-1 mb-1">
            <div className="absolute top-1/2 left-0 w-full border-t-2 border-dashed border-accent/40"></div>
            <div className="absolute -left-2 top-1/2 -translate-y-1/2 w-3 h-3 bg-cream rounded-full border-r border-accent/20"></div>
            <div className="absolute -right-2 top-1/2 -translate-y-1/2 w-3 h-3 bg-cream rounded-full border-l border-accent/20"></div>
        </div>

        {/* DETAILS BODY */}
        <div className="p-5 pt-2 pb-6">

          {/* Reference Number - Prominent */}
          {booking.referenceNo && (
            <div 
              onClick={(e) => copyToClipboard(e, booking.referenceNo!)}
              className="flex items-center justify-between p-3 bg-cream/50 rounded-xl border border-accent/30 mb-5 cursor-pointer active:scale-[0.99] transition-transform group hover:border-stitch/30"
            >
               <div>
                  <p className="text-[9px] font-black uppercase text-navy/30 tracking-widest">Booking Ref</p>
                  <p className="text-xl font-black text-navy font-mono tracking-wider">{booking.referenceNo}</p>
               </div>
               <div className="w-8 h-8 rounded-full bg-white flex items-center justify-center shadow-sm text-stitch group-hover:scale-110 transition-transform">
                  <Copy size={14} />
               </div>
            </div>
          )}

          <div className="grid grid-cols-2 gap-y-5 gap-x-4">

            {/* FLIGHT SPECIFIC LAYOUT */}
            {booking.type === 'Flight' && (
              <>
                {/* Route Visual */}
                {(booking.details.from || booking.details.to) && (
                   <div className="col-span-2 flex items-center gap-4 p-3 rounded-xl border border-accent/30 bg-white shadow-sm mb-1">
                      <div className="flex-1 min-w-0">
                         <p className="text-[9px] font-black text-navy/30 uppercase tracking-wider">From</p>
                         <p className="text-xl font-black text-navy truncate">{booking.details.from}</p>
                         <p className="text-[10px] font-bold text-navy/40">{booking.details.time}</p>
                      </div>
                      <div className="flex flex-col items-center gap-1 opacity-20">
                         <Plane size={20} className="rotate-90 text-navy" />
                         <div className="w-12 border-t-2 border-dashed border-navy"></div>
                      </div>
                      <div className="flex-1 text-right min-w-0">
                         <p className="text-[9px] font-black text-navy/30 uppercase tracking-wider">To</p>
                         <p className="text-xl font-black text-navy truncate">{booking.details.to}</p>
                         <p className="text-[10px] font-bold text-navy/40">{booking.details.arrivalTime}</p>
                      </div>
                   </div>
                )}

                <DetailField label="Airline" value={booking.details.airline} />
                <DetailField label="Flight No" value={booking.details.flightNo} />
                <DetailField label="Gate" value={booking.details.gate} />
                <DetailField label="Seat" value={booking.details.seat} />
                <DetailField label="Class" value={booking.details.class} />
              </>
            )}

            {/* HOTEL / CAR LAYOUT */}
            {(booking.type === 'Hotel' || booking.type === 'Car') && (
               <>
                 <DetailField label="Address / Location" value={booking.details.address} fullWidth />

                 {(booking.details.checkIn || booking.details.checkOut) && (
                   <div className="col-span-2 bg-cream/30 p-3 rounded-xl border border-accent/30 flex gap-4">
                      <div className="flex-1">
                         <p className="text-[9px] font-black text-navy/30 uppercase tracking-wider">{booking.type === 'Car' ? 'Pick-up' : 'Check-In'}</p>
                         <p className="font-bold text-navy">{booking.details.checkIn}</p>
                      </div>
                      <div className="w-px bg-accent/30"></div>
                      <div className="flex-1">
                         <p className="text-[9px] font-black text-navy/30 uppercase tracking-wider">{booking.type === 'Car' ? 'Drop-off' : 'Check-Out'}</p>
                         <p className="font-bold text-navy">{booking.details.checkOut}</p>
                      </div>
                   </div>
                 )}

                 <DetailField label="Room / Vehicle" value={booking.details.room || booking.details.vehicle} fullWidth />
               </>
            )}

            {/* GENERIC FIELDS (Filter empty & specific keys) */}
            {Object.entries(booking.details).map(([key, value]) => {
                const ignoredKeys = [
                    'from', 'to', 'gate', 'seat', 'checkIn', 'checkOut', 'address', 'imageUrl', 
                    'arrivalTime', 'time', 'date', 'airline', 'flightNo', 'class', 'room', 'vehicle'
                ];
                if (ignoredKeys.includes(key)) return null;
                // Fix: Cast 'value' to 'any' to ensure it's compatible with DetailField props and avoid 'unknown' inference.
                return <DetailField key={key} label={key} value={value as any} fullWidth={String(value).length > 20} />;
             })}
          </div>

          {/* Action Buttons */}
          <div className="flex justify-end gap-3 mt-8 pt-4 border-t border-accent/30">
             <button onClick={(e) => handleEdit(e, booking)} className="flex items-center gap-1 px-4 py-2 bg-cream rounded-full text-[10px] font-black text-navy hover:bg-stitch hover:text-white transition-colors">
               <Edit2 size={12} /> EDIT
             </button>
             <button onClick={(e) => handleDelete(e, booking.id)} className="flex items-center gap-1 px-4 py-2 bg-cream rounded-full text-[10px] font-black text-red-400 hover:bg-red-400 hover:text-white transition-colors">
               <Trash2 size={12} /> REMOVE
             </button>
          </div>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6 pb-24 animate-in fade-in duration-500 min-h-screen">

      {/* Header with Search Toggle */}
      <div className="flex justify-between items-center px-1 sticky top-0 bg-cream/95 backdrop-blur-sm z-[60] py-4 border-b border-accent/20">
        <div>
          <h2 className="text-2xl font-black text-navy">Ticket Wallet</h2>
          <p className="text-[10px] font-bold text-navy/30 uppercase tracking-[0.2em]">
             {filteredBookings.length} Vouchers
          </p>
        </div>
        <div className="flex gap-2">
           <button 
             onClick={() => setIsSearchVisible(!isSearchVisible)}
             className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${isSearchVisible ? 'bg-navy text-white' : 'bg-white text-navy/40 border border-accent'}`}
           >
             <Search size={18} />
           </button>
           <button 
             onClick={() => { setEditingBooking(null); setIsModalOpen(true); }}
             className="w-10 h-10 bg-donald rounded-full flex items-center justify-center text-navy shadow-lg border border-white active:scale-90 transition-transform"
           >
             <Plus size={20} />
           </button>
        </div>
      </div>

      {/* Collapsible Search Bar */}
      {isSearchVisible && (
        <div className="animate-in slide-in-from-top-2 fade-in duration-200 -mt-2 mb-4 bg-white p-4 rounded-2xl-sticker border border-accent sticker-shadow">
           <div className="flex items-center gap-2 bg-cream p-3 rounded-xl border border-accent/50 mb-3">
              <input 
                 type="text" 
                 placeholder="Search tickets, Ref No..." 
                 value={searchTerm}
                 onChange={(e) => setSearchTerm(e.target.value)}
                 className="flex-1 bg-transparent border-none p-0 text-navy font-bold placeholder:text-navy/20 focus:ring-0 text-sm"
                 autoFocus
              />
              {searchTerm && <button onClick={() => setSearchTerm('')}><X size={14} className="text-navy/30" /></button>}
           </div>
           <div className="flex gap-2 overflow-x-auto pb-1 scrollbar-hide">
              <button 
                 onClick={() => setFilterUser('All')}
                 className={`flex-shrink-0 px-3 py-1.5 rounded-full flex items-center gap-1.5 border transition-all ${filterUser === 'All' ? 'bg-navy border-navy text-white' : 'bg-white border-accent text-navy/40'}`}
              >
                 <User size={12} /> <span className="text-[10px] font-black uppercase">All</span>
              </button>
              {members.map(m => (
                 <button 
                    key={m.id}
                    onClick={() => setFilterUser(m.id)}
                    className={`flex-shrink-0 pr-3 py-1 rounded-full flex items-center gap-2 border transition-all ${filterUser === m.id ? 'bg-stitch border-stitch text-white pl-1' : 'bg-white border-accent text-navy/40 pl-1'}`}
                 >
                    <img src={m.avatar} className="w-5 h-5 rounded-full" />
                    <span className="text-[10px] font-black uppercase">{m.name}</span>
                 </button>
              ))}
           </div>
        </div>
      )}

      {/* Stacked Layout Container */}
      <div className="relative pb-24 flex flex-col pt-4 px-1">
        {filteredBookings.length > 0 ? (
          filteredBookings.map((booking, index) => {
             const isExpanded = expandedId === booking.id;
             // Improved Stacking Logic: Show visible Header (Top info)
             return (
               <div 
                  key={booking.id}
                  onClick={() => setExpandedId(isExpanded ? null : booking.id)}
                  className={`
                     relative w-full rounded-2xl-sticker overflow-hidden border-2 sticker-shadow transition-all duration-500 ease-in-out cursor-pointer
                     ${isExpanded 
                        ? 'z-50 my-4 scale-[1.02] shadow-2xl' 
                        : 'z-0 -mt-12 hover:-mt-10 hover:z-40 hover:scale-[1.005] hover:shadow-lg' // -mt-12 ensures top ~50px is visible
                     }
                     ${index === 0 && !isExpanded ? 'mt-0' : ''}
                     ${booking.type === 'Flight' ? 'border-navy' : booking.type === 'Amusement' ? 'border-donald' : 'border-accent'}
                  `}
                  style={{ zIndex: isExpanded ? 50 : index }}
               >
                  {renderHeaderStrip(booking, isExpanded, index, filteredBookings.length)}

                  {/* Expandable Content Area */}
                  <div className={`transition-[max-height] duration-500 ease-in-out overflow-hidden ${isExpanded ? 'max-h-[1000px]' : 'max-h-0'}`}>
                     {renderBookingDetails(booking)}
                  </div>
               </div>
             );
          })
        ) : (
          <div className="py-24 text-center opacity-30 flex flex-col items-center border-2 border-dashed border-accent rounded-3xl bg-paper/50 mt-4">
            <TicketIcon size={56} className="mb-4 text-navy/20" />
            <p className="font-black text-xl">Empty Pocket</p>
            <p className="text-sm font-bold max-w-[200px] mx-auto">No tickets found. Tap + to add one!</p>
          </div>
        )}
      </div>

      {isModalOpen && (
        <BookingFormModal 
          initialData={editingBooking} 
          members={members}
          itinerary={itinerary}
          currentUser={currentUser}
          onClose={() => setIsModalOpen(false)} 
          onSave={handleSave} 
        />
      )}
    </div>
  );
};

// Image compression utility
const compressImage = (file: File): Promise<string> => {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target?.result as string;
      img.onload = () => {
        const canvas = document.createElement('canvas');
        const MAX_WIDTH = 800;
        const scaleSize = MAX_WIDTH / img.width;
        canvas.width = MAX_WIDTH;
        canvas.height = img.height * scaleSize;

        const ctx = canvas.getContext('2d');
        ctx?.drawImage(img, 0, 0, canvas.width, canvas.height);
        resolve(canvas.toDataURL('image/jpeg', 0.6)); 
      };
    };
  });
};

